-- ============================================================
-- Section: maludb_core--0.1.0--0.2.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.2.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.1.0 → 0.2.0
--
-- Anchors the R1.1 alpha additions that landed after R1.0 sign-off:
--   R1.1-12 — compartmentalized vector substrate (Stage 1.7)
--   R1.1-13 — C top-K heap exact vector search
--   R1.1-14 — vector search observability + maludb.memory.search.exact
--
-- Purely additive against the R1.0 baseline. No object renames, no
-- destructive changes. Apply with:
--
--   ALTER EXTENSION maludb_core UPDATE TO '0.2.0';
-- =====================================================================

-- ---------------------------------------------------------------------
-- Bump the version-reporting function. pg_extension.extversion is
-- managed by PG from the control file; this function is how
-- maludb.health and other callers read the same string back. The
-- release-line string (maludb_core_release) stays at "R1.0 Stage 1
-- substrate" — 0.2.0 is still inside the R1.0 release line; it just
-- carries the R1.1 alpha additions ahead of the v1.0.0-rc1 tag.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.2.0'::text $body$;

-- ---------------------------------------------------------------------
-- New Stage 1.7 object_type seeds. The base R1.0 install closes its
-- object_type INSERT with `mc2db_invocation`; we add a follow-on
-- INSERT for the four vector_* types here.
-- ---------------------------------------------------------------------
INSERT INTO malu$object_type(object_type, stage, description) VALUES
    ('vector_subject',       1, 'Stage 1.7. Compartment-routing subject (instance, per-tenant).'),
    ('vector_verb',          1, 'Stage 1.7. Compartment-routing verb (instance, per-tenant).'),
    ('vector_compartment',   1, 'Stage 1.7. (subject, verb) routing compartment for vector search.'),
    ('vector_chunk',         1, 'Stage 1.7. BYTEA-packed float32 embedding bound to a compartment.');

-- =====================================================================
-- R1.1-12: Compartmentalized vector search — catalog + BYTEA storage
--
-- Stage 1.7 vector substrate. Tables sit beneath the Stage 2+ memory
-- object model and are deliberately distinct from malu$svpor_*
-- (Stage 3 semantic SVPOR) and malu$verb_type / malu$source_type
-- (Stage 1 type registries). Design from
-- docs/research/2026-05-06-compartmentalized-vector-search.md.
--
-- Doctrine: relational filter first. Exact vector scoring second.
-- Top-K third. Compartment = (owner_schema, namespace, subject_id,
-- verb_id) and is the primary access path; vectors are ranked
-- INSIDE a resolved compartment, never across the whole table.
-- Embeddings stored as BYTEA-packed little-endian float32 (length
-- divisible by 4). pgvector dependency stays for the malu$vector_demo
-- legacy smoke table from R1.0-1; new path is BYTEA-only.
-- =====================================================================

CREATE TABLE malu$vector_subject (
    subject_id     bigserial PRIMARY KEY,
    owner_schema   name NOT NULL DEFAULT current_schema(),
    namespace      text NOT NULL,
    subject_name   text NOT NULL,
    description    text,
    created_at     timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, namespace, subject_name)
);

CREATE TABLE malu$vector_verb (
    verb_id        bigserial PRIMARY KEY,
    owner_schema   name NOT NULL DEFAULT current_schema(),
    namespace      text NOT NULL,
    verb_name      text NOT NULL,
    description    text,
    created_at     timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, namespace, verb_name)
);

CREATE TABLE malu$vector_compartment (
    compartment_id    bigserial PRIMARY KEY,
    owner_schema      name NOT NULL DEFAULT current_schema(),
    namespace         text NOT NULL,
    subject_id        bigint NOT NULL REFERENCES malu$vector_subject(subject_id) ON DELETE RESTRICT,
    verb_id           bigint NOT NULL REFERENCES malu$vector_verb(verb_id)       ON DELETE RESTRICT,
    embedding_dim     integer NOT NULL,
    embedding_model   text    NOT NULL,
    distance_metric   text    NOT NULL DEFAULT 'cosine'
        CHECK (distance_metric IN ('cosine','l2','inner_product')),
    vector_count      bigint  NOT NULL DEFAULT 0,
    search_mode       text    NOT NULL DEFAULT 'exact'
        CHECK (search_mode IN ('exact','exact_parallel','local_ann')),
    ann_index_status  text    NOT NULL DEFAULT 'none'
        CHECK (ann_index_status IN ('none','building','ready','stale','rebuilding','disabled')),
    created_at        timestamptz NOT NULL DEFAULT now(),
    updated_at        timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, namespace, subject_id, verb_id)
);

CREATE TABLE malu$vector_chunk (
    chunk_id         bigserial PRIMARY KEY,
    compartment_id   bigint NOT NULL
        REFERENCES malu$vector_compartment(compartment_id) ON DELETE CASCADE,
    source_text      text NOT NULL,
    embedding        bytea NOT NULL,
    embedding_dim    integer NOT NULL,
    embedding_model  text NOT NULL,
    embedding_norm   double precision,
    importance_score numeric(6,3),
    created_at       timestamptz NOT NULL DEFAULT now(),
    CHECK (octet_length(embedding) = embedding_dim * 4),
    CHECK (embedding_dim > 0)
);

CREATE INDEX malu$vector_chunk_compartment_idx
    ON malu$vector_chunk(compartment_id);

-- =====================================================================
-- C distance helpers (LANGUAGE C, defined in src/maludb_vector.c)
-- =====================================================================
CREATE FUNCTION vector_from_real_array(real[]) RETURNS bytea
    AS 'MODULE_PATHNAME', 'maludb_vector_from_real_array'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_to_real_array(bytea) RETURNS real[]
    AS 'MODULE_PATHNAME', 'maludb_vector_to_real_array'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_dims(bytea) RETURNS integer
    AS 'MODULE_PATHNAME', 'maludb_vector_dims'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_norm(bytea) RETURNS double precision
    AS 'MODULE_PATHNAME', 'maludb_vector_norm'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_dot_product(bytea, bytea) RETURNS double precision
    AS 'MODULE_PATHNAME', 'maludb_vector_dot_product'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_l2_squared(bytea, bytea) RETURNS double precision
    AS 'MODULE_PATHNAME', 'maludb_vector_l2_squared'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_normalize(bytea) RETURNS bytea
    AS 'MODULE_PATHNAME', 'maludb_vector_normalize'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

-- =====================================================================
-- PL/pgSQL distance wrappers — convert C primitives into the metrics
-- a search planner uses. cosine assumes vectors may not be normalized;
-- the search hot path uses inner_product on pre-normalized chunks.
-- =====================================================================
CREATE FUNCTION cosine_distance(a bytea, b bytea) RETURNS double precision
LANGUAGE plpgsql IMMUTABLE STRICT PARALLEL SAFE
AS $body$
DECLARE
    na double precision := vector_norm(a);
    nb double precision := vector_norm(b);
BEGIN
    IF na = 0 OR nb = 0 THEN RETURN 1.0; END IF;
    RETURN 1.0 - (vector_dot_product(a, b) / (na * nb));
END;
$body$;

CREATE FUNCTION l2_squared_distance(a bytea, b bytea) RETURNS double precision
LANGUAGE sql IMMUTABLE STRICT PARALLEL SAFE
AS $body$ SELECT vector_l2_squared(a, b) $body$;

CREATE FUNCTION inner_product(a bytea, b bytea) RETURNS double precision
LANGUAGE sql IMMUTABLE STRICT PARALLEL SAFE
AS $body$ SELECT vector_dot_product(a, b) $body$;

-- =====================================================================
-- Registration APIs — idempotent for catalog rows; chunk normalizes
-- the embedding at insert and bumps the parent compartment's
-- vector_count. Operators MUST register subject/verb/compartment before
-- inserting chunks.
-- =====================================================================
CREATE FUNCTION register_vector_subject(p_namespace text, p_subject_name text)
RETURNS bigint LANGUAGE plpgsql AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$vector_subject(namespace, subject_name)
         VALUES (p_namespace, p_subject_name)
    ON CONFLICT (owner_schema, namespace, subject_name)
        DO UPDATE SET subject_name = EXCLUDED.subject_name
        RETURNING subject_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_vector_verb(p_namespace text, p_verb_name text)
RETURNS bigint LANGUAGE plpgsql AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$vector_verb(namespace, verb_name)
         VALUES (p_namespace, p_verb_name)
    ON CONFLICT (owner_schema, namespace, verb_name)
        DO UPDATE SET verb_name = EXCLUDED.verb_name
        RETURNING verb_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_vector_compartment(
    p_namespace        text,
    p_subject_name     text,
    p_verb_name        text,
    p_embedding_dim    integer,
    p_embedding_model  text,
    p_distance_metric  text DEFAULT 'cosine'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_subject_id     bigint := register_vector_subject(p_namespace, p_subject_name);
    v_verb_id        bigint := register_vector_verb(p_namespace, p_verb_name);
    v_compartment_id bigint;
BEGIN
    INSERT INTO malu$vector_compartment
        (namespace, subject_id, verb_id,
         embedding_dim, embedding_model, distance_metric)
    VALUES
        (p_namespace, v_subject_id, v_verb_id,
         p_embedding_dim, p_embedding_model, p_distance_metric)
    ON CONFLICT (owner_schema, namespace, subject_id, verb_id)
        DO UPDATE SET updated_at = now()
        RETURNING compartment_id INTO v_compartment_id;
    RETURN v_compartment_id;
END;
$body$;

CREATE FUNCTION register_vector_chunk(
    p_compartment_id  bigint,
    p_source_text     text,
    p_embedding       bytea,
    p_embedding_model text DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_dim       integer := vector_dims(p_embedding);
    v_normed    bytea   := vector_normalize(p_embedding);
    v_norm      double precision := vector_norm(p_embedding);
    v_compart   malu$vector_compartment%ROWTYPE;
    v_chunk_id  bigint;
    v_model     text;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_dim <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'embedding_dim mismatch: chunk=% compartment=%',
            v_dim, v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_model := COALESCE(p_embedding_model, v_compart.embedding_model);

    INSERT INTO malu$vector_chunk
        (compartment_id, source_text, embedding,
         embedding_dim, embedding_model, embedding_norm)
    VALUES
        (p_compartment_id, p_source_text, v_normed,
         v_dim, v_model, v_norm)
    RETURNING chunk_id INTO v_chunk_id;

    UPDATE malu$vector_compartment
       SET vector_count = vector_count + 1,
           updated_at   = now()
     WHERE compartment_id = p_compartment_id;

    RETURN v_chunk_id;
END;
$body$;

-- =====================================================================
-- exact_vector_search_sql / _plpgsql / _c — exact compartment scan
-- with top-K result. The SQL-callable name is exact_vector_search_sql;
-- it dispatches to the C implementation (exact_vector_search_c) by
-- default. The PL/pgSQL implementation is retained as
-- exact_vector_search_plpgsql for cross-validation in tests and
-- as a fallback if the C function is unavailable. R1.1-13.
-- =====================================================================

-- C implementation: bounded top-K max-heap; O(N·log K) time, O(K) memory.
CREATE FUNCTION exact_vector_search_c(
    p_compartment_id bigint,
    p_query          bytea,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
)
AS 'MODULE_PATHNAME', 'maludb_exact_vector_search_c'
LANGUAGE C STABLE PARALLEL SAFE;

-- Public name dispatches to C. Same signature as the PL/pgSQL prototype.
CREATE FUNCTION exact_vector_search_sql(
    p_compartment_id bigint,
    p_query          bytea,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_compart malu$vector_compartment%ROWTYPE;
    v_metric  text;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF vector_dims(p_query) <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'query dim % does not match compartment dim %',
            vector_dims(p_query), v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_metric := COALESCE(p_metric, v_compart.distance_metric);
    RETURN QUERY
        SELECT * FROM exact_vector_search_c(
            p_compartment_id, vector_normalize(p_query), p_limit, v_metric);
END;
$body$;

-- PL/pgSQL fallback / cross-validation implementation.
CREATE FUNCTION exact_vector_search_plpgsql(
    p_compartment_id bigint,
    p_query          bytea,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_metric  text;
    v_compart malu$vector_compartment%ROWTYPE;
    v_query   bytea;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF vector_dims(p_query) <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'query dim % does not match compartment dim %',
            vector_dims(p_query), v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_metric := COALESCE(p_metric, v_compart.distance_metric);
    v_query  := vector_normalize(p_query);

    IF v_metric = 'cosine' THEN
        RETURN QUERY
            SELECT c.chunk_id, c.source_text,
                   1.0 - vector_dot_product(c.embedding, v_query) AS distance,
                         vector_dot_product(c.embedding, v_query) AS similarity,
                   ROW_NUMBER() OVER (
                       ORDER BY vector_dot_product(c.embedding, v_query) DESC
                   )::integer AS rank_no
              FROM malu$vector_chunk c
             WHERE c.compartment_id = p_compartment_id
             ORDER BY similarity DESC
             LIMIT p_limit;
    ELSIF v_metric = 'l2' THEN
        RETURN QUERY
            SELECT c.chunk_id, c.source_text,
                   vector_l2_squared(c.embedding, p_query)        AS distance,
                   -vector_l2_squared(c.embedding, p_query)       AS similarity,
                   ROW_NUMBER() OVER (
                       ORDER BY vector_l2_squared(c.embedding, p_query) ASC
                   )::integer AS rank_no
              FROM malu$vector_chunk c
             WHERE c.compartment_id = p_compartment_id
             ORDER BY distance ASC
             LIMIT p_limit;
    ELSIF v_metric = 'inner_product' THEN
        RETURN QUERY
            SELECT c.chunk_id, c.source_text,
                   -vector_dot_product(c.embedding, p_query)      AS distance,
                    vector_dot_product(c.embedding, p_query)      AS similarity,
                   ROW_NUMBER() OVER (
                       ORDER BY vector_dot_product(c.embedding, p_query) DESC
                   )::integer AS rank_no
              FROM malu$vector_chunk c
             WHERE c.compartment_id = p_compartment_id
             ORDER BY similarity DESC
             LIMIT p_limit;
    ELSE
        RAISE EXCEPTION 'unknown distance metric: %', v_metric
            USING ERRCODE = 'check_violation';
    END IF;
END;
$body$;

CREATE FUNCTION search_memory_exact(
    p_namespace      text,
    p_subject        text,
    p_verb           text,
    p_query          bytea,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id        bigint,
    source_text     text,
    distance        double precision,
    similarity      double precision,
    rank_no         integer,
    compartment_id  bigint
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_compartment_id bigint;
BEGIN
    SELECT c.compartment_id INTO v_compartment_id
      FROM malu$vector_compartment c
      JOIN malu$vector_subject s ON s.subject_id = c.subject_id
      JOIN malu$vector_verb    v ON v.verb_id    = c.verb_id
     WHERE c.namespace = p_namespace
       AND s.subject_name = p_subject
       AND v.verb_name    = p_verb
     LIMIT 1;
    IF v_compartment_id IS NULL THEN
        RAISE EXCEPTION 'no compartment for namespace=% subject=% verb=%',
            p_namespace, p_subject, p_verb
            USING ERRCODE = 'no_data_found';
    END IF;
    RETURN QUERY
        SELECT r.chunk_id, r.source_text, r.distance, r.similarity, r.rank_no,
               v_compartment_id
          FROM exact_vector_search_sql(v_compartment_id, p_query, p_limit, p_metric) r;
END;
$body$;

-- =====================================================================
-- R1.1-14: vector search observability + MC2DB tool
--
-- - Stats view: aggregate vector_count + per-compartment query
--   counters from the audit table.
-- - explain_vector_search(): planner rationale for a given lookup.
-- - r10_memory_search_exact: PL/pgSQL wrapper for the MC2DB tool that
--   accepts a query text alongside the embedding (caller does the
--   embedding render externally for now; R1.2 may add an in-DB
--   embedding model registry).
-- - mc2db.register_tool() entry: maludb.memory.search.exact.
-- =====================================================================

CREATE VIEW malu$vector_compartment_stats AS
SELECT
    c.compartment_id,
    c.namespace,
    s.subject_name,
    v.verb_name,
    c.embedding_dim,
    c.embedding_model,
    c.distance_metric,
    c.vector_count,
    c.search_mode,
    c.ann_index_status,
    c.created_at,
    c.updated_at
FROM malu$vector_compartment c
JOIN malu$vector_subject s ON s.subject_id = c.subject_id
JOIN malu$vector_verb    v ON v.verb_id    = c.verb_id;

CREATE FUNCTION explain_vector_search(
    p_namespace text,
    p_subject   text,
    p_verb      text
) RETURNS TABLE (
    compartment_id    bigint,
    namespace         text,
    subject_name      text,
    verb_name         text,
    embedding_dim     integer,
    embedding_model   text,
    distance_metric   text,
    vector_count      bigint,
    search_mode       text,
    recommended_mode  text,
    ann_index_status  text
) LANGUAGE sql STABLE
AS $body$
    SELECT
        c.compartment_id,
        c.namespace,
        s.subject_name,
        v.verb_name,
        c.embedding_dim,
        c.embedding_model,
        c.distance_metric,
        c.vector_count,
        c.search_mode,
        CASE
            WHEN c.vector_count <    10000 THEN 'exact'
            WHEN c.vector_count <   250000 THEN 'exact_or_ann'
            ELSE                                'local_ann'
        END                              AS recommended_mode,
        c.ann_index_status
    FROM malu$vector_compartment c
    JOIN malu$vector_subject s ON s.subject_id = c.subject_id
    JOIN malu$vector_verb    v ON v.verb_id    = c.verb_id
    WHERE c.namespace    = p_namespace
      AND s.subject_name = p_subject
      AND v.verb_name    = p_verb;
$body$;

CREATE FUNCTION r10_memory_search_exact(args jsonb, context jsonb) RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_namespace  text  := args->>'namespace';
    v_subject    text  := args->>'subject';
    v_verb       text  := args->>'verb';
    v_query_b64  text  := args->>'query_embedding_b64';
    v_limit      int   := COALESCE((args->>'limit')::int, 10);
    v_metric     text  := args->>'metric';
    v_query      bytea;
    v_results    jsonb;
    v_compartment bigint;
BEGIN
    IF v_namespace IS NULL OR v_subject IS NULL OR v_verb IS NULL OR v_query_b64 IS NULL THEN
        CALL mc2db.put_error('namespace, subject, verb, and query_embedding_b64 are required',
            jsonb_build_object('code','BAD_INPUT'));
        RETURN;
    END IF;

    v_query := decode(v_query_b64, 'base64');

    SELECT compartment_id INTO v_compartment FROM explain_vector_search(v_namespace, v_subject, v_verb);
    IF v_compartment IS NULL THEN
        CALL mc2db.put_error(format('no compartment for %s/%s/%s', v_namespace, v_subject, v_verb),
            jsonb_build_object('code','NOT_FOUND'));
        RETURN;
    END IF;

    SELECT COALESCE(jsonb_agg(jsonb_build_object(
        'chunk_id',    r.chunk_id,
        'source_text', r.source_text,
        'distance',    r.distance,
        'similarity',  r.similarity,
        'rank',        r.rank_no) ORDER BY r.rank_no), '[]'::jsonb)
    INTO v_results
    FROM search_memory_exact(v_namespace, v_subject, v_verb, v_query, v_limit, v_metric) r;

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object('type','text',
            'text', format('%s result(s) from compartment %s',
                           jsonb_array_length(v_results), v_compartment))),
        'structuredContent', jsonb_build_object(
            'compartment_id', v_compartment,
            'results',        v_results),
        'isError', false));
END;
$body$;

SELECT mc2db.register_tool(
    server_name => 'maludb.r10',
    tool_name   => 'maludb.memory.search.exact',
    description => 'Compartment-first exact vector search. Resolves (namespace, subject, verb) to a vector compartment, then ranks by distance. Caller supplies a base64-encoded BYTEA-packed float32 query embedding.',
    implementation_type => 'sql_function',
    input_schema => '{"type":"object",
        "properties":{
            "namespace":{"type":"string"},
            "subject":{"type":"string"},
            "verb":{"type":"string"},
            "query_embedding_b64":{"type":"string",
                "description":"base64-encoded BYTEA-packed little-endian float32 vector"},
            "limit":{"type":"integer","minimum":1,"maximum":1000},
            "metric":{"type":"string","enum":["cosine","l2","inner_product"]}},
        "required":["namespace","subject","verb","query_embedding_b64"]}'::jsonb,
    output_schema => '{"type":"object",
        "required":["compartment_id","results"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.r10_memory_search_exact(jsonb, jsonb)'));


-- ============================================================
-- Section: maludb_core--0.2.0--0.3.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.3.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.2.0 → 0.3.0
--
-- R1.1-7: LLM-specific role and permission model with row-level
-- security. Adds six functional roles and turns RLS on for the
-- LLM-tenancy tables (prompt_template, session, session_context,
-- prompt_render, model_request, model_response, model_provider,
-- model_alias).
--
-- Tenancy binding is GUC-primary with a session_user fallback:
--   1. If `maludb_core.current_account_id` GUC is set, use it.
--   2. Else if `session_user` matches a row in `malu$account`,
--      use that account_id.
--   3. Else `current_account_id()` returns NULL → user sees no rows.
--
-- Service / superuser roles bypass RLS:
--   - maludb_llm_admin (BYPASSRLS) — full ALL access
--   - maludb_llm_auditor (BYPASSRLS) — SELECT-only across the surface
--
-- Operator follow-up after upgrade (NOT performed by this script):
--   GRANT maludb_llm_executor    TO maludb_mc2dbd;
--   GRANT maludb_llm_admin       TO maludb_modeld;   -- needs cross-tenant view
--   (or whatever roles the bootstrap created for the service users)
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.3.0';
-- =====================================================================

-- ---------------------------------------------------------------------
-- Version bump
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.3.0'::text $body$;

-- ---------------------------------------------------------------------
-- Roles. NOLOGIN — these are group roles that operators GRANT to the
-- actual login roles (humans, service accounts, mc2dbd, modeld, etc).
-- BYPASSRLS only where the role is meant to operate across tenants.
-- ---------------------------------------------------------------------
DO $body$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_llm_admin') THEN
        CREATE ROLE maludb_llm_admin NOLOGIN BYPASSRLS;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_llm_prompt_author') THEN
        CREATE ROLE maludb_llm_prompt_author NOLOGIN;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_llm_prompt_approver') THEN
        CREATE ROLE maludb_llm_prompt_approver NOLOGIN;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_llm_model_admin') THEN
        CREATE ROLE maludb_llm_model_admin NOLOGIN;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_llm_executor') THEN
        CREATE ROLE maludb_llm_executor NOLOGIN;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_llm_auditor') THEN
        CREATE ROLE maludb_llm_auditor NOLOGIN BYPASSRLS;
    END IF;
END;
$body$;

-- ---------------------------------------------------------------------
-- Tenancy helper. GUC-primary; session_user → account_name fallback.
--
-- SECURITY DEFINER so RLS-restricted roles can resolve their own
-- tenant without needing SELECT on `malu$account`. SET search_path is
-- pinned to avoid the classic definer-function hijack via a
-- caller-controlled search_path. STABLE: result is consistent within a
-- single query.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION current_account_id() RETURNS bigint
    LANGUAGE plpgsql STABLE PARALLEL SAFE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
DECLARE
    v_guc text;
    v_id  bigint;
BEGIN
    v_guc := current_setting('maludb_core.current_account_id', true);
    IF v_guc IS NOT NULL AND v_guc <> '' THEN
        BEGIN
            RETURN v_guc::bigint;
        EXCEPTION WHEN invalid_text_representation THEN
            RETURN NULL;
        END;
    END IF;
    SELECT account_id INTO v_id
    FROM malu$account
    WHERE account_name = session_user
      AND enabled;
    RETURN v_id;
END;
$body$;

GRANT EXECUTE ON FUNCTION current_account_id() TO
    maludb_llm_admin, maludb_llm_prompt_author, maludb_llm_prompt_approver,
    maludb_llm_model_admin, maludb_llm_executor, maludb_llm_auditor;

COMMENT ON FUNCTION current_account_id() IS
    'Returns the account_id for the current session. Reads the '
    '`maludb_core.current_account_id` GUC first; falls back to the row in '
    '`malu$account` whose account_name matches session_user. Returns NULL '
    'when neither path matches — RLS policies treat NULL as no-tenant and '
    'filter out all rows (fail-closed).';

-- ---------------------------------------------------------------------
-- Schema-level USAGE grants. Without USAGE on the schema, the role
-- cannot even resolve table names; the table-level grants below would
-- be inert.
-- ---------------------------------------------------------------------
GRANT USAGE ON SCHEMA maludb_core TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_executor,
    maludb_llm_auditor;

-- ---------------------------------------------------------------------
-- Table-level grants per role.
--
-- The matrix:
--                            tmpl  ses  sctx ren  req  res  prov alia
--   admin                    ALL   ALL  ALL  ALL  ALL  ALL  ALL  ALL
--   prompt_author            CRUD  -    -    R    R    R    R    R
--   prompt_approver          RU    -    -    -    -    -    R    R
--   model_admin              R     -    -    -    -    -    CRUD CRUD
--   executor                 R     CRUD CRUD CRUD CRUD R    R    R
--   auditor                  R     R    R    R    R    R    R    R
--
-- (R = SELECT, CRUD = SELECT+INSERT+UPDATE+DELETE, RU = SELECT+UPDATE)
-- ---------------------------------------------------------------------

-- All LLM roles get read access to the identity reference tables.
-- malu$account / malu$role / malu$account_role are not row-filtered;
-- identity metadata is cluster-wide reference data. Grants only —
-- mutation stays restricted to the admin role.
GRANT SELECT ON malu$account, malu$role, malu$account_role TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_executor,
    maludb_llm_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$account, malu$role, malu$account_role
    TO maludb_llm_admin;

-- admin: ALL on everything LLM-related
GRANT ALL ON
    malu$prompt_template, malu$session, malu$session_context,
    malu$prompt_render, malu$model_request, malu$model_response,
    malu$model_provider, malu$model_alias
TO maludb_llm_admin;

-- prompt_author: CRUD on prompt_template; read on related (no direct
-- access to `malu$model_provider` — only the public view, so secret_ref
-- is never reachable).
GRANT SELECT, INSERT, UPDATE, DELETE ON malu$prompt_template TO maludb_llm_prompt_author;
GRANT SELECT ON
    malu$session, malu$session_context, malu$prompt_render,
    malu$model_request, malu$model_response,
    malu$model_alias
TO maludb_llm_prompt_author;

-- prompt_approver: SELECT + UPDATE on prompt_template (for R1.1-6 status transitions)
GRANT SELECT, UPDATE ON malu$prompt_template TO maludb_llm_prompt_approver;
GRANT SELECT ON malu$model_alias TO maludb_llm_prompt_approver;

-- model_admin: CRUD on provider + alias
GRANT SELECT, INSERT, UPDATE, DELETE ON malu$model_provider, malu$model_alias
    TO maludb_llm_model_admin;
GRANT SELECT ON malu$prompt_template TO maludb_llm_model_admin;

-- executor: run sessions, render prompts, submit requests
GRANT SELECT ON malu$prompt_template, malu$model_alias TO maludb_llm_executor;
GRANT SELECT, INSERT, UPDATE, DELETE ON
    malu$session, malu$session_context, malu$prompt_render, malu$model_request
TO maludb_llm_executor;
GRANT SELECT ON malu$model_response TO maludb_llm_executor;

-- All LLM roles need sequence USAGE on the tables they can INSERT into.
-- Granting ALL SEQUENCES is broader than strictly necessary (covers
-- non-LLM tables like vector_*) but avoids brittleness around the
-- $-containing default sequence names.
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA maludb_core TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_model_admin,
    maludb_llm_executor;

-- auditor: SELECT everywhere LLM-related (BYPASSRLS = sees all tenants)
GRANT SELECT ON
    malu$prompt_template, malu$session, malu$session_context,
    malu$prompt_render, malu$model_request, malu$model_response,
    malu$model_provider, malu$model_alias
TO maludb_llm_auditor;

-- ---------------------------------------------------------------------
-- A view that hides the sensitive `secret_ref` column on
-- `malu$model_provider`. Most callers should go through this view;
-- only model_admin and BYPASSRLS roles get direct table SELECT.
-- ---------------------------------------------------------------------
CREATE VIEW malu_provider_public AS
SELECT provider_id, provider_name, provider_kind, adapter_name,
       data_sensitivity, enabled, created_at
FROM malu$model_provider;

GRANT SELECT ON malu_provider_public TO
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_executor,
    maludb_llm_auditor,
    maludb_llm_model_admin,
    maludb_llm_admin;

-- ---------------------------------------------------------------------
-- Row-level security policies.
--
-- Pattern: per-table ENABLE ROW LEVEL SECURITY, then one or more
-- permissive policies. Multiple permissive policies OR together.
--
-- Tenant rows: USING (account_id IS NULL OR account_id = current_account_id()).
-- Child rows (via session/request): USING ( parent EXISTS where parent
--   account matches ).
-- Catalog rows (provider, alias): readable by all SELECT-grantees;
--   writable only via a role check.
-- ---------------------------------------------------------------------

-- prompt_template — NULL owner = shared/global template
ALTER TABLE malu$prompt_template ENABLE ROW LEVEL SECURITY;
CREATE POLICY prompt_template_tenant
    ON malu$prompt_template
    USING (
        owner_account_id IS NULL
        OR owner_account_id = current_account_id()
    )
    WITH CHECK (
        owner_account_id IS NULL
        OR owner_account_id = current_account_id()
    );

-- session — must belong to current tenant
ALTER TABLE malu$session ENABLE ROW LEVEL SECURITY;
CREATE POLICY session_tenant
    ON malu$session
    USING (account_id = current_account_id())
    WITH CHECK (account_id = current_account_id());

-- session_context — visible iff parent session is visible
ALTER TABLE malu$session_context ENABLE ROW LEVEL SECURITY;
CREATE POLICY session_context_via_session
    ON malu$session_context
    USING (
        EXISTS (
            SELECT 1 FROM malu$session s
            WHERE s.session_id = malu$session_context.session_id
              AND s.account_id = current_account_id()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$session s
            WHERE s.session_id = malu$session_context.session_id
              AND s.account_id = current_account_id()
        )
    );

-- prompt_render — NULL account = anonymous render (shared visibility)
ALTER TABLE malu$prompt_render ENABLE ROW LEVEL SECURITY;
CREATE POLICY prompt_render_tenant
    ON malu$prompt_render
    USING (account_id IS NULL OR account_id = current_account_id())
    WITH CHECK (account_id IS NULL OR account_id = current_account_id());

-- model_request — same shape as prompt_render
ALTER TABLE malu$model_request ENABLE ROW LEVEL SECURITY;
CREATE POLICY model_request_tenant
    ON malu$model_request
    USING (account_id IS NULL OR account_id = current_account_id())
    WITH CHECK (account_id IS NULL OR account_id = current_account_id());

-- model_response — visible iff parent request is visible
ALTER TABLE malu$model_response ENABLE ROW LEVEL SECURITY;
CREATE POLICY model_response_via_request
    ON malu$model_response
    USING (
        EXISTS (
            SELECT 1 FROM malu$model_request r
            WHERE r.request_id = malu$model_response.request_id
              AND (r.account_id IS NULL OR r.account_id = current_account_id())
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$model_request r
            WHERE r.request_id = malu$model_response.request_id
              AND (r.account_id IS NULL OR r.account_id = current_account_id())
        )
    );

-- model_provider — readable by anyone with SELECT grant; writable only
-- if the caller has the model_admin role. The sensitive `secret_ref`
-- column is hidden behind `malu_provider_public` (above), so even
-- though SELECT here returns rows, non-admins shouldn't be GRANT'd
-- table-level SELECT in the first place (only the view).
ALTER TABLE malu$model_provider ENABLE ROW LEVEL SECURITY;
CREATE POLICY model_provider_read
    ON malu$model_provider
    FOR SELECT
    USING (
        pg_has_role(current_user, 'maludb_llm_model_admin', 'USAGE')
        OR pg_has_role(current_user, 'maludb_llm_auditor', 'USAGE')
    );
CREATE POLICY model_provider_write
    ON malu$model_provider
    FOR ALL
    USING (pg_has_role(current_user, 'maludb_llm_model_admin', 'USAGE'))
    WITH CHECK (pg_has_role(current_user, 'maludb_llm_model_admin', 'USAGE'));

-- model_alias — readable by all SELECT-grantees; writable by model_admin.
ALTER TABLE malu$model_alias ENABLE ROW LEVEL SECURITY;
CREATE POLICY model_alias_read
    ON malu$model_alias
    FOR SELECT
    USING (true);
CREATE POLICY model_alias_write
    ON malu$model_alias
    FOR ALL
    USING (pg_has_role(current_user, 'maludb_llm_model_admin', 'USAGE'))
    WITH CHECK (pg_has_role(current_user, 'maludb_llm_model_admin', 'USAGE'));

-- ============================================================
-- Section: maludb_core--0.3.0--0.4.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.4.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.3.0 → 0.4.0
--
-- R1.1-3: http_endpoint dispatcher.
--
-- 0.1.0 left `malu$mc2db_tool_http_endpoint` as a placeholder
-- (tool_id only); this upgrade fills in the columns the listener
-- needs to make a real HTTP call. Companion code lives in
-- mc2dbd/src/http_endpoint.c.
--
-- Schema additions are nullable on the way in (so existing rows from
-- the placeholder era survive an ALTER without backfill); validation
-- moves into mc2db.register_tool and the dispatcher, both of which
-- reject rows that don't carry an endpoint_url.
-- =====================================================================

-- ---------------------------------------------------------------------
-- Version bump
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.4.0'::text $body$;

-- ---------------------------------------------------------------------
-- http_endpoint metadata. Nullable on add; populated by register_tool.
-- ---------------------------------------------------------------------
ALTER TABLE malu$mc2db_tool_http_endpoint
    ADD COLUMN endpoint_url    text,
    ADD COLUMN http_method     text NOT NULL DEFAULT 'POST',
    ADD COLUMN static_headers  jsonb NOT NULL DEFAULT '{}'::jsonb,
    ADD COLUMN auth_type       text NOT NULL DEFAULT 'none',
    ADD COLUMN auth_token      text;

ALTER TABLE malu$mc2db_tool_http_endpoint
    ADD CONSTRAINT malu$mc2db_tool_http_endpoint_method_check
        CHECK (http_method IN ('GET','POST','PUT','PATCH','DELETE')),
    ADD CONSTRAINT malu$mc2db_tool_http_endpoint_auth_check
        CHECK (auth_type IN ('none','bearer','basic'));

-- ---------------------------------------------------------------------
-- register_tool: accept http_endpoint metadata and route into the
-- new columns. Replaces the placeholder INSERT.
--
-- IMPORTANT: parameter order and types must match the 0.1.0 signature
-- exactly so CREATE OR REPLACE actually replaces the existing function
-- rather than creating a new overload (PG matches function identity by
-- (name, parameter-types-in-order), not by names).
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION mc2db.register_tool(
    server_name          text,
    tool_name            text,
    description          text,
    implementation_type  text,
    input_schema         jsonb DEFAULT '{}'::jsonb,
    output_schema        jsonb DEFAULT NULL,
    title                text DEFAULT NULL,
    risk_class           text DEFAULT 'read_only',
    read_only            boolean DEFAULT true,
    require_confirmation boolean DEFAULT false,
    timeout_ms           integer DEFAULT 10000,
    max_input_bytes      integer DEFAULT 262144,
    max_output_bytes     integer DEFAULT 1048576,
    allow_network        boolean DEFAULT false,
    required_privileges  text[] DEFAULT ARRAY[]::text[],
    impl_metadata        jsonb DEFAULT '{}'::jsonb
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_server_id bigint;
    v_tool_id   bigint;
    v_keys      text[];
    v_allowed   text[];
BEGIN
    SELECT server_id INTO v_server_id
      FROM maludb_core.malu$mc2db_server
     WHERE malu$mc2db_server.server_name = register_tool.server_name;
    IF v_server_id IS NULL THEN
        RAISE EXCEPTION 'MC2DB_SERVER_NOT_FOUND: %', server_name;
    END IF;

    IF implementation_type NOT IN
       ('sql_function','external_exec','mcp_proxy','http_endpoint') THEN
        RAISE EXCEPTION 'MC2DB_BAD_IMPL_TYPE: %', implementation_type;
    END IF;

    v_keys := ARRAY(SELECT jsonb_object_keys(impl_metadata));

    v_allowed := CASE implementation_type
        WHEN 'sql_function'  THEN ARRAY['function_signature','transaction_mode',
                                        'set_role_name','pinned_search_path']
        WHEN 'external_exec' THEN ARRAY['command_path','argv_template','working_dir',
                                        'run_as_user','input_mode','output_mode',
                                        'environment']
        WHEN 'mcp_proxy'     THEN ARRAY['remote_server_name','remote_tool_name',
                                        'transport_type','endpoint_url',
                                        'command_path','argv']
        WHEN 'http_endpoint' THEN ARRAY['endpoint_url','http_method',
                                        'static_headers','auth_type','auth_token']
    END;

    IF EXISTS (
        SELECT 1 FROM unnest(v_keys) k
        WHERE k <> ALL (v_allowed)
    ) THEN
        RAISE EXCEPTION
          'MC2DB_IMPL_METADATA_MISMATCH: implementation_type=% does not accept keys %',
          implementation_type,
          (SELECT array_agg(k) FROM unnest(v_keys) k WHERE k <> ALL (v_allowed));
    END IF;

    INSERT INTO maludb_core.malu$mc2db_tool(
        server_id, tool_name, title, description, implementation_type,
        input_schema, output_schema, risk_class, read_only,
        require_confirmation, timeout_ms, max_input_bytes,
        max_output_bytes, allow_network, required_privileges)
    VALUES (
        v_server_id, tool_name, title, description, implementation_type,
        input_schema, output_schema, risk_class, read_only,
        require_confirmation, timeout_ms, max_input_bytes,
        max_output_bytes, allow_network, required_privileges)
    RETURNING tool_id INTO v_tool_id;

    IF implementation_type = 'sql_function' THEN
        IF impl_metadata ? 'function_signature' = false THEN
            RAISE EXCEPTION
              'MC2DB_IMPL_METADATA_MISSING: sql_function requires function_signature';
        END IF;
        INSERT INTO maludb_core.malu$mc2db_tool_sql_function(
            tool_id, function_signature, transaction_mode,
            set_role_name, pinned_search_path)
        VALUES (
            v_tool_id,
            (impl_metadata->>'function_signature')::regprocedure,
            COALESCE(impl_metadata->>'transaction_mode', 'read_committed'),
            NULLIF(impl_metadata->>'set_role_name','')::name,
            COALESCE(impl_metadata->>'pinned_search_path','maludb_core, pg_catalog'));

    ELSIF implementation_type = 'external_exec' THEN
        IF impl_metadata ? 'command_path' = false THEN
            RAISE EXCEPTION
              'MC2DB_IMPL_METADATA_MISSING: external_exec requires command_path';
        END IF;
        INSERT INTO maludb_core.malu$mc2db_tool_external_exec(
            tool_id, command_path, argv_template, working_dir,
            run_as_user, input_mode, output_mode, environment)
        VALUES (
            v_tool_id,
            impl_metadata->>'command_path',
            COALESCE(impl_metadata->'argv_template','[]'::jsonb),
            impl_metadata->>'working_dir',
            impl_metadata->>'run_as_user',
            COALESCE(impl_metadata->>'input_mode','stdin_json'),
            COALESCE(impl_metadata->>'output_mode','stdout_json'),
            COALESCE(impl_metadata->'environment','{}'::jsonb));

    ELSIF implementation_type = 'mcp_proxy' THEN
        IF impl_metadata ? 'remote_server_name' = false
           OR impl_metadata ? 'remote_tool_name' = false
           OR impl_metadata ? 'transport_type'   = false THEN
            RAISE EXCEPTION
              'MC2DB_IMPL_METADATA_MISSING: mcp_proxy requires remote_server_name, remote_tool_name, transport_type';
        END IF;
        INSERT INTO maludb_core.malu$mc2db_tool_mcp_proxy(
            tool_id, remote_server_name, remote_tool_name, transport_type,
            endpoint_url, command_path, argv)
        VALUES (
            v_tool_id,
            impl_metadata->>'remote_server_name',
            impl_metadata->>'remote_tool_name',
            impl_metadata->>'transport_type',
            impl_metadata->>'endpoint_url',
            impl_metadata->>'command_path',
            COALESCE(impl_metadata->'argv','[]'::jsonb));

    ELSIF implementation_type = 'http_endpoint' THEN
        IF impl_metadata ? 'endpoint_url' = false
           OR coalesce(impl_metadata->>'endpoint_url','') = '' THEN
            RAISE EXCEPTION
              'MC2DB_IMPL_METADATA_MISSING: http_endpoint requires endpoint_url';
        END IF;
        INSERT INTO maludb_core.malu$mc2db_tool_http_endpoint(
            tool_id, endpoint_url, http_method,
            static_headers, auth_type, auth_token)
        VALUES (
            v_tool_id,
            impl_metadata->>'endpoint_url',
            COALESCE(impl_metadata->>'http_method','POST'),
            COALESCE(impl_metadata->'static_headers','{}'::jsonb),
            COALESCE(impl_metadata->>'auth_type','none'),
            NULLIF(impl_metadata->>'auth_token',''));
    END IF;

    RETURN v_tool_id;
END;
$body$;

-- ============================================================
-- Section: maludb_core--0.4.0--0.5.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.5.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.4.0 → 0.5.0
--
-- R1.1-5: Prompt variable schema + bind options.
--
-- Adds malu$prompt_variable (typed declaration of the variables a
-- prompt template expects) and the malu$bind_options composite that
-- the R1.1-4 bind_prompt() will accept. _validate_bind_variables()
-- centralises the rules so the eventual bind_prompt and the legacy
-- render_prompt path can both reuse them.
--
-- Doctrine (per release-1.0-build-plan.md §13): the new table is
-- ADDITIVE. Existing templates that declare their variables only via
-- the JSONB `variables` column on malu$prompt_template keep working;
-- when malu$prompt_variable rows exist for a template, they become
-- authoritative.
-- =====================================================================

-- ---------------------------------------------------------------------
-- Version bump
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.5.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$prompt_variable
--
-- One row per declared variable on a prompt template. PK is
-- (template_id, variable_name) so callers can upsert by name.
-- ---------------------------------------------------------------------
CREATE TABLE malu$prompt_variable (
    template_id     bigint  NOT NULL
        REFERENCES malu$prompt_template(template_id) ON DELETE CASCADE,
    variable_name   text    NOT NULL
        CHECK (variable_name ~ '^[A-Za-z_][A-Za-z0-9_]*$'),
    variable_type   text    NOT NULL DEFAULT 'text'
        CHECK (variable_type IN ('text','integer','number','boolean','json','enum')),
    required        boolean NOT NULL DEFAULT false,
    default_value   text,
    validation_rule text,
    max_length      integer
        CHECK (max_length IS NULL OR max_length > 0),
    enum_values     text[],
    sensitivity     text    NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    created_at      timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (template_id, variable_name),
    -- enum_values is only meaningful for the enum type, but only enforce
    -- the positive direction (enum → values required); allow enum_values
    -- to be set on non-enum types for forward-compat with future kinds.
    CHECK (variable_type <> 'enum' OR (enum_values IS NOT NULL AND array_length(enum_values, 1) > 0))
);

COMMENT ON TABLE malu$prompt_variable IS
    'Typed declaration of variables expected by a malu$prompt_template. '
    'Additive over the legacy malu$prompt_template.variables JSONB; when '
    'rows exist for a template here, _validate_bind_variables treats them '
    'as authoritative.';

-- ---------------------------------------------------------------------
-- malu$bind_options
--
-- Composite-typed bag of bind-time policy knobs. _default_bind_options()
-- returns the production-safe default posture. Callers can override
-- individual fields by SELECTing the default and rewriting the columns
-- they care about.
-- ---------------------------------------------------------------------
CREATE TYPE malu$bind_options AS (
    strict                      boolean,
    on_missing_variable         text,   -- 'error' | 'blank' | 'preserve'
    on_extra_variable           text,   -- 'ignore' | 'warn'  | 'error'
    null_handling               text,   -- 'null_literal' | 'empty' | 'error'
    max_variable_chars          integer,
    max_rendered_prompt_chars   integer,
    on_truncate                 text,   -- 'error' | 'truncate_with_notice'
    escape_mode                 text    -- 'none' | 'json' | 'sql_literal'
);

CREATE FUNCTION _default_bind_options() RETURNS malu$bind_options
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT ROW(
        true,           -- strict
        'error',        -- on_missing_variable
        'warn',         -- on_extra_variable
        'null_literal', -- null_handling
        NULL::integer,  -- max_variable_chars
        NULL::integer,  -- max_rendered_prompt_chars
        'error',        -- on_truncate
        'none'          -- escape_mode
    )::malu$bind_options;
$body$;

-- ---------------------------------------------------------------------
-- malu$bind_validation
--
-- Result of _validate_bind_variables(). status is 'ok' when no warnings
-- were emitted and 'warned' otherwise. Errors raise; the validator
-- never returns status='error'.
-- ---------------------------------------------------------------------
CREATE TYPE malu$bind_validation AS (
    status                 text,
    normalized_variables   jsonb,
    declared_count         integer,
    supplied_count         integer,
    warnings               text[]
);

-- ---------------------------------------------------------------------
-- _coerce_variable: cast a raw JSONB value to the declared variable
-- type, applying max_length / enum constraints. Returns the coerced
-- value as TEXT (the rendering path is text-based) plus a boolean
-- indicating whether the input was NULL.
-- ---------------------------------------------------------------------
CREATE FUNCTION _coerce_variable(
    p_var       malu$prompt_variable,
    p_raw       jsonb,
    p_opts      malu$bind_options,
    OUT v_text  text,
    OUT v_null  boolean
)
LANGUAGE plpgsql IMMUTABLE
AS $body$
DECLARE
    v_max int;
BEGIN
    v_null := (p_raw IS NULL OR jsonb_typeof(p_raw) = 'null');
    IF v_null THEN
        v_text := NULL;
        RETURN;
    END IF;

    CASE p_var.variable_type
        WHEN 'text' THEN
            IF jsonb_typeof(p_raw) = 'string' THEN
                v_text := p_raw #>> '{}';
            ELSE
                v_text := p_raw::text;
            END IF;
        WHEN 'integer' THEN
            IF jsonb_typeof(p_raw) NOT IN ('number','string') THEN
                RAISE EXCEPTION
                  'BIND_TYPE_MISMATCH: variable % expects integer, got %',
                  p_var.variable_name, jsonb_typeof(p_raw)
                  USING ERRCODE = 'invalid_parameter_value';
            END IF;
            v_text := (p_raw #>> '{}')::bigint::text;
        WHEN 'number' THEN
            IF jsonb_typeof(p_raw) NOT IN ('number','string') THEN
                RAISE EXCEPTION
                  'BIND_TYPE_MISMATCH: variable % expects number, got %',
                  p_var.variable_name, jsonb_typeof(p_raw)
                  USING ERRCODE = 'invalid_parameter_value';
            END IF;
            v_text := (p_raw #>> '{}')::numeric::text;
        WHEN 'boolean' THEN
            IF jsonb_typeof(p_raw) NOT IN ('boolean','string') THEN
                RAISE EXCEPTION
                  'BIND_TYPE_MISMATCH: variable % expects boolean, got %',
                  p_var.variable_name, jsonb_typeof(p_raw)
                  USING ERRCODE = 'invalid_parameter_value';
            END IF;
            v_text := (p_raw #>> '{}')::boolean::text;
        WHEN 'json' THEN
            v_text := p_raw::text;
        WHEN 'enum' THEN
            IF jsonb_typeof(p_raw) <> 'string' THEN
                RAISE EXCEPTION
                  'BIND_TYPE_MISMATCH: variable % (enum) expects string, got %',
                  p_var.variable_name, jsonb_typeof(p_raw)
                  USING ERRCODE = 'invalid_parameter_value';
            END IF;
            v_text := p_raw #>> '{}';
            IF v_text <> ALL (p_var.enum_values) THEN
                RAISE EXCEPTION
                  'BIND_ENUM_VIOLATION: variable %=% not in allowed set %',
                  p_var.variable_name, v_text, p_var.enum_values
                  USING ERRCODE = 'invalid_parameter_value';
            END IF;
    END CASE;

    -- max_length applies to the rendered string form. per-var declared
    -- max wins over the global cap when both are set.
    v_max := COALESCE(p_var.max_length, p_opts.max_variable_chars);
    IF v_max IS NOT NULL AND char_length(v_text) > v_max THEN
        IF COALESCE(p_opts.on_truncate, 'error') = 'truncate_with_notice' THEN
            RAISE NOTICE
              'BIND_TRUNCATE: variable % length %, truncated to %',
              p_var.variable_name, char_length(v_text), v_max;
            v_text := left(v_text, v_max);
        ELSE
            RAISE EXCEPTION
              'BIND_LENGTH_VIOLATION: variable % length % exceeds limit %',
              p_var.variable_name, char_length(v_text), v_max
              USING ERRCODE = 'string_data_right_truncation';
        END IF;
    END IF;

    -- validation_rule is a regex check for text/enum, opaque otherwise.
    IF p_var.validation_rule IS NOT NULL
       AND p_var.variable_type IN ('text','enum')
       AND v_text !~ p_var.validation_rule THEN
        RAISE EXCEPTION
          'BIND_VALIDATION_FAILED: variable %=% does not match rule %',
          p_var.variable_name, v_text, p_var.validation_rule
          USING ERRCODE = 'check_violation';
    END IF;
END;
$body$;

-- ---------------------------------------------------------------------
-- _escape_for: text-rendering escape, applied by the bind path before
-- substitution. The legacy render_prompt() does NOT call this (it
-- keeps its raw substitution semantics for backward compat); R1.1-4
-- bind_prompt() will.
-- ---------------------------------------------------------------------
CREATE FUNCTION _escape_for(p_value text, p_mode text) RETURNS text
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT CASE COALESCE(p_mode, 'none')
        WHEN 'none'        THEN p_value
        WHEN 'json'        THEN trim(both '"' FROM to_jsonb(p_value)::text)
        WHEN 'sql_literal' THEN replace(p_value, '''', '''''')
        ELSE p_value
    END;
$body$;

-- ---------------------------------------------------------------------
-- _validate_bind_variables
--
-- Centralised validator. Resolves the variable schema for the template
-- (preferring malu$prompt_variable rows; falling back to the JSONB
-- column on malu$prompt_template), applies the bind options, and
-- returns the normalized variables JSONB along with metadata.
--
-- Schema sources, in order of authority:
--   1. malu$prompt_variable rows for the template (typed)
--   2. malu$prompt_template.variables JSONB keys (loose, type=text,
--      required=false, no default)
--   3. empty (template declares nothing, free-form binding)
--
-- Raises on hard errors:
--   - required variable missing + on_missing_variable='error'
--   - extra variable supplied + on_extra_variable='error'
--   - null + null_handling='error'
--   - per-variable type/length/enum/regex failure (always raises)
--   - rendered output projected to exceed max_rendered_prompt_chars
--     with on_truncate='error'
--
-- Returns the normalized variables (after coercion + escaping) so the
-- caller can pass them through to the rendering path without re-doing
-- the work.
-- ---------------------------------------------------------------------
CREATE FUNCTION _validate_bind_variables(
    p_template_id bigint,
    p_variables   jsonb,
    p_opts        malu$bind_options
) RETURNS malu$bind_validation
LANGUAGE plpgsql
AS $body$
DECLARE
    v_opts        malu$bind_options := COALESCE(p_opts, _default_bind_options());
    v_vars        jsonb             := COALESCE(p_variables, '{}'::jsonb);
    v_declared    jsonb;
    v_normalized  jsonb := '{}'::jsonb;
    v_warnings    text[] := ARRAY[]::text[];
    v_status      text   := 'ok';
    v_declared_n  integer := 0;
    v_supplied_n  integer;
    v_var         malu$prompt_variable;
    v_supplied    jsonb;
    v_coerced     record;
    v_used_typed  boolean := false;
    v_legacy_keys text[];
    v_extra_keys  text[];
    v_msg         text;
BEGIN
    IF jsonb_typeof(v_vars) <> 'object' THEN
        RAISE EXCEPTION
          'BIND_BAD_INPUT: variables must be a JSON object, got %',
          jsonb_typeof(v_vars)
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    v_supplied_n := (SELECT count(*)::integer FROM jsonb_object_keys(v_vars));

    -- Pull typed declarations. If any exist for this template, they
    -- become authoritative; the JSONB fallback is ignored.
    SELECT count(*) INTO v_declared_n
    FROM malu$prompt_variable WHERE template_id = p_template_id;
    v_used_typed := v_declared_n > 0;

    IF v_used_typed THEN
        FOR v_var IN
            SELECT * FROM malu$prompt_variable
            WHERE template_id = p_template_id
            ORDER BY variable_name
        LOOP
            v_supplied := v_vars -> v_var.variable_name;

            IF v_supplied IS NULL THEN
                -- not supplied: default or missing
                IF v_var.default_value IS NOT NULL THEN
                    v_normalized := v_normalized
                        || jsonb_build_object(v_var.variable_name,
                            _escape_for(v_var.default_value, v_opts.escape_mode));
                    CONTINUE;
                END IF;
                IF v_var.required THEN
                    CASE COALESCE(v_opts.on_missing_variable, 'error')
                        WHEN 'error' THEN
                            RAISE EXCEPTION
                              'BIND_REQUIRED_MISSING: variable % not supplied',
                              v_var.variable_name
                              USING ERRCODE = 'not_null_violation';
                        WHEN 'blank' THEN
                            v_normalized := v_normalized
                                || jsonb_build_object(v_var.variable_name, '');
                        WHEN 'preserve' THEN
                            -- leave the {{name}}/:name token in place
                            NULL;
                        ELSE
                            RAISE EXCEPTION
                              'BIND_BAD_OPTION: on_missing_variable=%',
                              v_opts.on_missing_variable
                              USING ERRCODE = 'invalid_parameter_value';
                    END CASE;
                END IF;
                CONTINUE;
            END IF;

            -- supplied: coerce + length-check
            v_coerced := _coerce_variable(v_var, v_supplied, v_opts);

            IF v_coerced.v_null THEN
                CASE COALESCE(v_opts.null_handling, 'null_literal')
                    WHEN 'null_literal' THEN
                        v_normalized := v_normalized
                            || jsonb_build_object(v_var.variable_name, 'null');
                    WHEN 'empty' THEN
                        v_normalized := v_normalized
                            || jsonb_build_object(v_var.variable_name, '');
                    WHEN 'error' THEN
                        RAISE EXCEPTION
                          'BIND_NULL_REJECTED: variable % was null',
                          v_var.variable_name
                          USING ERRCODE = 'null_value_not_allowed';
                    ELSE
                        RAISE EXCEPTION
                          'BIND_BAD_OPTION: null_handling=%',
                          v_opts.null_handling
                          USING ERRCODE = 'invalid_parameter_value';
                END CASE;
            ELSE
                v_normalized := v_normalized
                    || jsonb_build_object(
                        v_var.variable_name,
                        _escape_for(v_coerced.v_text, v_opts.escape_mode));
            END IF;
        END LOOP;

        -- detect extras: keys in v_vars not declared
        SELECT array_agg(k ORDER BY k) INTO v_extra_keys
        FROM jsonb_object_keys(v_vars) k
        WHERE k NOT IN (
            SELECT variable_name FROM malu$prompt_variable
            WHERE template_id = p_template_id
        );

    ELSE
        -- Legacy JSONB path: variable keys declared on the template
        -- itself, no type info. Accept all of them as text.
        SELECT array_agg(k ORDER BY k) INTO v_legacy_keys
        FROM jsonb_object_keys(
            COALESCE(
                (SELECT variables FROM malu$prompt_template
                 WHERE template_id = p_template_id),
                '{}'::jsonb)
        ) k;
        v_declared_n := COALESCE(array_length(v_legacy_keys, 1), 0);

        -- carry every supplied var through, escaped, with NULL handling
        FOR v_msg IN SELECT k FROM jsonb_object_keys(v_vars) k LOOP
            v_supplied := v_vars -> v_msg;
            IF v_supplied IS NULL OR jsonb_typeof(v_supplied) = 'null' THEN
                CASE COALESCE(v_opts.null_handling, 'null_literal')
                    WHEN 'null_literal' THEN
                        v_normalized := v_normalized
                            || jsonb_build_object(v_msg, 'null');
                    WHEN 'empty' THEN
                        v_normalized := v_normalized
                            || jsonb_build_object(v_msg, '');
                    WHEN 'error' THEN
                        RAISE EXCEPTION
                          'BIND_NULL_REJECTED: variable % was null', v_msg
                          USING ERRCODE = 'null_value_not_allowed';
                END CASE;
                CONTINUE;
            END IF;
            v_normalized := v_normalized
                || jsonb_build_object(
                    v_msg,
                    _escape_for(
                        CASE WHEN jsonb_typeof(v_supplied) = 'string'
                             THEN v_supplied #>> '{}'
                             ELSE v_supplied::text
                        END,
                        v_opts.escape_mode));
        END LOOP;

        IF v_legacy_keys IS NOT NULL THEN
            SELECT array_agg(k ORDER BY k) INTO v_extra_keys
            FROM jsonb_object_keys(v_vars) k
            WHERE k <> ALL(v_legacy_keys);
        END IF;
    END IF;

    -- Handle extra-variable policy. Empty array -> NULL via the SELECT
    -- above; normalise here for branching.
    IF v_extra_keys IS NOT NULL AND array_length(v_extra_keys, 1) > 0 THEN
        CASE COALESCE(v_opts.on_extra_variable, 'warn')
            WHEN 'error' THEN
                RAISE EXCEPTION
                  'BIND_UNDECLARED_VARIABLES: %', v_extra_keys
                  USING ERRCODE = 'invalid_parameter_value';
            WHEN 'warn' THEN
                v_warnings := v_warnings ||
                    format('undeclared variables: %s', v_extra_keys);
                v_status := 'warned';
                RAISE NOTICE 'BIND_UNDECLARED_VARIABLES: %', v_extra_keys;
                -- still carry them through (typed path drops; legacy path keeps)
                IF v_used_typed THEN
                    -- already dropped (not in the typed loop above)
                    NULL;
                END IF;
            WHEN 'ignore' THEN
                -- drop in typed mode; keep in legacy mode (no-op)
                IF v_used_typed THEN
                    NULL;
                END IF;
            ELSE
                RAISE EXCEPTION
                  'BIND_BAD_OPTION: on_extra_variable=%',
                  v_opts.on_extra_variable
                  USING ERRCODE = 'invalid_parameter_value';
        END CASE;
    END IF;

    -- Project a worst-case rendered length cap. Without the template
    -- text in hand we can only cap the sum of variable values; the
    -- bind path (R1.1-4) re-checks the actual rendered text against
    -- max_rendered_prompt_chars.
    IF v_opts.max_rendered_prompt_chars IS NOT NULL THEN
        DECLARE
            v_total int := 0;
            v_k     text;
        BEGIN
            FOR v_k IN SELECT k FROM jsonb_object_keys(v_normalized) k LOOP
                v_total := v_total + char_length(v_normalized #>> ARRAY[v_k]);
            END LOOP;
            IF v_total > v_opts.max_rendered_prompt_chars THEN
                IF COALESCE(v_opts.on_truncate, 'error') = 'error' THEN
                    RAISE EXCEPTION
                      'BIND_RENDER_TOO_LARGE: variables sum % chars exceeds cap %',
                      v_total, v_opts.max_rendered_prompt_chars
                      USING ERRCODE = 'string_data_right_truncation';
                ELSE
                    v_warnings := v_warnings ||
                        format('variables sum %s chars (cap %s); bind path will truncate',
                               v_total, v_opts.max_rendered_prompt_chars);
                    v_status := 'warned';
                END IF;
            END IF;
        END;
    END IF;

    RETURN ROW(v_status, v_normalized, v_declared_n, v_supplied_n, v_warnings)::malu$bind_validation;
END;
$body$;

-- ---------------------------------------------------------------------
-- declare_prompt_variable: convenience writer for malu$prompt_variable.
-- Upserts by (template_id, variable_name). Resolves the template by
-- name+version, current latest version when version is NULL.
-- ---------------------------------------------------------------------
CREATE FUNCTION declare_prompt_variable(
    p_template_name    text,
    p_variable_name    text,
    p_variable_type    text    DEFAULT 'text',
    p_required         boolean DEFAULT false,
    p_default_value    text    DEFAULT NULL,
    p_validation_rule  text    DEFAULT NULL,
    p_max_length       integer DEFAULT NULL,
    p_enum_values      text[]  DEFAULT NULL,
    p_sensitivity      text    DEFAULT 'internal',
    p_template_version integer DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_template_id bigint;
BEGIN
    IF p_template_version IS NULL THEN
        SELECT template_id INTO v_template_id
        FROM malu$prompt_template
        WHERE template_name = p_template_name AND enabled = true
        ORDER BY template_version DESC
        LIMIT 1;
    ELSE
        SELECT template_id INTO v_template_id
        FROM malu$prompt_template
        WHERE template_name = p_template_name
          AND template_version = p_template_version;
    END IF;
    IF v_template_id IS NULL THEN
        RAISE EXCEPTION
          'unknown prompt template: % (version %)',
          p_template_name, COALESCE(p_template_version::text, 'latest')
          USING ERRCODE = 'no_data_found';
    END IF;

    INSERT INTO malu$prompt_variable AS pv (
        template_id, variable_name, variable_type, required,
        default_value, validation_rule, max_length, enum_values, sensitivity)
    VALUES (
        v_template_id, p_variable_name, p_variable_type, p_required,
        p_default_value, p_validation_rule, p_max_length, p_enum_values,
        p_sensitivity)
    ON CONFLICT (template_id, variable_name) DO UPDATE
        SET variable_type   = EXCLUDED.variable_type,
            required        = EXCLUDED.required,
            default_value   = EXCLUDED.default_value,
            validation_rule = EXCLUDED.validation_rule,
            max_length      = EXCLUDED.max_length,
            enum_values     = EXCLUDED.enum_values,
            sensitivity     = EXCLUDED.sensitivity;
    RETURN v_template_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- RLS + grants, mirroring the R1.1-7 pattern on malu$prompt_template.
-- ---------------------------------------------------------------------
ALTER TABLE malu$prompt_variable ENABLE ROW LEVEL SECURITY;
CREATE POLICY prompt_variable_via_template
    ON malu$prompt_variable
    USING (
        EXISTS (
            SELECT 1 FROM malu$prompt_template pt
            WHERE pt.template_id = malu$prompt_variable.template_id
              AND (pt.owner_account_id IS NULL
                   OR pt.owner_account_id = current_account_id())
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$prompt_template pt
            WHERE pt.template_id = malu$prompt_variable.template_id
              AND (pt.owner_account_id IS NULL
                   OR pt.owner_account_id = current_account_id())
        )
    );

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$prompt_variable TO
    maludb_llm_admin,
    maludb_llm_prompt_author;
GRANT SELECT ON malu$prompt_variable TO
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_executor,
    maludb_llm_auditor;

-- ============================================================
-- Section: maludb_core--0.5.0--0.6.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.6.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.5.0 → 0.6.0
--
-- R1.1-4: Prompt-binding ergonomics.
--
-- Adds the `bound_prompt` composite type plus bind_prompt() and call()
-- as a convenience layer on top of the R1.0 render_prompt/submit_render
-- primitives. The legacy three-step flow keeps working unchanged.
--
-- bind_prompt:
--   1. resolve template by name + version
--   2. run R1.1-5 _validate_bind_variables on the supplied variables
--   3. substitute into each channel (system/developer/user) and into
--      the legacy body field, then assemble rendered_full
--   4. (optional) merge session context if p_session_id is supplied
--   5. persist a malu$prompt_render row (so legacy submit_render can
--      consume it) and a malu$bound_prompt row (channel-aware)
--   6. return the bound_prompt composite
--
-- call:
--   1. resolve alias by name
--   2. resolve account_id (param > current_account_id() > NULL)
--   3. insert malu$model_request pointing at the render captured at
--      bind time
--   4. return request_id
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.6.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$bound_prompt
--
-- One row per bind_prompt() call. Pairs with malu$prompt_render via
-- render_id (the legacy R1.0 artifact); adds the channel-aware shape,
-- the resolved bind options, and the validator's status + warnings.
-- ---------------------------------------------------------------------
CREATE TABLE malu$bound_prompt (
    bound_prompt_id        bigserial PRIMARY KEY,
    render_id              bigint REFERENCES malu$prompt_render(render_id) ON DELETE SET NULL,
    template_id            bigint NOT NULL
        REFERENCES malu$prompt_template(template_id) ON DELETE RESTRICT,
    template_hash          text NOT NULL,
    account_id             bigint REFERENCES malu$account(account_id) ON DELETE SET NULL,
    session_id             bigint REFERENCES malu$session(session_id) ON DELETE SET NULL,
    variables_raw          jsonb NOT NULL DEFAULT '{}'::jsonb,
    variables_normalized   jsonb NOT NULL DEFAULT '{}'::jsonb,
    rendered_system        text,
    rendered_developer     text,
    rendered_user          text,
    rendered_full          text NOT NULL,
    prompt_hash            text NOT NULL,
    bind_options           malu$bind_options NOT NULL,
    validation_status      text NOT NULL
        CHECK (validation_status IN ('ok','warned')),
    validation_warnings    text[] NOT NULL DEFAULT ARRAY[]::text[],
    estimated_tokens       integer NOT NULL,
    created_at             timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX malu$bound_prompt_template_idx
    ON malu$bound_prompt (template_id, created_at DESC);

COMMENT ON TABLE malu$bound_prompt IS
    'R1.1-4: persistent audit row for a bind_prompt() result. The composite '
    'returned by bind_prompt mirrors a subset of these columns; call() looks '
    'rows up by bound_prompt_id to recover render_id for submission.';

-- ---------------------------------------------------------------------
-- bound_prompt composite type
--
-- Caller-facing surface. Mirrors what's persistent but stays narrower —
-- bind_options, raw variables, audit timestamps are kept in the table
-- only.
-- ---------------------------------------------------------------------
CREATE TYPE bound_prompt AS (
    bound_prompt_id     bigint,
    template_id         bigint,
    template_name       text,
    template_version    integer,
    template_hash       text,
    variables           jsonb,
    rendered_system     text,
    rendered_developer  text,
    rendered_user       text,
    rendered_full       text,
    prompt_hash         text,
    validation_status   text,
    estimated_tokens    integer
);

-- ---------------------------------------------------------------------
-- _template_hash: SHA256 of the channel+body bytes at bind time. Lets
-- callers detect template body changes even when version stays pinned.
-- ---------------------------------------------------------------------
CREATE FUNCTION _template_hash(p_t malu$prompt_template) RETURNS text
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT encode(sha256(
        (COALESCE(p_t.system_template,    '') || E'\x1f' ||
         COALESCE(p_t.developer_template, '') || E'\x1f' ||
         COALESCE(p_t.user_template,      '') || E'\x1f' ||
         COALESCE(p_t.body,               ''))::bytea
    ), 'hex');
$body$;

-- ---------------------------------------------------------------------
-- _render_channels: substitute normalized variables into each channel
-- + body separately. rendered_full reuses _render_compose so callers
-- that ignore channels still get the same flattened text the R1.0
-- legacy path produced.
-- ---------------------------------------------------------------------
CREATE FUNCTION _render_channels(
    p_template       malu$prompt_template,
    p_variables      jsonb,
    OUT s_text       text,
    OUT d_text       text,
    OUT u_text       text,
    OUT full_text    text
)
LANGUAGE sql IMMUTABLE
AS $body$
    SELECT
        CASE WHEN p_template.system_template IS NULL THEN NULL
             ELSE _render_substitute(p_template.system_template, p_variables) END,
        CASE WHEN p_template.developer_template IS NULL THEN NULL
             ELSE _render_substitute(p_template.developer_template, p_variables) END,
        CASE WHEN p_template.user_template IS NULL THEN NULL
             ELSE _render_substitute(p_template.user_template, p_variables) END,
        _render_substitute(_render_compose(p_template), p_variables);
$body$;

-- ---------------------------------------------------------------------
-- _estimate_tokens: rough heuristic. Real tokenization happens on the
-- model side and is recorded in malu$model_response.prompt_tokens.
-- ---------------------------------------------------------------------
CREATE FUNCTION _estimate_tokens(p_text text) RETURNS integer
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT GREATEST(1, (char_length(COALESCE(p_text, '')) + 3) / 4);
$body$;

-- ---------------------------------------------------------------------
-- bind_prompt: render variables into a template, persist + return the
-- bound_prompt composite. p_session_id is optional; when supplied,
-- session context is appended to rendered_full (same shape _render_core
-- produces).
-- ---------------------------------------------------------------------
CREATE FUNCTION bind_prompt(
    p_template_name    text,
    p_variables        jsonb              DEFAULT '{}'::jsonb,
    p_opts             malu$bind_options  DEFAULT NULL,
    p_session_id       bigint             DEFAULT NULL,
    p_template_version integer            DEFAULT NULL,
    p_account_id       bigint             DEFAULT NULL
) RETURNS bound_prompt
LANGUAGE plpgsql
AS $body$
DECLARE
    v_template          malu$prompt_template%ROWTYPE;
    v_opts              malu$bind_options := COALESCE(p_opts, _default_bind_options());
    v_validation        malu$bind_validation;
    v_normalized        jsonb;
    v_channels          record;
    v_full              text;
    v_context_text      text;
    v_context_hash      text;
    v_context_count     integer := 0;
    v_prompt_hash       text;
    v_render_id         bigint;
    v_bound_id          bigint;
    v_template_hash     text;
    v_account_id        bigint := p_account_id;
    v_bound             bound_prompt;
BEGIN
    IF p_template_version IS NULL THEN
        SELECT * INTO v_template
        FROM malu$prompt_template
        WHERE template_name = p_template_name AND enabled = true
        ORDER BY template_version DESC
        LIMIT 1;
    ELSE
        SELECT * INTO v_template
        FROM malu$prompt_template
        WHERE template_name = p_template_name
          AND template_version = p_template_version;
    END IF;
    IF v_template.template_id IS NULL THEN
        RAISE EXCEPTION
          'unknown prompt template: % (version %)',
          p_template_name, COALESCE(p_template_version::text, 'latest')
          USING ERRCODE = 'no_data_found';
    END IF;

    v_validation := _validate_bind_variables(
        v_template.template_id, p_variables, v_opts);
    v_normalized := v_validation.normalized_variables;

    v_channels := _render_channels(v_template, v_normalized);
    v_full     := v_channels.full_text;

    IF p_session_id IS NOT NULL THEN
        PERFORM 1 FROM malu$session WHERE session_id = p_session_id;
        IF NOT FOUND THEN
            RAISE EXCEPTION 'unknown session: %', p_session_id
                USING ERRCODE = 'no_data_found';
        END IF;

        SELECT
            string_agg(
                COALESCE(role, '') || ': ' ||
                COALESCE(content_text, content_jsonb::text),
                E'\n'
                ORDER BY ordinal
            ),
            encode(sha256(string_agg(content_hash, '|' ORDER BY ordinal)::bytea), 'hex'),
            count(*)::integer
        INTO v_context_text, v_context_hash, v_context_count
        FROM malu$session_context
        WHERE session_id = p_session_id;

        v_context_count := COALESCE(v_context_count, 0);
        v_full := v_full || COALESCE(E'\n\n' || v_context_text, '');

        IF v_account_id IS NULL THEN
            SELECT account_id INTO v_account_id
            FROM malu$session WHERE session_id = p_session_id;
        END IF;
    END IF;

    v_prompt_hash := encode(sha256(v_full::bytea), 'hex');

    -- Enforce max_rendered_prompt_chars against the actual rendered text.
    IF v_opts.max_rendered_prompt_chars IS NOT NULL
       AND char_length(v_full) > v_opts.max_rendered_prompt_chars THEN
        IF COALESCE(v_opts.on_truncate, 'error') = 'error' THEN
            RAISE EXCEPTION
              'BIND_RENDER_TOO_LARGE: rendered prompt % chars exceeds cap %',
              char_length(v_full), v_opts.max_rendered_prompt_chars
              USING ERRCODE = 'string_data_right_truncation';
        ELSE
            RAISE NOTICE
              'BIND_TRUNCATE: rendered prompt % chars truncated to %',
              char_length(v_full), v_opts.max_rendered_prompt_chars;
            v_full := left(v_full, v_opts.max_rendered_prompt_chars);
            v_prompt_hash := encode(sha256(v_full::bytea), 'hex');
        END IF;
    END IF;

    v_template_hash := _template_hash(v_template);

    INSERT INTO malu$prompt_render
        (template_id, session_id, account_id, variables,
         rendered_prompt, prompt_hash, context_block_count, context_hash)
    VALUES
        (v_template.template_id, p_session_id, v_account_id,
         COALESCE(p_variables, '{}'::jsonb),
         v_full, v_prompt_hash, v_context_count, v_context_hash)
    RETURNING render_id INTO v_render_id;

    INSERT INTO malu$bound_prompt
        (render_id, template_id, template_hash, account_id, session_id,
         variables_raw, variables_normalized,
         rendered_system, rendered_developer, rendered_user, rendered_full,
         prompt_hash, bind_options, validation_status, validation_warnings,
         estimated_tokens)
    VALUES
        (v_render_id, v_template.template_id, v_template_hash, v_account_id, p_session_id,
         COALESCE(p_variables, '{}'::jsonb), v_normalized,
         v_channels.s_text, v_channels.d_text, v_channels.u_text, v_full,
         v_prompt_hash, v_opts, v_validation.status, v_validation.warnings,
         _estimate_tokens(v_full))
    RETURNING bound_prompt_id INTO v_bound_id;

    v_bound := ROW(
        v_bound_id,
        v_template.template_id,
        v_template.template_name,
        v_template.template_version,
        v_template_hash,
        v_normalized,
        v_channels.s_text,
        v_channels.d_text,
        v_channels.u_text,
        v_full,
        v_prompt_hash,
        v_validation.status,
        _estimate_tokens(v_full)
    )::bound_prompt;
    RETURN v_bound;
END;
$body$;

-- ---------------------------------------------------------------------
-- call: submit a bound prompt against a model alias. Returns the new
-- malu$model_request.request_id.
--
-- The function is named `call` per the R1.1-4 spec. CALL is a reserved
-- statement keyword but PG accepts `call(...)` as a function invocation;
-- the schema-qualified form `maludb_core.call(...)` is unambiguous.
-- ---------------------------------------------------------------------
CREATE FUNCTION call(
    p_bound             bound_prompt,
    p_alias_name        text,
    p_session_id        bigint  DEFAULT NULL,
    p_generation_params jsonb   DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000,
    p_account_name      text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_alias_id    bigint;
    v_account_id  bigint;
    v_render_id   bigint;
    v_request_id  bigint;
    v_bound_row   malu$bound_prompt%ROWTYPE;
BEGIN
    IF p_bound.bound_prompt_id IS NULL THEN
        RAISE EXCEPTION 'call: bound_prompt is NULL or unbound'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_bound_row
    FROM malu$bound_prompt
    WHERE bound_prompt_id = p_bound.bound_prompt_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'call: unknown bound_prompt_id %', p_bound.bound_prompt_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'no_data_found';
        END IF;
    ELSE
        v_account_id := COALESCE(v_bound_row.account_id, current_account_id());
    END IF;

    v_render_id := v_bound_row.render_id;

    INSERT INTO malu$model_request
        (session_id, prompt_render_id, alias_id, account_id,
         rendered_prompt, prompt_hash,
         generation_params, timeout_ms, status)
    VALUES
        (COALESCE(p_session_id, v_bound_row.session_id),
         v_render_id, v_alias_id, v_account_id,
         v_bound_row.rendered_full, v_bound_row.prompt_hash,
         COALESCE(p_generation_params, '{}'::jsonb),
         p_timeout_ms, 'pending')
    RETURNING request_id INTO v_request_id;

    RETURN v_request_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- RLS + grants on malu$bound_prompt. Mirrors the prompt_render policy:
-- NULL account_id = anonymous/shared; otherwise tenant-scoped.
-- ---------------------------------------------------------------------
ALTER TABLE malu$bound_prompt ENABLE ROW LEVEL SECURITY;
CREATE POLICY bound_prompt_tenant
    ON malu$bound_prompt
    USING (account_id IS NULL OR account_id = current_account_id())
    WITH CHECK (account_id IS NULL OR account_id = current_account_id());

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$bound_prompt TO
    maludb_llm_admin,
    maludb_llm_executor;
GRANT SELECT ON malu$bound_prompt TO
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_auditor;

-- ============================================================
-- Section: maludb_core--0.6.0--0.7.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.7.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.6.0 → 0.7.0
--
-- R1.1-6: Prompt approval workflow.
--
-- Adds the draft/approved/deprecated lifecycle to malu$prompt_template,
-- a minimal malu$safety_policy catalog, and promote/deprecate helpers.
-- submit_render and bind_prompt now reject non-'approved' templates;
-- render_prompt and preview_prompt still work (so authors can debug
-- drafts).
--
-- Migration choice (per session 2026-05-12): existing rows default to
-- 'approved' so R1.0 fixtures keep working. New rows also default to
-- 'approved'; operators opt into the draft workflow by setting
-- status='draft' explicitly at INSERT time or via request_review().
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.7.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$safety_policy (Tier-A catalog)
--
-- A named, declarative label attached to a prompt template. R1.1-6
-- only stores the label; enforcement (PII redaction, legal review, etc.)
-- is the responsibility of downstream code in later phases. The catalog
-- gives operators a stable surface to attach to prompts now.
-- ---------------------------------------------------------------------
CREATE TABLE malu$safety_policy (
    policy_id     bigserial PRIMARY KEY,
    policy_name   text NOT NULL UNIQUE,
    description   text,
    created_at    timestamptz NOT NULL DEFAULT now()
);

INSERT INTO malu$safety_policy (policy_name, description) VALUES
    ('open',          'No additional safety filtering beyond model defaults.'),
    ('pii_redact',    'Redact personally identifiable information from inputs and outputs.'),
    ('legal_review',  'Outputs require legal review before delivery to external parties.'),
    ('internal_only', 'Outputs may not leave the internal environment.');

GRANT SELECT ON malu$safety_policy TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_executor,
    maludb_llm_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$safety_policy TO maludb_llm_admin;

-- ---------------------------------------------------------------------
-- ALTER malu$prompt_template — lifecycle columns
-- ---------------------------------------------------------------------
ALTER TABLE malu$prompt_template
    ADD COLUMN status text NOT NULL DEFAULT 'approved'
        CHECK (status IN ('draft','approved','deprecated')),
    ADD COLUMN safety_policy_id bigint
        REFERENCES malu$safety_policy(policy_id) ON DELETE SET NULL,
    ADD COLUMN approved_at timestamptz,
    ADD COLUMN approved_by_account_id bigint
        REFERENCES malu$account(account_id) ON DELETE SET NULL,
    ADD COLUMN deprecated_at timestamptz,
    ADD COLUMN deprecation_reason text;

-- mark existing rows as approved (the default already does this for the
-- ADD COLUMN, but stamp approved_at so audit views know when the row
-- entered the approved state)
UPDATE malu$prompt_template SET approved_at = now()
WHERE status = 'approved' AND approved_at IS NULL;

CREATE INDEX malu$prompt_template_status_idx
    ON malu$prompt_template (status, template_name);

-- ---------------------------------------------------------------------
-- _resolve_template_for_lifecycle: helper used by all three transition
-- functions. Resolves by name+version (NULL version = latest by
-- template_version), returns the template_id, or raises.
-- ---------------------------------------------------------------------
CREATE FUNCTION _resolve_template_for_lifecycle(
    p_template_name    text,
    p_template_version integer
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id bigint;
BEGIN
    IF p_template_version IS NULL THEN
        SELECT template_id INTO v_id
        FROM malu$prompt_template
        WHERE template_name = p_template_name
        ORDER BY template_version DESC
        LIMIT 1;
    ELSE
        SELECT template_id INTO v_id
        FROM malu$prompt_template
        WHERE template_name = p_template_name
          AND template_version = p_template_version;
    END IF;
    IF v_id IS NULL THEN
        RAISE EXCEPTION
          'unknown prompt template: % (version %)',
          p_template_name, COALESCE(p_template_version::text, 'latest')
          USING ERRCODE = 'no_data_found';
    END IF;
    RETURN v_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- approve_prompt: draft → approved (or re-affirm approved).
-- Records approver + safety policy. Deprecated rows are NOT promotable
-- here; callers must explicitly rehab via UPDATE.
-- ---------------------------------------------------------------------
CREATE FUNCTION approve_prompt(
    p_template_name    text,
    p_template_version integer DEFAULT NULL,
    p_safety_policy    text    DEFAULT NULL,
    p_approver_account text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_template_id  bigint := _resolve_template_for_lifecycle(p_template_name, p_template_version);
    v_policy_id    bigint;
    v_approver_id  bigint;
    v_current_status text;
BEGIN
    SELECT status INTO v_current_status FROM malu$prompt_template WHERE template_id = v_template_id;
    IF v_current_status = 'deprecated' THEN
        RAISE EXCEPTION
          'PROMPT_LIFECYCLE_INVALID: cannot approve a deprecated template (%); rehab via UPDATE first',
          p_template_name
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    IF p_safety_policy IS NOT NULL THEN
        SELECT policy_id INTO v_policy_id
        FROM malu$safety_policy WHERE policy_name = p_safety_policy;
        IF v_policy_id IS NULL THEN
            RAISE EXCEPTION 'unknown safety_policy: %', p_safety_policy
                USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    IF p_approver_account IS NOT NULL THEN
        SELECT account_id INTO v_approver_id
        FROM malu$account WHERE account_name = p_approver_account;
        IF v_approver_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_approver_account
                USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    UPDATE malu$prompt_template
       SET status                 = 'approved',
           approved_at            = now(),
           approved_by_account_id = COALESCE(v_approver_id, approved_by_account_id),
           safety_policy_id       = COALESCE(v_policy_id, safety_policy_id),
           deprecated_at          = NULL,
           deprecation_reason     = NULL
     WHERE template_id = v_template_id;

    RETURN v_template_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- deprecate_prompt: approved|draft → deprecated. Optional reason.
-- ---------------------------------------------------------------------
CREATE FUNCTION deprecate_prompt(
    p_template_name    text,
    p_template_version integer DEFAULT NULL,
    p_reason           text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_template_id bigint := _resolve_template_for_lifecycle(p_template_name, p_template_version);
BEGIN
    UPDATE malu$prompt_template
       SET status             = 'deprecated',
           deprecated_at      = now(),
           deprecation_reason = p_reason
     WHERE template_id = v_template_id;
    RETURN v_template_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- request_review: approved → draft. Moves a previously-approved row
-- back to draft for further editing; clears approved_at.
-- Deprecated rows must rehab explicitly via UPDATE.
-- ---------------------------------------------------------------------
CREATE FUNCTION request_review(
    p_template_name    text,
    p_template_version integer DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_template_id    bigint := _resolve_template_for_lifecycle(p_template_name, p_template_version);
    v_current_status text;
BEGIN
    SELECT status INTO v_current_status FROM malu$prompt_template WHERE template_id = v_template_id;
    IF v_current_status = 'deprecated' THEN
        RAISE EXCEPTION
          'PROMPT_LIFECYCLE_INVALID: cannot request_review on a deprecated template (%)',
          p_template_name
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    UPDATE malu$prompt_template
       SET status                 = 'draft',
           approved_at            = NULL,
           approved_by_account_id = NULL
     WHERE template_id = v_template_id;

    RETURN v_template_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- Gate: submit_render rejects draft + deprecated templates.
--
-- bind_prompt gets the same gate (see CREATE OR REPLACE below).
-- render_prompt + preview_prompt stay open so authors can debug drafts.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION submit_render(
    p_render_id         bigint,
    p_alias_name        text,
    p_account_name      text DEFAULT NULL,
    p_generation_params jsonb DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_render        malu$prompt_render%ROWTYPE;
    v_alias_id      bigint;
    v_account_id    bigint;
    v_request_id    bigint;
    v_template_status text;
BEGIN
    SELECT * INTO v_render
    FROM malu$prompt_render WHERE render_id = p_render_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'unknown render: %', p_render_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT status INTO v_template_status
    FROM malu$prompt_template WHERE template_id = v_render.template_id;
    IF v_template_status <> 'approved' THEN
        RAISE EXCEPTION
          'PROMPT_NOT_APPROVED: render % refers to template (id %) with status %; only approved templates may be submitted',
          p_render_id, v_render.template_id, v_template_status
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'foreign_key_violation';
        END IF;
    END IF;

    INSERT INTO malu$model_request
           (alias_id, account_id, session_id, prompt_render_id,
            rendered_prompt, prompt_hash,
            generation_params, timeout_ms)
    VALUES (v_alias_id,
            COALESCE(v_account_id, v_render.account_id),
            v_render.session_id, p_render_id,
            v_render.rendered_prompt, v_render.prompt_hash,
            COALESCE(p_generation_params, '{}'::jsonb), p_timeout_ms)
    RETURNING request_id INTO v_request_id;
    RETURN v_request_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- Gate: bind_prompt rejects draft + deprecated templates.
--
-- The only change vs 0.5.0→0.6.0 is the status check inserted right
-- after the template lookup. The rest of the function is unchanged.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION bind_prompt(
    p_template_name    text,
    p_variables        jsonb              DEFAULT '{}'::jsonb,
    p_opts             malu$bind_options  DEFAULT NULL,
    p_session_id       bigint             DEFAULT NULL,
    p_template_version integer            DEFAULT NULL,
    p_account_id       bigint             DEFAULT NULL
) RETURNS bound_prompt
LANGUAGE plpgsql
AS $body$
DECLARE
    v_template          malu$prompt_template%ROWTYPE;
    v_opts              malu$bind_options := COALESCE(p_opts, _default_bind_options());
    v_validation        malu$bind_validation;
    v_normalized        jsonb;
    v_channels          record;
    v_full              text;
    v_context_text      text;
    v_context_hash      text;
    v_context_count     integer := 0;
    v_prompt_hash       text;
    v_render_id         bigint;
    v_bound_id          bigint;
    v_template_hash     text;
    v_account_id        bigint := p_account_id;
    v_bound             bound_prompt;
BEGIN
    IF p_template_version IS NULL THEN
        SELECT * INTO v_template
        FROM malu$prompt_template
        WHERE template_name = p_template_name AND enabled = true
        ORDER BY template_version DESC
        LIMIT 1;
    ELSE
        SELECT * INTO v_template
        FROM malu$prompt_template
        WHERE template_name = p_template_name
          AND template_version = p_template_version;
    END IF;
    IF v_template.template_id IS NULL THEN
        RAISE EXCEPTION
          'unknown prompt template: % (version %)',
          p_template_name, COALESCE(p_template_version::text, 'latest')
          USING ERRCODE = 'no_data_found';
    END IF;

    IF v_template.status <> 'approved' THEN
        RAISE EXCEPTION
          'PROMPT_NOT_APPROVED: template % (version %) has status %; only approved templates may be bound',
          v_template.template_name, v_template.template_version, v_template.status
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    v_validation := _validate_bind_variables(
        v_template.template_id, p_variables, v_opts);
    v_normalized := v_validation.normalized_variables;

    v_channels := _render_channels(v_template, v_normalized);
    v_full     := v_channels.full_text;

    IF p_session_id IS NOT NULL THEN
        PERFORM 1 FROM malu$session WHERE session_id = p_session_id;
        IF NOT FOUND THEN
            RAISE EXCEPTION 'unknown session: %', p_session_id
                USING ERRCODE = 'no_data_found';
        END IF;

        SELECT
            string_agg(
                COALESCE(role, '') || ': ' ||
                COALESCE(content_text, content_jsonb::text),
                E'\n'
                ORDER BY ordinal
            ),
            encode(sha256(string_agg(content_hash, '|' ORDER BY ordinal)::bytea), 'hex'),
            count(*)::integer
        INTO v_context_text, v_context_hash, v_context_count
        FROM malu$session_context
        WHERE session_id = p_session_id;

        v_context_count := COALESCE(v_context_count, 0);
        v_full := v_full || COALESCE(E'\n\n' || v_context_text, '');

        IF v_account_id IS NULL THEN
            SELECT account_id INTO v_account_id
            FROM malu$session WHERE session_id = p_session_id;
        END IF;
    END IF;

    v_prompt_hash := encode(sha256(v_full::bytea), 'hex');

    IF v_opts.max_rendered_prompt_chars IS NOT NULL
       AND char_length(v_full) > v_opts.max_rendered_prompt_chars THEN
        IF COALESCE(v_opts.on_truncate, 'error') = 'error' THEN
            RAISE EXCEPTION
              'BIND_RENDER_TOO_LARGE: rendered prompt % chars exceeds cap %',
              char_length(v_full), v_opts.max_rendered_prompt_chars
              USING ERRCODE = 'string_data_right_truncation';
        ELSE
            RAISE NOTICE
              'BIND_TRUNCATE: rendered prompt % chars truncated to %',
              char_length(v_full), v_opts.max_rendered_prompt_chars;
            v_full := left(v_full, v_opts.max_rendered_prompt_chars);
            v_prompt_hash := encode(sha256(v_full::bytea), 'hex');
        END IF;
    END IF;

    v_template_hash := _template_hash(v_template);

    INSERT INTO malu$prompt_render
        (template_id, session_id, account_id, variables,
         rendered_prompt, prompt_hash, context_block_count, context_hash)
    VALUES
        (v_template.template_id, p_session_id, v_account_id,
         COALESCE(p_variables, '{}'::jsonb),
         v_full, v_prompt_hash, v_context_count, v_context_hash)
    RETURNING render_id INTO v_render_id;

    INSERT INTO malu$bound_prompt
        (render_id, template_id, template_hash, account_id, session_id,
         variables_raw, variables_normalized,
         rendered_system, rendered_developer, rendered_user, rendered_full,
         prompt_hash, bind_options, validation_status, validation_warnings,
         estimated_tokens)
    VALUES
        (v_render_id, v_template.template_id, v_template_hash, v_account_id, p_session_id,
         COALESCE(p_variables, '{}'::jsonb), v_normalized,
         v_channels.s_text, v_channels.d_text, v_channels.u_text, v_full,
         v_prompt_hash, v_opts, v_validation.status, v_validation.warnings,
         _estimate_tokens(v_full))
    RETURNING bound_prompt_id INTO v_bound_id;

    v_bound := ROW(
        v_bound_id,
        v_template.template_id,
        v_template.template_name,
        v_template.template_version,
        v_template_hash,
        v_normalized,
        v_channels.s_text,
        v_channels.d_text,
        v_channels.u_text,
        v_full,
        v_prompt_hash,
        v_validation.status,
        _estimate_tokens(v_full)
    )::bound_prompt;
    RETURN v_bound;
END;
$body$;

-- ---------------------------------------------------------------------
-- Grants: prompt_approver gets EXECUTE on the workflow helpers.
-- prompt_author keeps EXECUTE on request_review (they're the ones who
-- author drafts and request review). deprecate_prompt is open to both
-- author and approver — either can pull a bad prompt out of service.
-- ---------------------------------------------------------------------
GRANT EXECUTE ON FUNCTION approve_prompt(text, integer, text, text) TO
    maludb_llm_admin,
    maludb_llm_prompt_approver;
GRANT EXECUTE ON FUNCTION deprecate_prompt(text, integer, text) TO
    maludb_llm_admin,
    maludb_llm_prompt_approver,
    maludb_llm_prompt_author;
GRANT EXECUTE ON FUNCTION request_review(text, integer) TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver;

-- ============================================================
-- Section: maludb_core--0.7.0--0.8.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.8.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.7.0 → 0.8.0
--
-- R1.1-11: Convenience response accessors.
--
-- Pure SQL helpers on malu$model_response. Each accessor has two
-- overloads:
--
--   accessor(r malu$model_response)  — pure function, IMMUTABLE
--   accessor(p_request_id bigint)    — looks up response by request_id,
--                                      STABLE (reads malu$model_response)
--
-- response_cost() returns NULL until R1.1-9 wires per-alias pricing
-- columns. The accessor is provided now so application code can adopt
-- the surface and start benefiting once R1.1-9 lands without churn.
--
-- No schema change.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.8.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$response_tokens
--
-- Composite returned by response_tokens(). total is the sum when both
-- input and output token counts are recorded, NULL otherwise (so the
-- caller can distinguish "we don't know" from "0 tokens").
-- ---------------------------------------------------------------------
CREATE TYPE malu$response_tokens AS (
    prompt      integer,
    completion  integer,
    total       integer
);

-- ---------------------------------------------------------------------
-- response_text
--
-- Returns the recorded text output. Returns NULL when:
--   * response is missing
--   * response succeeded but adapter wrote only output_json (rare in R1.0)
--   * response failed (use response_error to inspect)
-- ---------------------------------------------------------------------
CREATE FUNCTION response_text(r malu$model_response) RETURNS text
LANGUAGE sql IMMUTABLE
AS $body$ SELECT r.output_text $body$;

CREATE FUNCTION response_text(p_request_id bigint) RETURNS text
LANGUAGE sql STABLE
AS $body$
    SELECT output_text FROM malu$model_response WHERE request_id = p_request_id;
$body$;

-- ---------------------------------------------------------------------
-- response_json
--
-- Returns the recorded structured output. Preference order:
--   1. output_json (already parsed)
--   2. output_text parsed as JSON (if it parses)
--   3. NULL
-- ---------------------------------------------------------------------
CREATE FUNCTION response_json(r malu$model_response) RETURNS jsonb
LANGUAGE plpgsql IMMUTABLE
AS $body$
DECLARE
    v jsonb;
BEGIN
    IF r.output_json IS NOT NULL THEN
        RETURN r.output_json;
    END IF;
    IF r.output_text IS NULL THEN
        RETURN NULL;
    END IF;
    BEGIN
        v := r.output_text::jsonb;
        RETURN v;
    EXCEPTION WHEN invalid_text_representation OR datatype_mismatch THEN
        RETURN NULL;
    END;
END;
$body$;

CREATE FUNCTION response_json(p_request_id bigint) RETURNS jsonb
LANGUAGE sql STABLE
AS $body$
    SELECT response_json(r) FROM malu$model_response r WHERE r.request_id = p_request_id;
$body$;

-- ---------------------------------------------------------------------
-- response_tokens
--
-- Composite of (prompt, completion, total). Any NULL inputs propagate
-- into a NULL `total`.
-- ---------------------------------------------------------------------
CREATE FUNCTION response_tokens(r malu$model_response) RETURNS malu$response_tokens
LANGUAGE sql IMMUTABLE
AS $body$
    SELECT ROW(
        r.prompt_tokens,
        r.completion_tokens,
        CASE
            WHEN r.prompt_tokens IS NULL OR r.completion_tokens IS NULL THEN NULL
            ELSE r.prompt_tokens + r.completion_tokens
        END
    )::malu$response_tokens;
$body$;

CREATE FUNCTION response_tokens(p_request_id bigint) RETURNS malu$response_tokens
LANGUAGE sql STABLE
AS $body$
    SELECT response_tokens(r) FROM malu$model_response r WHERE r.request_id = p_request_id;
$body$;

-- ---------------------------------------------------------------------
-- response_cost
--
-- Returns the run-time cost in currency-neutral units. Always NULL
-- until R1.1-9 adds pricing columns to malu$model_alias. Provided now
-- so application code can adopt the API stable surface.
-- ---------------------------------------------------------------------
CREATE FUNCTION response_cost(r malu$model_response) RETURNS numeric
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$ SELECT NULL::numeric $body$;

CREATE FUNCTION response_cost(p_request_id bigint) RETURNS numeric
LANGUAGE sql STABLE
AS $body$
    -- Touch the table so the function still semantically depends on a
    -- recorded response (returns NULL for unknown request_id too, but
    -- callers can disambiguate via response_text() returning NULL).
    SELECT NULL::numeric FROM malu$model_response WHERE request_id = p_request_id;
$body$;

-- ---------------------------------------------------------------------
-- response_error
--
-- Returns the user-safe error message. Preference order:
--   1. user_safe_error (curated)
--   2. error_class (uncurated, may be technical)
--   3. NULL when the response succeeded
-- ---------------------------------------------------------------------
CREATE FUNCTION response_error(r malu$model_response) RETURNS text
LANGUAGE sql IMMUTABLE
AS $body$
    SELECT CASE
        WHEN r.status = 'succeeded' THEN NULL
        ELSE COALESCE(r.user_safe_error, r.error_class)
    END;
$body$;

CREATE FUNCTION response_error(p_request_id bigint) RETURNS text
LANGUAGE sql STABLE
AS $body$
    SELECT response_error(r) FROM malu$model_response r WHERE r.request_id = p_request_id;
$body$;

-- ---------------------------------------------------------------------
-- Grants. All accessors are read-only; expose to every LLM role that
-- already has SELECT on malu$model_response.
-- ---------------------------------------------------------------------
GRANT EXECUTE ON FUNCTION response_text(malu$model_response),
                       response_text(bigint),
                       response_json(malu$model_response),
                       response_json(bigint),
                       response_tokens(malu$model_response),
                       response_tokens(bigint),
                       response_cost(malu$model_response),
                       response_cost(bigint),
                       response_error(malu$model_response),
                       response_error(bigint)
TO maludb_llm_admin,
   maludb_llm_prompt_author,
   maludb_llm_prompt_approver,
   maludb_llm_model_admin,
   maludb_llm_executor,
   maludb_llm_auditor;

-- ============================================================
-- Section: maludb_core--0.8.0--0.9.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.9.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.8.0 → 0.9.0
--
-- R1.1-8: Response caching.
--
-- Adds cache_key + cache_mode on malu$model_request and cache_hit +
-- cached_from_request_id on malu$model_response. Cache scope is
-- per-account (chosen 2026-05-12): cache_key embeds the resolved
-- account_id so tenants never serve each other's cached responses.
--
-- Cache modes:
--   off       — default. No cache lookup, no cache_key recorded.
--   prefer    — lookup first; serve hit synchronously, else execute
--               normally and record cache_key for future hits.
--   required  — lookup; serve hit, else raise CACHE_MISS_REQUIRED.
--   refresh   — skip lookup; always execute; record cache_key.
--
-- Cache key = sha256(account || template_id || alias_id ||
--                    prompt_hash || sha256(generation_params)).
-- generation_params normalisation is the legacy jsonb::text — same
-- params text always hashes the same way.
--
-- Cache hit produces a NEW malu$model_request (audit) + a NEW
-- malu$model_response with cache_hit=true, cached_from_request_id
-- pointing at the original, and prompt_tokens/completion_tokens=0
-- (so R1.1-9 budget accounting will skip cache rows).
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.9.0'::text $body$;

-- ---------------------------------------------------------------------
-- Schema additions
-- ---------------------------------------------------------------------
ALTER TABLE malu$model_request
    ADD COLUMN cache_key  text,
    ADD COLUMN cache_mode text NOT NULL DEFAULT 'off'
        CHECK (cache_mode IN ('off','prefer','required','refresh'));

CREATE INDEX malu$model_request_cache_key_idx
    ON malu$model_request (cache_key, submitted_at DESC)
    WHERE cache_key IS NOT NULL;

ALTER TABLE malu$model_response
    ADD COLUMN cache_hit              boolean NOT NULL DEFAULT false,
    ADD COLUMN cached_from_request_id bigint
        REFERENCES malu$model_request(request_id) ON DELETE SET NULL;

CREATE INDEX malu$model_response_cache_hit_idx
    ON malu$model_response (cache_hit) WHERE cache_hit = true;

-- ---------------------------------------------------------------------
-- _compute_cache_key
--
-- Stable, per-account cache key. account_id NULL → 'anon' so anonymous
-- callers share a separate, narrower cache slot rather than colliding
-- with any real tenant.
-- ---------------------------------------------------------------------
CREATE FUNCTION _compute_cache_key(
    p_account_id       bigint,
    p_template_id      bigint,
    p_alias_id         bigint,
    p_prompt_hash      text,
    p_generation_params jsonb
) RETURNS text
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT encode(sha256(
        (
            COALESCE(p_account_id::text, 'anon') || '|' ||
            p_template_id::text || '|' ||
            p_alias_id::text   || '|' ||
            COALESCE(p_prompt_hash, '') || '|' ||
            encode(sha256(
                COALESCE(p_generation_params, '{}'::jsonb)::text::bytea
            ), 'hex')
        )::bytea
    ), 'hex');
$body$;

-- ---------------------------------------------------------------------
-- _lookup_cache
--
-- Returns the request_id of the most recent successful, non-cached
-- response matching cache_key. NULL means cache miss.
-- ---------------------------------------------------------------------
CREATE FUNCTION _lookup_cache(p_cache_key text) RETURNS bigint
LANGUAGE sql STABLE
AS $body$
    SELECT mr.request_id
    FROM malu$model_request mr
    JOIN malu$model_response resp ON resp.request_id = mr.request_id
    WHERE mr.cache_key = p_cache_key
      AND resp.cache_hit = false
      AND resp.status    = 'succeeded'
    ORDER BY mr.submitted_at DESC
    LIMIT 1;
$body$;

-- ---------------------------------------------------------------------
-- _apply_cache_hit
--
-- Given the new request_id and the cached original's request_id, copy
-- the original's response into a new response row with cache_hit=true,
-- token counts zeroed, and set the new request to 'succeeded'.
-- Returns the new response_id.
-- ---------------------------------------------------------------------
CREATE FUNCTION _apply_cache_hit(
    p_new_request_id      bigint,
    p_original_request_id bigint
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_orig       malu$model_response%ROWTYPE;
    v_new_resp_id bigint;
BEGIN
    SELECT * INTO v_orig
    FROM malu$model_response WHERE request_id = p_original_request_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'cache hit pointed at request % but no response found',
            p_original_request_id
            USING ERRCODE = 'no_data_found';
    END IF;

    INSERT INTO malu$model_response (
        request_id, status, output_text, output_hash, output_json, tool_calls,
        finish_reason, raw_provider_response,
        prompt_tokens, completion_tokens, latency_ms,
        error_class, user_safe_error, adapter_name,
        cache_hit, cached_from_request_id
    ) VALUES (
        p_new_request_id, 'succeeded', v_orig.output_text, v_orig.output_hash,
        v_orig.output_json, v_orig.tool_calls,
        v_orig.finish_reason, v_orig.raw_provider_response,
        0, 0, 0,  -- cache hits don't consume tokens or model time
        NULL, NULL,
        v_orig.adapter_name,
        true, p_original_request_id
    ) RETURNING response_id INTO v_new_resp_id;

    UPDATE malu$model_request
       SET status      = 'succeeded',
           started_at  = now(),
           finished_at = now()
     WHERE request_id = p_new_request_id;

    RETURN v_new_resp_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- submit_render (cache-aware)
--
-- New optional p_cache_mode parameter. Default 'off' preserves R1.0/R1.1
-- behavior exactly. Modes 'prefer' and 'required' look up cache; mode
-- 'refresh' records cache_key but skips lookup.
--
-- Adding p_cache_mode changes the function's identity (PG matches on
-- argument types, not names), so CREATE OR REPLACE would produce a new
-- overload instead of replacing the prior 5-arg version. Drop the
-- old signature first.
-- ---------------------------------------------------------------------
DROP FUNCTION submit_render(bigint, text, text, jsonb, integer);

CREATE FUNCTION submit_render(
    p_render_id         bigint,
    p_alias_name        text,
    p_account_name      text DEFAULT NULL,
    p_generation_params jsonb DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000,
    p_cache_mode        text DEFAULT 'off'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_render          malu$prompt_render%ROWTYPE;
    v_alias_id        bigint;
    v_account_id      bigint;
    v_request_id      bigint;
    v_template_status text;
    v_cache_key       text;
    v_orig_request_id bigint;
BEGIN
    IF p_cache_mode NOT IN ('off','prefer','required','refresh') THEN
        RAISE EXCEPTION 'CACHE_BAD_MODE: %', p_cache_mode
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_render
    FROM malu$prompt_render WHERE render_id = p_render_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'unknown render: %', p_render_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT status INTO v_template_status
    FROM malu$prompt_template WHERE template_id = v_render.template_id;
    IF v_template_status <> 'approved' THEN
        RAISE EXCEPTION
          'PROMPT_NOT_APPROVED: render % refers to template (id %) with status %; only approved templates may be submitted',
          p_render_id, v_render.template_id, v_template_status
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'foreign_key_violation';
        END IF;
    END IF;
    v_account_id := COALESCE(v_account_id, v_render.account_id);

    IF p_cache_mode <> 'off' THEN
        v_cache_key := _compute_cache_key(
            v_account_id, v_render.template_id, v_alias_id,
            v_render.prompt_hash, COALESCE(p_generation_params, '{}'::jsonb));
    END IF;

    IF p_cache_mode IN ('prefer','required') THEN
        v_orig_request_id := _lookup_cache(v_cache_key);
        IF v_orig_request_id IS NULL AND p_cache_mode = 'required' THEN
            RAISE EXCEPTION
              'CACHE_MISS_REQUIRED: no cached response for key % (template=%, alias=%)',
              v_cache_key, v_render.template_id, v_alias_id
              USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    INSERT INTO malu$model_request
           (alias_id, account_id, session_id, prompt_render_id,
            rendered_prompt, prompt_hash,
            generation_params, timeout_ms,
            cache_key, cache_mode,
            status)
    VALUES (v_alias_id,
            v_account_id,
            v_render.session_id, p_render_id,
            v_render.rendered_prompt, v_render.prompt_hash,
            COALESCE(p_generation_params, '{}'::jsonb), p_timeout_ms,
            v_cache_key, p_cache_mode,
            CASE WHEN v_orig_request_id IS NOT NULL THEN 'pending' ELSE 'pending' END)
    RETURNING request_id INTO v_request_id;

    IF v_orig_request_id IS NOT NULL THEN
        PERFORM _apply_cache_hit(v_request_id, v_orig_request_id);
    END IF;

    RETURN v_request_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- call (cache-aware) — bound_prompt path
--
-- Same surface as 0.5.0→0.6.0 plus p_cache_mode. The cache key uses
-- the bound prompt's account_id when p_account_name isn't supplied,
-- preserving tenant isolation. As with submit_render above, drop the
-- old 6-arg signature so the new 7-arg form replaces it cleanly.
-- ---------------------------------------------------------------------
DROP FUNCTION call(bound_prompt, text, bigint, jsonb, integer, text);

CREATE FUNCTION call(
    p_bound             bound_prompt,
    p_alias_name        text,
    p_session_id        bigint  DEFAULT NULL,
    p_generation_params jsonb   DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000,
    p_account_name      text    DEFAULT NULL,
    p_cache_mode        text    DEFAULT 'off'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_alias_id        bigint;
    v_account_id      bigint;
    v_request_id      bigint;
    v_bound_row       malu$bound_prompt%ROWTYPE;
    v_cache_key       text;
    v_orig_request_id bigint;
BEGIN
    IF p_cache_mode NOT IN ('off','prefer','required','refresh') THEN
        RAISE EXCEPTION 'CACHE_BAD_MODE: %', p_cache_mode
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    IF p_bound.bound_prompt_id IS NULL THEN
        RAISE EXCEPTION 'call: bound_prompt is NULL or unbound'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_bound_row
    FROM malu$bound_prompt
    WHERE bound_prompt_id = p_bound.bound_prompt_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'call: unknown bound_prompt_id %', p_bound.bound_prompt_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'no_data_found';
        END IF;
    ELSE
        v_account_id := COALESCE(v_bound_row.account_id, current_account_id());
    END IF;

    IF p_cache_mode <> 'off' THEN
        v_cache_key := _compute_cache_key(
            v_account_id, v_bound_row.template_id, v_alias_id,
            v_bound_row.prompt_hash, COALESCE(p_generation_params, '{}'::jsonb));
    END IF;

    IF p_cache_mode IN ('prefer','required') THEN
        v_orig_request_id := _lookup_cache(v_cache_key);
        IF v_orig_request_id IS NULL AND p_cache_mode = 'required' THEN
            RAISE EXCEPTION
              'CACHE_MISS_REQUIRED: no cached response for key % (template=%, alias=%)',
              v_cache_key, v_bound_row.template_id, v_alias_id
              USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    INSERT INTO malu$model_request
        (session_id, prompt_render_id, alias_id, account_id,
         rendered_prompt, prompt_hash,
         generation_params, timeout_ms,
         cache_key, cache_mode, status)
    VALUES
        (COALESCE(p_session_id, v_bound_row.session_id),
         v_bound_row.render_id, v_alias_id, v_account_id,
         v_bound_row.rendered_full, v_bound_row.prompt_hash,
         COALESCE(p_generation_params, '{}'::jsonb),
         p_timeout_ms,
         v_cache_key, p_cache_mode, 'pending')
    RETURNING request_id INTO v_request_id;

    IF v_orig_request_id IS NOT NULL THEN
        PERFORM _apply_cache_hit(v_request_id, v_orig_request_id);
    END IF;

    RETURN v_request_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- Grants: cache helpers are read by every LLM role that already reads
-- malu$model_request / _response. EXECUTE on the new function overload
-- is implicitly granted PUBLIC by CREATE OR REPLACE, but we make it
-- explicit for the helpers for symmetry with the prior phases.
-- ---------------------------------------------------------------------
GRANT EXECUTE ON FUNCTION _compute_cache_key(bigint, bigint, bigint, text, jsonb),
                          _lookup_cache(text)
TO maludb_llm_admin,
   maludb_llm_prompt_author,
   maludb_llm_prompt_approver,
   maludb_llm_model_admin,
   maludb_llm_executor,
   maludb_llm_auditor;

GRANT EXECUTE ON FUNCTION _apply_cache_hit(bigint, bigint)
TO maludb_llm_admin,
   maludb_llm_executor;

-- ============================================================
-- Section: maludb_core--0.9.0--0.10.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.10.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.9.0 → 0.10.0
--
-- R1.1-10: Idempotency + retry framework.
--
-- Adds:
--   * malu$model_request.idempotency_key (Stripe-style; second submit
--     with same key returns the prior request_id, regardless of its
--     status)
--   * malu$retry_policy (per-provider backoff metadata; the
--     maludb_modeld daemon consumes this in a follow-up phase)
--   * malu$model_request.attempt_count + last_retry_error (counters
--     bumped by the daemon when it retries)
--   * submit_render / call gain p_idempotency_key
--
-- Idempotency key scope is per-account (matches cache scope choice
-- from R1.1-8 / 2026-05-12 decisions). UNIQUE partial index on
-- (account_id, idempotency_key) WHERE idempotency_key IS NOT NULL.
--
-- Retry policy storage only; the daemon's retry executor is the
-- consumer and is not part of this phase. get_retry_policy(provider)
-- returns the provider-specific policy when present, else the row
-- with provider_id IS NULL (the "default" row).
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.10.0'::text $body$;

-- ---------------------------------------------------------------------
-- Schema additions on malu$model_request
-- ---------------------------------------------------------------------
ALTER TABLE malu$model_request
    ADD COLUMN idempotency_key text,
    ADD COLUMN attempt_count   integer NOT NULL DEFAULT 1
        CHECK (attempt_count >= 1),
    ADD COLUMN last_retry_error text;

CREATE UNIQUE INDEX malu$model_request_idempotency_idx
    ON malu$model_request (account_id, idempotency_key)
    WHERE idempotency_key IS NOT NULL;

-- ---------------------------------------------------------------------
-- malu$retry_policy
--
-- One row per provider plus an optional "default" row (provider_id
-- IS NULL) that applies when no provider-specific policy exists.
-- ---------------------------------------------------------------------
CREATE TABLE malu$retry_policy (
    policy_id           bigserial PRIMARY KEY,
    provider_id         bigint
        REFERENCES malu$model_provider(provider_id) ON DELETE CASCADE,
    max_attempts        integer NOT NULL DEFAULT 3
        CHECK (max_attempts >= 1 AND max_attempts <= 10),
    backoff_initial_ms  integer NOT NULL DEFAULT 1000
        CHECK (backoff_initial_ms >= 0),
    backoff_multiplier  numeric(4,2) NOT NULL DEFAULT 2.0
        CHECK (backoff_multiplier >= 1.0),
    max_backoff_ms      integer NOT NULL DEFAULT 60000
        CHECK (max_backoff_ms >= 0),
    retry_on            text[] NOT NULL DEFAULT ARRAY['timeout','rate_limit','transient'],
    enabled             boolean NOT NULL DEFAULT true,
    created_at          timestamptz NOT NULL DEFAULT now()
);

CREATE UNIQUE INDEX malu$retry_policy_provider_idx
    ON malu$retry_policy (COALESCE(provider_id, 0));

INSERT INTO malu$retry_policy (provider_id, max_attempts, backoff_initial_ms,
                               backoff_multiplier, max_backoff_ms, retry_on)
VALUES (NULL, 3, 1000, 2.0, 60000,
        ARRAY['timeout','rate_limit','transient']);

GRANT SELECT ON malu$retry_policy TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_executor,
    maludb_llm_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$retry_policy TO
    maludb_llm_admin,
    maludb_llm_model_admin;

-- ---------------------------------------------------------------------
-- get_retry_policy: return the policy for a provider, falling back to
-- the default row when no provider-specific policy is configured.
-- ---------------------------------------------------------------------
CREATE FUNCTION get_retry_policy(p_provider_id bigint) RETURNS malu$retry_policy
LANGUAGE sql STABLE
AS $body$
    SELECT *
    FROM malu$retry_policy
    WHERE enabled = true
      AND (provider_id = p_provider_id OR provider_id IS NULL)
    ORDER BY (provider_id IS NULL) ASC  -- prefer specific, fall back to default
    LIMIT 1;
$body$;

-- ---------------------------------------------------------------------
-- _lookup_idempotent_request: returns existing request_id when the
-- (account_id, idempotency_key) pair already exists. NULL otherwise.
-- ---------------------------------------------------------------------
CREATE FUNCTION _lookup_idempotent_request(
    p_account_id      bigint,
    p_idempotency_key text
) RETURNS bigint
LANGUAGE sql STABLE
AS $body$
    SELECT request_id
    FROM malu$model_request
    WHERE idempotency_key = p_idempotency_key
      AND (account_id = p_account_id
           OR (account_id IS NULL AND p_account_id IS NULL))
    ORDER BY submitted_at ASC
    LIMIT 1;
$body$;

-- ---------------------------------------------------------------------
-- submit_render (idempotency-aware)
--
-- Adds p_idempotency_key. When set, the function first looks for a
-- prior request with the same (account, key). If found, returns that
-- request_id without creating a new row — Stripe-style idempotency.
-- The cache lookup runs only when no idempotent match exists.
-- ---------------------------------------------------------------------
DROP FUNCTION submit_render(bigint, text, text, jsonb, integer, text);

CREATE FUNCTION submit_render(
    p_render_id         bigint,
    p_alias_name        text,
    p_account_name      text    DEFAULT NULL,
    p_generation_params jsonb   DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000,
    p_cache_mode        text    DEFAULT 'off',
    p_idempotency_key   text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_render          malu$prompt_render%ROWTYPE;
    v_alias_id        bigint;
    v_account_id      bigint;
    v_request_id      bigint;
    v_template_status text;
    v_cache_key       text;
    v_orig_request_id bigint;
    v_existing        bigint;
BEGIN
    IF p_cache_mode NOT IN ('off','prefer','required','refresh') THEN
        RAISE EXCEPTION 'CACHE_BAD_MODE: %', p_cache_mode
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_render
    FROM malu$prompt_render WHERE render_id = p_render_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'unknown render: %', p_render_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT status INTO v_template_status
    FROM malu$prompt_template WHERE template_id = v_render.template_id;
    IF v_template_status <> 'approved' THEN
        RAISE EXCEPTION
          'PROMPT_NOT_APPROVED: render % refers to template (id %) with status %; only approved templates may be submitted',
          p_render_id, v_render.template_id, v_template_status
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'foreign_key_violation';
        END IF;
    END IF;
    v_account_id := COALESCE(v_account_id, v_render.account_id);

    -- Idempotency wins over cache: if a prior request with the same
    -- (account, key) exists, return it.
    IF p_idempotency_key IS NOT NULL THEN
        v_existing := _lookup_idempotent_request(v_account_id, p_idempotency_key);
        IF v_existing IS NOT NULL THEN
            RETURN v_existing;
        END IF;
    END IF;

    IF p_cache_mode <> 'off' THEN
        v_cache_key := _compute_cache_key(
            v_account_id, v_render.template_id, v_alias_id,
            v_render.prompt_hash, COALESCE(p_generation_params, '{}'::jsonb));
    END IF;

    IF p_cache_mode IN ('prefer','required') THEN
        v_orig_request_id := _lookup_cache(v_cache_key);
        IF v_orig_request_id IS NULL AND p_cache_mode = 'required' THEN
            RAISE EXCEPTION
              'CACHE_MISS_REQUIRED: no cached response for key % (template=%, alias=%)',
              v_cache_key, v_render.template_id, v_alias_id
              USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    INSERT INTO malu$model_request
           (alias_id, account_id, session_id, prompt_render_id,
            rendered_prompt, prompt_hash,
            generation_params, timeout_ms,
            cache_key, cache_mode,
            idempotency_key,
            status)
    VALUES (v_alias_id,
            v_account_id,
            v_render.session_id, p_render_id,
            v_render.rendered_prompt, v_render.prompt_hash,
            COALESCE(p_generation_params, '{}'::jsonb), p_timeout_ms,
            v_cache_key, p_cache_mode,
            p_idempotency_key,
            'pending')
    RETURNING request_id INTO v_request_id;

    IF v_orig_request_id IS NOT NULL THEN
        PERFORM _apply_cache_hit(v_request_id, v_orig_request_id);
    END IF;

    RETURN v_request_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- call (idempotency-aware) — bound_prompt path
-- ---------------------------------------------------------------------
DROP FUNCTION call(bound_prompt, text, bigint, jsonb, integer, text, text);

CREATE FUNCTION call(
    p_bound             bound_prompt,
    p_alias_name        text,
    p_session_id        bigint  DEFAULT NULL,
    p_generation_params jsonb   DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000,
    p_account_name      text    DEFAULT NULL,
    p_cache_mode        text    DEFAULT 'off',
    p_idempotency_key   text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_alias_id        bigint;
    v_account_id      bigint;
    v_request_id      bigint;
    v_bound_row       malu$bound_prompt%ROWTYPE;
    v_cache_key       text;
    v_orig_request_id bigint;
    v_existing        bigint;
BEGIN
    IF p_cache_mode NOT IN ('off','prefer','required','refresh') THEN
        RAISE EXCEPTION 'CACHE_BAD_MODE: %', p_cache_mode
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    IF p_bound.bound_prompt_id IS NULL THEN
        RAISE EXCEPTION 'call: bound_prompt is NULL or unbound'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_bound_row
    FROM malu$bound_prompt
    WHERE bound_prompt_id = p_bound.bound_prompt_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'call: unknown bound_prompt_id %', p_bound.bound_prompt_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'no_data_found';
        END IF;
    ELSE
        v_account_id := COALESCE(v_bound_row.account_id, current_account_id());
    END IF;

    IF p_idempotency_key IS NOT NULL THEN
        v_existing := _lookup_idempotent_request(v_account_id, p_idempotency_key);
        IF v_existing IS NOT NULL THEN
            RETURN v_existing;
        END IF;
    END IF;

    IF p_cache_mode <> 'off' THEN
        v_cache_key := _compute_cache_key(
            v_account_id, v_bound_row.template_id, v_alias_id,
            v_bound_row.prompt_hash, COALESCE(p_generation_params, '{}'::jsonb));
    END IF;

    IF p_cache_mode IN ('prefer','required') THEN
        v_orig_request_id := _lookup_cache(v_cache_key);
        IF v_orig_request_id IS NULL AND p_cache_mode = 'required' THEN
            RAISE EXCEPTION
              'CACHE_MISS_REQUIRED: no cached response for key % (template=%, alias=%)',
              v_cache_key, v_bound_row.template_id, v_alias_id
              USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    INSERT INTO malu$model_request
        (session_id, prompt_render_id, alias_id, account_id,
         rendered_prompt, prompt_hash,
         generation_params, timeout_ms,
         cache_key, cache_mode,
         idempotency_key,
         status)
    VALUES
        (COALESCE(p_session_id, v_bound_row.session_id),
         v_bound_row.render_id, v_alias_id, v_account_id,
         v_bound_row.rendered_full, v_bound_row.prompt_hash,
         COALESCE(p_generation_params, '{}'::jsonb),
         p_timeout_ms,
         v_cache_key, p_cache_mode,
         p_idempotency_key,
         'pending')
    RETURNING request_id INTO v_request_id;

    IF v_orig_request_id IS NOT NULL THEN
        PERFORM _apply_cache_hit(v_request_id, v_orig_request_id);
    END IF;

    RETURN v_request_id;
END;
$body$;

GRANT EXECUTE ON FUNCTION get_retry_policy(bigint),
                          _lookup_idempotent_request(bigint, text)
TO maludb_llm_admin,
   maludb_llm_prompt_author,
   maludb_llm_prompt_approver,
   maludb_llm_model_admin,
   maludb_llm_executor,
   maludb_llm_auditor;

-- ============================================================
-- Section: maludb_core--0.10.0--0.11.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.11.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.10.0 → 0.11.0
--
-- R1.1-9: Budget + quota + token accounting.
--
-- Adds:
--   * pricing columns on malu$model_alias (micro-cents per token, USD)
--   * response_cost() rewired to compute real numbers (NULL when token
--     counts or pricing aren't set; 0 for cache hits)
--   * malu$budget_policy table: scope IN (account, prompt, role, global)
--     × kind IN (tokens_daily, cost_daily, requests_daily)
--   * check_budget() raises BUDGET_EXCEEDED at submit time (hard-reject,
--     per 2026-05-12 decision)
--   * usage_today() helper for operators
--   * cost_by_account view for daily roll-ups
--
-- Currency: signed integer micro-cents (10^-6 USD) per the 2026-05-12
-- decision. Single implied currency for v1; multi-currency is a
-- follow-up.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.11.0'::text $body$;

-- ---------------------------------------------------------------------
-- Pricing columns on malu$model_alias
-- ---------------------------------------------------------------------
ALTER TABLE malu$model_alias
    ADD COLUMN price_per_input_token  bigint NOT NULL DEFAULT 0
        CHECK (price_per_input_token >= 0),
    ADD COLUMN price_per_output_token bigint NOT NULL DEFAULT 0
        CHECK (price_per_output_token >= 0);

COMMENT ON COLUMN malu$model_alias.price_per_input_token  IS
    'Input-token price in micro-cents (10^-6 USD). 0 = unpriced (response_cost will return 0 for input).';
COMMENT ON COLUMN malu$model_alias.price_per_output_token IS
    'Output-token price in micro-cents (10^-6 USD). 0 = unpriced.';

-- ---------------------------------------------------------------------
-- malu$budget_policy
--
-- Exactly one of scope_role / scope_template_id / scope_account_id is
-- non-NULL (or all NULL for scope='global'). Enforced via CHECK.
-- ---------------------------------------------------------------------
CREATE TABLE malu$budget_policy (
    policy_id          bigserial PRIMARY KEY,
    policy_name        text NOT NULL UNIQUE,
    scope              text NOT NULL
        CHECK (scope IN ('account','prompt','role','global')),
    scope_account_id   bigint REFERENCES malu$account(account_id) ON DELETE CASCADE,
    scope_template_id  bigint REFERENCES malu$prompt_template(template_id) ON DELETE CASCADE,
    scope_role         text,
    limit_kind         text NOT NULL
        CHECK (limit_kind IN ('tokens_daily','cost_daily','requests_daily')),
    limit_value        bigint NOT NULL CHECK (limit_value > 0),
    enabled            boolean NOT NULL DEFAULT true,
    created_at         timestamptz NOT NULL DEFAULT now(),
    CONSTRAINT malu$budget_policy_scope_one_of CHECK (
        CASE scope
            WHEN 'account' THEN scope_account_id IS NOT NULL AND scope_template_id IS NULL AND scope_role IS NULL
            WHEN 'prompt'  THEN scope_template_id IS NOT NULL AND scope_account_id IS NULL AND scope_role IS NULL
            WHEN 'role'    THEN scope_role IS NOT NULL AND scope_account_id IS NULL AND scope_template_id IS NULL
            WHEN 'global'  THEN scope_account_id IS NULL AND scope_template_id IS NULL AND scope_role IS NULL
        END
    )
);

CREATE INDEX malu$budget_policy_lookup_idx
    ON malu$budget_policy (scope, enabled);

GRANT SELECT ON malu$budget_policy TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_executor,
    maludb_llm_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$budget_policy TO
    maludb_llm_admin;

-- ---------------------------------------------------------------------
-- response_cost: rewired to compute from tokens × per-alias pricing.
--
--  * cache_hit row → 0 (the original is what got charged)
--  * NULL prompt_tokens or completion_tokens → NULL (don't lie)
--  * any other case → prompt*input_price + completion*output_price,
--    expressed in micro-cents
-- ---------------------------------------------------------------------
DROP FUNCTION response_cost(malu$model_response);
DROP FUNCTION response_cost(bigint);

CREATE FUNCTION response_cost(r malu$model_response) RETURNS numeric
LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    v_input_price  bigint;
    v_output_price bigint;
BEGIN
    IF r.cache_hit THEN
        RETURN 0;
    END IF;
    IF r.prompt_tokens IS NULL OR r.completion_tokens IS NULL THEN
        RETURN NULL;
    END IF;

    SELECT ma.price_per_input_token, ma.price_per_output_token
    INTO v_input_price, v_output_price
    FROM malu$model_request mr
    JOIN malu$model_alias   ma ON ma.alias_id = mr.alias_id
    WHERE mr.request_id = r.request_id;

    IF v_input_price IS NULL THEN
        RETURN NULL;
    END IF;
    RETURN (r.prompt_tokens::numeric    * v_input_price) +
           (r.completion_tokens::numeric * v_output_price);
END;
$body$;

CREATE FUNCTION response_cost(p_request_id bigint) RETURNS numeric
LANGUAGE sql STABLE
AS $body$
    SELECT response_cost(r) FROM malu$model_response r WHERE r.request_id = p_request_id;
$body$;

GRANT EXECUTE ON FUNCTION response_cost(malu$model_response),
                          response_cost(bigint)
TO maludb_llm_admin,
   maludb_llm_prompt_author,
   maludb_llm_prompt_approver,
   maludb_llm_model_admin,
   maludb_llm_executor,
   maludb_llm_auditor;

-- ---------------------------------------------------------------------
-- usage_today
--
-- Returns today's usage value for one scope row. The "today" boundary
-- is the calling session's current_date.
--
-- For cost/tokens, cache_hit responses are excluded (they were free).
-- For requests, every request counts.
-- ---------------------------------------------------------------------
CREATE FUNCTION usage_today(
    p_scope            text,
    p_scope_account_id bigint,
    p_scope_template_id bigint,
    p_scope_role       text,
    p_limit_kind       text
) RETURNS numeric
LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    v_value numeric := 0;
BEGIN
    CASE p_limit_kind
    WHEN 'requests_daily' THEN
        SELECT count(*)::numeric INTO v_value
        FROM malu$model_request mr
        LEFT JOIN malu$account a ON a.account_id = mr.account_id
        LEFT JOIN malu$account_role ar ON ar.account_id = mr.account_id
        LEFT JOIN malu$role         r  ON r.role_id     = ar.role_id
        WHERE mr.submitted_at >= date_trunc('day', now())
          AND (
              CASE p_scope
                WHEN 'account' THEN mr.account_id = p_scope_account_id
                WHEN 'prompt'  THEN EXISTS (
                    SELECT 1 FROM malu$prompt_render pr
                    WHERE pr.render_id = mr.prompt_render_id
                      AND pr.template_id = p_scope_template_id)
                WHEN 'role'    THEN r.role_name = p_scope_role
                WHEN 'global'  THEN true
              END
          );
    WHEN 'tokens_daily' THEN
        SELECT COALESCE(sum(
                    COALESCE(resp.prompt_tokens, 0) +
                    COALESCE(resp.completion_tokens, 0)
                ), 0)::numeric INTO v_value
        FROM malu$model_response resp
        JOIN malu$model_request  mr ON mr.request_id = resp.request_id
        LEFT JOIN malu$account_role ar ON ar.account_id = mr.account_id
        LEFT JOIN malu$role         r  ON r.role_id     = ar.role_id
        WHERE resp.finished_at >= date_trunc('day', now())
          AND resp.cache_hit  = false
          AND (
              CASE p_scope
                WHEN 'account' THEN mr.account_id = p_scope_account_id
                WHEN 'prompt'  THEN EXISTS (
                    SELECT 1 FROM malu$prompt_render pr
                    WHERE pr.render_id = mr.prompt_render_id
                      AND pr.template_id = p_scope_template_id)
                WHEN 'role'    THEN r.role_name = p_scope_role
                WHEN 'global'  THEN true
              END
          );
    WHEN 'cost_daily' THEN
        SELECT COALESCE(sum(response_cost(resp)), 0)::numeric INTO v_value
        FROM malu$model_response resp
        JOIN malu$model_request  mr ON mr.request_id = resp.request_id
        LEFT JOIN malu$account_role ar ON ar.account_id = mr.account_id
        LEFT JOIN malu$role         r  ON r.role_id     = ar.role_id
        WHERE resp.finished_at >= date_trunc('day', now())
          AND resp.cache_hit  = false
          AND (
              CASE p_scope
                WHEN 'account' THEN mr.account_id = p_scope_account_id
                WHEN 'prompt'  THEN EXISTS (
                    SELECT 1 FROM malu$prompt_render pr
                    WHERE pr.render_id = mr.prompt_render_id
                      AND pr.template_id = p_scope_template_id)
                WHEN 'role'    THEN r.role_name = p_scope_role
                WHEN 'global'  THEN true
              END
          );
    END CASE;

    RETURN COALESCE(v_value, 0);
END;
$body$;

GRANT EXECUTE ON FUNCTION usage_today(text, bigint, bigint, text, text)
TO maludb_llm_admin,
   maludb_llm_prompt_author,
   maludb_llm_prompt_approver,
   maludb_llm_model_admin,
   maludb_llm_executor,
   maludb_llm_auditor;

-- ---------------------------------------------------------------------
-- check_budget
--
-- Iterate over every enabled policy that applies to this submission.
-- Raise BUDGET_EXCEEDED on the first violation. Idempotent and cache
-- hits don't trigger budget checks because they don't reach this far
-- (submit_render/call return early on those paths).
-- ---------------------------------------------------------------------
CREATE FUNCTION check_budget(
    p_account_id  bigint,
    p_template_id bigint
) RETURNS void
LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    v_policy malu$budget_policy%ROWTYPE;
    v_usage  numeric;
BEGIN
    FOR v_policy IN
        SELECT * FROM malu$budget_policy
        WHERE enabled = true
          AND (
              (scope = 'account' AND scope_account_id  = p_account_id)
           OR (scope = 'prompt'  AND scope_template_id = p_template_id)
           OR (scope = 'role'    AND EXISTS (
                   SELECT 1 FROM malu$account_role ar
                   JOIN malu$role r ON r.role_id = ar.role_id
                   WHERE ar.account_id = p_account_id
                     AND r.role_name   = scope_role))
           OR (scope = 'global')
          )
        ORDER BY
            CASE scope
                WHEN 'account' THEN 1
                WHEN 'prompt'  THEN 2
                WHEN 'role'    THEN 3
                WHEN 'global'  THEN 4
            END
    LOOP
        v_usage := usage_today(v_policy.scope,
                               v_policy.scope_account_id,
                               v_policy.scope_template_id,
                               v_policy.scope_role,
                               v_policy.limit_kind);
        IF v_usage >= v_policy.limit_value THEN
            RAISE EXCEPTION
              'BUDGET_EXCEEDED: policy % (scope=%, kind=%) — today % >= limit %',
              v_policy.policy_name, v_policy.scope, v_policy.limit_kind,
              v_usage, v_policy.limit_value
              USING ERRCODE = 'insufficient_resources';
        END IF;
    END LOOP;
END;
$body$;

GRANT EXECUTE ON FUNCTION check_budget(bigint, bigint)
TO maludb_llm_admin,
   maludb_llm_executor;

-- ---------------------------------------------------------------------
-- submit_render (budget-aware)
--
-- check_budget runs BEFORE the request INSERT. Cache hits and
-- idempotent replays return early so they bypass the check, which is
-- the intended behavior (no model invocation, no cost).
-- ---------------------------------------------------------------------
DROP FUNCTION submit_render(bigint, text, text, jsonb, integer, text, text);

CREATE FUNCTION submit_render(
    p_render_id         bigint,
    p_alias_name        text,
    p_account_name      text    DEFAULT NULL,
    p_generation_params jsonb   DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000,
    p_cache_mode        text    DEFAULT 'off',
    p_idempotency_key   text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_render          malu$prompt_render%ROWTYPE;
    v_alias_id        bigint;
    v_account_id      bigint;
    v_request_id      bigint;
    v_template_status text;
    v_cache_key       text;
    v_orig_request_id bigint;
    v_existing        bigint;
BEGIN
    IF p_cache_mode NOT IN ('off','prefer','required','refresh') THEN
        RAISE EXCEPTION 'CACHE_BAD_MODE: %', p_cache_mode
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_render
    FROM malu$prompt_render WHERE render_id = p_render_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'unknown render: %', p_render_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT status INTO v_template_status
    FROM malu$prompt_template WHERE template_id = v_render.template_id;
    IF v_template_status <> 'approved' THEN
        RAISE EXCEPTION
          'PROMPT_NOT_APPROVED: render % refers to template (id %) with status %; only approved templates may be submitted',
          p_render_id, v_render.template_id, v_template_status
          USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'foreign_key_violation';
        END IF;
    END IF;
    v_account_id := COALESCE(v_account_id, v_render.account_id);

    -- Idempotency wins: skip cache + budget entirely on replay.
    IF p_idempotency_key IS NOT NULL THEN
        v_existing := _lookup_idempotent_request(v_account_id, p_idempotency_key);
        IF v_existing IS NOT NULL THEN
            RETURN v_existing;
        END IF;
    END IF;

    IF p_cache_mode <> 'off' THEN
        v_cache_key := _compute_cache_key(
            v_account_id, v_render.template_id, v_alias_id,
            v_render.prompt_hash, COALESCE(p_generation_params, '{}'::jsonb));
    END IF;

    IF p_cache_mode IN ('prefer','required') THEN
        v_orig_request_id := _lookup_cache(v_cache_key);
        IF v_orig_request_id IS NULL AND p_cache_mode = 'required' THEN
            RAISE EXCEPTION
              'CACHE_MISS_REQUIRED: no cached response for key % (template=%, alias=%)',
              v_cache_key, v_render.template_id, v_alias_id
              USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    -- Budget check: only applies when we're actually going to invoke
    -- the model (cache miss or cache off). Cache hits skip below.
    IF v_orig_request_id IS NULL THEN
        PERFORM check_budget(v_account_id, v_render.template_id);
    END IF;

    INSERT INTO malu$model_request
           (alias_id, account_id, session_id, prompt_render_id,
            rendered_prompt, prompt_hash,
            generation_params, timeout_ms,
            cache_key, cache_mode,
            idempotency_key,
            status)
    VALUES (v_alias_id,
            v_account_id,
            v_render.session_id, p_render_id,
            v_render.rendered_prompt, v_render.prompt_hash,
            COALESCE(p_generation_params, '{}'::jsonb), p_timeout_ms,
            v_cache_key, p_cache_mode,
            p_idempotency_key,
            'pending')
    RETURNING request_id INTO v_request_id;

    IF v_orig_request_id IS NOT NULL THEN
        PERFORM _apply_cache_hit(v_request_id, v_orig_request_id);
    END IF;

    RETURN v_request_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- call (budget-aware) — bound_prompt path
-- ---------------------------------------------------------------------
DROP FUNCTION call(bound_prompt, text, bigint, jsonb, integer, text, text, text);

CREATE FUNCTION call(
    p_bound             bound_prompt,
    p_alias_name        text,
    p_session_id        bigint  DEFAULT NULL,
    p_generation_params jsonb   DEFAULT '{}'::jsonb,
    p_timeout_ms        integer DEFAULT 30000,
    p_account_name      text    DEFAULT NULL,
    p_cache_mode        text    DEFAULT 'off',
    p_idempotency_key   text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_alias_id        bigint;
    v_account_id      bigint;
    v_request_id      bigint;
    v_bound_row       malu$bound_prompt%ROWTYPE;
    v_cache_key       text;
    v_orig_request_id bigint;
    v_existing        bigint;
BEGIN
    IF p_cache_mode NOT IN ('off','prefer','required','refresh') THEN
        RAISE EXCEPTION 'CACHE_BAD_MODE: %', p_cache_mode
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    IF p_bound.bound_prompt_id IS NULL THEN
        RAISE EXCEPTION 'call: bound_prompt is NULL or unbound'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_bound_row
    FROM malu$bound_prompt
    WHERE bound_prompt_id = p_bound.bound_prompt_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'call: unknown bound_prompt_id %', p_bound.bound_prompt_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT alias_id INTO v_alias_id
    FROM malu$model_alias
    WHERE alias_name = p_alias_name AND enabled = true;
    IF v_alias_id IS NULL THEN
        RAISE EXCEPTION 'unknown or disabled alias: %', p_alias_name
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_account_name IS NOT NULL THEN
        SELECT account_id INTO v_account_id
        FROM malu$account WHERE account_name = p_account_name;
        IF v_account_id IS NULL THEN
            RAISE EXCEPTION 'unknown account: %', p_account_name
                USING ERRCODE = 'no_data_found';
        END IF;
    ELSE
        v_account_id := COALESCE(v_bound_row.account_id, current_account_id());
    END IF;

    IF p_idempotency_key IS NOT NULL THEN
        v_existing := _lookup_idempotent_request(v_account_id, p_idempotency_key);
        IF v_existing IS NOT NULL THEN
            RETURN v_existing;
        END IF;
    END IF;

    IF p_cache_mode <> 'off' THEN
        v_cache_key := _compute_cache_key(
            v_account_id, v_bound_row.template_id, v_alias_id,
            v_bound_row.prompt_hash, COALESCE(p_generation_params, '{}'::jsonb));
    END IF;

    IF p_cache_mode IN ('prefer','required') THEN
        v_orig_request_id := _lookup_cache(v_cache_key);
        IF v_orig_request_id IS NULL AND p_cache_mode = 'required' THEN
            RAISE EXCEPTION
              'CACHE_MISS_REQUIRED: no cached response for key % (template=%, alias=%)',
              v_cache_key, v_bound_row.template_id, v_alias_id
              USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    IF v_orig_request_id IS NULL THEN
        PERFORM check_budget(v_account_id, v_bound_row.template_id);
    END IF;

    INSERT INTO malu$model_request
        (session_id, prompt_render_id, alias_id, account_id,
         rendered_prompt, prompt_hash,
         generation_params, timeout_ms,
         cache_key, cache_mode,
         idempotency_key,
         status)
    VALUES
        (COALESCE(p_session_id, v_bound_row.session_id),
         v_bound_row.render_id, v_alias_id, v_account_id,
         v_bound_row.rendered_full, v_bound_row.prompt_hash,
         COALESCE(p_generation_params, '{}'::jsonb),
         p_timeout_ms,
         v_cache_key, p_cache_mode,
         p_idempotency_key,
         'pending')
    RETURNING request_id INTO v_request_id;

    IF v_orig_request_id IS NOT NULL THEN
        PERFORM _apply_cache_hit(v_request_id, v_orig_request_id);
    END IF;

    RETURN v_request_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- cost_by_account view
--
-- Live view (not materialized) for v1; daily roll-up by account +
-- alias. Operators can materialize this themselves with a partial
-- index if the volume warrants.
-- ---------------------------------------------------------------------
CREATE VIEW cost_by_account AS
SELECT
    a.account_id,
    a.account_name,
    ma.alias_name,
    date_trunc('day', resp.finished_at)::date AS day,
    count(*)                                  AS request_count,
    sum(COALESCE(resp.prompt_tokens, 0))      AS input_tokens,
    sum(COALESCE(resp.completion_tokens, 0))  AS output_tokens,
    sum(response_cost(resp))                  AS cost_micro_cents
FROM malu$model_response  resp
JOIN malu$model_request   mr ON mr.request_id = resp.request_id
LEFT JOIN malu$account    a  ON a.account_id  = mr.account_id
JOIN malu$model_alias     ma ON ma.alias_id   = mr.alias_id
WHERE resp.cache_hit = false
GROUP BY a.account_id, a.account_name, ma.alias_name, date_trunc('day', resp.finished_at);

GRANT SELECT ON cost_by_account TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_auditor;

-- ============================================================
-- Section: maludb_core--0.11.0--0.12.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.12.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.11.0 → 0.12.0
--
-- R1.1-17: Custom malu_vector PG type.
--
-- Replaces BYTEA-as-vector with a real custom varlena type. Storage
-- is binary-compatible with bytea (same varlena header, same float32
-- payload), so a WITHOUT FUNCTION cast suffices in both directions
-- and the ALTER TABLE ... TYPE ... USING is a catalog-only operation
-- (no row rewrite).
--
-- Text I/O matches pgvector's vector(N) format: "[f1, f2, ...]".
-- Binary I/O is the raw float32 payload (same as bytea_send/recv on
-- the same bytes).
--
-- All R1.1-12/13/14 C entry points (maludb_vector_*, maludb_search_*)
-- already use VARSIZE_ANY_EXHDR + VARDATA_ANY, which apply to any
-- varlena type. Only the SQL declarations swap from bytea to
-- malu_vector; the C objects are unchanged.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.12.0'::text $body$;

-- ---------------------------------------------------------------------
-- I/O functions (C, defined in src/maludb_type.c). Use the shell-type
-- pattern: declare the I/O functions first with stand-in types, then
-- CREATE TYPE binds them. PostgreSQL requires this dance because the
-- IN function references the type that doesn't exist yet.
-- ---------------------------------------------------------------------
CREATE TYPE malu_vector;  -- shell

CREATE FUNCTION malu_vector_in(cstring) RETURNS malu_vector
    AS 'MODULE_PATHNAME', 'maludb_vector_in'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION malu_vector_out(malu_vector) RETURNS cstring
    AS 'MODULE_PATHNAME', 'maludb_vector_out'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION malu_vector_recv(internal) RETURNS malu_vector
    AS 'MODULE_PATHNAME', 'maludb_vector_recv'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION malu_vector_send(malu_vector) RETURNS bytea
    AS 'MODULE_PATHNAME', 'maludb_vector_send'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE TYPE malu_vector (
    INPUT          = malu_vector_in,
    OUTPUT         = malu_vector_out,
    RECEIVE        = malu_vector_recv,
    SEND           = malu_vector_send,
    INTERNALLENGTH = VARIABLE,
    STORAGE        = extended,
    ALIGNMENT      = int4
);

COMMENT ON TYPE malu_vector IS
    'R1.1-17 custom varlena vector type. Binary-compatible with bytea '
    '(WITHOUT FUNCTION cast in both directions). Text format: "[f1, f2, ...]".';

-- ---------------------------------------------------------------------
-- Binary-compatible casts. WITHOUT FUNCTION = zero-cost reinterpret.
-- Both directions are ASSIGNMENT context (not IMPLICIT) so the type
-- system doesn't auto-cast in ambiguous expressions, but explicit
-- ::malu_vector / ::bytea casts and column-type changes work.
-- ---------------------------------------------------------------------
CREATE CAST (bytea       AS malu_vector) WITHOUT FUNCTION AS ASSIGNMENT;
CREATE CAST (malu_vector AS bytea)       WITHOUT FUNCTION AS ASSIGNMENT;

-- octet_length overload — needed by the malu$vector_chunk CHECK constraint
-- that ALTER COLUMN preserves below. Delegates through the binary cast.
CREATE FUNCTION octet_length(malu_vector) RETURNS integer
    LANGUAGE sql IMMUTABLE STRICT PARALLEL SAFE
    AS $body$ SELECT octet_length($1::bytea) $body$;

-- ---------------------------------------------------------------------
-- Swap vector primitive function signatures from bytea → malu_vector.
-- We DROP+CREATE because PG matches function identity by argument
-- types; CREATE OR REPLACE with a different type creates an overload.
--
-- The C entry points (maludb_vector_dot_product, etc.) are unchanged
-- — they read varlena bytes generically.
-- ---------------------------------------------------------------------
DROP FUNCTION vector_from_real_array(real[]);
DROP FUNCTION vector_to_real_array(bytea);
DROP FUNCTION vector_dims(bytea);
DROP FUNCTION vector_norm(bytea);
DROP FUNCTION vector_dot_product(bytea, bytea);
DROP FUNCTION vector_l2_squared(bytea, bytea);
DROP FUNCTION vector_normalize(bytea);

CREATE FUNCTION vector_from_real_array(real[]) RETURNS malu_vector
    AS 'MODULE_PATHNAME', 'maludb_vector_from_real_array'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_to_real_array(malu_vector) RETURNS real[]
    AS 'MODULE_PATHNAME', 'maludb_vector_to_real_array'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_dims(malu_vector) RETURNS integer
    AS 'MODULE_PATHNAME', 'maludb_vector_dims'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_norm(malu_vector) RETURNS double precision
    AS 'MODULE_PATHNAME', 'maludb_vector_norm'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_dot_product(malu_vector, malu_vector) RETURNS double precision
    AS 'MODULE_PATHNAME', 'maludb_vector_dot_product'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_l2_squared(malu_vector, malu_vector) RETURNS double precision
    AS 'MODULE_PATHNAME', 'maludb_vector_l2_squared'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION vector_normalize(malu_vector) RETURNS malu_vector
    AS 'MODULE_PATHNAME', 'maludb_vector_normalize'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

-- ---------------------------------------------------------------------
-- PL/pgSQL distance wrappers — same DROP+CREATE dance.
-- ---------------------------------------------------------------------
DROP FUNCTION cosine_distance(bytea, bytea);
DROP FUNCTION l2_squared_distance(bytea, bytea);
DROP FUNCTION inner_product(bytea, bytea);

CREATE FUNCTION cosine_distance(a malu_vector, b malu_vector) RETURNS double precision
LANGUAGE plpgsql IMMUTABLE STRICT PARALLEL SAFE
AS $body$
DECLARE
    na double precision := vector_norm(a);
    nb double precision := vector_norm(b);
BEGIN
    IF na = 0 OR nb = 0 THEN RETURN 1.0; END IF;
    RETURN 1.0 - (vector_dot_product(a, b) / (na * nb));
END;
$body$;

CREATE FUNCTION l2_squared_distance(a malu_vector, b malu_vector) RETURNS double precision
LANGUAGE sql IMMUTABLE STRICT PARALLEL SAFE
AS $body$ SELECT vector_l2_squared(a, b) $body$;

CREATE FUNCTION inner_product(a malu_vector, b malu_vector) RETURNS double precision
LANGUAGE sql IMMUTABLE STRICT PARALLEL SAFE
AS $body$ SELECT vector_dot_product(a, b) $body$;

-- ---------------------------------------------------------------------
-- Swap the malu$vector_chunk.embedding column type to malu_vector.
-- Binary layout is identical to bytea, so the USING cast is a no-op
-- on the data side; only pg_attribute changes.
-- ---------------------------------------------------------------------
ALTER TABLE malu$vector_chunk
    ALTER COLUMN embedding TYPE malu_vector USING embedding::malu_vector;

-- octet_length still works on malu_vector via the implicit varlena
-- interpretation, so the existing CHECK constraint stays meaningful.

-- ---------------------------------------------------------------------
-- Re-declare the search functions (exact + planner + tool) with
-- malu_vector signatures. The C entry point for exact_vector_search_c
-- is unchanged.
-- ---------------------------------------------------------------------
DROP FUNCTION search_memory_exact(text, text, text, bytea, integer, text);
DROP FUNCTION exact_vector_search_sql(bigint, bytea, integer, text);
DROP FUNCTION exact_vector_search_plpgsql(bigint, bytea, integer, text);
DROP FUNCTION exact_vector_search_c(bigint, bytea, integer, text);

CREATE FUNCTION exact_vector_search_c(
    p_compartment_id bigint,
    p_query          malu_vector,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
)
AS 'MODULE_PATHNAME', 'maludb_exact_vector_search_c'
LANGUAGE C STABLE PARALLEL SAFE;

CREATE FUNCTION exact_vector_search_sql(
    p_compartment_id bigint,
    p_query          malu_vector,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_compart malu$vector_compartment%ROWTYPE;
    v_metric  text;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF vector_dims(p_query) <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'query dim % does not match compartment dim %',
            vector_dims(p_query), v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_metric := COALESCE(p_metric, v_compart.distance_metric);
    RETURN QUERY
        SELECT * FROM exact_vector_search_c(
            p_compartment_id, vector_normalize(p_query), p_limit, v_metric);
END;
$body$;

CREATE FUNCTION exact_vector_search_plpgsql(
    p_compartment_id bigint,
    p_query          malu_vector,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_metric  text;
    v_compart malu$vector_compartment%ROWTYPE;
    v_query   malu_vector;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF vector_dims(p_query) <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'query dim % does not match compartment dim %',
            vector_dims(p_query), v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_metric := COALESCE(p_metric, v_compart.distance_metric);
    v_query  := vector_normalize(p_query);

    IF v_metric = 'cosine' THEN
        RETURN QUERY
            SELECT c.chunk_id, c.source_text,
                   1.0 - vector_dot_product(c.embedding, v_query) AS distance,
                         vector_dot_product(c.embedding, v_query) AS similarity,
                   ROW_NUMBER() OVER (
                       ORDER BY vector_dot_product(c.embedding, v_query) DESC
                   )::integer AS rank_no
              FROM malu$vector_chunk c
             WHERE c.compartment_id = p_compartment_id
             ORDER BY similarity DESC
             LIMIT p_limit;
    ELSIF v_metric = 'l2' THEN
        RETURN QUERY
            SELECT c.chunk_id, c.source_text,
                   vector_l2_squared(c.embedding, p_query)        AS distance,
                   -vector_l2_squared(c.embedding, p_query)       AS similarity,
                   ROW_NUMBER() OVER (
                       ORDER BY vector_l2_squared(c.embedding, p_query) ASC
                   )::integer AS rank_no
              FROM malu$vector_chunk c
             WHERE c.compartment_id = p_compartment_id
             ORDER BY distance ASC
             LIMIT p_limit;
    ELSIF v_metric = 'inner_product' THEN
        RETURN QUERY
            SELECT c.chunk_id, c.source_text,
                   -vector_dot_product(c.embedding, p_query)      AS distance,
                    vector_dot_product(c.embedding, p_query)      AS similarity,
                   ROW_NUMBER() OVER (
                       ORDER BY vector_dot_product(c.embedding, p_query) DESC
                   )::integer AS rank_no
              FROM malu$vector_chunk c
             WHERE c.compartment_id = p_compartment_id
             ORDER BY similarity DESC
             LIMIT p_limit;
    ELSE
        RAISE EXCEPTION 'unknown distance metric: %', v_metric
            USING ERRCODE = 'check_violation';
    END IF;
END;
$body$;

CREATE FUNCTION search_memory_exact(
    p_namespace      text,
    p_subject        text,
    p_verb           text,
    p_query          malu_vector,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id        bigint,
    source_text     text,
    distance        double precision,
    similarity      double precision,
    rank_no         integer,
    compartment_id  bigint
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_compartment_id bigint;
BEGIN
    SELECT c.compartment_id INTO v_compartment_id
      FROM malu$vector_compartment c
      JOIN malu$vector_subject s ON s.subject_id = c.subject_id
      JOIN malu$vector_verb    v ON v.verb_id    = c.verb_id
     WHERE c.namespace = p_namespace
       AND s.subject_name = p_subject
       AND v.verb_name    = p_verb
     LIMIT 1;
    IF v_compartment_id IS NULL THEN
        RAISE EXCEPTION 'no compartment for namespace=% subject=% verb=%',
            p_namespace, p_subject, p_verb
            USING ERRCODE = 'no_data_found';
    END IF;
    RETURN QUERY
        SELECT r.chunk_id, r.source_text, r.distance, r.similarity, r.rank_no,
               v_compartment_id
          FROM exact_vector_search_sql(v_compartment_id, p_query, p_limit, p_metric) r;
END;
$body$;

-- ---------------------------------------------------------------------
-- register_vector_chunk — accept malu_vector instead of bytea.
-- ---------------------------------------------------------------------
DROP FUNCTION register_vector_chunk(bigint, text, bytea, text);

CREATE FUNCTION register_vector_chunk(
    p_compartment_id  bigint,
    p_source_text     text,
    p_embedding       malu_vector,
    p_embedding_model text DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_dim       integer := vector_dims(p_embedding);
    v_normed    malu_vector := vector_normalize(p_embedding);
    v_norm      double precision := vector_norm(p_embedding);
    v_compart   malu$vector_compartment%ROWTYPE;
    v_chunk_id  bigint;
    v_model     text;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_dim <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'embedding_dim mismatch: chunk=% compartment=%',
            v_dim, v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_model := COALESCE(p_embedding_model, v_compart.embedding_model);

    INSERT INTO malu$vector_chunk
        (compartment_id, source_text, embedding,
         embedding_dim, embedding_model, embedding_norm)
    VALUES
        (p_compartment_id, p_source_text, v_normed,
         v_dim, v_model, v_norm)
    RETURNING chunk_id INTO v_chunk_id;

    UPDATE malu$vector_compartment
       SET vector_count = vector_count + 1,
           updated_at   = now()
     WHERE compartment_id = p_compartment_id;

    RETURN v_chunk_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- r10_memory_search_exact wraps the MC2DB tool. The body decodes the
-- base64 query into bytea, then casts to malu_vector for the search.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION r10_memory_search_exact(args jsonb, context jsonb) RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_namespace  text  := args->>'namespace';
    v_subject    text  := args->>'subject';
    v_verb       text  := args->>'verb';
    v_query_b64  text  := args->>'query_embedding_b64';
    v_limit      int   := COALESCE((args->>'limit')::int, 10);
    v_metric     text  := args->>'metric';
    v_query      malu_vector;
    v_results    jsonb;
    v_compartment bigint;
BEGIN
    IF v_namespace IS NULL OR v_subject IS NULL OR v_verb IS NULL OR v_query_b64 IS NULL THEN
        CALL mc2db.put_error('namespace, subject, verb, and query_embedding_b64 are required',
            jsonb_build_object('code','BAD_INPUT'));
        RETURN;
    END IF;

    v_query := decode(v_query_b64, 'base64')::malu_vector;

    SELECT compartment_id INTO v_compartment FROM explain_vector_search(v_namespace, v_subject, v_verb);
    IF v_compartment IS NULL THEN
        CALL mc2db.put_error(format('no compartment for %s/%s/%s', v_namespace, v_subject, v_verb),
            jsonb_build_object('code','NOT_FOUND'));
        RETURN;
    END IF;

    SELECT COALESCE(jsonb_agg(jsonb_build_object(
        'chunk_id',    r.chunk_id,
        'source_text', r.source_text,
        'distance',    r.distance,
        'similarity',  r.similarity,
        'rank',        r.rank_no) ORDER BY r.rank_no), '[]'::jsonb)
    INTO v_results
    FROM search_memory_exact(v_namespace, v_subject, v_verb, v_query, v_limit, v_metric) r;

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object('type','text',
            'text', format('%s result(s) from compartment %s',
                           jsonb_array_length(v_results), v_compartment))),
        'structuredContent', jsonb_build_object(
            'compartment_id', v_compartment,
            'results',        v_results),
        'isError', false));
END;
$body$;

-- ============================================================
-- Section: maludb_core--0.12.0--0.13.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.13.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.12.0 → 0.13.0
--
-- R1.1-15: Parallel exact vector search.
--
-- Adds a parallel-safe custom aggregate `topk_vector_search` whose
-- INTERNAL state is a bounded top-K max-heap (src/maludb_topk.c).
-- PG's parallel-aware aggregate machinery splits the
-- malu$vector_chunk scan across worker backends; each maintains its
-- own heap; the COMBINEFUNC merges worker heaps into the leader.
--
-- The exact_vector_search_sql dispatcher checks
-- malu$vector_compartment.search_mode:
--   - 'exact'           → existing single-process C heap (R1.1-13)
--   - 'exact_parallel'  → new aggregate path (this phase)
--   - 'local_ann'       → reserved for R1.1-16 (raises until then)
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.13.0'::text $body$;

-- ---------------------------------------------------------------------
-- C functions backing the aggregate. Internal state is opaque
-- (LANGUAGE C with INTERNAL stype); serial/deserial round-trip the
-- state through bytea at worker boundaries.
-- ---------------------------------------------------------------------
CREATE FUNCTION topk_vector_sfunc(
    state        internal,
    embedding    malu_vector,
    chunk_id     bigint,
    source_text  text,
    query        malu_vector,
    k            integer,
    metric       text
) RETURNS internal
    AS 'MODULE_PATHNAME', 'maludb_topk_vector_sfunc'
    LANGUAGE C IMMUTABLE PARALLEL SAFE;

CREATE FUNCTION topk_vector_combine(internal, internal) RETURNS internal
    AS 'MODULE_PATHNAME', 'maludb_topk_vector_combine'
    LANGUAGE C IMMUTABLE PARALLEL SAFE;

CREATE FUNCTION topk_vector_serialize(internal) RETURNS bytea
    AS 'MODULE_PATHNAME', 'maludb_topk_vector_serialize'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION topk_vector_deserialize(bytea, internal) RETURNS internal
    AS 'MODULE_PATHNAME', 'maludb_topk_vector_deserialize'
    LANGUAGE C IMMUTABLE STRICT PARALLEL SAFE;

CREATE FUNCTION topk_vector_finalize(internal) RETURNS jsonb
    AS 'MODULE_PATHNAME', 'maludb_topk_vector_finalize'
    LANGUAGE C IMMUTABLE PARALLEL SAFE;

-- ---------------------------------------------------------------------
-- The aggregate. Returns a jsonb array of top-K entries
-- (sorted by distance ascending). exact_vector_search_parallel_c()
-- below fans this out into the standard search result rowtype.
-- ---------------------------------------------------------------------
CREATE AGGREGATE topk_vector_search(
    embedding    malu_vector,
    chunk_id     bigint,
    source_text  text,
    query        malu_vector,
    k            integer,
    metric       text
) (
    SFUNC        = topk_vector_sfunc,
    STYPE        = internal,
    COMBINEFUNC  = topk_vector_combine,
    SERIALFUNC   = topk_vector_serialize,
    DESERIALFUNC = topk_vector_deserialize,
    FINALFUNC    = topk_vector_finalize,
    PARALLEL     = SAFE
);

-- ---------------------------------------------------------------------
-- exact_vector_search_parallel_c: SQL wrapper. The aggregate runs over
-- malu$vector_chunk filtered by compartment_id (relational filter
-- first), and we unpack the resulting jsonb into the standard result
-- rowtype.
-- ---------------------------------------------------------------------
CREATE FUNCTION exact_vector_search_parallel_c(
    p_compartment_id bigint,
    p_query          malu_vector,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
) LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    v_compart  malu$vector_compartment%ROWTYPE;
    v_metric   text;
    v_qnorm    malu_vector;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF vector_dims(p_query) <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'query dim % does not match compartment dim %',
            vector_dims(p_query), v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_metric := COALESCE(p_metric, v_compart.distance_metric);
    v_qnorm  := vector_normalize(p_query);

    RETURN QUERY
        WITH agg AS (
            SELECT topk_vector_search(
                       c.embedding, c.chunk_id, c.source_text,
                       v_qnorm, p_limit, v_metric) AS j
            FROM malu$vector_chunk c
            WHERE c.compartment_id = p_compartment_id
        ),
        rows AS (
            SELECT e
            FROM   agg, jsonb_array_elements(agg.j) e
        )
        SELECT (e->>'chunk_id')::bigint,
               e->>'source_text',
               (e->>'distance')::double precision,
               (e->>'similarity')::double precision,
               (e->>'rank_no')::integer
        FROM   rows
        ORDER BY (e->>'rank_no')::integer;
END;
$body$;

-- ---------------------------------------------------------------------
-- exact_vector_search_sql: dispatcher that honours
-- malu$vector_compartment.search_mode.
--
-- Behaviour table:
--   search_mode='exact'           → exact_vector_search_c (R1.1-13)
--   search_mode='exact_parallel'  → exact_vector_search_parallel_c
--   search_mode='local_ann'       → raises (reserved for R1.1-16)
-- ---------------------------------------------------------------------
DROP FUNCTION exact_vector_search_sql(bigint, malu_vector, integer, text);

CREATE FUNCTION exact_vector_search_sql(
    p_compartment_id bigint,
    p_query          malu_vector,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_compart malu$vector_compartment%ROWTYPE;
    v_metric  text;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF vector_dims(p_query) <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'query dim % does not match compartment dim %',
            vector_dims(p_query), v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_metric := COALESCE(p_metric, v_compart.distance_metric);

    IF v_compart.search_mode = 'exact_parallel' THEN
        RETURN QUERY
            SELECT * FROM exact_vector_search_parallel_c(
                p_compartment_id, p_query, p_limit, v_metric);
    ELSIF v_compart.search_mode = 'local_ann' THEN
        RAISE EXCEPTION
          'SEARCH_MODE_UNAVAILABLE: local_ann is reserved for R1.1-16 and not yet implemented'
          USING ERRCODE = 'feature_not_supported';
    ELSE
        RETURN QUERY
            SELECT * FROM exact_vector_search_c(
                p_compartment_id, vector_normalize(p_query), p_limit, v_metric);
    END IF;
END;
$body$;

-- ============================================================
-- Section: maludb_core--0.13.0--0.14.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.14.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.13.0 → 0.14.0
--
-- R1.1-16: Local ANN per compartment.
--
-- Adds a single-layer NSW (Navigable Small-World) graph stored as a
-- single BYTEA blob per compartment, plus the delta + tombstone +
-- rebuild lifecycle described in
-- docs/research/2026-05-06-compartmentalized-vector-search.md §10-§14.
--
-- Scope decisions (2026-05-13):
--   * Single-layer NSW, not multilevel HNSW. Functionally similar at
--     moderate compartment sizes; ~half the code. R1.1-16.1 may
--     upgrade to multilevel HNSW.
--   * Single BYTEA blob per compartment (transcript §7 hybrid). One
--     row read serves the whole search; no per-edge SQL round-trip.
--   * Full lifecycle: delta search merged into top-K, tombstones
--     filtered, ann_rebuild() drains delta + clears tombstones.
--
-- Tables:
--   malu$ann_index          — one row per compartment with an ANN built
--   malu$ann_delta          — chunks added since last build
--   malu$vector_tombstone   — chunks marked for filtering on search
--
-- Search path when search_mode='local_ann':
--   1. ann_search over graph in malu$ann_index.graph_bytes
--   2. exact search over delta chunks not yet in graph
--   3. filter out tombstones from both
--   4. merge by distance + return top K
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.14.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$ann_index — graph blob + parameters per compartment
-- ---------------------------------------------------------------------
CREATE TABLE malu$ann_index (
    compartment_id       bigint PRIMARY KEY
        REFERENCES malu$vector_compartment(compartment_id) ON DELETE CASCADE,
    algorithm            text   NOT NULL DEFAULT 'nsw'
        CHECK (algorithm IN ('nsw','hnsw')),
    distance_metric      text   NOT NULL
        CHECK (distance_metric IN ('cosine','l2','inner_product')),
    m                    integer NOT NULL DEFAULT 16
        CHECK (m > 0 AND m <= 256),
    ef_construction      integer NOT NULL DEFAULT 64
        CHECK (ef_construction > 0 AND ef_construction <= 4096),
    ef_search_default    integer NOT NULL DEFAULT 32
        CHECK (ef_search_default > 0 AND ef_search_default <= 4096),
    embedding_dim        integer NOT NULL,
    graph_bytes          bytea  NOT NULL,
    vector_count_at_build bigint NOT NULL DEFAULT 0,
    status               text   NOT NULL DEFAULT 'ready'
        CHECK (status IN ('building','ready','stale','rebuilding','disabled')),
    built_at             timestamptz NOT NULL DEFAULT now(),
    last_rebuilt_at      timestamptz
);

CREATE INDEX malu$ann_index_status_idx ON malu$ann_index(status);

-- ---------------------------------------------------------------------
-- malu$ann_delta — chunks inserted since last build. Search merges
-- these with the graph results so new vectors are immediately
-- findable.
-- ---------------------------------------------------------------------
CREATE TABLE malu$ann_delta (
    compartment_id   bigint NOT NULL
        REFERENCES malu$vector_compartment(compartment_id) ON DELETE CASCADE,
    chunk_id         bigint NOT NULL
        REFERENCES malu$vector_chunk(chunk_id) ON DELETE CASCADE,
    created_at       timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (compartment_id, chunk_id)
);

CREATE INDEX malu$ann_delta_compartment_idx ON malu$ann_delta(compartment_id);

-- ---------------------------------------------------------------------
-- malu$vector_tombstone — chunks to filter out on search. We don't
-- physically delete chunks (graph references would break); instead
-- mark them tombstoned and let ann_rebuild() clear them next time.
-- ---------------------------------------------------------------------
CREATE TABLE malu$vector_tombstone (
    chunk_id    bigint PRIMARY KEY
        REFERENCES malu$vector_chunk(chunk_id) ON DELETE CASCADE,
    deleted_at  timestamptz NOT NULL DEFAULT now()
);

GRANT SELECT ON malu$ann_index, malu$ann_delta, malu$vector_tombstone TO
    maludb_llm_admin,
    maludb_llm_prompt_author,
    maludb_llm_prompt_approver,
    maludb_llm_model_admin,
    maludb_llm_executor,
    maludb_llm_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$ann_index, malu$ann_delta, malu$vector_tombstone TO
    maludb_llm_admin;
GRANT INSERT, UPDATE, DELETE ON malu$ann_delta, malu$vector_tombstone TO
    maludb_llm_executor;

-- ---------------------------------------------------------------------
-- C functions backing the NSW algorithm.
--
--   maludb_ann_build_c(compartment_id, m, ef_construct, metric)
--     → bytea (the graph blob)
--   maludb_ann_search_c(graph, query, k, ef_search, metric)
--     → TABLE(chunk_id, distance, similarity, rank_no)
-- ---------------------------------------------------------------------
CREATE FUNCTION maludb_ann_build_c(
    p_compartment_id bigint,
    p_m              integer,
    p_ef_construct   integer,
    p_metric         text
) RETURNS bytea
    AS 'MODULE_PATHNAME', 'maludb_ann_build_c'
    LANGUAGE C STABLE STRICT;

CREATE FUNCTION maludb_ann_search_c(
    p_graph          bytea,
    p_query          malu_vector,
    p_limit          integer,
    p_ef_search      integer,
    p_metric         text
) RETURNS TABLE (
    chunk_id    bigint,
    distance    double precision,
    similarity  double precision,
    rank_no     integer
)
    AS 'MODULE_PATHNAME', 'maludb_ann_search_c'
    LANGUAGE C STABLE PARALLEL SAFE;

-- ---------------------------------------------------------------------
-- ann_build: builds the NSW graph for a compartment and inserts/replaces
-- the malu$ann_index row. Sets compartment.search_mode='local_ann' so
-- exact_vector_search_sql routes through ANN going forward.
-- ---------------------------------------------------------------------
CREATE FUNCTION ann_build(
    p_compartment_id  bigint,
    p_m               integer DEFAULT 16,
    p_ef_construction integer DEFAULT 64,
    p_ef_search       integer DEFAULT 32
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_compart  malu$vector_compartment%ROWTYPE;
    v_graph    bytea;
    v_count    bigint;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;

    UPDATE malu$vector_compartment SET ann_index_status = 'building',
                                       updated_at       = now()
     WHERE compartment_id = p_compartment_id;

    v_graph := maludb_ann_build_c(
        p_compartment_id, p_m, p_ef_construction, v_compart.distance_metric);

    SELECT count(*) INTO v_count FROM malu$vector_chunk
     WHERE compartment_id = p_compartment_id
       AND chunk_id NOT IN (SELECT chunk_id FROM malu$vector_tombstone);

    INSERT INTO malu$ann_index
        (compartment_id, distance_metric, m, ef_construction, ef_search_default,
         embedding_dim, graph_bytes, vector_count_at_build, status, built_at)
    VALUES
        (p_compartment_id, v_compart.distance_metric, p_m,
         p_ef_construction, p_ef_search,
         v_compart.embedding_dim, v_graph, v_count, 'ready', now())
    ON CONFLICT (compartment_id) DO UPDATE
       SET distance_metric        = EXCLUDED.distance_metric,
           m                      = EXCLUDED.m,
           ef_construction        = EXCLUDED.ef_construction,
           ef_search_default      = EXCLUDED.ef_search_default,
           embedding_dim          = EXCLUDED.embedding_dim,
           graph_bytes            = EXCLUDED.graph_bytes,
           vector_count_at_build  = EXCLUDED.vector_count_at_build,
           status                 = 'ready',
           last_rebuilt_at        = now();

    -- Draining delta because everything is now in the graph.
    DELETE FROM malu$ann_delta WHERE compartment_id = p_compartment_id;

    UPDATE malu$vector_compartment
       SET search_mode      = 'local_ann',
           ann_index_status = 'ready',
           updated_at       = now()
     WHERE compartment_id = p_compartment_id;

    RETURN v_count;
END;
$body$;

-- ---------------------------------------------------------------------
-- ann_rebuild: alias for ann_build (idempotent). Provided as a distinct
-- name so operators can wire monitoring against the rebuild lifecycle.
-- Also clears tombstones since rebuilt graph no longer references them.
-- ---------------------------------------------------------------------
CREATE FUNCTION ann_rebuild(
    p_compartment_id bigint
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_idx malu$ann_index%ROWTYPE;
    v_built bigint;
BEGIN
    SELECT * INTO v_idx FROM malu$ann_index
     WHERE compartment_id = p_compartment_id;
    IF v_idx.compartment_id IS NULL THEN
        RAISE EXCEPTION 'no ANN index for compartment %; call ann_build() first',
            p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;

    v_built := ann_build(p_compartment_id, v_idx.m, v_idx.ef_construction,
                         v_idx.ef_search_default);
    DELETE FROM malu$vector_tombstone
     WHERE chunk_id IN (
         SELECT chunk_id FROM malu$vector_chunk
          WHERE compartment_id = p_compartment_id);
    RETURN v_built;
END;
$body$;

-- ---------------------------------------------------------------------
-- ann_status: per-compartment lifecycle snapshot. Reports counts that
-- drive the rebuild-trigger heuristics from transcript §14.
-- ---------------------------------------------------------------------
CREATE FUNCTION ann_status(p_compartment_id bigint) RETURNS TABLE (
    compartment_id          bigint,
    algorithm               text,
    distance_metric         text,
    m                       integer,
    ef_search_default       integer,
    embedding_dim           integer,
    graph_byte_size         integer,
    vector_count_at_build   bigint,
    delta_count             bigint,
    tombstone_count         bigint,
    status                  text,
    built_at                timestamptz,
    last_rebuilt_at         timestamptz
) LANGUAGE sql STABLE
AS $body$
    SELECT
        i.compartment_id,
        i.algorithm,
        i.distance_metric,
        i.m,
        i.ef_search_default,
        i.embedding_dim,
        octet_length(i.graph_bytes)::integer,
        i.vector_count_at_build,
        (SELECT count(*) FROM malu$ann_delta d
          WHERE d.compartment_id = i.compartment_id),
        (SELECT count(*) FROM malu$vector_tombstone t
          JOIN malu$vector_chunk c ON c.chunk_id = t.chunk_id
          WHERE c.compartment_id = i.compartment_id),
        i.status,
        i.built_at,
        i.last_rebuilt_at
    FROM malu$ann_index i
    WHERE i.compartment_id = p_compartment_id;
$body$;

-- ---------------------------------------------------------------------
-- register_vector_chunk: when an ANN index exists for the compartment,
-- new inserts go into the delta buffer.
-- ---------------------------------------------------------------------
DROP FUNCTION register_vector_chunk(bigint, text, malu_vector, text);

CREATE FUNCTION register_vector_chunk(
    p_compartment_id  bigint,
    p_source_text     text,
    p_embedding       malu_vector,
    p_embedding_model text DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_dim       integer := vector_dims(p_embedding);
    v_normed    malu_vector := vector_normalize(p_embedding);
    v_norm      double precision := vector_norm(p_embedding);
    v_compart   malu$vector_compartment%ROWTYPE;
    v_chunk_id  bigint;
    v_model     text;
    v_has_ann   boolean;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_dim <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'embedding_dim mismatch: chunk=% compartment=%',
            v_dim, v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_model := COALESCE(p_embedding_model, v_compart.embedding_model);

    INSERT INTO malu$vector_chunk
        (compartment_id, source_text, embedding,
         embedding_dim, embedding_model, embedding_norm)
    VALUES
        (p_compartment_id, p_source_text, v_normed,
         v_dim, v_model, v_norm)
    RETURNING chunk_id INTO v_chunk_id;

    UPDATE malu$vector_compartment
       SET vector_count = vector_count + 1,
           updated_at   = now()
     WHERE compartment_id = p_compartment_id;

    -- If an ANN index exists, mark the new chunk as delta. The
    -- search path will exact-search the delta until the next rebuild.
    SELECT EXISTS (SELECT 1 FROM malu$ann_index
                    WHERE compartment_id = p_compartment_id) INTO v_has_ann;
    IF v_has_ann THEN
        INSERT INTO malu$ann_delta (compartment_id, chunk_id)
        VALUES (p_compartment_id, v_chunk_id)
        ON CONFLICT DO NOTHING;
        UPDATE malu$vector_compartment
           SET ann_index_status = 'stale', updated_at = now()
         WHERE compartment_id = p_compartment_id;
    END IF;

    RETURN v_chunk_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- tombstone_vector_chunk: mark a chunk for filtering on search. The
-- physical row stays so the ANN graph's edges don't dangle; ann_rebuild
-- will remove it next time.
-- ---------------------------------------------------------------------
CREATE FUNCTION tombstone_vector_chunk(p_chunk_id bigint) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE
    v_compartment_id bigint;
BEGIN
    SELECT compartment_id INTO v_compartment_id
    FROM malu$vector_chunk WHERE chunk_id = p_chunk_id;
    IF v_compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown chunk_id: %', p_chunk_id
            USING ERRCODE = 'no_data_found';
    END IF;

    INSERT INTO malu$vector_tombstone (chunk_id)
    VALUES (p_chunk_id)
    ON CONFLICT DO NOTHING;

    UPDATE malu$vector_compartment
       SET ann_index_status = 'stale', updated_at = now()
     WHERE compartment_id = v_compartment_id
       AND EXISTS (SELECT 1 FROM malu$ann_index
                    WHERE compartment_id = v_compartment_id);
END;
$body$;

-- ---------------------------------------------------------------------
-- exact_vector_search_sql: rewire the local_ann branch to actually
-- search the ANN graph + merge delta + filter tombstones.
-- ---------------------------------------------------------------------
DROP FUNCTION exact_vector_search_sql(bigint, malu_vector, integer, text);

CREATE FUNCTION exact_vector_search_sql(
    p_compartment_id bigint,
    p_query          malu_vector,
    p_limit          integer DEFAULT 10,
    p_metric         text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer
) LANGUAGE plpgsql
AS $body$
DECLARE
    v_compart malu$vector_compartment%ROWTYPE;
    v_metric  text;
    v_idx     malu$ann_index%ROWTYPE;
BEGIN
    SELECT * INTO v_compart FROM malu$vector_compartment
     WHERE compartment_id = p_compartment_id;
    IF v_compart.compartment_id IS NULL THEN
        RAISE EXCEPTION 'unknown compartment_id: %', p_compartment_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF vector_dims(p_query) <> v_compart.embedding_dim THEN
        RAISE EXCEPTION 'query dim % does not match compartment dim %',
            vector_dims(p_query), v_compart.embedding_dim
            USING ERRCODE = 'check_violation';
    END IF;
    v_metric := COALESCE(p_metric, v_compart.distance_metric);

    IF v_compart.search_mode = 'local_ann' THEN
        SELECT * INTO v_idx FROM malu$ann_index
         WHERE compartment_id = p_compartment_id;
        IF v_idx.compartment_id IS NULL THEN
            RAISE EXCEPTION
              'compartment % has search_mode=local_ann but no malu$ann_index row; call ann_build()',
              p_compartment_id
              USING ERRCODE = 'no_data_found';
        END IF;

        -- Bare `chunk_id` / `distance` / `similarity` / `rank_no` are
        -- ambiguous inside this RETURNS TABLE body (they're also OUT
        -- variable names). All references must be qualified.
        RETURN QUERY
            WITH ann_hits AS (
                SELECT a.chunk_id AS cid, a.distance AS d, a.similarity AS s
                FROM   maludb_ann_search_c(
                           v_idx.graph_bytes,
                           vector_normalize(p_query),
                           p_limit * 2,                    -- over-fetch for tombstone filter
                           v_idx.ef_search_default,
                           v_metric) a
                WHERE  a.chunk_id NOT IN (SELECT t.chunk_id FROM malu$vector_tombstone t)
            ),
            delta_hits AS (
                SELECT c.chunk_id AS cid,
                       CASE v_metric
                         WHEN 'cosine'        THEN 1.0 - vector_dot_product(c.embedding, vector_normalize(p_query))
                         WHEN 'l2'            THEN vector_l2_squared(c.embedding, p_query)
                         WHEN 'inner_product' THEN -vector_dot_product(c.embedding, p_query)
                       END AS d,
                       CASE v_metric
                         WHEN 'cosine'        THEN vector_dot_product(c.embedding, vector_normalize(p_query))
                         WHEN 'l2'            THEN -vector_l2_squared(c.embedding, p_query)
                         WHEN 'inner_product' THEN vector_dot_product(c.embedding, p_query)
                       END AS s
                FROM   malu$ann_delta dlt
                JOIN   malu$vector_chunk c ON c.chunk_id = dlt.chunk_id
                WHERE  dlt.compartment_id = p_compartment_id
                  AND  c.chunk_id NOT IN (SELECT t.chunk_id FROM malu$vector_tombstone t)
            ),
            merged AS (
                SELECT cid, d, s FROM ann_hits
                UNION ALL
                SELECT cid, d, s FROM delta_hits
            ),
            ranked AS (
                SELECT mg.cid AS cid, mg.d AS d, mg.s AS s,
                       ROW_NUMBER() OVER (ORDER BY mg.d ASC, mg.cid ASC)::integer AS r
                FROM merged mg
            )
            SELECT r.cid,
                   vc.source_text,
                   r.d,
                   r.s,
                   r.r
            FROM ranked r
            JOIN malu$vector_chunk vc ON vc.chunk_id = r.cid
            WHERE r.r <= p_limit
            ORDER BY r.r;
        RETURN;
    ELSIF v_compart.search_mode = 'exact_parallel' THEN
        RETURN QUERY
            SELECT * FROM exact_vector_search_parallel_c(
                p_compartment_id, p_query, p_limit, v_metric);
    ELSE
        RETURN QUERY
            SELECT * FROM exact_vector_search_c(
                p_compartment_id, vector_normalize(p_query), p_limit, v_metric);
    END IF;
END;
$body$;

GRANT EXECUTE ON FUNCTION ann_build(bigint, integer, integer, integer),
                          ann_rebuild(bigint),
                          ann_status(bigint),
                          tombstone_vector_chunk(bigint)
TO maludb_llm_admin,
   maludb_llm_executor;

-- ============================================================
-- Section: maludb_core--0.14.0--0.15.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.15.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.14.0 → 0.15.0
--
-- Stage 2 — Memory object model + Derivation Ledger (S2-1 + S2-3).
--
-- Installs the seven core memory object tables:
--   malu$source_package       — verbatim source ingestion artifact
--   malu$claim                — extracted assertion with source ref
--   malu$fact                 — claim(s) accepted within a scope
--   malu$fact_claim           — fact ↔ claim junction
--   malu$memory               — contextual record of event/decision/...
--   malu$episode_object       — specific remembered episode
--   malu$memory_detail_object — recursively addressable detail
--   malu$relationship_edge    — typed polymorphic edges between objects
--   malu$derivation_ledger    — auditable lineage of every derived object
--
-- Per CLAUDE.md tenancy model:
--   * Tier-B governed objects carry `owner_schema name NOT NULL DEFAULT
--     current_schema()`. One PG schema = one MaluDB tenant.
--   * RLS scopes by owner_schema (cross-tenant grants via S2-5
--     malu$object_grant — deferred).
--   * Base tables get no PUBLIC grants. Three new functional roles
--     (maludb_memory_admin / _executor / _auditor) gate access.
--
-- Doctrine (per CLAUDE.md):
--   * Multi-model writes that span object + edge + ledger must be in a
--     single transaction. S2-7 will add C-level atomic helpers; for
--     now PL/pgSQL `register_*` functions wrap each.
--   * Every derived object must have a malu$derivation_ledger row.
--     The helper `record_derivation()` is the canonical writer.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.15.0'::text $body$;

-- ---------------------------------------------------------------------
-- Stage 2 functional roles. Three roles for now — the prompt-style
-- author/approver split from R1.1 doesn't map cleanly to memory writes,
-- so we keep it flat: admin / executor / auditor.
-- ---------------------------------------------------------------------
DO $$ BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_memory_admin') THEN
        CREATE ROLE maludb_memory_admin   NOLOGIN NOINHERIT BYPASSRLS;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_memory_executor') THEN
        CREATE ROLE maludb_memory_executor NOLOGIN NOINHERIT;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_memory_auditor') THEN
        CREATE ROLE maludb_memory_auditor  NOLOGIN NOINHERIT BYPASSRLS;
    END IF;
END $$;

-- =====================================================================
-- malu$source_package
--
-- Verbatim source ingestion artifact. Stage 2 S2-2 will add the
-- immutable archive layer (sealing, tiered placement, retention class
-- enforcement); this S2-1 row holds enough to reference and search.
-- =====================================================================
CREATE TABLE malu$source_package (
    source_package_id   bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    source_type         text NOT NULL
        REFERENCES malu$source_type(source_type),
    -- Content (one of these must be non-NULL)
    content_bytes       bytea,
    content_text        text,
    content_jsonb       jsonb,
    content_hash        text NOT NULL,   -- sha256 hex over the canonical form
    content_size        bigint NOT NULL CHECK (content_size >= 0),
    media_type          text,
    -- Origin
    origin_jsonb        jsonb,           -- {producer, connector, ingested_by, ...}
    captured_at         timestamptz,
    ingested_at         timestamptz NOT NULL DEFAULT now(),
    -- Retention + legal hold
    retention_class     text NOT NULL DEFAULT 'standard'
        CHECK (retention_class IN ('standard','sensitive','restricted','prohibited')),
    legal_hold          boolean NOT NULL DEFAULT false,
    legal_hold_reason   text,
    retain_until        timestamptz,
    -- Sensitivity (independent of retention)
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    -- Lifecycle (S2-2 wires the seal/archive transitions properly)
    sealed_at           timestamptz,
    archived_at         timestamptz,
    tombstoned_at       timestamptz,
    -- Audit
    created_at          timestamptz NOT NULL DEFAULT now(),
    updated_at          timestamptz NOT NULL DEFAULT now(),
    CHECK (content_bytes IS NOT NULL OR content_text IS NOT NULL OR content_jsonb IS NOT NULL)
);
CREATE INDEX malu$source_package_owner_idx ON malu$source_package(owner_schema);
CREATE INDEX malu$source_package_hash_idx  ON malu$source_package(content_hash);
CREATE INDEX malu$source_package_type_idx  ON malu$source_package(source_type);

-- =====================================================================
-- malu$claim
--
-- An extracted assertion. May or may not reference a source package
-- (hypothetical claims have no source). SVPOR shape carried as plain
-- text columns; Stage 3 will normalize via malu$svpor_*.
-- =====================================================================
CREATE TABLE malu$claim (
    claim_id            bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    -- SVPOR text shape (Stage 3 will normalize)
    subject             text,
    verb                text,
    predicate           text,
    object_value        text,
    relationship        text,
    -- Free-form statement
    statement_text      text,
    statement_jsonb     jsonb,
    -- Source reference (optional)
    source_package_id   bigint REFERENCES malu$source_package(source_package_id) ON DELETE SET NULL,
    source_locator      jsonb,           -- {page, byte_offset, line_no, message_id, ...}
    -- Lifecycle
    asserted_at         timestamptz NOT NULL DEFAULT now(),
    retracted_at        timestamptz,
    retraction_reason   text,
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    created_at          timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$claim_owner_idx       ON malu$claim(owner_schema);
CREATE INDEX malu$claim_source_idx      ON malu$claim(source_package_id) WHERE source_package_id IS NOT NULL;
CREATE INDEX malu$claim_subj_verb_idx   ON malu$claim(subject, verb) WHERE subject IS NOT NULL;

-- =====================================================================
-- malu$fact
--
-- A claim or set of claims accepted as true within a defined scope.
-- supersedes_fact_id captures simple correction chains; Stage 3 will
-- replace with full bitemporal supersession.
-- =====================================================================
CREATE TABLE malu$fact (
    fact_id             bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    subject             text,
    verb                text,
    predicate           text,
    object_value        text,
    relationship        text,
    statement_text      text,
    statement_jsonb     jsonb,
    -- Verification (Stage 3 MAUT will replace)
    verification_scope  text,
    verification_method text,
    verified_at         timestamptz NOT NULL DEFAULT now(),
    -- Supersession (Stage 3 will replace)
    supersedes_fact_id  bigint REFERENCES malu$fact(fact_id) ON DELETE SET NULL,
    superseded_at       timestamptz,
    -- Sensitivity / lifecycle
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    lifecycle_state     text NOT NULL DEFAULT 'active'
        CHECK (lifecycle_state IN ('active','superseded','retired','legal_hold','tombstoned')),
    created_at          timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$fact_owner_idx      ON malu$fact(owner_schema);
CREATE INDEX malu$fact_subj_verb_idx  ON malu$fact(subject, verb) WHERE subject IS NOT NULL;
CREATE INDEX malu$fact_supersedes_idx ON malu$fact(supersedes_fact_id) WHERE supersedes_fact_id IS NOT NULL;

-- =====================================================================
-- malu$fact_claim — junction. A fact aggregates one or more claims.
-- =====================================================================
CREATE TABLE malu$fact_claim (
    fact_id     bigint  NOT NULL REFERENCES malu$fact(fact_id)   ON DELETE CASCADE,
    claim_id    bigint  NOT NULL REFERENCES malu$claim(claim_id) ON DELETE RESTRICT,
    role        text    NOT NULL DEFAULT 'supports'
        CHECK (role IN ('supports','contradicts','contextualizes')),
    added_at    timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (fact_id, claim_id)
);
CREATE INDEX malu$fact_claim_claim_idx ON malu$fact_claim(claim_id);

-- =====================================================================
-- malu$memory
--
-- Contextual record. memory_kind is operator-defined (event, decision,
-- discovery, lesson, dependency, change, observation, ...).
-- =====================================================================
CREATE TABLE malu$memory (
    memory_id           bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    memory_kind         text NOT NULL,
    title               text,
    summary             text,
    payload_jsonb       jsonb NOT NULL DEFAULT '{}'::jsonb,
    -- Temporal anchors (Stage 3 fills in full bitemporal)
    occurred_at         timestamptz,
    occurred_until      timestamptz,
    recorded_at         timestamptz NOT NULL DEFAULT now(),
    -- Sensitivity / lifecycle
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    lifecycle_state     text NOT NULL DEFAULT 'active'
        CHECK (lifecycle_state IN ('active','consolidated','superseded','archived','retired','legal_hold','tombstoned')),
    consolidated_into_memory_id bigint
        REFERENCES malu$memory(memory_id) ON DELETE SET NULL,
    created_at          timestamptz NOT NULL DEFAULT now(),
    updated_at          timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$memory_owner_idx       ON malu$memory(owner_schema);
CREATE INDEX malu$memory_kind_idx        ON malu$memory(memory_kind);
CREATE INDEX malu$memory_occurred_idx    ON malu$memory(occurred_at)    WHERE occurred_at IS NOT NULL;
CREATE INDEX malu$memory_lifecycle_idx   ON malu$memory(lifecycle_state) WHERE lifecycle_state <> 'active';

-- =====================================================================
-- malu$episode_object
--
-- DBMS representation of a specific remembered episode. An episode
-- typically aggregates memories + facts + Memory Detail Objects under
-- one lifecycle. Stage 5 will add Workflow Trace extraction over
-- these.
-- =====================================================================
CREATE TABLE malu$episode_object (
    episode_id          bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    episode_kind        text NOT NULL,
    title               text NOT NULL,
    summary             text,
    payload_jsonb       jsonb NOT NULL DEFAULT '{}'::jsonb,
    occurred_at         timestamptz,
    occurred_until      timestamptz,
    recorded_at         timestamptz NOT NULL DEFAULT now(),
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    lifecycle_state     text NOT NULL DEFAULT 'active'
        CHECK (lifecycle_state IN ('active','consolidated','superseded','archived','retired','legal_hold','tombstoned')),
    created_at          timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$episode_owner_idx     ON malu$episode_object(owner_schema);
CREATE INDEX malu$episode_kind_idx      ON malu$episode_object(episode_kind);
CREATE INDEX malu$episode_occurred_idx  ON malu$episode_object(occurred_at) WHERE occurred_at IS NOT NULL;

-- =====================================================================
-- malu$memory_detail_object — recursively containable child of a
-- memory or episode. parent_mdo_id self-references for nesting.
-- =====================================================================
CREATE TABLE malu$memory_detail_object (
    mdo_id              bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    -- Parent: nested under another MDO, OR top-level under memory/episode.
    parent_mdo_id       bigint REFERENCES malu$memory_detail_object(mdo_id) ON DELETE CASCADE,
    memory_id           bigint REFERENCES malu$memory(memory_id)              ON DELETE CASCADE,
    episode_id          bigint REFERENCES malu$episode_object(episode_id)     ON DELETE CASCADE,
    detail_kind         text NOT NULL,
    -- examples: step, substep, parameter, command, validation, exception,
    --           source_excerpt, evidence, observation
    ordinal             integer,
    title               text,
    body_text           text,
    body_jsonb          jsonb,
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    created_at          timestamptz NOT NULL DEFAULT now(),
    CHECK (parent_mdo_id IS NOT NULL OR memory_id IS NOT NULL OR episode_id IS NOT NULL)
);
CREATE INDEX malu$mdo_owner_idx   ON malu$memory_detail_object(owner_schema);
CREATE INDEX malu$mdo_parent_idx  ON malu$memory_detail_object(parent_mdo_id) WHERE parent_mdo_id IS NOT NULL;
CREATE INDEX malu$mdo_memory_idx  ON malu$memory_detail_object(memory_id)     WHERE memory_id     IS NOT NULL;
CREATE INDEX malu$mdo_episode_idx ON malu$memory_detail_object(episode_id)    WHERE episode_id    IS NOT NULL;

-- =====================================================================
-- malu$relationship_edge — typed polymorphic edges between governed
-- objects. Cross-tenant edges land in the schema that recorded them;
-- visibility across tenants is mediated by future malu$object_grant
-- (S2-5).
-- =====================================================================
CREATE TABLE malu$relationship_edge (
    edge_id                 bigserial PRIMARY KEY,
    owner_schema            name NOT NULL DEFAULT current_schema(),
    relationship_type       text NOT NULL
        REFERENCES malu$relationship_type(relationship_type),
    source_object_type      text NOT NULL,
    source_object_id        bigint NOT NULL,
    target_object_type      text NOT NULL,
    target_object_id        bigint NOT NULL,
    label                   text,
    edge_jsonb              jsonb,
    confidence              numeric(5,4) CHECK (confidence IS NULL OR (confidence >= 0 AND confidence <= 1)),
    created_at              timestamptz NOT NULL DEFAULT now(),
    CHECK (source_object_type IN
        ('source_package','claim','fact','memory','episode_object','memory_detail_object')),
    CHECK (target_object_type IN
        ('source_package','claim','fact','memory','episode_object','memory_detail_object'))
);
CREATE INDEX malu$edge_owner_idx ON malu$relationship_edge(owner_schema);
CREATE INDEX malu$edge_src_idx   ON malu$relationship_edge(source_object_type, source_object_id);
CREATE INDEX malu$edge_tgt_idx   ON malu$relationship_edge(target_object_type, target_object_id);
CREATE INDEX malu$edge_rel_idx   ON malu$relationship_edge(relationship_type);

-- =====================================================================
-- malu$derivation_ledger (S2-3)
--
-- Auditable lineage. Every derived object MUST have a row here. Stage
-- 3 will extend with MAUT subscore tables; for now we record the
-- pipeline + the input set hash.
-- =====================================================================
CREATE TABLE malu$derivation_ledger (
    derivation_id           bigserial PRIMARY KEY,
    owner_schema            name NOT NULL DEFAULT current_schema(),
    derived_object_type     text NOT NULL,
    derived_object_id       bigint NOT NULL,
    -- The pipeline that produced the derived object
    parser_name             text,
    model_alias_id          bigint REFERENCES malu$model_alias(alias_id)         ON DELETE SET NULL,
    prompt_template_id      bigint REFERENCES malu$prompt_template(template_id)  ON DELETE SET NULL,
    policy_name             text,
    verifier_name           text,
    -- When the derivation went through the R1.0 model gateway, link it.
    model_request_id        bigint REFERENCES malu$model_request(request_id)     ON DELETE SET NULL,
    -- Inputs: jsonb manifest plus a sha256 over the canonical form
    inputs_jsonb            jsonb NOT NULL DEFAULT '[]'::jsonb,
    inputs_hash             text  NOT NULL,
    derived_at              timestamptz NOT NULL DEFAULT now(),
    CHECK (derived_object_type IN
        ('source_package','claim','fact','memory','episode_object','memory_detail_object',
         'relationship_edge'))
);
CREATE INDEX malu$ledger_owner_idx     ON malu$derivation_ledger(owner_schema);
CREATE INDEX malu$ledger_derived_idx   ON malu$derivation_ledger(derived_object_type, derived_object_id);
CREATE INDEX malu$ledger_request_idx   ON malu$derivation_ledger(model_request_id) WHERE model_request_id IS NOT NULL;

-- =====================================================================
-- Row-level security. Tenancy by owner_schema = current_schema().
-- Auditor + admin BYPASSRLS; executor sees their tenant only.
-- =====================================================================
ALTER TABLE malu$source_package        ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$claim                 ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$fact                  ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$fact_claim            ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$memory                ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$episode_object        ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$memory_detail_object  ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$relationship_edge     ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$derivation_ledger     ENABLE ROW LEVEL SECURITY;

CREATE POLICY tenant_owner ON malu$source_package
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$claim
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$fact
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_via_fact ON malu$fact_claim
    USING (
        EXISTS (SELECT 1 FROM malu$fact f
                WHERE f.fact_id = malu$fact_claim.fact_id
                  AND f.owner_schema = current_schema())
    )
    WITH CHECK (
        EXISTS (SELECT 1 FROM malu$fact f
                WHERE f.fact_id = malu$fact_claim.fact_id
                  AND f.owner_schema = current_schema())
    );
CREATE POLICY tenant_owner ON malu$memory
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$episode_object
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$memory_detail_object
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$relationship_edge
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$derivation_ledger
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

-- ---------------------------------------------------------------------
-- Grants
-- ---------------------------------------------------------------------
-- All memory roles read the catalog reference tables too.
GRANT SELECT ON malu$object_type, malu$relationship_type, malu$source_type
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- admin: full CRUD on every Stage 2 governed table
GRANT ALL ON
    malu$source_package, malu$claim, malu$fact, malu$fact_claim,
    malu$memory, malu$episode_object, malu$memory_detail_object,
    malu$relationship_edge, malu$derivation_ledger
TO maludb_memory_admin;

-- executor: CRUD within tenant (RLS handles scoping)
GRANT SELECT, INSERT, UPDATE, DELETE ON
    malu$source_package, malu$claim, malu$fact, malu$fact_claim,
    malu$memory, malu$episode_object, malu$memory_detail_object,
    malu$relationship_edge, malu$derivation_ledger
TO maludb_memory_executor;

-- auditor: SELECT only (BYPASSRLS = sees all tenants)
GRANT SELECT ON
    malu$source_package, malu$claim, malu$fact, malu$fact_claim,
    malu$memory, malu$episode_object, malu$memory_detail_object,
    malu$relationship_edge, malu$derivation_ledger
TO maludb_memory_auditor;

GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA maludb_core
    TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- Registration helpers. Each register_* is a thin write API with input
-- validation; multi-model atomic helpers come in S2-7.
-- =====================================================================

CREATE FUNCTION register_source_package(
    p_source_type     text,
    p_content_bytes   bytea   DEFAULT NULL,
    p_content_text    text    DEFAULT NULL,
    p_content_jsonb   jsonb   DEFAULT NULL,
    p_media_type      text    DEFAULT NULL,
    p_origin_jsonb    jsonb   DEFAULT NULL,
    p_captured_at     timestamptz DEFAULT NULL,
    p_retention_class text    DEFAULT 'standard',
    p_sensitivity     text    DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id    bigint;
    v_hash  text;
    v_size  bigint;
    v_bytes bytea;
BEGIN
    IF p_content_bytes IS NULL AND p_content_text IS NULL AND p_content_jsonb IS NULL THEN
        RAISE EXCEPTION 'register_source_package: one of content_bytes / _text / _jsonb is required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    -- Canonical hash form: bytes if given; else text; else jsonb::text.
    IF p_content_bytes IS NOT NULL THEN
        v_bytes := p_content_bytes;
    ELSIF p_content_text IS NOT NULL THEN
        v_bytes := convert_to(p_content_text, 'UTF8');
    ELSE
        v_bytes := convert_to(p_content_jsonb::text, 'UTF8');
    END IF;
    v_hash := encode(sha256(v_bytes), 'hex');
    v_size := octet_length(v_bytes);

    INSERT INTO malu$source_package
        (source_type, content_bytes, content_text, content_jsonb,
         content_hash, content_size, media_type, origin_jsonb,
         captured_at, retention_class, sensitivity)
    VALUES
        (p_source_type, p_content_bytes, p_content_text, p_content_jsonb,
         v_hash, v_size, p_media_type, p_origin_jsonb,
         p_captured_at, p_retention_class, p_sensitivity)
    RETURNING source_package_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_claim(
    p_subject           text  DEFAULT NULL,
    p_verb              text  DEFAULT NULL,
    p_predicate         text  DEFAULT NULL,
    p_object_value      text  DEFAULT NULL,
    p_relationship      text  DEFAULT NULL,
    p_statement_text    text  DEFAULT NULL,
    p_statement_jsonb   jsonb DEFAULT NULL,
    p_source_package_id bigint DEFAULT NULL,
    p_source_locator    jsonb DEFAULT NULL,
    p_sensitivity       text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$claim
        (subject, verb, predicate, object_value, relationship,
         statement_text, statement_jsonb,
         source_package_id, source_locator, sensitivity)
    VALUES (p_subject, p_verb, p_predicate, p_object_value, p_relationship,
            p_statement_text, p_statement_jsonb,
            p_source_package_id, p_source_locator, p_sensitivity)
    RETURNING claim_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_fact(
    p_claim_ids         bigint[],
    p_subject           text  DEFAULT NULL,
    p_verb              text  DEFAULT NULL,
    p_predicate         text  DEFAULT NULL,
    p_object_value      text  DEFAULT NULL,
    p_relationship      text  DEFAULT NULL,
    p_statement_text    text  DEFAULT NULL,
    p_statement_jsonb   jsonb DEFAULT NULL,
    p_verification_scope  text DEFAULT NULL,
    p_verification_method text DEFAULT NULL,
    p_sensitivity       text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id    bigint;
    v_claim bigint;
BEGIN
    INSERT INTO malu$fact
        (subject, verb, predicate, object_value, relationship,
         statement_text, statement_jsonb,
         verification_scope, verification_method, sensitivity)
    VALUES (p_subject, p_verb, p_predicate, p_object_value, p_relationship,
            p_statement_text, p_statement_jsonb,
            p_verification_scope, p_verification_method, p_sensitivity)
    RETURNING fact_id INTO v_id;

    IF p_claim_ids IS NOT NULL THEN
        FOREACH v_claim IN ARRAY p_claim_ids LOOP
            INSERT INTO malu$fact_claim (fact_id, claim_id)
            VALUES (v_id, v_claim);
        END LOOP;
    END IF;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_memory(
    p_memory_kind   text,
    p_title         text  DEFAULT NULL,
    p_summary       text  DEFAULT NULL,
    p_payload_jsonb jsonb DEFAULT '{}'::jsonb,
    p_occurred_at   timestamptz DEFAULT NULL,
    p_occurred_until timestamptz DEFAULT NULL,
    p_sensitivity   text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$memory
        (memory_kind, title, summary, payload_jsonb,
         occurred_at, occurred_until, sensitivity)
    VALUES (p_memory_kind, p_title, p_summary, COALESCE(p_payload_jsonb, '{}'::jsonb),
            p_occurred_at, p_occurred_until, p_sensitivity)
    RETURNING memory_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_episode(
    p_episode_kind  text,
    p_title         text,
    p_summary       text  DEFAULT NULL,
    p_payload_jsonb jsonb DEFAULT '{}'::jsonb,
    p_occurred_at   timestamptz DEFAULT NULL,
    p_occurred_until timestamptz DEFAULT NULL,
    p_sensitivity   text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$episode_object
        (episode_kind, title, summary, payload_jsonb,
         occurred_at, occurred_until, sensitivity)
    VALUES (p_episode_kind, p_title, p_summary, COALESCE(p_payload_jsonb, '{}'::jsonb),
            p_occurred_at, p_occurred_until, p_sensitivity)
    RETURNING episode_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_memory_detail(
    p_detail_kind   text,
    p_parent_mdo_id bigint DEFAULT NULL,
    p_memory_id     bigint DEFAULT NULL,
    p_episode_id    bigint DEFAULT NULL,
    p_ordinal       integer DEFAULT NULL,
    p_title         text   DEFAULT NULL,
    p_body_text     text   DEFAULT NULL,
    p_body_jsonb    jsonb  DEFAULT NULL,
    p_sensitivity   text   DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    IF p_parent_mdo_id IS NULL AND p_memory_id IS NULL AND p_episode_id IS NULL THEN
        RAISE EXCEPTION
          'register_memory_detail: at least one of parent_mdo_id / memory_id / episode_id required'
          USING ERRCODE = 'invalid_parameter_value';
    END IF;
    INSERT INTO malu$memory_detail_object
        (parent_mdo_id, memory_id, episode_id, detail_kind,
         ordinal, title, body_text, body_jsonb, sensitivity)
    VALUES (p_parent_mdo_id, p_memory_id, p_episode_id, p_detail_kind,
            p_ordinal, p_title, p_body_text, p_body_jsonb, p_sensitivity)
    RETURNING mdo_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_relationship_edge(
    p_source_object_type text,
    p_source_object_id   bigint,
    p_target_object_type text,
    p_target_object_id   bigint,
    p_relationship_type  text,
    p_label              text   DEFAULT NULL,
    p_edge_jsonb         jsonb  DEFAULT NULL,
    p_confidence         numeric DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$relationship_edge
        (relationship_type, source_object_type, source_object_id,
         target_object_type, target_object_id,
         label, edge_jsonb, confidence)
    VALUES (p_relationship_type, p_source_object_type, p_source_object_id,
            p_target_object_type, p_target_object_id,
            p_label, p_edge_jsonb, p_confidence)
    RETURNING edge_id INTO v_id;
    RETURN v_id;
END;
$body$;

-- =====================================================================
-- record_derivation — the canonical ledger writer.
--
-- Per CLAUDE.md doctrine: every derived object MUST have a ledger
-- entry. Callers wrap their object creation + this call in one
-- transaction. S2-7 will provide atomic C wrappers.
-- =====================================================================
CREATE FUNCTION record_derivation(
    p_derived_object_type text,
    p_derived_object_id   bigint,
    p_parser_name         text   DEFAULT NULL,
    p_model_alias_id      bigint DEFAULT NULL,
    p_prompt_template_id  bigint DEFAULT NULL,
    p_policy_name         text   DEFAULT NULL,
    p_verifier_name       text   DEFAULT NULL,
    p_model_request_id    bigint DEFAULT NULL,
    p_inputs_jsonb        jsonb  DEFAULT '[]'::jsonb
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id   bigint;
    v_hash text;
BEGIN
    v_hash := encode(sha256(
        convert_to(COALESCE(p_inputs_jsonb, '[]'::jsonb)::text, 'UTF8')
    ), 'hex');

    INSERT INTO malu$derivation_ledger
        (derived_object_type, derived_object_id,
         parser_name, model_alias_id, prompt_template_id,
         policy_name, verifier_name, model_request_id,
         inputs_jsonb, inputs_hash)
    VALUES (p_derived_object_type, p_derived_object_id,
            p_parser_name, p_model_alias_id, p_prompt_template_id,
            p_policy_name, p_verifier_name, p_model_request_id,
            COALESCE(p_inputs_jsonb, '[]'::jsonb), v_hash)
    RETURNING derivation_id INTO v_id;
    RETURN v_id;
END;
$body$;

GRANT EXECUTE ON FUNCTION
    register_source_package(text,bytea,text,jsonb,text,jsonb,timestamptz,text,text),
    register_claim(text,text,text,text,text,text,jsonb,bigint,jsonb,text),
    register_fact(bigint[],text,text,text,text,text,text,jsonb,text,text,text),
    register_memory(text,text,text,jsonb,timestamptz,timestamptz,text),
    register_episode(text,text,text,jsonb,timestamptz,timestamptz,text),
    register_memory_detail(text,bigint,bigint,bigint,integer,text,text,jsonb,text),
    register_relationship_edge(text,bigint,text,bigint,text,text,jsonb,numeric),
    record_derivation(text,bigint,text,bigint,bigint,text,text,bigint,jsonb)
TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- Stage-boundary update.
--
-- stage_boundary_violations() had a hardcoded list that flagged any
-- malu$<stage2>* table as a violation. Now that S2-1 actually installs
-- them, narrow the forbidden list to Stage 3+ only. The Stage 2 names
-- we install (source_package, claim, fact, episode_object, memory,
-- memory_detail_object, relationship_edge, derivation_ledger) are
-- removed; malu$verbatim_archive (S2-2) and malu$governed_object
-- (currently unscoped) remain reserved.
-- =====================================================================
CREATE OR REPLACE FUNCTION stage_boundary_violations()
RETURNS TABLE(object_kind text, object_name text, stage smallint)
LANGUAGE sql STABLE
AS $body$
    WITH forbidden(name, stage) AS (
        VALUES
            ('malu$governed_object'::text,       2::smallint),
            ('malu$verbatim_archive',            2),
            ('malu$valid_time_window',           3),
            ('malu$transaction_time_window',     3),
            ('malu$supersession_edge',           3),
            ('malu$svpor_subject',               3),
            ('malu$svpor_verb',                  3),
            ('malu$svpor_predicate',             3),
            ('malu$maut_score',                  3),
            ('malu$workflow_trace',              5),
            ('malu$generalized_workflow',        5),
            ('malu$procedural_memory_object',    5),
            ('malu$skill_package',               5),
            ('malu$competency_package',          5),
            ('malu$active_memory_pool',          5),
            ('malu$episode_replay',              5),
            ('malu$local_memory_node',           6),
            ('malu$node_sync_record',            6)
    )
    SELECT 'table'::text, c.relname::text, f.stage
    FROM pg_catalog.pg_class c
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    JOIN forbidden f ON f.name = c.relname
    WHERE n.nspname = 'maludb_core'
      AND c.relkind IN ('r','p','v','m')
    ORDER BY f.stage, c.relname;
$body$;

