-- Section: maludb_core--0.15.0--0.16.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.16.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.15.0 → 0.16.0
--
-- Stage 2 — Verbatim Source Archive (S2-2).
--
-- Adds the storage + verification + lifecycle around malu$source_package
-- needed to meet requirements.md §3.6 (Verbatim Source Archive) and
-- §9 Stage 2 ("immutable hash-verified storage, tiered placement,
-- retention/legal-hold metadata").
--
-- New surface:
--   * malu$verbatim_archive          — placement-tier audit row per
--                                       sealed source (inline/hot/warm/
--                                       cold/external)
--   * malu$source_verification       — hash-verification audit log
--   * seal_source_package()          — sets sealed_at; locks content
--   * unseal_source_package()        — admin override; reason required
--   * archive_source_package()       — records archive transition
--   * tombstone_source_package()     — drops content unless legal hold
--   * verify_source_hash()           — recomputes + audits
--   * reingest_source_package()      — verbatim read with verify
--   * source_package_seal_lock_tg    — trigger; rejects content UPDATE
--                                       once sealed_at is set
--
-- Doctrine: once sealed_at is non-NULL, content_bytes / content_text /
-- content_jsonb / content_hash / content_size are immutable to anyone
-- but maludb_memory_admin (via unseal). Tombstone preserves the row
-- but clears content unless legal_hold prevents it.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.16.0'::text $body$;

-- ---------------------------------------------------------------------
-- Relax the S2-1 content-required CHECK on malu$source_package so
-- tombstone_source_package() can NULL the content without violating
-- the constraint. New semantics: at least one of content_bytes /
-- _text / _jsonb must be set OR the row must be tombstoned.
-- ---------------------------------------------------------------------
ALTER TABLE malu$source_package
    DROP CONSTRAINT malu$source_package_check;
ALTER TABLE malu$source_package
    ADD CONSTRAINT malu$source_package_content_or_tombstoned_check
    CHECK (
        content_bytes IS NOT NULL
        OR content_text IS NOT NULL
        OR content_jsonb IS NOT NULL
        OR tombstoned_at IS NOT NULL
    );

-- =====================================================================
-- malu$verbatim_archive
--
-- One row per archive event for a source_package. placement_tier
-- distinguishes where the verbatim bytes actually live:
--   inline   — bytes stay on malu$source_package (default; v1).
--   hot      — duplicated here uncompressed for fast read.
--   warm     — compressed copy here (gzip/zstd).
--   cold     — metadata only; bytes evicted to external_uri.
--   external — managed entirely outside MaluDB; external_uri is the
--              system-of-record pointer.
-- =====================================================================
CREATE TABLE malu$verbatim_archive (
    archive_id            bigserial PRIMARY KEY,
    source_package_id     bigint NOT NULL
        REFERENCES malu$source_package(source_package_id) ON DELETE RESTRICT,
    owner_schema          name NOT NULL DEFAULT current_schema(),
    placement_tier        text NOT NULL DEFAULT 'inline'
        CHECK (placement_tier IN ('inline','hot','warm','cold','external')),
    content_bytes         bytea,
    content_compression   text NOT NULL DEFAULT 'none'
        CHECK (content_compression IN ('none','gzip','zstd')),
    content_size_archived bigint,
    archive_hash          text NOT NULL,
    external_uri          text,
    external_etag         text,
    sealed_at             timestamptz NOT NULL DEFAULT now(),
    superseded_at         timestamptz,
    note                  text,
    CHECK (placement_tier <> 'external' OR external_uri IS NOT NULL),
    CHECK (placement_tier <> 'cold'     OR external_uri IS NOT NULL),
    CHECK (placement_tier NOT IN ('inline','hot') OR content_compression = 'none')
);
CREATE INDEX malu$verbatim_archive_pkg_idx
    ON malu$verbatim_archive(source_package_id);
CREATE INDEX malu$verbatim_archive_tier_idx
    ON malu$verbatim_archive(placement_tier)
    WHERE superseded_at IS NULL;

ALTER TABLE malu$verbatim_archive ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$verbatim_archive
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

-- =====================================================================
-- malu$source_verification
--
-- Audit log for every verify_source_hash() call. Records the expected
-- hash (from the row), the computed hash, whether they matched, and
-- the role that ran the verification.
-- =====================================================================
CREATE TABLE malu$source_verification (
    verification_id      bigserial PRIMARY KEY,
    source_package_id    bigint NOT NULL
        REFERENCES malu$source_package(source_package_id) ON DELETE CASCADE,
    archive_id           bigint
        REFERENCES malu$verbatim_archive(archive_id) ON DELETE SET NULL,
    performed_by         name NOT NULL DEFAULT current_user,
    performed_at         timestamptz NOT NULL DEFAULT now(),
    expected_hash        text NOT NULL,
    computed_hash        text NOT NULL,
    matched              boolean NOT NULL,
    context_note         text
);
CREATE INDEX malu$source_verification_pkg_idx
    ON malu$source_verification(source_package_id, performed_at DESC);
CREATE INDEX malu$source_verification_failed_idx
    ON malu$source_verification(source_package_id) WHERE matched = false;

ALTER TABLE malu$source_verification ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_source ON malu$source_verification
    USING (EXISTS (
        SELECT 1 FROM malu$source_package sp
        WHERE sp.source_package_id = malu$source_verification.source_package_id
          AND sp.owner_schema = current_schema()
    ))
    WITH CHECK (EXISTS (
        SELECT 1 FROM malu$source_package sp
        WHERE sp.source_package_id = malu$source_verification.source_package_id
          AND sp.owner_schema = current_schema()
    ));

GRANT SELECT ON malu$verbatim_archive, malu$source_verification TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$verbatim_archive, malu$source_verification TO
    maludb_memory_admin;
GRANT INSERT ON malu$source_verification TO maludb_memory_executor;

-- =====================================================================
-- Canonical content hash + size — computed identically by
-- register_source_package and verify_source_hash to ensure
-- round-tripping doesn't yield false mismatches.
-- =====================================================================
CREATE FUNCTION _source_canonical_bytes(
    p_bytes bytea, p_text text, p_jsonb jsonb
) RETURNS bytea
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT
        CASE
            WHEN p_bytes IS NOT NULL THEN p_bytes
            WHEN p_text  IS NOT NULL THEN convert_to(p_text, 'UTF8')
            WHEN p_jsonb IS NOT NULL THEN convert_to(p_jsonb::text, 'UTF8')
            ELSE convert_to('', 'UTF8')
        END;
$body$;

-- =====================================================================
-- Immutability trigger.
--
-- Once sealed_at is set, content_bytes / content_text / content_jsonb /
-- content_hash / content_size cannot be modified. The trigger fires on
-- UPDATE and inspects the prior-row sealed_at vs the new-row values.
--
-- maludb_memory_admin can bypass by first calling unseal_source_package()
-- (which writes a verbatim_archive note and clears sealed_at). The
-- trigger does NOT special-case role identity — it enforces the seal
-- as a row-state invariant.
-- =====================================================================
CREATE FUNCTION _source_package_seal_lock() RETURNS trigger
LANGUAGE plpgsql
AS $body$
BEGIN
    IF OLD.sealed_at IS NOT NULL THEN
        IF NEW.content_bytes IS DISTINCT FROM OLD.content_bytes
           OR NEW.content_text IS DISTINCT FROM OLD.content_text
           OR NEW.content_jsonb IS DISTINCT FROM OLD.content_jsonb
           OR NEW.content_hash IS DISTINCT FROM OLD.content_hash
           OR NEW.content_size IS DISTINCT FROM OLD.content_size
           OR NEW.source_type IS DISTINCT FROM OLD.source_type THEN
            RAISE EXCEPTION
              'SOURCE_PACKAGE_SEALED: content of source_package_id=% is sealed at %; call unseal_source_package() first',
              OLD.source_package_id, OLD.sealed_at
              USING ERRCODE = 'object_not_in_prerequisite_state';
        END IF;
    END IF;
    RETURN NEW;
END;
$body$;

CREATE TRIGGER source_package_seal_lock_tg
    BEFORE UPDATE ON malu$source_package
    FOR EACH ROW EXECUTE FUNCTION _source_package_seal_lock();

-- =====================================================================
-- seal_source_package
--
-- Sets sealed_at = now() and writes the corresponding
-- malu$verbatim_archive row (placement_tier='inline' by default).
-- Idempotent: if already sealed, no-op + returns the existing
-- archive_id.
-- =====================================================================
CREATE FUNCTION seal_source_package(
    p_source_package_id bigint,
    p_placement_tier    text DEFAULT 'inline',
    p_external_uri      text DEFAULT NULL,
    p_note              text DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_sp          malu$source_package%ROWTYPE;
    v_archive_id  bigint;
    v_size        bigint;
BEGIN
    SELECT * INTO v_sp FROM malu$source_package
     WHERE source_package_id = p_source_package_id;
    IF v_sp.source_package_id IS NULL THEN
        RAISE EXCEPTION 'unknown source_package_id: %', p_source_package_id
            USING ERRCODE = 'no_data_found';
    END IF;

    IF v_sp.sealed_at IS NOT NULL THEN
        -- Already sealed; surface the current archive_id.
        SELECT archive_id INTO v_archive_id FROM malu$verbatim_archive
         WHERE source_package_id = p_source_package_id
           AND superseded_at IS NULL
         ORDER BY sealed_at DESC LIMIT 1;
        RETURN v_archive_id;
    END IF;

    UPDATE malu$source_package SET sealed_at = now()
     WHERE source_package_id = p_source_package_id;

    v_size := octet_length(_source_canonical_bytes(
                  v_sp.content_bytes, v_sp.content_text, v_sp.content_jsonb));

    INSERT INTO malu$verbatim_archive
        (source_package_id, placement_tier, content_size_archived,
         archive_hash, external_uri, note)
    VALUES (p_source_package_id, p_placement_tier, v_size,
            v_sp.content_hash, p_external_uri, p_note)
    RETURNING archive_id INTO v_archive_id;

    RETURN v_archive_id;
END;
$body$;

-- =====================================================================
-- unseal_source_package — admin override. Records the unseal as a
-- verbatim_archive note row (placement_tier=inline + note=reason) so
-- the seal/unseal history stays auditable.
-- =====================================================================
CREATE FUNCTION unseal_source_package(
    p_source_package_id bigint,
    p_reason            text
) RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    IF p_reason IS NULL OR p_reason = '' THEN
        RAISE EXCEPTION 'unseal_source_package: reason required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    PERFORM 1 FROM malu$source_package
     WHERE source_package_id = p_source_package_id AND sealed_at IS NOT NULL;
    IF NOT FOUND THEN
        RAISE EXCEPTION
          'source_package_id=% is not currently sealed',
          p_source_package_id
          USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    UPDATE malu$verbatim_archive
       SET superseded_at = now()
     WHERE source_package_id = p_source_package_id
       AND superseded_at IS NULL;

    UPDATE malu$source_package SET sealed_at = NULL
     WHERE source_package_id = p_source_package_id;

    INSERT INTO malu$verbatim_archive
        (source_package_id, placement_tier, archive_hash, note, sealed_at, superseded_at)
    VALUES (p_source_package_id, 'inline',
            (SELECT content_hash FROM malu$source_package WHERE source_package_id = p_source_package_id),
            'unseal: ' || p_reason,
            now(), now());
END;
$body$;

-- =====================================================================
-- archive_source_package — sets archived_at, records a new
-- verbatim_archive row at the requested placement_tier. The row's
-- content_bytes column may carry a (possibly compressed) snapshot
-- when the operator wants tier-local storage; for inline/external
-- tiers it's NULL.
-- =====================================================================
CREATE FUNCTION archive_source_package(
    p_source_package_id bigint,
    p_placement_tier    text,
    p_content_bytes     bytea  DEFAULT NULL,
    p_content_compression text DEFAULT 'none',
    p_external_uri      text   DEFAULT NULL,
    p_external_etag     text   DEFAULT NULL,
    p_note              text   DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_sp          malu$source_package%ROWTYPE;
    v_archive_id  bigint;
BEGIN
    SELECT * INTO v_sp FROM malu$source_package
     WHERE source_package_id = p_source_package_id;
    IF v_sp.source_package_id IS NULL THEN
        RAISE EXCEPTION 'unknown source_package_id: %', p_source_package_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_sp.sealed_at IS NULL THEN
        RAISE EXCEPTION
          'archive_source_package: seal first (source_package_id=%)',
          p_source_package_id
          USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    UPDATE malu$verbatim_archive
       SET superseded_at = now()
     WHERE source_package_id = p_source_package_id
       AND superseded_at IS NULL;

    INSERT INTO malu$verbatim_archive
        (source_package_id, placement_tier, content_bytes,
         content_compression, content_size_archived, archive_hash,
         external_uri, external_etag, note)
    VALUES (p_source_package_id, p_placement_tier, p_content_bytes,
            p_content_compression,
            CASE WHEN p_content_bytes IS NOT NULL
                 THEN octet_length(p_content_bytes) END,
            v_sp.content_hash, p_external_uri, p_external_etag, p_note)
    RETURNING archive_id INTO v_archive_id;

    UPDATE malu$source_package SET archived_at = now()
     WHERE source_package_id = p_source_package_id;

    RETURN v_archive_id;
END;
$body$;

-- =====================================================================
-- tombstone_source_package — sets tombstoned_at. If the row is NOT on
-- legal hold, NULL out the inline content + any non-cold archive rows.
-- Hash + size stay intact for audit. legal_hold rows keep their content
-- (the whole point of legal hold).
-- =====================================================================
CREATE FUNCTION tombstone_source_package(
    p_source_package_id bigint,
    p_reason            text
) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE
    v_sp malu$source_package%ROWTYPE;
BEGIN
    IF p_reason IS NULL OR p_reason = '' THEN
        RAISE EXCEPTION 'tombstone_source_package: reason required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_sp FROM malu$source_package
     WHERE source_package_id = p_source_package_id;
    IF v_sp.source_package_id IS NULL THEN
        RAISE EXCEPTION 'unknown source_package_id: %', p_source_package_id
            USING ERRCODE = 'no_data_found';
    END IF;

    -- Lift the seal so the content-immutability trigger lets the
    -- tombstone NULL pass through. Record the seal lift in the
    -- archive log.
    UPDATE malu$source_package
       SET sealed_at     = NULL,
           tombstoned_at = now()
     WHERE source_package_id = p_source_package_id;

    INSERT INTO malu$verbatim_archive
        (source_package_id, placement_tier, archive_hash, note, sealed_at, superseded_at)
    VALUES (p_source_package_id, 'inline', v_sp.content_hash,
            'tombstone: ' || p_reason, now(), now());

    IF NOT v_sp.legal_hold THEN
        UPDATE malu$source_package
           SET content_bytes = NULL,
               content_text  = NULL,
               content_jsonb = NULL
         WHERE source_package_id = p_source_package_id;
        -- Re-seal the now-empty row.
        UPDATE malu$source_package SET sealed_at = now()
         WHERE source_package_id = p_source_package_id;
        -- Mark non-external archives as superseded so re-ingest fails
        -- loudly (the inline / hot / warm copies just got dropped).
        UPDATE malu$verbatim_archive
           SET superseded_at = now()
         WHERE source_package_id = p_source_package_id
           AND superseded_at    IS NULL
           AND placement_tier   IN ('inline','hot','warm');
    END IF;
END;
$body$;

-- =====================================================================
-- verify_source_hash — recompute the content hash from the inline
-- payload and compare to the stored value. Writes a malu$source_
-- verification audit row regardless of outcome.
--
-- Returns a (matched, expected, computed) composite. The function
-- never raises on mismatch — operators decide how to react (legal
-- hold, alert, reseal from archive, etc.).
-- =====================================================================
CREATE TYPE malu$verify_result AS (
    matched          boolean,
    expected_hash    text,
    computed_hash    text,
    verification_id  bigint
);

CREATE FUNCTION verify_source_hash(
    p_source_package_id bigint,
    p_context_note      text DEFAULT NULL
) RETURNS malu$verify_result
LANGUAGE plpgsql
AS $body$
DECLARE
    v_sp        malu$source_package%ROWTYPE;
    v_canon     bytea;
    v_computed  text;
    v_id        bigint;
    v_archive_id bigint;
    v_matched   boolean;
BEGIN
    SELECT * INTO v_sp FROM malu$source_package
     WHERE source_package_id = p_source_package_id;
    IF v_sp.source_package_id IS NULL THEN
        RAISE EXCEPTION 'unknown source_package_id: %', p_source_package_id
            USING ERRCODE = 'no_data_found';
    END IF;

    v_canon    := _source_canonical_bytes(v_sp.content_bytes,
                                          v_sp.content_text,
                                          v_sp.content_jsonb);
    v_computed := encode(sha256(v_canon), 'hex');
    v_matched  := (v_computed = v_sp.content_hash);

    SELECT archive_id INTO v_archive_id FROM malu$verbatim_archive
     WHERE source_package_id = p_source_package_id
       AND superseded_at IS NULL
     ORDER BY sealed_at DESC LIMIT 1;

    INSERT INTO malu$source_verification
        (source_package_id, archive_id, expected_hash, computed_hash,
         matched, context_note)
    VALUES (p_source_package_id, v_archive_id, v_sp.content_hash,
            v_computed, v_matched, p_context_note)
    RETURNING verification_id INTO v_id;

    RETURN ROW(v_matched, v_sp.content_hash, v_computed, v_id)::malu$verify_result;
END;
$body$;

-- =====================================================================
-- reingest_source_package — the canonical verbatim-read API. Per
-- requirements.md §3.6, future extraction/summarization/embedding
-- models call this to operate on the original evidence with hash
-- verification.
--
-- p_verify=true (default) runs verify_source_hash() first and raises
-- on mismatch. p_verify=false skips verification for read-heavy
-- workloads where the operator already trusts the substrate.
-- =====================================================================
CREATE TYPE malu$reingest_result AS (
    content_bytes  bytea,
    content_text   text,
    content_jsonb  jsonb,
    content_hash   text,
    source_type    text,
    media_type     text,
    sealed_at      timestamptz
);

CREATE FUNCTION reingest_source_package(
    p_source_package_id bigint,
    p_verify            boolean DEFAULT true
) RETURNS malu$reingest_result
LANGUAGE plpgsql
AS $body$
DECLARE
    v_sp     malu$source_package%ROWTYPE;
    v_check  malu$verify_result;
BEGIN
    SELECT * INTO v_sp FROM malu$source_package
     WHERE source_package_id = p_source_package_id;
    IF v_sp.source_package_id IS NULL THEN
        RAISE EXCEPTION 'unknown source_package_id: %', p_source_package_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_sp.tombstoned_at IS NOT NULL
       AND v_sp.content_bytes IS NULL
       AND v_sp.content_text  IS NULL
       AND v_sp.content_jsonb IS NULL THEN
        RAISE EXCEPTION
          'SOURCE_TOMBSTONED: source_package_id=% content was tombstoned at %',
          p_source_package_id, v_sp.tombstoned_at
          USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    IF p_verify THEN
        v_check := verify_source_hash(p_source_package_id, 'reingest');
        IF NOT v_check.matched THEN
            RAISE EXCEPTION
              'SOURCE_HASH_MISMATCH: source_package_id=% expected=% computed=%',
              p_source_package_id, v_check.expected_hash, v_check.computed_hash
              USING ERRCODE = 'data_corrupted';
        END IF;
    END IF;

    RETURN ROW(v_sp.content_bytes, v_sp.content_text, v_sp.content_jsonb,
               v_sp.content_hash, v_sp.source_type, v_sp.media_type,
               v_sp.sealed_at)::malu$reingest_result;
END;
$body$;

-- =====================================================================
-- _validate_source_locator — sanity-check the source_locator JSONB
-- structure on malu$claim. Recognised keys must be the expected type;
-- unknown keys are allowed (forward-compat). Returns true on valid;
-- raises on type mismatch.
--
-- Recognised keys (§3.6 reference model):
--   document_id        text
--   timestamp          text (ISO 8601)
--   authorship         text
--   page_no            integer
--   line_no            integer
--   byte_offset        integer
--   byte_length        integer
--   message_id         text
--   transcript_offset  integer
--   api_record_id      text
--   source_cursor      text
-- =====================================================================
CREATE FUNCTION _validate_source_locator(p_locator jsonb) RETURNS boolean
LANGUAGE plpgsql IMMUTABLE
AS $body$
DECLARE
    v_int_keys constant text[] := ARRAY[
        'page_no','line_no','byte_offset','byte_length','transcript_offset'];
    v_txt_keys constant text[] := ARRAY[
        'document_id','timestamp','authorship','message_id','api_record_id','source_cursor'];
    k text;
BEGIN
    IF p_locator IS NULL THEN RETURN true; END IF;
    IF jsonb_typeof(p_locator) <> 'object' THEN
        RAISE EXCEPTION 'source_locator must be a JSON object, got %', jsonb_typeof(p_locator)
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    FOREACH k IN ARRAY v_int_keys LOOP
        IF p_locator ? k AND jsonb_typeof(p_locator->k) NOT IN ('number','null') THEN
            RAISE EXCEPTION 'source_locator.% must be an integer, got %',
                k, jsonb_typeof(p_locator->k)
                USING ERRCODE = 'invalid_parameter_value';
        END IF;
    END LOOP;
    FOREACH k IN ARRAY v_txt_keys LOOP
        IF p_locator ? k AND jsonb_typeof(p_locator->k) NOT IN ('string','null') THEN
            RAISE EXCEPTION 'source_locator.% must be a string, got %',
                k, jsonb_typeof(p_locator->k)
                USING ERRCODE = 'invalid_parameter_value';
        END IF;
    END LOOP;
    RETURN true;
END;
$body$;

GRANT EXECUTE ON FUNCTION
    seal_source_package(bigint, text, text, text),
    archive_source_package(bigint, text, bytea, text, text, text, text),
    tombstone_source_package(bigint, text),
    verify_source_hash(bigint, text),
    reingest_source_package(bigint, boolean),
    _validate_source_locator(jsonb)
TO maludb_memory_admin, maludb_memory_executor;

-- unseal is admin-only.
GRANT EXECUTE ON FUNCTION unseal_source_package(bigint, text)
TO maludb_memory_admin;

-- =====================================================================
-- Stage-boundary update. S2-2 installs malu$verbatim_archive — remove
-- it from the forbidden list. malu$governed_object stays reserved.
-- =====================================================================
CREATE OR REPLACE FUNCTION stage_boundary_violations()
RETURNS TABLE(object_kind text, object_name text, stage smallint)
LANGUAGE sql STABLE
AS $body$
    WITH forbidden(name, stage) AS (
        VALUES
            ('malu$governed_object'::text,       2::smallint),
            ('malu$valid_time_window',           3),
            ('malu$transaction_time_window',     3),
            ('malu$supersession_edge',           3),
            ('malu$svpor_subject',               3),
            ('malu$svpor_verb',                  3),
            ('malu$svpor_predicate',             3),
            ('malu$maut_score',                  3),
            ('malu$workflow_trace',              5),
            ('malu$generalized_workflow',        5),
            ('malu$procedural_memory_object',    5),
            ('malu$skill_package',               5),
            ('malu$competency_package',          5),
            ('malu$active_memory_pool',          5),
            ('malu$episode_replay',              5),
            ('malu$local_memory_node',           6),
            ('malu$node_sync_record',            6)
    )
    SELECT 'table'::text, c.relname::text, f.stage
    FROM pg_catalog.pg_class c
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    JOIN forbidden f ON f.name = c.relname
    WHERE n.nspname = 'maludb_core'
      AND c.relkind IN ('r','p','v','m')
    ORDER BY f.stage, c.relname;
$body$;

-- ============================================================
-- Section: maludb_core--0.16.0--0.17.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.17.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.16.0 → 0.17.0
--
-- Stage 2 — Recursive Memory Detail Object addressing (S2-4).
--
-- Per requirements.md §3.7 Memory Detail Objects MUST be:
--   * addressable independently of their parent memory
--   * recursively containable
--   * depth-limited expansion supported at query time
--
-- The S2-1 table already has the structural recursion (parent_mdo_id
-- self-reference + memory_id/episode_id top-level attach). S2-4 adds:
--
--   * mdo_uri  — stable generated column "mdo://<schema>/<id>",
--                independent of parent. Unique index for O(log n)
--                URI → row lookup.
--   * mdo_resolve(uri)        → bigint
--   * mdo_ancestors(mdo_id)   → SETOF chain rows (0 = self, 1 = parent, ...)
--   * mdo_descendants(mdo_id, max_depth) → SETOF subtree rows with
--                ordinal_path. NULL max_depth = unbounded.
--   * mdo_root(mdo_id)        → (root_kind, root_id, mdo_chain bigint[])
--   * mdo_subtree_json(mdo_id, max_depth=5) → jsonb tree for API surfaces
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.17.0'::text $body$;

-- ---------------------------------------------------------------------
-- Stable URI column. Generated STORED so the value lives next to the
-- row data and lookups by URI hit a unique index.
-- ---------------------------------------------------------------------
ALTER TABLE malu$memory_detail_object
    ADD COLUMN mdo_uri text GENERATED ALWAYS AS
        ('mdo://' || owner_schema || '/' || mdo_id::text) STORED;

CREATE UNIQUE INDEX malu$mdo_uri_idx
    ON malu$memory_detail_object(mdo_uri);

-- ---------------------------------------------------------------------
-- mdo_resolve(uri) → bigint
--
-- Parses a mdo:// URI and returns the matching mdo_id (subject to RLS
-- on the underlying table). Raises invalid_parameter_value on
-- malformed URIs and no_data_found when the row isn't accessible.
-- ---------------------------------------------------------------------
CREATE FUNCTION mdo_resolve(p_uri text) RETURNS bigint
LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    v_parts  text[];
    v_schema text;
    v_id     bigint;
BEGIN
    IF p_uri IS NULL OR p_uri !~ '^mdo://[^/]+/[0-9]+$' THEN
        RAISE EXCEPTION 'invalid mdo URI: %', COALESCE(p_uri, '<null>')
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    v_parts  := regexp_match(p_uri, '^mdo://([^/]+)/([0-9]+)$');
    v_schema := v_parts[1];
    v_id     := v_parts[2]::bigint;

    PERFORM 1 FROM malu$memory_detail_object
     WHERE mdo_id = v_id AND owner_schema = v_schema::name;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'MDO not found or not visible: %', p_uri
            USING ERRCODE = 'no_data_found';
    END IF;
    RETURN v_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- mdo_ancestors(mdo_id) → SETOF (mdo_id, parent_mdo_id, depth,
--                                detail_kind, title)
--
-- Walks the parent chain upward. depth=0 is the input row itself;
-- depth=1 is its parent_mdo, etc. Terminates when parent_mdo_id is
-- NULL (top-level MDO attached directly to a memory or episode).
-- ---------------------------------------------------------------------
CREATE FUNCTION mdo_ancestors(p_mdo_id bigint) RETURNS TABLE (
    mdo_id        bigint,
    parent_mdo_id bigint,
    depth         integer,
    detail_kind   text,
    title         text
) LANGUAGE sql STABLE
AS $body$
    WITH RECURSIVE walk AS (
        SELECT m.mdo_id, m.parent_mdo_id, 0::integer AS depth,
               m.detail_kind, m.title
        FROM malu$memory_detail_object m
        WHERE m.mdo_id = p_mdo_id
        UNION ALL
        SELECT m.mdo_id, m.parent_mdo_id, w.depth + 1,
               m.detail_kind, m.title
        FROM walk w
        JOIN malu$memory_detail_object m ON m.mdo_id = w.parent_mdo_id
    )
    SELECT mdo_id, parent_mdo_id, depth, detail_kind, title
    FROM walk
    ORDER BY depth;
$body$;

-- ---------------------------------------------------------------------
-- mdo_descendants(mdo_id, max_depth=NULL) →
--     SETOF (mdo_id, parent_mdo_id, depth, ordinal_path,
--            detail_kind, title)
--
-- Walks the subtree downward. depth=0 is the input row itself.
-- ordinal_path is a dotted ordinal chain like "1.2.3"; NULLs in the
-- chain render as "?" so the path stays human-scannable. Pass
-- max_depth to bound the recursion (None = unbounded).
-- ---------------------------------------------------------------------
CREATE FUNCTION mdo_descendants(
    p_mdo_id    bigint,
    p_max_depth integer DEFAULT NULL
) RETURNS TABLE (
    mdo_id        bigint,
    parent_mdo_id bigint,
    depth         integer,
    ordinal_path  text,
    detail_kind   text,
    title         text
) LANGUAGE sql STABLE
AS $body$
    WITH RECURSIVE walk AS (
        SELECT m.mdo_id, m.parent_mdo_id, 0::integer AS depth,
               COALESCE(m.ordinal::text, '?') AS ordinal_path,
               m.detail_kind, m.title
        FROM malu$memory_detail_object m
        WHERE m.mdo_id = p_mdo_id
        UNION ALL
        SELECT c.mdo_id, c.parent_mdo_id, w.depth + 1,
               w.ordinal_path || '.' || COALESCE(c.ordinal::text, '?'),
               c.detail_kind, c.title
        FROM walk w
        JOIN malu$memory_detail_object c ON c.parent_mdo_id = w.mdo_id
        WHERE p_max_depth IS NULL OR w.depth + 1 <= p_max_depth
    )
    SELECT mdo_id, parent_mdo_id, depth, ordinal_path, detail_kind, title
    FROM walk
    ORDER BY ordinal_path, mdo_id;
$body$;

-- ---------------------------------------------------------------------
-- mdo_root(mdo_id) → (root_kind, root_id, mdo_chain bigint[])
--
-- Identifies the top-level owner of the chain (memory, episode_object,
-- or 'orphan' if the chain top has neither). mdo_chain is the
-- ordered ID list from root MDO down to leaf — `mdo_chain[1]` is the
-- top-most MDO. Useful for breadcrumbs and replay seed selection.
-- ---------------------------------------------------------------------
CREATE TYPE malu$mdo_root_result AS (
    root_kind  text,
    root_id    bigint,
    mdo_chain  bigint[]
);

CREATE FUNCTION mdo_root(p_mdo_id bigint) RETURNS malu$mdo_root_result
LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    v_top_id    bigint;
    v_chain     bigint[];
    v_memory_id bigint;
    v_episode_id bigint;
    v_kind      text;
BEGIN
    SELECT array_agg(a.mdo_id ORDER BY a.depth DESC)
    INTO v_chain
    FROM mdo_ancestors(p_mdo_id) a;

    IF v_chain IS NULL OR array_length(v_chain, 1) IS NULL THEN
        RAISE EXCEPTION 'unknown mdo_id: %', p_mdo_id
            USING ERRCODE = 'no_data_found';
    END IF;

    v_top_id := v_chain[1];
    SELECT memory_id, episode_id
    INTO v_memory_id, v_episode_id
    FROM malu$memory_detail_object WHERE mdo_id = v_top_id;

    IF v_memory_id  IS NOT NULL THEN v_kind := 'memory';
    ELSIF v_episode_id IS NOT NULL THEN v_kind := 'episode_object';
    ELSE v_kind := 'orphan';
    END IF;

    RETURN ROW(
        v_kind,
        COALESCE(v_memory_id, v_episode_id),
        v_chain
    )::malu$mdo_root_result;
END;
$body$;

-- ---------------------------------------------------------------------
-- mdo_subtree_json(mdo_id, max_depth=5) → jsonb
--
-- Tree-shaped JSON for API surfaces. Each node carries:
--   { mdo_id, mdo_uri, detail_kind, ordinal, title, body_text,
--     body_jsonb, children: [...] }
--
-- Implemented bottom-up: assemble each node's `children` array first
-- (because PG's jsonb_object_agg / nested aggregation is awkward),
-- then walk up. Single recursive CTE plus a final aggregation pass.
-- ---------------------------------------------------------------------
CREATE FUNCTION mdo_subtree_json(
    p_mdo_id    bigint,
    p_max_depth integer DEFAULT 5
) RETURNS jsonb
LANGUAGE sql STABLE
AS $body$
    WITH RECURSIVE walk AS (
        SELECT m.mdo_id, m.parent_mdo_id, 0::integer AS depth,
               m.mdo_uri, m.detail_kind, m.ordinal, m.title,
               m.body_text, m.body_jsonb
        FROM malu$memory_detail_object m
        WHERE m.mdo_id = p_mdo_id
        UNION ALL
        SELECT c.mdo_id, c.parent_mdo_id, w.depth + 1,
               c.mdo_uri, c.detail_kind, c.ordinal, c.title,
               c.body_text, c.body_jsonb
        FROM walk w
        JOIN malu$memory_detail_object c ON c.parent_mdo_id = w.mdo_id
        WHERE w.depth + 1 <= p_max_depth
    ),
    rev AS (
        -- Build each node's JSON, including its children — process
        -- deepest first so children's JSON is ready when the parent
        -- aggregates them. Materialize via a CTE expression with a
        -- LATERAL subquery that re-walks the partial subtree.
        SELECT w.mdo_id, w.parent_mdo_id, w.depth,
               jsonb_build_object(
                   'mdo_id',      w.mdo_id,
                   'mdo_uri',     w.mdo_uri,
                   'detail_kind', w.detail_kind,
                   'ordinal',     w.ordinal,
                   'title',       w.title,
                   'body_text',   w.body_text,
                   'body_jsonb',  w.body_jsonb,
                   'children',    COALESCE(
                       (SELECT jsonb_agg(
                                   mdo_subtree_json(c.mdo_id, p_max_depth - w.depth - 1)
                                   ORDER BY c.ordinal NULLS LAST, c.mdo_id)
                        FROM malu$memory_detail_object c
                        WHERE c.parent_mdo_id = w.mdo_id
                          AND w.depth + 1 <= p_max_depth),
                       '[]'::jsonb)
               ) AS node_json
        FROM walk w
        WHERE w.depth = 0
    )
    SELECT node_json FROM rev LIMIT 1;
$body$;

GRANT EXECUTE ON FUNCTION
    mdo_resolve(text),
    mdo_ancestors(bigint),
    mdo_descendants(bigint, integer),
    mdo_root(bigint),
    mdo_subtree_json(bigint, integer)
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.17.0--0.18.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.18.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.17.0 → 0.18.0
--
-- Stage 2 — Cross-tenant relationship edges + malu$object_grant
-- (S2-5).
--
-- Per CLAUDE.md tenancy doc: cross-tenant malu$relationship_edge rows
-- are owned by the schema that recorded the edge; cross-tenant
-- visibility requires malu$object_grant entries.
--
-- Implementation: add a second PERMISSIVE RLS policy to each Stage 2
-- table. RLS combines permissive policies with OR, so the existing
-- tenant_owner policy stays in force and the new grant_visibility
-- policy expands the visible set when explicit grants exist.
--
-- malu$object_grant rows live in the granter's schema (granted_by_
-- schema = current_schema()). The grant points at a specific
-- (object_type, object_id) and a target schema (granted_to_schema)
-- with a grant_level ∈ {read, write, full}. Time-bounded via
-- expires_at; revoked via revoked_at.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.18.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$object_grant
-- ---------------------------------------------------------------------
CREATE TABLE malu$object_grant (
    grant_id            bigserial PRIMARY KEY,
    object_type         text NOT NULL,
    object_id           bigint NOT NULL,
    granted_by_schema   name NOT NULL DEFAULT current_schema(),
    granted_to_schema   name NOT NULL,
    grant_level         text NOT NULL DEFAULT 'read'
        CHECK (grant_level IN ('read','write','full')),
    granted_at          timestamptz NOT NULL DEFAULT now(),
    expires_at          timestamptz,
    revoked_at          timestamptz,
    note                text,
    CHECK (object_type IN
        ('source_package','claim','fact','memory','episode_object',
         'memory_detail_object','relationship_edge','derivation_ledger')),
    -- A given grantee can only have one active grant per object —
    -- raise the level instead of stacking. Revoked rows are kept for
    -- audit; partial unique index ensures only one active row.
    CONSTRAINT malu$object_grant_unique_active
        EXCLUDE (object_type WITH =, object_id WITH =, granted_to_schema WITH =)
        WHERE (revoked_at IS NULL)
);

CREATE INDEX malu$object_grant_target_idx
    ON malu$object_grant(object_type, object_id, granted_to_schema)
    WHERE revoked_at IS NULL;

CREATE INDEX malu$object_grant_grantee_idx
    ON malu$object_grant(granted_to_schema, object_type)
    WHERE revoked_at IS NULL;

CREATE INDEX malu$object_grant_granter_idx
    ON malu$object_grant(granted_by_schema, object_type)
    WHERE revoked_at IS NULL;

-- ---------------------------------------------------------------------
-- RLS on malu$object_grant: granter sees/manages their own grants;
-- grantee sees the grants pointed at them (read-only).
-- ---------------------------------------------------------------------
ALTER TABLE malu$object_grant ENABLE ROW LEVEL SECURITY;

CREATE POLICY granter_owns ON malu$object_grant
    USING (granted_by_schema = current_schema())
    WITH CHECK (granted_by_schema = current_schema());

CREATE POLICY grantee_can_see ON malu$object_grant
    AS PERMISSIVE FOR SELECT
    USING (granted_to_schema = current_schema());

GRANT SELECT ON malu$object_grant TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$object_grant TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$object_grant_grant_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- ---------------------------------------------------------------------
-- _grant_active(p_object_type, p_object_id, p_grant_levels[]) → bool
--
-- Helper for RLS USING/WITH CHECK clauses. Returns true when an
-- active grant exists from any schema to current_schema() for the
-- given object at one of the requested levels.
-- ---------------------------------------------------------------------
CREATE FUNCTION _grant_active(
    p_object_type  text,
    p_object_id    bigint,
    p_grant_levels text[]
) RETURNS boolean
LANGUAGE sql STABLE
AS $body$
    SELECT EXISTS (
        SELECT 1 FROM malu$object_grant g
        WHERE g.object_type = p_object_type
          AND g.object_id   = p_object_id
          AND g.granted_to_schema = current_schema()
          AND g.grant_level = ANY(p_grant_levels)
          AND g.revoked_at IS NULL
          AND (g.expires_at IS NULL OR g.expires_at > now())
    );
$body$;

-- =====================================================================
-- Permissive RLS policies on the eight Stage 2 governed tables.
-- These OR with the existing tenant_owner policies — never replace.
--
-- USING clause: read access requires any grant level.
-- WITH CHECK clause: write requires grant_level ∈ {write, full}.
--   DELETE is enforced via the same WITH CHECK (PG checks WITH CHECK
--   on UPDATE; DELETE uses USING only — so we restrict DELETE via
--   the underlying table GRANT, not this policy).
-- =====================================================================

CREATE POLICY grant_visibility ON malu$source_package
    AS PERMISSIVE
    USING (_grant_active('source_package', source_package_id,
                         ARRAY['read','write','full']))
    WITH CHECK (_grant_active('source_package', source_package_id,
                              ARRAY['write','full']));

CREATE POLICY grant_visibility ON malu$claim
    AS PERMISSIVE
    USING (_grant_active('claim', claim_id, ARRAY['read','write','full']))
    WITH CHECK (_grant_active('claim', claim_id, ARRAY['write','full']));

CREATE POLICY grant_visibility ON malu$fact
    AS PERMISSIVE
    USING (_grant_active('fact', fact_id, ARRAY['read','write','full']))
    WITH CHECK (_grant_active('fact', fact_id, ARRAY['write','full']));

CREATE POLICY grant_via_fact ON malu$fact_claim
    AS PERMISSIVE
    USING (_grant_active('fact', fact_id, ARRAY['read','write','full']))
    WITH CHECK (_grant_active('fact', fact_id, ARRAY['write','full']));

CREATE POLICY grant_visibility ON malu$memory
    AS PERMISSIVE
    USING (_grant_active('memory', memory_id, ARRAY['read','write','full']))
    WITH CHECK (_grant_active('memory', memory_id, ARRAY['write','full']));

CREATE POLICY grant_visibility ON malu$episode_object
    AS PERMISSIVE
    USING (_grant_active('episode_object', episode_id,
                         ARRAY['read','write','full']))
    WITH CHECK (_grant_active('episode_object', episode_id,
                              ARRAY['write','full']));

CREATE POLICY grant_visibility ON malu$memory_detail_object
    AS PERMISSIVE
    USING (_grant_active('memory_detail_object', mdo_id,
                         ARRAY['read','write','full']))
    WITH CHECK (_grant_active('memory_detail_object', mdo_id,
                              ARRAY['write','full']));

CREATE POLICY grant_visibility ON malu$relationship_edge
    AS PERMISSIVE
    USING (_grant_active('relationship_edge', edge_id,
                         ARRAY['read','write','full']))
    WITH CHECK (_grant_active('relationship_edge', edge_id,
                              ARRAY['write','full']));

CREATE POLICY grant_visibility ON malu$derivation_ledger
    AS PERMISSIVE
    USING (_grant_active('derivation_ledger', derivation_id,
                         ARRAY['read','write','full']))
    WITH CHECK (_grant_active('derivation_ledger', derivation_id,
                              ARRAY['write','full']));

-- ---------------------------------------------------------------------
-- grant_object_access(object_type, object_id, granted_to_schema,
--                     grant_level='read', expires_at=NULL, note=NULL)
--   → bigint grant_id
--
-- Idempotent for active grants: if a non-revoked grant already exists
-- to the same (object, schema) pair, the level/expiry/note are
-- updated and the existing grant_id is returned. New target schemas
-- always create a new row.
--
-- The granter must own (or have a 'full' grant on) the object.
-- Enforcement happens via the table's RLS: if current_schema() can't
-- see the source row, the existence-check fails.
-- ---------------------------------------------------------------------
CREATE FUNCTION grant_object_access(
    p_object_type      text,
    p_object_id        bigint,
    p_granted_to_schema name,
    p_grant_level      text       DEFAULT 'read',
    p_expires_at       timestamptz DEFAULT NULL,
    p_note             text       DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id     bigint;
    v_exists boolean;
BEGIN
    IF p_grant_level NOT IN ('read','write','full') THEN
        RAISE EXCEPTION 'grant_object_access: bad level %', p_grant_level
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    IF p_granted_to_schema IS NULL OR p_granted_to_schema = current_schema() THEN
        RAISE EXCEPTION 'grant_object_access: must grant to a different schema'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    -- Existence check uses RLS: if the granter can't see the row,
    -- the EXISTS yields false and we refuse.
    EXECUTE format(
        'SELECT EXISTS (SELECT 1 FROM maludb_core.%I WHERE %I = $1)',
        CASE p_object_type
            WHEN 'source_package'        THEN 'malu$source_package'
            WHEN 'claim'                 THEN 'malu$claim'
            WHEN 'fact'                  THEN 'malu$fact'
            WHEN 'memory'                THEN 'malu$memory'
            WHEN 'episode_object'        THEN 'malu$episode_object'
            WHEN 'memory_detail_object'  THEN 'malu$memory_detail_object'
            WHEN 'relationship_edge'     THEN 'malu$relationship_edge'
            WHEN 'derivation_ledger'     THEN 'malu$derivation_ledger'
        END,
        CASE p_object_type
            WHEN 'source_package'        THEN 'source_package_id'
            WHEN 'claim'                 THEN 'claim_id'
            WHEN 'fact'                  THEN 'fact_id'
            WHEN 'memory'                THEN 'memory_id'
            WHEN 'episode_object'        THEN 'episode_id'
            WHEN 'memory_detail_object'  THEN 'mdo_id'
            WHEN 'relationship_edge'     THEN 'edge_id'
            WHEN 'derivation_ledger'     THEN 'derivation_id'
        END
    ) INTO v_exists USING p_object_id;
    IF NOT v_exists THEN
        RAISE EXCEPTION 'grant_object_access: %s id=% not visible to current schema',
            p_object_type, p_object_id
            USING ERRCODE = 'no_data_found';
    END IF;

    -- Upsert by (object_type, object_id, granted_to_schema) for the
    -- active row.
    UPDATE malu$object_grant
       SET grant_level = p_grant_level,
           expires_at  = p_expires_at,
           note        = COALESCE(p_note, note),
           granted_at  = now()
     WHERE object_type        = p_object_type
       AND object_id          = p_object_id
       AND granted_to_schema  = p_granted_to_schema
       AND revoked_at         IS NULL
     RETURNING grant_id INTO v_id;
    IF FOUND THEN
        RETURN v_id;
    END IF;

    INSERT INTO malu$object_grant
        (object_type, object_id, granted_to_schema,
         grant_level, expires_at, note)
    VALUES (p_object_type, p_object_id, p_granted_to_schema,
            p_grant_level, p_expires_at, p_note)
    RETURNING grant_id INTO v_id;
    RETURN v_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- revoke_object_grant(grant_id, reason=NULL) → void
--
-- Marks the grant revoked. Reason is appended to the note column for
-- audit; the row stays for history.
-- ---------------------------------------------------------------------
CREATE FUNCTION revoke_object_grant(
    p_grant_id bigint,
    p_reason   text DEFAULT NULL
) RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    UPDATE malu$object_grant
       SET revoked_at = now(),
           note       = COALESCE(note || E'\n', '') ||
                        'revoked: ' || COALESCE(p_reason, 'no reason given')
     WHERE grant_id = p_grant_id
       AND revoked_at IS NULL;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'revoke_object_grant: grant_id=% not found or already revoked',
            p_grant_id
            USING ERRCODE = 'no_data_found';
    END IF;
END;
$body$;

-- ---------------------------------------------------------------------
-- list_object_grants(p_object_type, p_object_id) → SETOF grant rows
-- Visible per RLS (granter sees own; grantee sees own).
-- ---------------------------------------------------------------------
CREATE FUNCTION list_object_grants(
    p_object_type text,
    p_object_id   bigint
) RETURNS TABLE (
    grant_id            bigint,
    granted_by_schema   name,
    granted_to_schema   name,
    grant_level         text,
    granted_at          timestamptz,
    expires_at          timestamptz,
    revoked_at          timestamptz,
    note                text
) LANGUAGE sql STABLE
AS $body$
    SELECT grant_id, granted_by_schema, granted_to_schema, grant_level,
           granted_at, expires_at, revoked_at, note
    FROM malu$object_grant
    WHERE object_type = p_object_type
      AND object_id   = p_object_id
    ORDER BY granted_at DESC;
$body$;

GRANT EXECUTE ON FUNCTION
    _grant_active(text, bigint, text[]),
    grant_object_access(text, bigint, name, text, timestamptz, text),
    revoke_object_grant(bigint, text),
    list_object_grants(text, bigint)
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.18.0--0.19.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.19.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.18.0 → 0.19.0
--
-- Stage 2 — JSON payload schema validation (S2-6).
--
-- Per requirements.md §9 Stage 2: "Document/JSON layout for memory
-- payloads (JSONB + pg_jsonschema)". pg_jsonschema isn't packaged in
-- PGDG for Ubuntu 24.04 / PG 17, so v1 ships a pure-PL/pgSQL subset
-- validator (_payload_validate) implementing the JSON Schema
-- features most useful for memory payloads:
--
--   * type        — string | integer | number | boolean | object |
--                    array | null
--   * required    — array of mandatory keys
--   * properties  — per-key recursive schema
--   * additionalProperties=false — reject unknown keys
--   * enum        — closed value set
--   * minimum/maximum            — numeric bounds
--   * minLength/maxLength        — string bounds
--   * pattern                    — string regex
--   * items                      — recursive schema for arrays
--
-- Drop-in replaceable: if/when pg_jsonschema lands, CREATE OR REPLACE
-- _payload_validate with a thin wrapper around jsonb_matches_schema()
-- and the rest of the surface keeps working.
--
-- Schemas live in malu$payload_schema, scoped per (object_type,
-- schema_name). schema_name follows the discriminator column where
-- present (memory.memory_kind, episode_object.episode_kind,
-- memory_detail_object.detail_kind, source_package.source_type);
-- 'default' applies when no kind-specific schema matches. The
-- triggers validate the payload column on INSERT/UPDATE and raise
-- on mismatch.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.19.0'::text $body$;

-- ---------------------------------------------------------------------
-- Payload-schema catalog
-- ---------------------------------------------------------------------
CREATE TABLE malu$payload_schema (
    schema_id           bigserial PRIMARY KEY,
    target_object_type  text NOT NULL,
    schema_name         text NOT NULL,
    schema_jsonb        jsonb NOT NULL,
    description         text,
    enabled             boolean NOT NULL DEFAULT true,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    created_at          timestamptz NOT NULL DEFAULT now(),
    updated_at          timestamptz NOT NULL DEFAULT now(),
    CHECK (target_object_type IN
        ('source_package','claim','fact','memory','episode_object',
         'memory_detail_object')),
    UNIQUE (target_object_type, schema_name, owner_schema)
);
CREATE INDEX malu$payload_schema_lookup_idx
    ON malu$payload_schema(target_object_type, schema_name, enabled);

ALTER TABLE malu$payload_schema ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$payload_schema
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$payload_schema TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$payload_schema TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$payload_schema_schema_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- ---------------------------------------------------------------------
-- _payload_validate(schema_def, instance, path='')  → text[]
--
-- Empty result = valid. Each text element is "<path>: <reason>". Path
-- uses dotted property names + [n] for array indices, e.g.
--   "config.servers[0].port: expected integer, got string"
-- ---------------------------------------------------------------------
CREATE FUNCTION _payload_validate(
    p_schema   jsonb,
    p_instance jsonb,
    p_path     text DEFAULT ''
) RETURNS text[]
LANGUAGE plpgsql IMMUTABLE
AS $body$
DECLARE
    errors      text[] := ARRAY[]::text[];
    sub_errors  text[];
    sch_type    text;
    inst_type   text;
    req         text;
    prop        text;
    item        jsonb;
    idx         int;
    enum_member jsonb;
    allowed     boolean;
    path_here   text;
BEGIN
    IF p_schema IS NULL OR jsonb_typeof(p_schema) <> 'object' THEN
        RETURN errors;     -- empty / non-object schema = no constraint
    END IF;
    IF p_instance IS NULL THEN
        RETURN errors;     -- caller decides null-handling
    END IF;

    inst_type := jsonb_typeof(p_instance);
    path_here := COALESCE(NULLIF(p_path, ''), '$');

    -- ----- type --------------------------------------------------
    sch_type := p_schema ->> 'type';
    IF sch_type IS NOT NULL THEN
        IF NOT (
            inst_type = sch_type
            OR (sch_type = 'integer' AND inst_type = 'number' AND
                (p_instance::text) !~ '\.')
        ) THEN
            RETURN errors || format('%s: expected %s, got %s',
                                    path_here, sch_type, inst_type);
        END IF;
    END IF;

    -- ----- enum --------------------------------------------------
    IF p_schema ? 'enum' THEN
        allowed := false;
        FOR enum_member IN
            SELECT value FROM jsonb_array_elements(p_schema -> 'enum') AS v(value)
        LOOP
            IF enum_member = p_instance THEN
                allowed := true;
                EXIT;
            END IF;
        END LOOP;
        IF NOT allowed THEN
            errors := errors || format('%s: value %s not in enum',
                                       path_here, p_instance::text);
        END IF;
    END IF;

    -- ----- object: required + properties + additionalProperties ---
    IF sch_type = 'object' AND inst_type = 'object' THEN
        IF p_schema ? 'required' THEN
            FOR req IN
                SELECT value FROM jsonb_array_elements_text(p_schema -> 'required') AS v(value)
            LOOP
                IF NOT (p_instance ? req) THEN
                    errors := errors || format('%s: missing required property %s',
                                               path_here, req);
                END IF;
            END LOOP;
        END IF;

        FOR prop IN SELECT key FROM jsonb_object_keys(p_instance) AS k(key) LOOP
            IF p_schema ? 'properties' AND (p_schema -> 'properties') ? prop THEN
                sub_errors := _payload_validate(
                    p_schema -> 'properties' -> prop,
                    p_instance -> prop,
                    CASE WHEN p_path = '' THEN prop
                         ELSE p_path || '.' || prop END);
                errors := errors || sub_errors;
            ELSIF COALESCE((p_schema ->> 'additionalProperties')::boolean, true) = false THEN
                errors := errors || format('%s: additional property %s not allowed',
                                           path_here, prop);
            END IF;
        END LOOP;
    END IF;

    -- ----- array: items -----------------------------------------
    IF sch_type = 'array' AND inst_type = 'array' THEN
        idx := 0;
        IF p_schema ? 'items' THEN
            FOR item IN SELECT value FROM jsonb_array_elements(p_instance) AS v(value) LOOP
                sub_errors := _payload_validate(
                    p_schema -> 'items', item,
                    p_path || '[' || idx::text || ']');
                errors := errors || sub_errors;
                idx := idx + 1;
            END LOOP;
        END IF;
        IF p_schema ? 'minItems' THEN
            IF jsonb_array_length(p_instance) < (p_schema ->> 'minItems')::integer THEN
                errors := errors || format('%s: array has %s items, minItems=%s',
                                           path_here, jsonb_array_length(p_instance),
                                           p_schema ->> 'minItems');
            END IF;
        END IF;
        IF p_schema ? 'maxItems' THEN
            IF jsonb_array_length(p_instance) > (p_schema ->> 'maxItems')::integer THEN
                errors := errors || format('%s: array has %s items, maxItems=%s',
                                           path_here, jsonb_array_length(p_instance),
                                           p_schema ->> 'maxItems');
            END IF;
        END IF;
    END IF;

    -- ----- numeric bounds ---------------------------------------
    IF sch_type IN ('integer','number') AND inst_type = 'number' THEN
        IF p_schema ? 'minimum' AND
           (p_instance::text)::numeric < (p_schema ->> 'minimum')::numeric THEN
            errors := errors || format('%s: %s < minimum %s',
                                       path_here, p_instance::text,
                                       p_schema ->> 'minimum');
        END IF;
        IF p_schema ? 'maximum' AND
           (p_instance::text)::numeric > (p_schema ->> 'maximum')::numeric THEN
            errors := errors || format('%s: %s > maximum %s',
                                       path_here, p_instance::text,
                                       p_schema ->> 'maximum');
        END IF;
    END IF;

    -- ----- string bounds + pattern -------------------------------
    IF sch_type = 'string' AND inst_type = 'string' THEN
        DECLARE
            s text := p_instance #>> '{}';
        BEGIN
            IF p_schema ? 'minLength' AND
               char_length(s) < (p_schema ->> 'minLength')::integer THEN
                errors := errors || format('%s: length %s < minLength %s',
                                           path_here, char_length(s),
                                           p_schema ->> 'minLength');
            END IF;
            IF p_schema ? 'maxLength' AND
               char_length(s) > (p_schema ->> 'maxLength')::integer THEN
                errors := errors || format('%s: length %s > maxLength %s',
                                           path_here, char_length(s),
                                           p_schema ->> 'maxLength');
            END IF;
            IF p_schema ? 'pattern' AND s !~ (p_schema ->> 'pattern') THEN
                errors := errors || format('%s: %s does not match pattern %s',
                                           path_here, p_instance::text,
                                           p_schema ->> 'pattern');
            END IF;
        END;
    END IF;

    RETURN errors;
END;
$body$;

-- ---------------------------------------------------------------------
-- validate_payload(target_object_type, schema_name, instance) → text[]
--
-- Looks up the matching schema rows (preferring kind-specific, then
-- 'default'). Visible-to-current-schema schemas apply: tenant_owner
-- RLS gates which catalog rows participate. Returns concatenated
-- validation errors across all matching schemas; empty array = valid.
-- ---------------------------------------------------------------------
CREATE FUNCTION validate_payload(
    p_target_object_type text,
    p_schema_name        text,
    p_instance           jsonb
) RETURNS text[]
LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    errors text[] := ARRAY[]::text[];
    rec    record;
BEGIN
    IF p_instance IS NULL THEN
        RETURN errors;
    END IF;
    FOR rec IN
        SELECT schema_name, schema_jsonb
        FROM malu$payload_schema
        WHERE target_object_type = p_target_object_type
          AND enabled = true
          AND schema_name IN (COALESCE(p_schema_name, '__none__'), 'default')
        ORDER BY (schema_name = 'default') ASC, schema_name
    LOOP
        errors := errors || _payload_validate(rec.schema_jsonb, p_instance);
    END LOOP;
    RETURN errors;
END;
$body$;

-- ---------------------------------------------------------------------
-- register_payload_schema — upsert helper.
-- ---------------------------------------------------------------------
CREATE FUNCTION register_payload_schema(
    p_target_object_type text,
    p_schema_name        text,
    p_schema_jsonb       jsonb,
    p_description        text DEFAULT NULL,
    p_enabled            boolean DEFAULT true
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$payload_schema
        (target_object_type, schema_name, schema_jsonb, description, enabled)
    VALUES (p_target_object_type, p_schema_name, p_schema_jsonb,
            p_description, p_enabled)
    ON CONFLICT (target_object_type, schema_name, owner_schema) DO UPDATE
        SET schema_jsonb = EXCLUDED.schema_jsonb,
            description  = COALESCE(EXCLUDED.description, malu$payload_schema.description),
            enabled      = EXCLUDED.enabled,
            updated_at   = now()
    RETURNING schema_id INTO v_id;
    RETURN v_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- Trigger functions — one per (table, payload column) pair.
-- Each one calls validate_payload() with the appropriate
-- (object_type, kind_or_default, payload). On error array non-empty,
-- raise check_violation with the concatenated error list.
-- ---------------------------------------------------------------------
CREATE FUNCTION _payload_validate_memory() RETURNS trigger
LANGUAGE plpgsql AS $body$
DECLARE errs text[];
BEGIN
    IF NEW.payload_jsonb IS NULL THEN RETURN NEW; END IF;
    errs := validate_payload('memory', NEW.memory_kind, NEW.payload_jsonb);
    IF array_length(errs, 1) > 0 THEN
        RAISE EXCEPTION 'PAYLOAD_VALIDATION_FAILED: memory_id=% kind=% errors=[%]',
            COALESCE(NEW.memory_id, 0), NEW.memory_kind, array_to_string(errs, '; ')
            USING ERRCODE = 'check_violation';
    END IF;
    RETURN NEW;
END;
$body$;

CREATE FUNCTION _payload_validate_episode() RETURNS trigger
LANGUAGE plpgsql AS $body$
DECLARE errs text[];
BEGIN
    IF NEW.payload_jsonb IS NULL THEN RETURN NEW; END IF;
    errs := validate_payload('episode_object', NEW.episode_kind, NEW.payload_jsonb);
    IF array_length(errs, 1) > 0 THEN
        RAISE EXCEPTION 'PAYLOAD_VALIDATION_FAILED: episode_id=% kind=% errors=[%]',
            COALESCE(NEW.episode_id, 0), NEW.episode_kind, array_to_string(errs, '; ')
            USING ERRCODE = 'check_violation';
    END IF;
    RETURN NEW;
END;
$body$;

CREATE FUNCTION _payload_validate_mdo() RETURNS trigger
LANGUAGE plpgsql AS $body$
DECLARE errs text[];
BEGIN
    IF NEW.body_jsonb IS NULL THEN RETURN NEW; END IF;
    errs := validate_payload('memory_detail_object', NEW.detail_kind, NEW.body_jsonb);
    IF array_length(errs, 1) > 0 THEN
        RAISE EXCEPTION 'PAYLOAD_VALIDATION_FAILED: mdo_id=% kind=% errors=[%]',
            COALESCE(NEW.mdo_id, 0), NEW.detail_kind, array_to_string(errs, '; ')
            USING ERRCODE = 'check_violation';
    END IF;
    RETURN NEW;
END;
$body$;

CREATE FUNCTION _payload_validate_claim() RETURNS trigger
LANGUAGE plpgsql AS $body$
DECLARE errs text[];
BEGIN
    IF NEW.statement_jsonb IS NULL THEN RETURN NEW; END IF;
    errs := validate_payload('claim', NULL, NEW.statement_jsonb);
    IF array_length(errs, 1) > 0 THEN
        RAISE EXCEPTION 'PAYLOAD_VALIDATION_FAILED: claim_id=% errors=[%]',
            COALESCE(NEW.claim_id, 0), array_to_string(errs, '; ')
            USING ERRCODE = 'check_violation';
    END IF;
    RETURN NEW;
END;
$body$;

CREATE FUNCTION _payload_validate_fact() RETURNS trigger
LANGUAGE plpgsql AS $body$
DECLARE errs text[];
BEGIN
    IF NEW.statement_jsonb IS NULL THEN RETURN NEW; END IF;
    errs := validate_payload('fact', NULL, NEW.statement_jsonb);
    IF array_length(errs, 1) > 0 THEN
        RAISE EXCEPTION 'PAYLOAD_VALIDATION_FAILED: fact_id=% errors=[%]',
            COALESCE(NEW.fact_id, 0), array_to_string(errs, '; ')
            USING ERRCODE = 'check_violation';
    END IF;
    RETURN NEW;
END;
$body$;

CREATE FUNCTION _payload_validate_source_package() RETURNS trigger
LANGUAGE plpgsql AS $body$
DECLARE errs text[];
BEGIN
    IF NEW.origin_jsonb IS NULL THEN RETURN NEW; END IF;
    errs := validate_payload('source_package', NEW.source_type, NEW.origin_jsonb);
    IF array_length(errs, 1) > 0 THEN
        RAISE EXCEPTION 'PAYLOAD_VALIDATION_FAILED: source_package_id=% type=% errors=[%]',
            COALESCE(NEW.source_package_id, 0), NEW.source_type, array_to_string(errs, '; ')
            USING ERRCODE = 'check_violation';
    END IF;
    RETURN NEW;
END;
$body$;

-- ---------------------------------------------------------------------
-- Triggers
-- ---------------------------------------------------------------------
CREATE TRIGGER memory_payload_validate_tg
    BEFORE INSERT OR UPDATE OF payload_jsonb, memory_kind
    ON malu$memory
    FOR EACH ROW EXECUTE FUNCTION _payload_validate_memory();

CREATE TRIGGER episode_payload_validate_tg
    BEFORE INSERT OR UPDATE OF payload_jsonb, episode_kind
    ON malu$episode_object
    FOR EACH ROW EXECUTE FUNCTION _payload_validate_episode();

CREATE TRIGGER mdo_payload_validate_tg
    BEFORE INSERT OR UPDATE OF body_jsonb, detail_kind
    ON malu$memory_detail_object
    FOR EACH ROW EXECUTE FUNCTION _payload_validate_mdo();

CREATE TRIGGER claim_payload_validate_tg
    BEFORE INSERT OR UPDATE OF statement_jsonb
    ON malu$claim
    FOR EACH ROW EXECUTE FUNCTION _payload_validate_claim();

CREATE TRIGGER fact_payload_validate_tg
    BEFORE INSERT OR UPDATE OF statement_jsonb
    ON malu$fact
    FOR EACH ROW EXECUTE FUNCTION _payload_validate_fact();

CREATE TRIGGER source_package_payload_validate_tg
    BEFORE INSERT OR UPDATE OF origin_jsonb, source_type
    ON malu$source_package
    FOR EACH ROW EXECUTE FUNCTION _payload_validate_source_package();

GRANT EXECUTE ON FUNCTION
    _payload_validate(jsonb, jsonb, text),
    validate_payload(text, text, jsonb),
    register_payload_schema(text, text, jsonb, text, boolean)
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.19.0--0.20.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.20.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.19.0 → 0.20.0
--
-- Stage 2 — Multi-model atomic insertion C extension (S2-7).
--
-- Per requirements.md §3.10: "Partial commits are forbidden". PG's
-- WAL/MVCC handles transaction atomicity; what S2-7 adds is:
--
--   1. No implicit savepoints. PL/pgSQL EXCEPTION blocks silently
--      create a savepoint per block, and a function that catches an
--      internal error can return success with partial writes visible.
--      C functions inherit the outer transaction directly; any
--      ereport(ERROR, ...) aborts the whole call.
--
--   2. Cross-write invariants verified in one SPI session (e.g.,
--      every claim_id in promote_claim_to_fact_atomic must be visible
--      before the fact row is created).
--
--   3. Ledger writes are mandatory (CLAUDE.md doctrine: derivations
--      without ledger entries are bugs). The C wrappers cannot be
--      called without writing a ledger row.
--
-- Functions live in src/maludb_atomic.c. SQL declarations bind them
-- with default-valued args so PL/pgSQL callers don't have to spell
-- every parameter.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.20.0'::text $body$;

-- ---------------------------------------------------------------------
-- ingest_claim_atomic — source_package + claim + derivation_ledger.
--
-- Returns the new claim_id. Aborts the whole chain on any failure.
-- ---------------------------------------------------------------------
CREATE FUNCTION ingest_claim_atomic(
    p_source_type        text,
    p_source_text        text,
    p_subject            text    DEFAULT NULL,
    p_verb               text    DEFAULT NULL,
    p_object_value       text    DEFAULT NULL,
    p_statement_text     text    DEFAULT NULL,
    p_parser_name        text    DEFAULT NULL,
    p_origin_jsonb       jsonb   DEFAULT NULL,
    p_source_locator     jsonb   DEFAULT NULL,
    p_model_request_id   bigint  DEFAULT NULL,
    p_inputs_jsonb       jsonb   DEFAULT NULL
) RETURNS bigint
    AS 'MODULE_PATHNAME', 'maludb_ingest_claim_atomic'
    LANGUAGE C VOLATILE;

-- ---------------------------------------------------------------------
-- promote_claim_to_fact_atomic — fact + fact_claim links + ledger.
--
-- Verifies every claim_id in p_claim_ids is visible (RLS-scoped)
-- before writing the fact row. Raises no_data_found on any missing
-- claim. Returns the new fact_id.
-- ---------------------------------------------------------------------
CREATE FUNCTION promote_claim_to_fact_atomic(
    p_claim_ids            bigint[],
    p_subject              text    DEFAULT NULL,
    p_verb                 text    DEFAULT NULL,
    p_object_value         text    DEFAULT NULL,
    p_statement_text       text    DEFAULT NULL,
    p_verification_scope   text    DEFAULT NULL,
    p_verification_method  text    DEFAULT NULL,
    p_parser_name          text    DEFAULT NULL,
    p_verifier_name        text    DEFAULT NULL,
    p_inputs_jsonb         jsonb   DEFAULT NULL
) RETURNS bigint
    AS 'MODULE_PATHNAME', 'maludb_promote_claim_to_fact_atomic'
    LANGUAGE C VOLATILE;

GRANT EXECUTE ON FUNCTION
    ingest_claim_atomic(text, text, text, text, text, text, text, jsonb, jsonb, bigint, jsonb),
    promote_claim_to_fact_atomic(bigint[], text, text, text, text, text, text, text, text, jsonb)
TO maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.20.0--0.21.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.21.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.20.0 → 0.21.0
--
-- Stage 2 — Ingestion contracts (S2-8).
--
-- Per requirements.md §9 Stage 2: "Retrospective and continuous
-- ingestion contracts for source packages, candidate claims, source
-- references, connector checkpoints, and source-specific offsets."
--
-- Lifecycle:
--   1. Operator registers a connector (Slack, GitHub, log tail, ...)
--      via register_connector().
--   2. Each connector advances one or more named cursors via
--      advance_checkpoint() as it consumes upstream events.
--   3. Parser/extractor logic registers raw events as source_packages
--      (S2-1/S2-2 surface) and proposes candidate claims via
--      propose_pending_claim().
--   4. A human reviewer or auto-promotion policy calls
--      accept_pending_claim() (writes malu$claim + ledger; updates
--      pending row) or reject_pending_claim().
--
-- Cursor formats supported: 'timestamp', 'opaque', 'message_id',
-- 'offset'. cursor_jsonb is provided for multi-part cursors (e.g.,
-- {channel_id, last_ts} for Slack).
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.21.0'::text $body$;

-- =====================================================================
-- malu$ingestion_connector
-- =====================================================================
CREATE TABLE malu$ingestion_connector (
    connector_id        bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    connector_name      text NOT NULL,
    connector_kind      text NOT NULL,
    source_type         text NOT NULL
        REFERENCES malu$source_type(source_type),
    config_jsonb        jsonb NOT NULL DEFAULT '{}'::jsonb,
    enabled             boolean NOT NULL DEFAULT true,
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    created_at          timestamptz NOT NULL DEFAULT now(),
    updated_at          timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, connector_name)
);
CREATE INDEX malu$ingestion_connector_kind_idx
    ON malu$ingestion_connector(connector_kind, enabled);

ALTER TABLE malu$ingestion_connector ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$ingestion_connector
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

-- =====================================================================
-- malu$ingestion_checkpoint
--
-- A connector may carry multiple cursors (e.g., one per Slack channel).
-- 'default' is the single-cursor pattern.
-- =====================================================================
CREATE TABLE malu$ingestion_checkpoint (
    checkpoint_id       bigserial PRIMARY KEY,
    connector_id        bigint NOT NULL
        REFERENCES malu$ingestion_connector(connector_id) ON DELETE CASCADE,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    cursor_name         text NOT NULL DEFAULT 'default',
    cursor_format       text NOT NULL DEFAULT 'opaque'
        CHECK (cursor_format IN ('timestamp','opaque','message_id','offset','jsonb')),
    cursor_value        text,
    cursor_jsonb        jsonb,
    mode                text NOT NULL DEFAULT 'continuous'
        CHECK (mode IN ('retrospective','continuous','paused')),
    last_advanced_at    timestamptz,
    last_attempt_at     timestamptz,
    last_error          text,
    items_ingested      bigint NOT NULL DEFAULT 0,
    created_at          timestamptz NOT NULL DEFAULT now(),
    updated_at          timestamptz NOT NULL DEFAULT now(),
    UNIQUE (connector_id, cursor_name)
);
CREATE INDEX malu$ingestion_checkpoint_mode_idx
    ON malu$ingestion_checkpoint(mode);

ALTER TABLE malu$ingestion_checkpoint ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$ingestion_checkpoint
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

-- =====================================================================
-- malu$pending_claim — candidate claims awaiting review/promotion
-- =====================================================================
CREATE TABLE malu$pending_claim (
    pending_claim_id    bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    connector_id        bigint
        REFERENCES malu$ingestion_connector(connector_id) ON DELETE SET NULL,
    source_package_id   bigint
        REFERENCES malu$source_package(source_package_id) ON DELETE SET NULL,
    subject             text,
    verb                text,
    predicate           text,
    object_value        text,
    relationship        text,
    statement_text      text,
    statement_jsonb     jsonb,
    source_locator      jsonb,
    confidence          numeric(5,4)
        CHECK (confidence IS NULL OR (confidence >= 0 AND confidence <= 1)),
    proposed_at         timestamptz NOT NULL DEFAULT now(),
    proposed_by         text,
    review_state        text NOT NULL DEFAULT 'pending'
        CHECK (review_state IN ('pending','accepted','rejected','duplicate','superseded')),
    reviewed_at         timestamptz,
    reviewed_by         text,
    review_note         text,
    promoted_claim_id   bigint
        REFERENCES malu$claim(claim_id) ON DELETE SET NULL,
    sensitivity         text NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited'))
);
CREATE INDEX malu$pending_claim_state_idx
    ON malu$pending_claim(review_state, proposed_at DESC)
    WHERE review_state = 'pending';
CREATE INDEX malu$pending_claim_connector_idx
    ON malu$pending_claim(connector_id, review_state);
CREATE INDEX malu$pending_claim_source_idx
    ON malu$pending_claim(source_package_id)
    WHERE source_package_id IS NOT NULL;

ALTER TABLE malu$pending_claim ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$pending_claim
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

-- =====================================================================
-- Grants + sequences
-- =====================================================================
GRANT SELECT ON malu$ingestion_connector, malu$ingestion_checkpoint, malu$pending_claim TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$ingestion_connector, malu$ingestion_checkpoint, malu$pending_claim TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE
    malu$ingestion_connector_connector_id_seq,
    malu$ingestion_checkpoint_checkpoint_id_seq,
    malu$pending_claim_pending_claim_id_seq
TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- register_connector — upsert by (owner_schema, connector_name).
-- =====================================================================
CREATE FUNCTION register_connector(
    p_connector_name text,
    p_connector_kind text,
    p_source_type    text,
    p_config_jsonb   jsonb DEFAULT '{}'::jsonb,
    p_sensitivity    text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$ingestion_connector
        (connector_name, connector_kind, source_type, config_jsonb, sensitivity)
    VALUES (p_connector_name, p_connector_kind, p_source_type,
            COALESCE(p_config_jsonb, '{}'::jsonb), p_sensitivity)
    ON CONFLICT (owner_schema, connector_name) DO UPDATE
        SET connector_kind = EXCLUDED.connector_kind,
            source_type    = EXCLUDED.source_type,
            config_jsonb   = EXCLUDED.config_jsonb,
            sensitivity    = EXCLUDED.sensitivity,
            updated_at     = now()
    RETURNING connector_id INTO v_id;
    RETURN v_id;
END;
$body$;

-- =====================================================================
-- advance_checkpoint — upsert by (connector_id, cursor_name). When the
-- caller is making forward progress, pass p_last_error => NULL. On
-- transient failure, pass the error string + skip the cursor advance.
-- =====================================================================
CREATE FUNCTION advance_checkpoint(
    p_connector_id    bigint,
    p_cursor_name     text    DEFAULT 'default',
    p_cursor_value    text    DEFAULT NULL,
    p_cursor_jsonb    jsonb   DEFAULT NULL,
    p_cursor_format   text    DEFAULT NULL,
    p_mode            text    DEFAULT NULL,
    p_items_added     bigint  DEFAULT 0,
    p_last_error      text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id     bigint;
    v_format text;
BEGIN
    -- Look up an existing row; if found, preserve cursor_format unless
    -- caller supplied a new one. INSERT path uses p_cursor_format
    -- explicitly so the default ('opaque') applies for first-touch.
    SELECT checkpoint_id, cursor_format INTO v_id, v_format
    FROM malu$ingestion_checkpoint
    WHERE connector_id = p_connector_id AND cursor_name = p_cursor_name;

    IF v_id IS NULL THEN
        INSERT INTO malu$ingestion_checkpoint
            (connector_id, cursor_name, cursor_format, cursor_value, cursor_jsonb,
             mode, last_advanced_at, last_attempt_at, last_error, items_ingested)
        VALUES
            (p_connector_id, p_cursor_name,
             COALESCE(p_cursor_format, 'opaque'),
             p_cursor_value, p_cursor_jsonb,
             COALESCE(p_mode, 'continuous'),
             CASE WHEN p_last_error IS NULL THEN now() END,
             now(), p_last_error, COALESCE(p_items_added, 0))
        RETURNING checkpoint_id INTO v_id;
    ELSE
        UPDATE malu$ingestion_checkpoint
           SET cursor_value     = CASE WHEN p_last_error IS NULL
                                       THEN COALESCE(p_cursor_value, cursor_value)
                                       ELSE cursor_value END,
               cursor_jsonb     = CASE WHEN p_last_error IS NULL
                                       THEN COALESCE(p_cursor_jsonb, cursor_jsonb)
                                       ELSE cursor_jsonb END,
               cursor_format    = COALESCE(p_cursor_format, cursor_format),
               mode             = COALESCE(p_mode, mode),
               last_advanced_at = CASE WHEN p_last_error IS NULL THEN now()
                                       ELSE last_advanced_at END,
               last_attempt_at  = now(),
               last_error       = p_last_error,
               items_ingested   = items_ingested + COALESCE(p_items_added, 0),
               updated_at       = now()
         WHERE checkpoint_id = v_id;
    END IF;
    RETURN v_id;
END;
$body$;

-- =====================================================================
-- propose_pending_claim — adds a candidate to the review queue.
-- =====================================================================
CREATE FUNCTION propose_pending_claim(
    p_connector_id      bigint   DEFAULT NULL,
    p_source_package_id bigint   DEFAULT NULL,
    p_subject           text     DEFAULT NULL,
    p_verb              text     DEFAULT NULL,
    p_predicate         text     DEFAULT NULL,
    p_object_value      text     DEFAULT NULL,
    p_relationship      text     DEFAULT NULL,
    p_statement_text    text     DEFAULT NULL,
    p_statement_jsonb   jsonb    DEFAULT NULL,
    p_source_locator    jsonb    DEFAULT NULL,
    p_confidence        numeric  DEFAULT NULL,
    p_proposed_by       text     DEFAULT NULL,
    p_sensitivity       text     DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$pending_claim
        (connector_id, source_package_id,
         subject, verb, predicate, object_value, relationship,
         statement_text, statement_jsonb, source_locator,
         confidence, proposed_by, sensitivity)
    VALUES (p_connector_id, p_source_package_id,
            p_subject, p_verb, p_predicate, p_object_value, p_relationship,
            p_statement_text, p_statement_jsonb, p_source_locator,
            p_confidence, p_proposed_by, p_sensitivity)
    RETURNING pending_claim_id INTO v_id;
    RETURN v_id;
END;
$body$;

-- =====================================================================
-- accept_pending_claim — the promotion path. Writes malu$claim +
-- malu$derivation_ledger in one tx and marks the pending row accepted.
--
-- Doctrine: pending → claim transitions MUST produce a ledger entry
-- (CLAUDE.md "Derivations without ledger entries are bugs"). No
-- EXCEPTION blocks inside this function, so any failure aborts the
-- whole call.
-- =====================================================================
CREATE FUNCTION accept_pending_claim(
    p_pending_claim_id bigint,
    p_reviewer         text  DEFAULT NULL,
    p_review_note      text  DEFAULT NULL,
    p_parser_name      text  DEFAULT NULL,
    p_verifier_name    text  DEFAULT NULL,
    p_inputs_jsonb     jsonb DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_pending malu$pending_claim%ROWTYPE;
    v_claim_id bigint;
    v_connector_kind text;
BEGIN
    SELECT * INTO v_pending FROM malu$pending_claim
     WHERE pending_claim_id = p_pending_claim_id
       FOR UPDATE;
    IF v_pending.pending_claim_id IS NULL THEN
        RAISE EXCEPTION 'unknown pending_claim_id: %', p_pending_claim_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_pending.review_state <> 'pending' THEN
        RAISE EXCEPTION
          'pending_claim_id=% is %; only pending rows can be accepted',
          p_pending_claim_id, v_pending.review_state
          USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    -- 1. Write the real claim row.
    v_claim_id := register_claim(
        p_subject           => v_pending.subject,
        p_verb              => v_pending.verb,
        p_predicate         => v_pending.predicate,
        p_object_value      => v_pending.object_value,
        p_relationship      => v_pending.relationship,
        p_statement_text    => v_pending.statement_text,
        p_statement_jsonb   => v_pending.statement_jsonb,
        p_source_package_id => v_pending.source_package_id,
        p_source_locator    => v_pending.source_locator,
        p_sensitivity       => v_pending.sensitivity);

    -- 2. Ledger entry. parser_name falls back to the connector kind
    -- if not supplied — gives the ledger a non-NULL provenance even
    -- when reviewers click 'accept' without filling extra fields.
    IF p_parser_name IS NULL AND v_pending.connector_id IS NOT NULL THEN
        SELECT connector_kind INTO v_connector_kind
        FROM malu$ingestion_connector
        WHERE connector_id = v_pending.connector_id;
    END IF;

    PERFORM record_derivation(
        p_derived_object_type => 'claim',
        p_derived_object_id   => v_claim_id,
        p_parser_name         => COALESCE(p_parser_name, v_connector_kind, 'pending_queue'),
        p_verifier_name       => p_verifier_name,
        p_inputs_jsonb        => COALESCE(p_inputs_jsonb,
            jsonb_build_object(
                'pending_claim_id', p_pending_claim_id,
                'connector_id',     v_pending.connector_id,
                'source_package_id', v_pending.source_package_id,
                'confidence',       v_pending.confidence)));

    -- 3. Update the pending row.
    UPDATE malu$pending_claim
       SET review_state      = 'accepted',
           reviewed_at       = now(),
           reviewed_by       = p_reviewer,
           review_note       = p_review_note,
           promoted_claim_id = v_claim_id
     WHERE pending_claim_id = p_pending_claim_id;

    RETURN v_claim_id;
END;
$body$;

-- =====================================================================
-- reject_pending_claim — non-destructive; row stays for audit.
-- =====================================================================
CREATE FUNCTION reject_pending_claim(
    p_pending_claim_id bigint,
    p_reviewer         text DEFAULT NULL,
    p_review_note      text DEFAULT NULL,
    p_final_state      text DEFAULT 'rejected'
) RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    IF p_final_state NOT IN ('rejected','duplicate','superseded') THEN
        RAISE EXCEPTION 'reject_pending_claim: bad final_state %', p_final_state
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    UPDATE malu$pending_claim
       SET review_state = p_final_state,
           reviewed_at  = now(),
           reviewed_by  = p_reviewer,
           review_note  = p_review_note
     WHERE pending_claim_id = p_pending_claim_id
       AND review_state     = 'pending';
    IF NOT FOUND THEN
        RAISE EXCEPTION
          'pending_claim_id=% not found or not in state=pending',
          p_pending_claim_id
          USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;
END;
$body$;

-- =====================================================================
-- list_pending_claims — operator/reviewer queue.
-- =====================================================================
CREATE FUNCTION list_pending_claims(
    p_connector_id bigint DEFAULT NULL,
    p_limit        integer DEFAULT 100
) RETURNS TABLE (
    pending_claim_id  bigint,
    connector_name    text,
    subject           text,
    verb              text,
    object_value      text,
    statement_text    text,
    confidence        numeric,
    proposed_at       timestamptz,
    proposed_by       text
) LANGUAGE sql STABLE
AS $body$
    SELECT p.pending_claim_id,
           c.connector_name,
           p.subject, p.verb, p.object_value, p.statement_text,
           p.confidence, p.proposed_at, p.proposed_by
    FROM malu$pending_claim p
    LEFT JOIN malu$ingestion_connector c ON c.connector_id = p.connector_id
    WHERE p.review_state = 'pending'
      AND (p_connector_id IS NULL OR p.connector_id = p_connector_id)
    ORDER BY p.proposed_at ASC, p.pending_claim_id
    LIMIT p_limit;
$body$;

GRANT EXECUTE ON FUNCTION
    register_connector(text, text, text, jsonb, text),
    advance_checkpoint(bigint, text, text, jsonb, text, text, bigint, text),
    propose_pending_claim(bigint, bigint, text, text, text, text, text, text, jsonb, jsonb, numeric, text, text),
    accept_pending_claim(bigint, text, text, text, text, jsonb),
    reject_pending_claim(bigint, text, text, text),
    list_pending_claims(bigint, integer)
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.21.0--0.22.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.22.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.21.0 → 0.22.0
--
-- Stage 2 — pgaudit + pg_stat_statements wiring (S2-9).
--
-- Closes Stage 2. Per requirements.md §9: "pgaudit +
-- pg_stat_statements configured."
--
-- The two extensions both require shared_preload_libraries entries.
-- This migration cannot CREATE EXTENSION on a cluster that hasn't
-- been preloaded, so we ship:
--
--   1. audit_status() — reports per-extension presence + preload
--      state so operators can verify their cluster config.
--   2. pgaudit_recommended_settings() — returns the postgresql.conf
--      lines operators need to add (and the corresponding
--      shared_preload_libraries entries).
--   3. malu$audit_event — SQL-queryable governance audit. pgaudit
--      writes OS-level logs for compliance; malu$audit_event gives
--      ops + UX a row-level view of who did what to which Stage 2
--      object when.
--   4. audit_event(...) helper that retrofitted lifecycle functions
--      (seal/unseal/tombstone/grant/revoke) call to record their
--      transitions.
--   5. malu$query_stats view — created only when pg_stat_statements
--      is actually installed (DO block guards the CREATE).
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.22.0'::text $body$;

-- =====================================================================
-- malu$audit_event
-- =====================================================================
CREATE TABLE malu$audit_event (
    event_id            bigserial PRIMARY KEY,
    owner_schema        name NOT NULL DEFAULT current_schema(),
    actor_role          name NOT NULL DEFAULT current_user,
    event_kind          text NOT NULL,
    target_object_type  text,
    target_object_id    bigint,
    event_jsonb         jsonb,
    error_text          text,
    occurred_at         timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$audit_event_owner_kind_idx
    ON malu$audit_event(owner_schema, event_kind, occurred_at DESC);
CREATE INDEX malu$audit_event_target_idx
    ON malu$audit_event(target_object_type, target_object_id)
    WHERE target_object_id IS NOT NULL;

ALTER TABLE malu$audit_event ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$audit_event
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$audit_event TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT ON malu$audit_event TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$audit_event_event_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- ---------------------------------------------------------------------
-- audit_event — internal helper that all retrofitted lifecycle
-- functions call. SECURITY INVOKER so actor_role tracks the caller,
-- not the function owner.
-- ---------------------------------------------------------------------
CREATE FUNCTION audit_event(
    p_event_kind         text,
    p_target_object_type text   DEFAULT NULL,
    p_target_object_id   bigint DEFAULT NULL,
    p_event_jsonb        jsonb  DEFAULT NULL,
    p_error_text         text   DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$audit_event
        (event_kind, target_object_type, target_object_id,
         event_jsonb, error_text)
    VALUES (p_event_kind, p_target_object_type, p_target_object_id,
            p_event_jsonb, p_error_text)
    RETURNING event_id INTO v_id;
    RETURN v_id;
END;
$body$;

-- =====================================================================
-- audit_status — reports the state of each governance/observability
-- extension. Operators check this once after install and after any
-- postgresql.conf change.
-- =====================================================================
CREATE FUNCTION audit_status() RETURNS TABLE (
    component  text,
    available  boolean,
    preloaded  boolean,
    installed  boolean,
    note       text
) LANGUAGE sql STABLE
AS $body$
    SELECT 'pg_stat_statements'::text,
           EXISTS (SELECT 1 FROM pg_available_extensions WHERE name='pg_stat_statements'),
           current_setting('shared_preload_libraries', true) LIKE '%pg_stat_statements%',
           EXISTS (SELECT 1 FROM pg_extension WHERE extname='pg_stat_statements'),
           CASE
             WHEN EXISTS (SELECT 1 FROM pg_extension WHERE extname='pg_stat_statements')
               THEN 'ready'
             WHEN current_setting('shared_preload_libraries', true) LIKE '%pg_stat_statements%'
               THEN 'preloaded; run CREATE EXTENSION pg_stat_statements'
             WHEN EXISTS (SELECT 1 FROM pg_available_extensions WHERE name='pg_stat_statements')
               THEN 'add to shared_preload_libraries + restart'
             ELSE 'install postgresql-NN-pg-stat-statements package'
           END
    UNION ALL
    SELECT 'pgaudit',
           EXISTS (SELECT 1 FROM pg_available_extensions WHERE name='pgaudit'),
           current_setting('shared_preload_libraries', true) LIKE '%pgaudit%',
           EXISTS (SELECT 1 FROM pg_extension WHERE extname='pgaudit'),
           CASE
             WHEN EXISTS (SELECT 1 FROM pg_extension WHERE extname='pgaudit')
               THEN 'ready'
             WHEN current_setting('shared_preload_libraries', true) LIKE '%pgaudit%'
               THEN 'preloaded; run CREATE EXTENSION pgaudit'
             WHEN EXISTS (SELECT 1 FROM pg_available_extensions WHERE name='pgaudit')
               THEN 'add to shared_preload_libraries + restart'
             ELSE 'install postgresql-NN-pgaudit package'
           END
    UNION ALL
    SELECT 'malu$audit_event',
           true, true,
           true,
           'SQL-side audit table: governance lifecycle events for ' ||
           'seal/unseal/tombstone/grant/revoke transitions';
$body$;

-- =====================================================================
-- pgaudit_recommended_settings — postgresql.conf lines operators
-- should add. Returned as a single text block so it can be piped
-- straight into a config-management tool.
-- =====================================================================
CREATE FUNCTION pgaudit_recommended_settings() RETURNS text
LANGUAGE sql IMMUTABLE
AS $body$
    SELECT $cfg$
# --- MaluDB Stage 2 S2-9 recommended postgresql.conf additions ---
# shared_preload_libraries must include both:
shared_preload_libraries = 'pg_stat_statements,pgaudit'

# pg_stat_statements: capture top-level + nested. Bump tracked-
# statement count for governance review.
pg_stat_statements.track = 'all'
pg_stat_statements.max  = 10000

# pgaudit: governance-grade log subset. Adjust per compliance
# requirements; 'role' captures GRANT/REVOKE for audit.
pgaudit.log = 'ddl,role,write'
pgaudit.log_relation = on
pgaudit.log_catalog  = off
pgaudit.log_parameter = off       # avoid leaking secrets to logs
pgaudit.log_statement_once = on
# --------------------------------------------------------------------
$cfg$::text;
$body$;

-- =====================================================================
-- malu$query_stats view — only created when pg_stat_statements is
-- actually installed in this database. Otherwise the migration
-- skips the CREATE and operators run CREATE OR REPLACE later via
-- maludb_core_attach_stat_statements_view().
-- =====================================================================
CREATE FUNCTION maludb_core_attach_stat_statements_view() RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_extension WHERE extname='pg_stat_statements') THEN
        RAISE NOTICE 'pg_stat_statements not installed; skipping malu$query_stats view';
        RETURN;
    END IF;

    EXECUTE $view$
        CREATE OR REPLACE VIEW malu$query_stats AS
        SELECT
            d.datname,
            r.rolname,
            s.queryid,
            s.calls,
            s.total_exec_time,
            s.mean_exec_time,
            s.rows AS total_rows,
            s.shared_blks_hit,
            s.shared_blks_read,
            substring(s.query, 1, 240) AS query_preview
        FROM pg_stat_statements s
        JOIN pg_database d ON d.oid = s.dbid
        JOIN pg_roles    r ON r.oid = s.userid
        WHERE current_setting('is_superuser') = 'on'
           OR r.rolname = current_user
    $view$;

    EXECUTE 'GRANT SELECT ON malu$query_stats TO ' ||
            'maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor';
END;
$body$;

-- Attempt the attach now; emits a notice on systems without the
-- extension preloaded and continues.
SELECT maludb_core_attach_stat_statements_view();

-- =====================================================================
-- Retrofit S2-2 + S2-5 lifecycle functions to call audit_event(). We
-- use CREATE OR REPLACE to update bodies; signatures are unchanged.
-- =====================================================================

-- ---- seal_source_package -------------------------------------------
CREATE OR REPLACE FUNCTION seal_source_package(
    p_source_package_id bigint,
    p_placement_tier    text DEFAULT 'inline',
    p_external_uri      text DEFAULT NULL,
    p_note              text DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_sp          malu$source_package%ROWTYPE;
    v_archive_id  bigint;
    v_size        bigint;
BEGIN
    SELECT * INTO v_sp FROM malu$source_package
     WHERE source_package_id = p_source_package_id;
    IF v_sp.source_package_id IS NULL THEN
        RAISE EXCEPTION 'unknown source_package_id: %', p_source_package_id
            USING ERRCODE = 'no_data_found';
    END IF;

    IF v_sp.sealed_at IS NOT NULL THEN
        SELECT archive_id INTO v_archive_id FROM malu$verbatim_archive
         WHERE source_package_id = p_source_package_id
           AND superseded_at IS NULL
         ORDER BY sealed_at DESC LIMIT 1;
        RETURN v_archive_id;
    END IF;

    UPDATE malu$source_package SET sealed_at = now()
     WHERE source_package_id = p_source_package_id;

    v_size := octet_length(_source_canonical_bytes(
                  v_sp.content_bytes, v_sp.content_text, v_sp.content_jsonb));

    INSERT INTO malu$verbatim_archive
        (source_package_id, placement_tier, content_size_archived,
         archive_hash, external_uri, note)
    VALUES (p_source_package_id, p_placement_tier, v_size,
            v_sp.content_hash, p_external_uri, p_note)
    RETURNING archive_id INTO v_archive_id;

    PERFORM audit_event('seal_source_package', 'source_package', p_source_package_id,
        jsonb_build_object('placement_tier', p_placement_tier,
                           'archive_id',     v_archive_id,
                           'external_uri',   p_external_uri));

    RETURN v_archive_id;
END;
$body$;

-- ---- unseal_source_package -----------------------------------------
CREATE OR REPLACE FUNCTION unseal_source_package(
    p_source_package_id bigint,
    p_reason            text
) RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    IF p_reason IS NULL OR p_reason = '' THEN
        RAISE EXCEPTION 'unseal_source_package: reason required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    PERFORM 1 FROM malu$source_package
     WHERE source_package_id = p_source_package_id AND sealed_at IS NOT NULL;
    IF NOT FOUND THEN
        RAISE EXCEPTION
          'source_package_id=% is not currently sealed',
          p_source_package_id
          USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    UPDATE malu$verbatim_archive
       SET superseded_at = now()
     WHERE source_package_id = p_source_package_id
       AND superseded_at IS NULL;

    UPDATE malu$source_package SET sealed_at = NULL
     WHERE source_package_id = p_source_package_id;

    INSERT INTO malu$verbatim_archive
        (source_package_id, placement_tier, archive_hash, note, sealed_at, superseded_at)
    VALUES (p_source_package_id, 'inline',
            (SELECT content_hash FROM malu$source_package
              WHERE source_package_id = p_source_package_id),
            'unseal: ' || p_reason,
            now(), now());

    PERFORM audit_event('unseal_source_package', 'source_package', p_source_package_id,
        jsonb_build_object('reason', p_reason));
END;
$body$;

-- ---- tombstone_source_package --------------------------------------
CREATE OR REPLACE FUNCTION tombstone_source_package(
    p_source_package_id bigint,
    p_reason            text
) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE
    v_sp malu$source_package%ROWTYPE;
BEGIN
    IF p_reason IS NULL OR p_reason = '' THEN
        RAISE EXCEPTION 'tombstone_source_package: reason required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    SELECT * INTO v_sp FROM malu$source_package
     WHERE source_package_id = p_source_package_id;
    IF v_sp.source_package_id IS NULL THEN
        RAISE EXCEPTION 'unknown source_package_id: %', p_source_package_id
            USING ERRCODE = 'no_data_found';
    END IF;

    UPDATE malu$source_package
       SET sealed_at     = NULL,
           tombstoned_at = now()
     WHERE source_package_id = p_source_package_id;

    INSERT INTO malu$verbatim_archive
        (source_package_id, placement_tier, archive_hash, note, sealed_at, superseded_at)
    VALUES (p_source_package_id, 'inline', v_sp.content_hash,
            'tombstone: ' || p_reason, now(), now());

    IF NOT v_sp.legal_hold THEN
        UPDATE malu$source_package
           SET content_bytes = NULL,
               content_text  = NULL,
               content_jsonb = NULL
         WHERE source_package_id = p_source_package_id;
        UPDATE malu$source_package SET sealed_at = now()
         WHERE source_package_id = p_source_package_id;
        UPDATE malu$verbatim_archive
           SET superseded_at = now()
         WHERE source_package_id = p_source_package_id
           AND superseded_at    IS NULL
           AND placement_tier   IN ('inline','hot','warm');
    END IF;

    PERFORM audit_event('tombstone_source_package', 'source_package', p_source_package_id,
        jsonb_build_object('reason', p_reason, 'legal_hold', v_sp.legal_hold));
END;
$body$;

-- ---- grant_object_access -------------------------------------------
CREATE OR REPLACE FUNCTION grant_object_access(
    p_object_type      text,
    p_object_id        bigint,
    p_granted_to_schema name,
    p_grant_level      text       DEFAULT 'read',
    p_expires_at       timestamptz DEFAULT NULL,
    p_note             text       DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id     bigint;
    v_exists boolean;
BEGIN
    IF p_grant_level NOT IN ('read','write','full') THEN
        RAISE EXCEPTION 'grant_object_access: bad level %', p_grant_level
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    IF p_granted_to_schema IS NULL OR p_granted_to_schema = current_schema() THEN
        RAISE EXCEPTION 'grant_object_access: must grant to a different schema'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    EXECUTE format(
        'SELECT EXISTS (SELECT 1 FROM maludb_core.%I WHERE %I = $1)',
        CASE p_object_type
            WHEN 'source_package'        THEN 'malu$source_package'
            WHEN 'claim'                 THEN 'malu$claim'
            WHEN 'fact'                  THEN 'malu$fact'
            WHEN 'memory'                THEN 'malu$memory'
            WHEN 'episode_object'        THEN 'malu$episode_object'
            WHEN 'memory_detail_object'  THEN 'malu$memory_detail_object'
            WHEN 'relationship_edge'     THEN 'malu$relationship_edge'
            WHEN 'derivation_ledger'     THEN 'malu$derivation_ledger'
        END,
        CASE p_object_type
            WHEN 'source_package'        THEN 'source_package_id'
            WHEN 'claim'                 THEN 'claim_id'
            WHEN 'fact'                  THEN 'fact_id'
            WHEN 'memory'                THEN 'memory_id'
            WHEN 'episode_object'        THEN 'episode_id'
            WHEN 'memory_detail_object'  THEN 'mdo_id'
            WHEN 'relationship_edge'     THEN 'edge_id'
            WHEN 'derivation_ledger'     THEN 'derivation_id'
        END
    ) INTO v_exists USING p_object_id;
    IF NOT v_exists THEN
        RAISE EXCEPTION 'grant_object_access: %s id=% not visible to current schema',
            p_object_type, p_object_id
            USING ERRCODE = 'no_data_found';
    END IF;

    UPDATE malu$object_grant
       SET grant_level = p_grant_level,
           expires_at  = p_expires_at,
           note        = COALESCE(p_note, note),
           granted_at  = now()
     WHERE object_type        = p_object_type
       AND object_id          = p_object_id
       AND granted_to_schema  = p_granted_to_schema
       AND revoked_at         IS NULL
     RETURNING grant_id INTO v_id;
    IF FOUND THEN
        PERFORM audit_event('grant_upgrade', p_object_type, p_object_id,
            jsonb_build_object('grant_id', v_id, 'granted_to', p_granted_to_schema,
                               'grant_level', p_grant_level));
        RETURN v_id;
    END IF;

    INSERT INTO malu$object_grant
        (object_type, object_id, granted_to_schema,
         grant_level, expires_at, note)
    VALUES (p_object_type, p_object_id, p_granted_to_schema,
            p_grant_level, p_expires_at, p_note)
    RETURNING grant_id INTO v_id;

    PERFORM audit_event('grant', p_object_type, p_object_id,
        jsonb_build_object('grant_id', v_id, 'granted_to', p_granted_to_schema,
                           'grant_level', p_grant_level));
    RETURN v_id;
END;
$body$;

-- ---- revoke_object_grant -------------------------------------------
CREATE OR REPLACE FUNCTION revoke_object_grant(
    p_grant_id bigint,
    p_reason   text DEFAULT NULL
) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE v_obj_type text; v_obj_id bigint;
BEGIN
    SELECT object_type, object_id INTO v_obj_type, v_obj_id
    FROM malu$object_grant WHERE grant_id = p_grant_id AND revoked_at IS NULL;

    UPDATE malu$object_grant
       SET revoked_at = now(),
           note       = COALESCE(note || E'\n', '') ||
                        'revoked: ' || COALESCE(p_reason, 'no reason given')
     WHERE grant_id = p_grant_id
       AND revoked_at IS NULL;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'revoke_object_grant: grant_id=% not found or already revoked',
            p_grant_id
            USING ERRCODE = 'no_data_found';
    END IF;

    PERFORM audit_event('revoke', v_obj_type, v_obj_id,
        jsonb_build_object('grant_id', p_grant_id, 'reason', p_reason));
END;
$body$;

GRANT EXECUTE ON FUNCTION
    audit_event(text, text, bigint, jsonb, text),
    audit_status(),
    pgaudit_recommended_settings(),
    maludb_core_attach_stat_statements_view()
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.22.0--0.23.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.23.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.22.0 → 0.23.0
--
-- Stage 3 — Bitemporal columns (S3-1).
--
-- Per requirements.md §3.4: bitemporal columns (event_time,
-- valid_time_*, transaction_time_*, source_time, verification_time,
-- stale_after) using tstzrange + GIST exclusion.
--
-- S3-1 adds the columns + generated tstzrange + helper functions.
-- The EXCLUDE USING gist constraint that enforces no-overlapping-
-- validity per (subject, verb, predicate) ships in S3-2 (Temporal
-- Supersession Engine), where the surrounding correction flow
-- (close prior window + open new version + supersedes edge) is also
-- defined.
--
-- Tables that get bitemporal columns:
--   malu$claim          — assertions; can be open-ended
--   malu$fact           — verified state; correction discipline applies
--   malu$memory         — contextual records
--   malu$episode_object — DBMS representation of an episode
--
-- malu$source_package keeps its existing single timestamps
-- (captured_at, ingested_at, sealed_at, archived_at, tombstoned_at);
-- verbatim artifacts don't have a "valid time" concept.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.23.0'::text $body$;

-- btree_gist is required for the (text WITH =, range WITH &&)
-- exclusion the supersession engine (S3-2) will add. Pulling it in
-- now so operators don't hit a surprise dep on the next upgrade.
CREATE EXTENSION IF NOT EXISTS btree_gist;

-- ---------------------------------------------------------------------
-- Generic helpers — bitemporal predicates that work on any (start, end)
-- pair. IMMUTABLE so they can participate in indexes/EXCLUDEs.
-- ---------------------------------------------------------------------
CREATE FUNCTION is_currently_valid(
    p_start timestamptz,
    p_end   timestamptz
) RETURNS boolean
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT (p_start IS NULL OR p_start <= now())
       AND (p_end   IS NULL OR p_end   >  now());
$body$;

CREATE FUNCTION is_valid_at(
    p_start timestamptz,
    p_end   timestamptz,
    p_at    timestamptz
) RETURNS boolean
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT (p_start IS NULL OR p_start <= p_at)
       AND (p_end   IS NULL OR p_end   >  p_at);
$body$;

-- ---------------------------------------------------------------------
-- Add bitemporal columns + generated tstzrange columns to each table.
-- Defaults are chosen so existing register_* helpers keep working
-- unchanged: valid_time_start defaults to now() at insert,
-- transaction_time_start is NOT NULL DEFAULT now() (the canonical
-- "row exists" timestamp).
-- ---------------------------------------------------------------------

-- ---- malu$claim ----------------------------------------------------
ALTER TABLE malu$claim
    ADD COLUMN event_time             timestamptz,
    ADD COLUMN valid_time_start       timestamptz DEFAULT now(),
    ADD COLUMN valid_time_end         timestamptz,
    ADD COLUMN transaction_time_start timestamptz NOT NULL DEFAULT now(),
    ADD COLUMN transaction_time_end   timestamptz,
    ADD COLUMN source_time            timestamptz,
    ADD COLUMN verification_time      timestamptz,
    ADD COLUMN stale_after            timestamptz;

ALTER TABLE malu$claim
    ADD COLUMN valid_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(valid_time_start, valid_time_end, '[)')) STORED,
    ADD COLUMN transaction_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(transaction_time_start, transaction_time_end, '[)')) STORED;

CREATE INDEX malu$claim_valid_time_idx
    ON malu$claim USING gist (valid_time_range);
CREATE INDEX malu$claim_tx_time_idx
    ON malu$claim USING gist (transaction_time_range);

-- ---- malu$fact -----------------------------------------------------
ALTER TABLE malu$fact
    ADD COLUMN event_time             timestamptz,
    ADD COLUMN valid_time_start       timestamptz DEFAULT now(),
    ADD COLUMN valid_time_end         timestamptz,
    ADD COLUMN transaction_time_start timestamptz NOT NULL DEFAULT now(),
    ADD COLUMN transaction_time_end   timestamptz,
    ADD COLUMN source_time            timestamptz,
    ADD COLUMN verification_time      timestamptz,
    ADD COLUMN stale_after            timestamptz;

ALTER TABLE malu$fact
    ADD COLUMN valid_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(valid_time_start, valid_time_end, '[)')) STORED,
    ADD COLUMN transaction_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(transaction_time_start, transaction_time_end, '[)')) STORED;

CREATE INDEX malu$fact_valid_time_idx
    ON malu$fact USING gist (valid_time_range);
CREATE INDEX malu$fact_tx_time_idx
    ON malu$fact USING gist (transaction_time_range);

-- ---- malu$memory ---------------------------------------------------
ALTER TABLE malu$memory
    ADD COLUMN event_time             timestamptz,
    ADD COLUMN valid_time_start       timestamptz DEFAULT now(),
    ADD COLUMN valid_time_end         timestamptz,
    ADD COLUMN transaction_time_start timestamptz NOT NULL DEFAULT now(),
    ADD COLUMN transaction_time_end   timestamptz,
    ADD COLUMN source_time            timestamptz,
    ADD COLUMN verification_time      timestamptz,
    ADD COLUMN stale_after            timestamptz;

ALTER TABLE malu$memory
    ADD COLUMN valid_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(valid_time_start, valid_time_end, '[)')) STORED,
    ADD COLUMN transaction_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(transaction_time_start, transaction_time_end, '[)')) STORED;

CREATE INDEX malu$memory_valid_time_idx
    ON malu$memory USING gist (valid_time_range);
CREATE INDEX malu$memory_tx_time_idx
    ON malu$memory USING gist (transaction_time_range);

-- ---- malu$episode_object -------------------------------------------
ALTER TABLE malu$episode_object
    ADD COLUMN event_time             timestamptz,
    ADD COLUMN valid_time_start       timestamptz DEFAULT now(),
    ADD COLUMN valid_time_end         timestamptz,
    ADD COLUMN transaction_time_start timestamptz NOT NULL DEFAULT now(),
    ADD COLUMN transaction_time_end   timestamptz,
    ADD COLUMN source_time            timestamptz,
    ADD COLUMN verification_time      timestamptz,
    ADD COLUMN stale_after            timestamptz;

ALTER TABLE malu$episode_object
    ADD COLUMN valid_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(valid_time_start, valid_time_end, '[)')) STORED,
    ADD COLUMN transaction_time_range tstzrange GENERATED ALWAYS AS
        (tstzrange(transaction_time_start, transaction_time_end, '[)')) STORED;

CREATE INDEX malu$episode_valid_time_idx
    ON malu$episode_object USING gist (valid_time_range);
CREATE INDEX malu$episode_tx_time_idx
    ON malu$episode_object USING gist (transaction_time_range);

-- ---------------------------------------------------------------------
-- "Current" views — operator-facing convenience over the bitemporal
-- shape. Each filters to lifecycle='active' AND is_currently_valid.
-- These views are non-updatable; writes still go through register_*
-- helpers.
-- ---------------------------------------------------------------------
CREATE VIEW malu$current_claim AS
SELECT * FROM malu$claim
WHERE is_currently_valid(valid_time_start, valid_time_end)
  AND retracted_at IS NULL;

CREATE VIEW malu$current_fact AS
SELECT * FROM malu$fact
WHERE is_currently_valid(valid_time_start, valid_time_end)
  AND lifecycle_state = 'active'
  AND superseded_at IS NULL;

CREATE VIEW malu$current_memory AS
SELECT * FROM malu$memory
WHERE is_currently_valid(valid_time_start, valid_time_end)
  AND lifecycle_state = 'active';

CREATE VIEW malu$current_episode AS
SELECT * FROM malu$episode_object
WHERE is_currently_valid(valid_time_start, valid_time_end)
  AND lifecycle_state = 'active';

GRANT SELECT ON
    malu$current_claim, malu$current_fact, malu$current_memory, malu$current_episode
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ---------------------------------------------------------------------
-- as_of(p_at) helper: same shape as the current views but at an
-- arbitrary point. Per requirements.md §3.4: replay must reconstruct
-- the historical, current-valid, transaction-time, or full bitemporal
-- view. S3-1 ships the valid-time slice; transaction-time slice is
-- straightforward to query directly with WHERE
-- transaction_time_range @> p_at.
-- ---------------------------------------------------------------------
CREATE FUNCTION fact_as_of(p_at timestamptz) RETURNS SETOF malu$fact
LANGUAGE sql STABLE
AS $body$
    SELECT * FROM malu$fact
    WHERE is_valid_at(valid_time_start, valid_time_end, p_at)
      AND (transaction_time_start <= p_at)
      AND (transaction_time_end IS NULL OR transaction_time_end > p_at)
      AND lifecycle_state = 'active';
$body$;

CREATE FUNCTION memory_as_of(p_at timestamptz) RETURNS SETOF malu$memory
LANGUAGE sql STABLE
AS $body$
    SELECT * FROM malu$memory
    WHERE is_valid_at(valid_time_start, valid_time_end, p_at)
      AND (transaction_time_start <= p_at)
      AND (transaction_time_end IS NULL OR transaction_time_end > p_at)
      AND lifecycle_state = 'active';
$body$;

CREATE FUNCTION episode_as_of(p_at timestamptz) RETURNS SETOF malu$episode_object
LANGUAGE sql STABLE
AS $body$
    SELECT * FROM malu$episode_object
    WHERE is_valid_at(valid_time_start, valid_time_end, p_at)
      AND (transaction_time_start <= p_at)
      AND (transaction_time_end IS NULL OR transaction_time_end > p_at)
      AND lifecycle_state = 'active';
$body$;

GRANT EXECUTE ON FUNCTION
    is_currently_valid(timestamptz, timestamptz),
    is_valid_at(timestamptz, timestamptz, timestamptz),
    fact_as_of(timestamptz),
    memory_as_of(timestamptz),
    episode_as_of(timestamptz)
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ---------------------------------------------------------------------
-- Stage-boundary update: malu$valid_time_window and
-- malu$transaction_time_window placeholders are NO LONGER reserved
-- as separate tables — those columns now live on each governed
-- table. Stage 3 reservations still pending: malu$supersession_edge,
-- malu$svpor_*, malu$maut_score.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION stage_boundary_violations()
RETURNS TABLE(object_kind text, object_name text, stage smallint)
LANGUAGE sql STABLE
AS $body$
    WITH forbidden(name, stage) AS (
        VALUES
            ('malu$governed_object'::text,       2::smallint),
            ('malu$supersession_edge',           3),
            ('malu$svpor_subject',               3),
            ('malu$svpor_verb',                  3),
            ('malu$svpor_predicate',             3),
            ('malu$maut_score',                  3),
            ('malu$workflow_trace',              5),
            ('malu$generalized_workflow',        5),
            ('malu$procedural_memory_object',    5),
            ('malu$skill_package',               5),
            ('malu$competency_package',          5),
            ('malu$active_memory_pool',          5),
            ('malu$episode_replay',              5),
            ('malu$local_memory_node',           6),
            ('malu$node_sync_record',            6)
    )
    SELECT 'table'::text, c.relname::text, f.stage
    FROM pg_catalog.pg_class c
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    JOIN forbidden f ON f.name = c.relname
    WHERE n.nspname = 'maludb_core'
      AND c.relkind IN ('r','p','v','m')
    ORDER BY f.stage, c.relname;
$body$;

-- ============================================================
-- Section: maludb_core--0.23.0--0.24.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.24.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.23.0 → 0.24.0
--
-- Stage 3 — Temporal Supersession Engine (S3-2).
--
-- Per CLAUDE.md doctrine: "Corrections must never silently overwrite
-- history. They close a valid_time_end, open a new version, and create
-- a supersedes edge. The Temporal Supersession Engine owns this —
-- application code should call its API rather than mutating temporal
-- columns directly."
--
-- Surface:
--   * malu$supersession_edge — canonical (predecessor, successor)
--                              audit table with kind + reason + actor.
--   * malu$fact EXCLUDE constraint — enforces no-overlapping-validity
--                              per (subject, verb, predicate) for
--                              active, non-superseded rows.
--   * correct_fact(...)      — close prior valid window + open new
--                              version + supersedes edge in one tx.
--   * retract_fact(...)      — close prior window without successor;
--                              records kind='retraction' edge with
--                              successor_id=NULL.
--   * close_valid_window(type, id, ...) — polymorphic helper for any
--                              of {fact, memory, episode_object, claim}.
--   * reopen_valid_window(type, id) — admin override; clears
--                              valid_time_end and lifecycle_state.
--   * propagate_staleness(type, id) — flags downstream objects
--                              (memory / episode / fact) as stale
--                              via the relationship_edge graph.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.24.0'::text $body$;

-- =====================================================================
-- malu$supersession_edge
-- =====================================================================
CREATE TABLE malu$supersession_edge (
    edge_id              bigserial PRIMARY KEY,
    owner_schema         name NOT NULL DEFAULT current_schema(),
    predecessor_type     text NOT NULL,
    predecessor_id       bigint NOT NULL,
    successor_type       text,
    successor_id         bigint,
    supersession_kind    text NOT NULL DEFAULT 'correction'
        CHECK (supersession_kind IN ('correction','refinement','retraction',
                                     'consolidation','merge','split')),
    reason               text,
    superseded_at        timestamptz NOT NULL DEFAULT now(),
    actor_role           name NOT NULL DEFAULT current_user,
    CHECK (predecessor_type IN ('fact','memory','episode_object','claim')),
    CHECK (successor_type IS NULL OR
           successor_type IN ('fact','memory','episode_object','claim')),
    -- predecessor and successor (when both present) must be the same kind
    CHECK (successor_type IS NULL OR predecessor_type = successor_type),
    -- no self-supersession
    CHECK (NOT (predecessor_type = successor_type
                AND predecessor_id = successor_id))
);
CREATE INDEX malu$supersession_pred_idx
    ON malu$supersession_edge(predecessor_type, predecessor_id);
CREATE INDEX malu$supersession_succ_idx
    ON malu$supersession_edge(successor_type, successor_id)
    WHERE successor_id IS NOT NULL;

ALTER TABLE malu$supersession_edge ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$supersession_edge
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$supersession_edge TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT ON malu$supersession_edge TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$supersession_edge_edge_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- EXCLUDE constraint on malu$fact — at most one active row per
-- (subject, verb, predicate) at any given moment of valid time.
--
-- NULLs are coerced to '' so the equality operator covers them.
-- WHERE clause limits the constraint to active, non-superseded rows
-- so historical chains (which intentionally have closed windows)
-- don't trigger it.
-- =====================================================================
ALTER TABLE malu$fact
    ADD CONSTRAINT malu$fact_active_window_excl
    EXCLUDE USING gist (
        (COALESCE(subject,   '')) WITH =,
        (COALESCE(verb,      '')) WITH =,
        (COALESCE(predicate, '')) WITH =,
        valid_time_range WITH &&
    ) WHERE (lifecycle_state = 'active' AND superseded_at IS NULL);

-- =====================================================================
-- close_valid_window — polymorphic helper. Sets valid_time_end and
-- (when transitioning out of active) lifecycle_state. Idempotent:
-- closing an already-closed window with the same end_time is a no-op.
-- =====================================================================
CREATE FUNCTION close_valid_window(
    p_object_type text,
    p_object_id   bigint,
    p_end_time    timestamptz DEFAULT now(),
    p_reason      text DEFAULT NULL
) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE
    v_table text;
    v_id_col text;
    v_sql   text;
BEGIN
    CASE p_object_type
        WHEN 'fact'           THEN v_table := 'malu$fact';
                                   v_id_col := 'fact_id';
        WHEN 'memory'         THEN v_table := 'malu$memory';
                                   v_id_col := 'memory_id';
        WHEN 'episode_object' THEN v_table := 'malu$episode_object';
                                   v_id_col := 'episode_id';
        WHEN 'claim'          THEN v_table := 'malu$claim';
                                   v_id_col := 'claim_id';
        ELSE
            RAISE EXCEPTION 'close_valid_window: unsupported object_type %',
                p_object_type
                USING ERRCODE = 'invalid_parameter_value';
    END CASE;

    v_sql := format(
        'UPDATE maludb_core.%I SET valid_time_end = $1 WHERE %I = $2 ' ||
        'AND (valid_time_end IS NULL OR valid_time_end > $1)',
        v_table, v_id_col);
    EXECUTE v_sql USING p_end_time, p_object_id;

    PERFORM audit_event('close_valid_window', p_object_type, p_object_id,
        jsonb_build_object('end_time', p_end_time, 'reason', p_reason));
END;
$body$;

-- =====================================================================
-- reopen_valid_window — admin override. Clears valid_time_end and
-- (when lifecycle was 'superseded') resets to 'active'. Records audit.
-- Does NOT remove existing supersession_edge rows.
-- =====================================================================
CREATE FUNCTION reopen_valid_window(
    p_object_type text,
    p_object_id   bigint,
    p_reason      text DEFAULT NULL
) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE
    v_table text;
    v_id_col text;
    v_sql   text;
BEGIN
    IF p_reason IS NULL OR p_reason = '' THEN
        RAISE EXCEPTION 'reopen_valid_window: reason required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    CASE p_object_type
        WHEN 'fact'           THEN v_table := 'malu$fact';
                                   v_id_col := 'fact_id';
        WHEN 'memory'         THEN v_table := 'malu$memory';
                                   v_id_col := 'memory_id';
        WHEN 'episode_object' THEN v_table := 'malu$episode_object';
                                   v_id_col := 'episode_id';
        WHEN 'claim'          THEN v_table := 'malu$claim';
                                   v_id_col := 'claim_id';
        ELSE
            RAISE EXCEPTION 'reopen_valid_window: unsupported object_type %',
                p_object_type
                USING ERRCODE = 'invalid_parameter_value';
    END CASE;

    -- Per-type SET clause: only malu$fact has superseded_at; only
    -- malu$claim has retracted_at + retraction_reason; everything
    -- carries lifecycle_state on the governed tables.
    CASE p_object_type
        WHEN 'fact' THEN
            v_sql := format(
                'UPDATE maludb_core.%I SET valid_time_end = NULL, ' ||
                'superseded_at = NULL, lifecycle_state = ''active'' WHERE %I = $1',
                v_table, v_id_col);
        WHEN 'claim' THEN
            v_sql := format(
                'UPDATE maludb_core.%I SET valid_time_end = NULL, ' ||
                'retracted_at = NULL, retraction_reason = NULL WHERE %I = $1',
                v_table, v_id_col);
        ELSE
            -- memory, episode_object
            v_sql := format(
                'UPDATE maludb_core.%I SET valid_time_end = NULL, ' ||
                'lifecycle_state = ''active'' WHERE %I = $1',
                v_table, v_id_col);
    END CASE;
    EXECUTE v_sql USING p_object_id;

    PERFORM audit_event('reopen_valid_window', p_object_type, p_object_id,
        jsonb_build_object('reason', p_reason));
END;
$body$;

-- =====================================================================
-- correct_fact — the canonical correction flow.
--
-- In one tx:
--   1. Lock the old fact row (FOR UPDATE).
--   2. Verify the old row is active and not already superseded.
--   3. Close the old row's valid_time_end + set superseded_at +
--      lifecycle_state = 'superseded'.
--   4. Insert a new fact with the same SVPOR + new content, valid
--      from now.
--   5. Set the new row's supersedes_fact_id pointer.
--   6. INSERT malu$supersession_edge (kind='correction' by default).
--   7. Audit event.
--
-- Returns the new fact_id. RAISES if the precondition fails.
-- =====================================================================
CREATE FUNCTION correct_fact(
    p_fact_id           bigint,
    p_new_object_value  text DEFAULT NULL,
    p_new_statement     text DEFAULT NULL,
    p_new_statement_jsonb jsonb DEFAULT NULL,
    p_reason            text DEFAULT NULL,
    p_supersession_kind text DEFAULT 'correction'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_old         malu$fact%ROWTYPE;
    v_new_fact_id bigint;
    v_now         timestamptz := now();
BEGIN
    SELECT * INTO v_old FROM malu$fact WHERE fact_id = p_fact_id FOR UPDATE;
    IF v_old.fact_id IS NULL THEN
        RAISE EXCEPTION 'unknown fact_id: %', p_fact_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_old.superseded_at IS NOT NULL THEN
        RAISE EXCEPTION 'fact_id=% is already superseded at %',
            p_fact_id, v_old.superseded_at
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;
    IF v_old.lifecycle_state <> 'active' THEN
        RAISE EXCEPTION 'fact_id=% lifecycle_state=%; only active facts may be corrected',
            p_fact_id, v_old.lifecycle_state
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    -- 1. Close the old row. valid_time_end = now, superseded_at = now,
    --    lifecycle_state = 'superseded'.
    UPDATE malu$fact
       SET valid_time_end  = v_now,
           superseded_at   = v_now,
           lifecycle_state = 'superseded'
     WHERE fact_id = p_fact_id;

    -- 2. Insert the corrected fact. valid_time_start = now; same SVPOR.
    INSERT INTO malu$fact
        (subject, verb, predicate, object_value, relationship,
         statement_text, statement_jsonb,
         verification_scope, verification_method,
         supersedes_fact_id, valid_time_start, sensitivity)
    VALUES (v_old.subject, v_old.verb, v_old.predicate,
            COALESCE(p_new_object_value, v_old.object_value),
            v_old.relationship,
            COALESCE(p_new_statement, v_old.statement_text),
            COALESCE(p_new_statement_jsonb, v_old.statement_jsonb),
            v_old.verification_scope, v_old.verification_method,
            p_fact_id, v_now, v_old.sensitivity)
    RETURNING fact_id INTO v_new_fact_id;

    -- 3. Supersession edge.
    INSERT INTO malu$supersession_edge
        (predecessor_type, predecessor_id, successor_type, successor_id,
         supersession_kind, reason)
    VALUES ('fact', p_fact_id, 'fact', v_new_fact_id,
            p_supersession_kind, p_reason);

    PERFORM audit_event('correct_fact', 'fact', p_fact_id,
        jsonb_build_object(
            'successor_fact_id', v_new_fact_id,
            'supersession_kind', p_supersession_kind,
            'reason',            p_reason));

    RETURN v_new_fact_id;
END;
$body$;

-- =====================================================================
-- retract_fact — close the window with no successor. Records a
-- supersession_edge with successor_id=NULL and kind='retraction'.
-- =====================================================================
CREATE FUNCTION retract_fact(
    p_fact_id bigint,
    p_reason  text
) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE v_old malu$fact%ROWTYPE;
BEGIN
    IF p_reason IS NULL OR p_reason = '' THEN
        RAISE EXCEPTION 'retract_fact: reason required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    SELECT * INTO v_old FROM malu$fact WHERE fact_id = p_fact_id FOR UPDATE;
    IF v_old.fact_id IS NULL THEN
        RAISE EXCEPTION 'unknown fact_id: %', p_fact_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_old.superseded_at IS NOT NULL THEN
        RAISE EXCEPTION 'fact_id=% already superseded at %',
            p_fact_id, v_old.superseded_at
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    UPDATE malu$fact
       SET valid_time_end  = now(),
           superseded_at   = now(),
           lifecycle_state = 'retired'
     WHERE fact_id = p_fact_id;

    INSERT INTO malu$supersession_edge
        (predecessor_type, predecessor_id, supersession_kind, reason)
    VALUES ('fact', p_fact_id, 'retraction', p_reason);

    PERFORM audit_event('retract_fact', 'fact', p_fact_id,
        jsonb_build_object('reason', p_reason));
END;
$body$;

-- =====================================================================
-- propagate_staleness — when an object is superseded or retracted,
-- flag downstream objects that reference it via the relationship_edge
-- graph (one hop, not transitive in v1). Sets stale_after = now() on
-- the target if it's a fact / memory / episode that has the column.
--
-- Returns the count of objects flagged.
-- =====================================================================
CREATE FUNCTION propagate_staleness(
    p_source_type text,
    p_source_id   bigint,
    p_reason      text DEFAULT NULL
) RETURNS integer
LANGUAGE plpgsql
AS $body$
DECLARE
    v_count integer := 0;
    rec     record;
BEGIN
    FOR rec IN
        SELECT target_object_type, target_object_id
        FROM malu$relationship_edge
        WHERE source_object_type = p_source_type
          AND source_object_id   = p_source_id
        UNION
        SELECT source_object_type, source_object_id
        FROM malu$relationship_edge
        WHERE target_object_type = p_source_type
          AND target_object_id   = p_source_id
    LOOP
        IF rec.target_object_type = 'memory' THEN
            UPDATE malu$memory SET stale_after = now()
             WHERE memory_id = rec.target_object_id
               AND stale_after IS NULL;
            IF FOUND THEN v_count := v_count + 1; END IF;
        ELSIF rec.target_object_type = 'episode_object' THEN
            UPDATE malu$episode_object SET stale_after = now()
             WHERE episode_id = rec.target_object_id
               AND stale_after IS NULL;
            IF FOUND THEN v_count := v_count + 1; END IF;
        ELSIF rec.target_object_type = 'fact' THEN
            UPDATE malu$fact SET stale_after = now()
             WHERE fact_id = rec.target_object_id
               AND stale_after IS NULL
               AND lifecycle_state = 'active';
            IF FOUND THEN v_count := v_count + 1; END IF;
        END IF;
    END LOOP;

    PERFORM audit_event('propagate_staleness', p_source_type, p_source_id,
        jsonb_build_object('downstream_count', v_count, 'reason', p_reason));
    RETURN v_count;
END;
$body$;

GRANT EXECUTE ON FUNCTION
    close_valid_window(text, bigint, timestamptz, text),
    reopen_valid_window(text, bigint, text),
    correct_fact(bigint, text, text, jsonb, text, text),
    retract_fact(bigint, text),
    propagate_staleness(text, bigint, text)
TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- Stage boundary update — malu$supersession_edge now installed.
-- =====================================================================
CREATE OR REPLACE FUNCTION stage_boundary_violations()
RETURNS TABLE(object_kind text, object_name text, stage smallint)
LANGUAGE sql STABLE
AS $body$
    WITH forbidden(name, stage) AS (
        VALUES
            ('malu$governed_object'::text,       2::smallint),
            ('malu$svpor_subject',               3),
            ('malu$svpor_verb',                  3),
            ('malu$svpor_predicate',             3),
            ('malu$maut_score',                  3),
            ('malu$workflow_trace',              5),
            ('malu$generalized_workflow',        5),
            ('malu$procedural_memory_object',    5),
            ('malu$skill_package',               5),
            ('malu$competency_package',          5),
            ('malu$active_memory_pool',          5),
            ('malu$episode_replay',              5),
            ('malu$local_memory_node',           6),
            ('malu$node_sync_record',            6)
    )
    SELECT 'table'::text, c.relname::text, f.stage
    FROM pg_catalog.pg_class c
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    JOIN forbidden f ON f.name = c.relname
    WHERE n.nspname = 'maludb_core'
      AND c.relkind IN ('r','p','v','m')
    ORDER BY f.stage, c.relname;
$body$;

-- ============================================================
-- Section: maludb_core--0.24.0--0.25.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.25.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.24.0 → 0.25.0
--
-- Stage 3 — SVPOR organization layer (S3-3).
--
-- Per requirements.md §3.2: "Memory objects, claims, facts, and
-- embedded chunks must carry an explicit SVPOR frame so the system
-- can route on (subject, verb), bind embedding inputs deterministically,
-- and surface contradictions across related predicates."
--
-- And §9 Stage 3: "SVPOR organization layer + routing indexes; SVPOR
-- participation in embedding inputs."
--
-- Surface:
--   * Three Tier-A-style canonical registries: malu$svpor_subject,
--     malu$svpor_verb, malu$svpor_predicate. Each row carries a
--     canonical_name + aliases[] for normalization.
--   * register_svpor_subject / _verb / _predicate helpers (upsert).
--   * resolve_svpor_subject / _verb / _predicate (canonical OR alias
--     lookup; returns id or NULL).
--   * malu$claim / malu$fact get nullable svpor_*_id FK columns
--     plus a BEFORE INSERT/UPDATE trigger that auto-resolves text
--     to IDs when a canonical match exists.
--   * Composite routing index on (svpor_subject_id, svpor_verb_id).
--   * svpor_frame_text(...) — the deterministic embedding-input
--     prefix the caller's pipeline prepends to chunk text before
--     submitting for embedding.
--
-- Distinct from R1.1-12 malu$vector_subject / _verb which are
-- per-compartment routing tags (Stage 1.7); the malu$svpor_*
-- registries are the Stage 3 SEMANTIC layer with synonyms and
-- equivalence classes.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.25.0'::text $body$;

-- =====================================================================
-- SVPOR registries
-- =====================================================================
CREATE TABLE malu$svpor_subject (
    subject_id      bigserial PRIMARY KEY,
    owner_schema    name NOT NULL DEFAULT current_schema(),
    canonical_name  text NOT NULL,
    aliases         text[] NOT NULL DEFAULT ARRAY[]::text[],
    description     text,
    created_at      timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, canonical_name)
);
CREATE INDEX malu$svpor_subject_aliases_gin
    ON malu$svpor_subject USING gin (aliases);

CREATE TABLE malu$svpor_verb (
    verb_id         bigserial PRIMARY KEY,
    owner_schema    name NOT NULL DEFAULT current_schema(),
    canonical_name  text NOT NULL,
    aliases         text[] NOT NULL DEFAULT ARRAY[]::text[],
    description     text,
    created_at      timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, canonical_name)
);
CREATE INDEX malu$svpor_verb_aliases_gin
    ON malu$svpor_verb USING gin (aliases);

CREATE TABLE malu$svpor_predicate (
    predicate_id    bigserial PRIMARY KEY,
    owner_schema    name NOT NULL DEFAULT current_schema(),
    canonical_name  text NOT NULL,
    aliases         text[] NOT NULL DEFAULT ARRAY[]::text[],
    description     text,
    created_at      timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, canonical_name)
);
CREATE INDEX malu$svpor_predicate_aliases_gin
    ON malu$svpor_predicate USING gin (aliases);

ALTER TABLE malu$svpor_subject   ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$svpor_verb      ENABLE ROW LEVEL SECURITY;
ALTER TABLE malu$svpor_predicate ENABLE ROW LEVEL SECURITY;

CREATE POLICY tenant_owner ON malu$svpor_subject
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$svpor_verb
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());
CREATE POLICY tenant_owner ON malu$svpor_predicate
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$svpor_subject, malu$svpor_verb, malu$svpor_predicate TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE, DELETE ON malu$svpor_subject, malu$svpor_verb, malu$svpor_predicate TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE
    malu$svpor_subject_subject_id_seq,
    malu$svpor_verb_verb_id_seq,
    malu$svpor_predicate_predicate_id_seq
TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- register_svpor_* — upsert by (owner_schema, canonical_name).
-- aliases array is merged (union) with any existing values on conflict.
-- =====================================================================
CREATE FUNCTION register_svpor_subject(
    p_canonical_name text,
    p_aliases        text[] DEFAULT ARRAY[]::text[],
    p_description    text   DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$svpor_subject (canonical_name, aliases, description)
    VALUES (p_canonical_name, COALESCE(p_aliases, ARRAY[]::text[]), p_description)
    ON CONFLICT (owner_schema, canonical_name) DO UPDATE
        SET aliases     = (SELECT array_agg(DISTINCT a)
                           FROM unnest(malu$svpor_subject.aliases || COALESCE(EXCLUDED.aliases, ARRAY[]::text[])) AS a),
            description = COALESCE(EXCLUDED.description, malu$svpor_subject.description)
    RETURNING subject_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_svpor_verb(
    p_canonical_name text,
    p_aliases        text[] DEFAULT ARRAY[]::text[],
    p_description    text   DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$svpor_verb (canonical_name, aliases, description)
    VALUES (p_canonical_name, COALESCE(p_aliases, ARRAY[]::text[]), p_description)
    ON CONFLICT (owner_schema, canonical_name) DO UPDATE
        SET aliases     = (SELECT array_agg(DISTINCT a)
                           FROM unnest(malu$svpor_verb.aliases || COALESCE(EXCLUDED.aliases, ARRAY[]::text[])) AS a),
            description = COALESCE(EXCLUDED.description, malu$svpor_verb.description)
    RETURNING verb_id INTO v_id;
    RETURN v_id;
END;
$body$;

CREATE FUNCTION register_svpor_predicate(
    p_canonical_name text,
    p_aliases        text[] DEFAULT ARRAY[]::text[],
    p_description    text   DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$svpor_predicate (canonical_name, aliases, description)
    VALUES (p_canonical_name, COALESCE(p_aliases, ARRAY[]::text[]), p_description)
    ON CONFLICT (owner_schema, canonical_name) DO UPDATE
        SET aliases     = (SELECT array_agg(DISTINCT a)
                           FROM unnest(malu$svpor_predicate.aliases || COALESCE(EXCLUDED.aliases, ARRAY[]::text[])) AS a),
            description = COALESCE(EXCLUDED.description, malu$svpor_predicate.description)
    RETURNING predicate_id INTO v_id;
    RETURN v_id;
END;
$body$;

-- =====================================================================
-- resolve_svpor_* — text → id lookup. Tries canonical_name first,
-- then aliases. Returns NULL when neither matches (graceful: callers
-- carry the literal text in the existing columns).
-- =====================================================================
CREATE FUNCTION resolve_svpor_subject(p_text text) RETURNS bigint
LANGUAGE sql STABLE
AS $body$
    SELECT subject_id FROM malu$svpor_subject
    WHERE canonical_name = p_text OR p_text = ANY(aliases)
    ORDER BY (canonical_name = p_text) DESC LIMIT 1;
$body$;

CREATE FUNCTION resolve_svpor_verb(p_text text) RETURNS bigint
LANGUAGE sql STABLE
AS $body$
    SELECT verb_id FROM malu$svpor_verb
    WHERE canonical_name = p_text OR p_text = ANY(aliases)
    ORDER BY (canonical_name = p_text) DESC LIMIT 1;
$body$;

CREATE FUNCTION resolve_svpor_predicate(p_text text) RETURNS bigint
LANGUAGE sql STABLE
AS $body$
    SELECT predicate_id FROM malu$svpor_predicate
    WHERE canonical_name = p_text OR p_text = ANY(aliases)
    ORDER BY (canonical_name = p_text) DESC LIMIT 1;
$body$;

-- =====================================================================
-- Add FK columns to malu$claim and malu$fact. ON DELETE SET NULL so
-- registry pruning doesn't cascade through governed data.
-- =====================================================================
ALTER TABLE malu$claim
    ADD COLUMN svpor_subject_id   bigint REFERENCES malu$svpor_subject(subject_id)     ON DELETE SET NULL,
    ADD COLUMN svpor_verb_id      bigint REFERENCES malu$svpor_verb(verb_id)           ON DELETE SET NULL,
    ADD COLUMN svpor_predicate_id bigint REFERENCES malu$svpor_predicate(predicate_id) ON DELETE SET NULL;

ALTER TABLE malu$fact
    ADD COLUMN svpor_subject_id   bigint REFERENCES malu$svpor_subject(subject_id)     ON DELETE SET NULL,
    ADD COLUMN svpor_verb_id      bigint REFERENCES malu$svpor_verb(verb_id)           ON DELETE SET NULL,
    ADD COLUMN svpor_predicate_id bigint REFERENCES malu$svpor_predicate(predicate_id) ON DELETE SET NULL;

-- Routing indexes: (subject, verb) is the dominant access path per §3.2.
CREATE INDEX malu$claim_svpor_routing_idx
    ON malu$claim (svpor_subject_id, svpor_verb_id)
    WHERE svpor_subject_id IS NOT NULL OR svpor_verb_id IS NOT NULL;
CREATE INDEX malu$fact_svpor_routing_idx
    ON malu$fact (svpor_subject_id, svpor_verb_id)
    WHERE svpor_subject_id IS NOT NULL OR svpor_verb_id IS NOT NULL;

-- =====================================================================
-- Auto-resolve trigger — when subject/verb/predicate text is written
-- and the matching svpor_*_id is NULL, attempt to resolve via the
-- registries. If no match, leave the FK NULL (caller carries the
-- literal text in subject/verb/predicate). Idempotent for re-resolve
-- after registry updates (operator can SET svpor_subject_id=NULL +
-- update text to force a fresh lookup).
-- =====================================================================
CREATE FUNCTION _svpor_auto_resolve() RETURNS trigger
LANGUAGE plpgsql
AS $body$
BEGIN
    IF NEW.svpor_subject_id IS NULL AND NEW.subject IS NOT NULL THEN
        NEW.svpor_subject_id := resolve_svpor_subject(NEW.subject);
    END IF;
    IF NEW.svpor_verb_id IS NULL AND NEW.verb IS NOT NULL THEN
        NEW.svpor_verb_id := resolve_svpor_verb(NEW.verb);
    END IF;
    IF NEW.svpor_predicate_id IS NULL AND NEW.predicate IS NOT NULL THEN
        NEW.svpor_predicate_id := resolve_svpor_predicate(NEW.predicate);
    END IF;
    RETURN NEW;
END;
$body$;

CREATE TRIGGER claim_svpor_resolve_tg
    BEFORE INSERT OR UPDATE OF subject, verb, predicate ON malu$claim
    FOR EACH ROW EXECUTE FUNCTION _svpor_auto_resolve();
CREATE TRIGGER fact_svpor_resolve_tg
    BEFORE INSERT OR UPDATE OF subject, verb, predicate ON malu$fact
    FOR EACH ROW EXECUTE FUNCTION _svpor_auto_resolve();

-- =====================================================================
-- svpor_frame_text — the embedding-input prefix. The caller's
-- pipeline prepends this to chunk text before submitting to the
-- embedding model. Per §3.2: "bind embedding inputs deterministically".
--
-- Format: "[svpor] <subject> · <verb> [· <predicate>] [= <object>]"
-- Stable across runs; missing components render as "?".
-- =====================================================================
CREATE FUNCTION svpor_frame_text(
    p_subject       text,
    p_verb          text,
    p_predicate     text DEFAULT NULL,
    p_object_value  text DEFAULT NULL
) RETURNS text
LANGUAGE sql IMMUTABLE PARALLEL SAFE
AS $body$
    SELECT '[svpor] ' ||
           COALESCE(NULLIF(p_subject, ''), '?') || ' · ' ||
           COALESCE(NULLIF(p_verb,    ''), '?') ||
           CASE WHEN NULLIF(p_predicate,    '') IS NOT NULL
                THEN ' · ' || p_predicate ELSE '' END ||
           CASE WHEN NULLIF(p_object_value, '') IS NOT NULL
                THEN ' = ' || p_object_value ELSE '' END;
$body$;

-- =====================================================================
-- A view that surfaces resolved canonical names alongside the
-- literal text for ops/UX surfaces.
-- =====================================================================
CREATE VIEW malu$claim_svpor_resolved AS
SELECT c.claim_id,
       c.owner_schema,
       c.subject       AS subject_text,
       s.canonical_name AS subject_canonical,
       c.verb          AS verb_text,
       v.canonical_name AS verb_canonical,
       c.predicate     AS predicate_text,
       p.canonical_name AS predicate_canonical,
       c.object_value,
       c.statement_text,
       c.svpor_subject_id, c.svpor_verb_id, c.svpor_predicate_id
FROM malu$claim c
LEFT JOIN malu$svpor_subject   s ON s.subject_id   = c.svpor_subject_id
LEFT JOIN malu$svpor_verb      v ON v.verb_id      = c.svpor_verb_id
LEFT JOIN malu$svpor_predicate p ON p.predicate_id = c.svpor_predicate_id;

CREATE VIEW malu$fact_svpor_resolved AS
SELECT f.fact_id,
       f.owner_schema,
       f.subject       AS subject_text,
       s.canonical_name AS subject_canonical,
       f.verb          AS verb_text,
       v.canonical_name AS verb_canonical,
       f.predicate     AS predicate_text,
       p.canonical_name AS predicate_canonical,
       f.object_value,
       f.statement_text,
       f.lifecycle_state,
       f.svpor_subject_id, f.svpor_verb_id, f.svpor_predicate_id
FROM malu$fact f
LEFT JOIN malu$svpor_subject   s ON s.subject_id   = f.svpor_subject_id
LEFT JOIN malu$svpor_verb      v ON v.verb_id      = f.svpor_verb_id
LEFT JOIN malu$svpor_predicate p ON p.predicate_id = f.svpor_predicate_id;

GRANT SELECT ON malu$claim_svpor_resolved, malu$fact_svpor_resolved TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

GRANT EXECUTE ON FUNCTION
    register_svpor_subject(text, text[], text),
    register_svpor_verb(text, text[], text),
    register_svpor_predicate(text, text[], text),
    resolve_svpor_subject(text),
    resolve_svpor_verb(text),
    resolve_svpor_predicate(text),
    svpor_frame_text(text, text, text, text)
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- =====================================================================
-- Stage-boundary update. Remove the three svpor_* placeholder names.
-- Remaining Stage 3+ reservations: malu$maut_score (S3-4); Stage 5+
-- and Stage 6+ rows unchanged.
-- =====================================================================
CREATE OR REPLACE FUNCTION stage_boundary_violations()
RETURNS TABLE(object_kind text, object_name text, stage smallint)
LANGUAGE sql STABLE
AS $body$
    WITH forbidden(name, stage) AS (
        VALUES
            ('malu$governed_object'::text,       2::smallint),
            ('malu$maut_score',                  3),
            ('malu$workflow_trace',              5),
            ('malu$generalized_workflow',        5),
            ('malu$procedural_memory_object',    5),
            ('malu$skill_package',               5),
            ('malu$competency_package',          5),
            ('malu$active_memory_pool',          5),
            ('malu$episode_replay',              5),
            ('malu$local_memory_node',           6),
            ('malu$node_sync_record',            6)
    )
    SELECT 'table'::text, c.relname::text, f.stage
    FROM pg_catalog.pg_class c
    JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
    JOIN forbidden f ON f.name = c.relname
    WHERE n.nspname = 'maludb_core'
      AND c.relkind IN ('r','p','v','m')
    ORDER BY f.stage, c.relname;
$body$;

