    advanced_write_episode(jsonb, jsonb),
    advanced_write_source_package(jsonb, jsonb)
TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.40.0--0.41.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.41.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.40.0 → 0.41.0
--
-- S7-2.a — owner_schema + RLS on malu$mc2db_invocation.
--
-- Closes docs/security-review.md finding #2: every MC2DB tool call
-- lands an audit row in malu$mc2db_invocation, but the table had no
-- tenant discriminator. As long as only the extension owner had
-- GRANT, the leak was theoretical — but as soon as an operator
-- opens self-service audit-reader access, cross-tenant invocation
-- patterns would be visible.
--
-- This migration:
--   1. ADD COLUMN owner_schema NOT NULL DEFAULT current_schema().
--   2. Backfills existing rows with 'maludb_core' (the extension
--      owner schema, which is where every pre-0.41 invocation row
--      originated).
--   3. ENABLE ROW LEVEL SECURITY + a tenant_owner policy.
--   4. Grants SELECT on the table to the memory_* role family so
--      tenants can read their own invocation history; INSERT stays
--      restricted to the extension owner (the dispatcher writes
--      through SECURITY DEFINER-style elevation, which is its job).
--
-- The dispatcher (mc2dbd) must, when invoking a tool on behalf of a
-- tenant, ensure current_schema() resolves to the tenant's schema
-- before the INSERT. The standard pattern is:
--   SET LOCAL ROLE <tenant_role>;
--   SET LOCAL search_path TO <tenant_schema>, maludb_core, public;
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.41.0'::text $body$;

-- =====================================================================
-- 1. Add owner_schema with a backfill-safe default.
-- =====================================================================
ALTER TABLE malu$mc2db_invocation
    ADD COLUMN owner_schema name NOT NULL DEFAULT current_schema();

-- 2. Backfill existing rows. ADD COLUMN ... NOT NULL DEFAULT fills
--    with the DEFAULT at the time of ALTER, which is 'maludb_core'
--    when the migration runs as the extension owner. Explicit update
--    here just to make the intent unmistakable.
UPDATE malu$mc2db_invocation
   SET owner_schema = 'maludb_core'
 WHERE owner_schema IS NULL OR owner_schema = '';

-- 3. RLS.
ALTER TABLE malu$mc2db_invocation ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$mc2db_invocation
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

CREATE INDEX malu$mc2db_invocation_owner_idx
    ON malu$mc2db_invocation(owner_schema, started_at DESC);

-- 4. Grants — same pattern as the Tier-B governed-object surface:
--    SELECT to admin/executor/auditor; no INSERT/UPDATE/DELETE to
--    memory_* (the dispatcher owns the write path, not tenants).
GRANT SELECT ON malu$mc2db_invocation TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- =====================================================================
-- Stage-boundary roadmap is unchanged; malu$mc2db_invocation was
-- never on the forbidden list.
-- =====================================================================

-- ============================================================
-- Section: maludb_core--0.41.0--0.42.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.42.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.41.0 → 0.42.0
--
-- Stage 9 / V3-AUTH-01: first-party API token catalog.
--
-- Adds the authentication primitives that MC2DB, the future V3 REST
-- gateway (maludb-restd), and the CLI will share — personal and service
-- tokens with hash storage, expiry, revocation, optional CIDR allow
-- lists, scopes, per-use audit, plus JWT signing-key registry rows.
--
-- This migration lands the SQL surface only. The C HMAC verifier and
-- the JWT signature verifier (RS256 / ES256 / EdDSA) come in a
-- follow-up; until then, `auth_token_verify` calls pgcrypto's hmac()
-- in PL/pgSQL and `jwt_verify` is an explicit stub that raises
-- AUTH_TOKEN_JWT_NOT_AVAILABLE.
--
-- Per requirements.md §1.5 and version3-plan.md V3-AUTH-01:
--   * Same token model for SQL, MC2DB, and REST.
--   * Revocation takes effect immediately, no service restart.
--   * Every create / use / revoke / failed-verify writes audit.
--   * RLS: an account sees only its own token rows. auditor and admin
--     bypass; the verifier reads across RLS via SECURITY DEFINER.
--
-- Plaintext token shape: `mldbat_<43 base64url chars>` — 32 random
-- bytes encoded, prefixed for grep-ability and easy revocation by
-- pattern match in operator logs.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.42.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.42.0'::text $body$;

-- ---------------------------------------------------------------------
-- pgcrypto dependency. Listed in maludb_core.control's `requires` for
-- fresh installs; this idempotent guard covers in-place upgrades from
-- 0.41.0, where pgcrypto wasn't yet required.
--
-- pgcrypto installs into `public` by default; the SECURITY DEFINER
-- functions below pin search_path = pg_catalog, maludb_core, so every
-- pgcrypto call is schema-qualified as `public.<fn>(...)`.
-- ---------------------------------------------------------------------
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- ---------------------------------------------------------------------
-- Schema USAGE for the maludb_memory_* role family. Created in 0.14.0,
-- but never granted USAGE on the maludb_core schema — table-level
-- privileges in earlier migrations went unused because no caller bound
-- to maludb_memory_executor without first becoming maludb_llm_executor
-- (which has the USAGE grant). Stage 9 introduces functions
-- (auth_token_create / _revoke / _verify) that maludb_memory_executor
-- needs to call directly, so the gap matters now.
-- ---------------------------------------------------------------------
GRANT USAGE ON SCHEMA maludb_core TO
    maludb_memory_admin,
    maludb_memory_executor,
    maludb_memory_auditor;

-- ---------------------------------------------------------------------
-- malu$auth_pepper — single-row server-side secret used as the key to
-- HMAC-SHA256 over each token's plaintext. Generated on first
-- migration; not visible to ordinary roles.
--
-- A pepper rotation lands as a future migration that re-hashes every
-- non-revoked token; out of scope for the initial cut.
-- ---------------------------------------------------------------------
CREATE TABLE malu$auth_pepper (
    pepper_id  smallint PRIMARY KEY CHECK (pepper_id = 1),
    pepper     bytea    NOT NULL,
    created_at timestamptz NOT NULL DEFAULT now()
);
REVOKE ALL ON malu$auth_pepper FROM PUBLIC;
INSERT INTO malu$auth_pepper(pepper_id, pepper)
VALUES (1, public.gen_random_bytes(32));

-- ---------------------------------------------------------------------
-- malu$auth_token — one row per issued token.
--   * token_hash stores HMAC-SHA256(pepper, plaintext); plaintext is
--     never persisted.
--   * allowed_cidrs is NULL = no IP restriction; otherwise the source
--     IP MUST match at least one CIDR at verify time.
--   * scopes is an opaque text[] consumed by callers; not interpreted
--     by the catalog.
--   * owner_schema is the tenant binding for RLS visibility — it
--     follows the project's tenancy convention (current_schema()).
-- ---------------------------------------------------------------------
CREATE TABLE malu$auth_token (
    token_id       bigserial PRIMARY KEY,
    account_id     bigint    NOT NULL REFERENCES malu$account(account_id) ON DELETE CASCADE,
    token_hash     bytea     NOT NULL UNIQUE,
    token_kind     text      NOT NULL CHECK (token_kind IN ('personal','service')),
    label          text,
    scopes         text[]    NOT NULL DEFAULT ARRAY[]::text[],
    allowed_cidrs  inet[],
    created_at     timestamptz NOT NULL DEFAULT now(),
    expires_at     timestamptz,
    last_used_at   timestamptz,
    revoked_at     timestamptz,
    owner_schema   name      NOT NULL DEFAULT current_schema(),
    CHECK (expires_at IS NULL OR expires_at > created_at)
);
CREATE INDEX malu$auth_token_account_idx
    ON malu$auth_token(account_id) WHERE revoked_at IS NULL;
CREATE INDEX malu$auth_token_owner_idx
    ON malu$auth_token(owner_schema, account_id, revoked_at);
COMMENT ON TABLE malu$auth_token IS
    'V3-AUTH-01: issued API tokens. Plaintext is never persisted; '
    'token_hash holds HMAC-SHA256(pepper, plaintext). Read-back is '
    'tenant-bound by RLS; the verifier crosses RLS via SECURITY DEFINER.';

-- ---------------------------------------------------------------------
-- malu$auth_token_use — append-only audit of every verification
-- attempt against a known token. Failed verifications (unknown hash)
-- land in malu$audit_event with event_kind = 'auth_token_verify_reject'
-- and a NULL token_id reference, since there is no row to attach to.
-- ---------------------------------------------------------------------
CREATE TABLE malu$auth_token_use (
    use_id      bigserial PRIMARY KEY,
    token_id    bigint    NOT NULL REFERENCES malu$auth_token(token_id) ON DELETE CASCADE,
    used_at     timestamptz NOT NULL DEFAULT now(),
    source_ip   inet,
    outcome     text      NOT NULL CHECK (outcome IN
                  ('accepted','rejected_expired','rejected_revoked',
                   'rejected_cidr','rejected_disabled_account')),
    detail      text
);
CREATE INDEX malu$auth_token_use_token_idx
    ON malu$auth_token_use(token_id, used_at DESC);
CREATE INDEX malu$auth_token_use_outcome_idx
    ON malu$auth_token_use(outcome, used_at DESC)
    WHERE outcome <> 'accepted';

-- ---------------------------------------------------------------------
-- malu$jwt_signing_key — registry of public signing keys that the
-- future jwt_verify path will trust. C verifier consumes these rows;
-- no plaintext private material is ever persisted.
-- ---------------------------------------------------------------------
CREATE TABLE malu$jwt_signing_key (
    key_id      bigserial PRIMARY KEY,
    kid         text      NOT NULL UNIQUE,
    kty         text      NOT NULL CHECK (kty IN ('RSA','EC','OKP')),
    alg         text      NOT NULL CHECK (alg IN ('RS256','RS384','RS512',
                                                  'ES256','ES384','ES512',
                                                  'EdDSA')),
    public_jwk  jsonb     NOT NULL,
    enabled     boolean   NOT NULL DEFAULT true,
    created_at  timestamptz NOT NULL DEFAULT now(),
    rotated_at  timestamptz,
    note        text
);
CREATE INDEX malu$jwt_signing_key_enabled_idx
    ON malu$jwt_signing_key(enabled, kid);

-- ---------------------------------------------------------------------
-- RLS — tokens are visible only to their owning account; uses follow
-- their parent token. JWT signing keys are admin-only and ungated.
-- ---------------------------------------------------------------------
ALTER TABLE malu$auth_token ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$auth_token
    USING      (account_id = current_account_id())
    WITH CHECK (account_id = current_account_id());

ALTER TABLE malu$auth_token_use ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_token ON malu$auth_token_use
    USING (
        EXISTS (
            SELECT 1 FROM malu$auth_token t
            WHERE t.token_id   = malu$auth_token_use.token_id
              AND t.account_id = current_account_id()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$auth_token t
            WHERE t.token_id   = malu$auth_token_use.token_id
              AND t.account_id = current_account_id()
        )
    );

ALTER TABLE malu$jwt_signing_key ENABLE ROW LEVEL SECURITY;
-- Non-superuser, non-BYPASSRLS roles see no rows by default; signing
-- keys are operator-managed via maludb_memory_admin (BYPASSRLS).
CREATE POLICY admin_only ON malu$jwt_signing_key USING (false) WITH CHECK (false);

-- ---------------------------------------------------------------------
-- Grants. Roles created in earlier migrations (0.14.0+) are reused:
--   * maludb_memory_admin    — BYPASSRLS, full CRUD across tenants.
--   * maludb_memory_executor — CRUD on own tokens via RLS; SELECT on
--                              own uses.
--   * maludb_memory_auditor  — BYPASSRLS, SELECT-only.
-- ---------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE, DELETE ON malu$auth_token, malu$auth_token_use TO
    maludb_memory_admin, maludb_memory_executor;
GRANT SELECT ON malu$auth_token, malu$auth_token_use TO
    maludb_memory_auditor;

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$jwt_signing_key TO
    maludb_memory_admin;
GRANT SELECT ON malu$jwt_signing_key TO
    maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$auth_token_token_id_seq        TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$auth_token_use_use_id_seq      TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$jwt_signing_key_key_id_seq     TO
    maludb_memory_admin;

-- =====================================================================
-- Helpers
-- =====================================================================

-- maludb_core.__auth_pepper — internal accessor to the single-row
-- pepper. SECURITY DEFINER so non-admin roles can verify their own
-- tokens through auth_token_verify without holding SELECT on
-- malu$auth_pepper. Returns bytea, never logged.
CREATE FUNCTION __auth_pepper() RETURNS bytea
    LANGUAGE plpgsql STABLE PARALLEL SAFE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
DECLARE v_p bytea;
BEGIN
    SELECT pepper INTO v_p FROM malu$auth_pepper WHERE pepper_id = 1;
    RETURN v_p;
END;
$body$;
REVOKE EXECUTE ON FUNCTION __auth_pepper() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION __auth_pepper() TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- __auth_token_encode — turns a 32-byte random into the public
-- mldbat_<base64url> form. base64url = base64 with '+'/'/' → '-'/'_'
-- and '=' padding stripped.
CREATE FUNCTION __auth_token_encode(p_bytes bytea) RETURNS text
    LANGUAGE plpgsql IMMUTABLE PARALLEL SAFE
    SET search_path = pg_catalog, maludb_core
    AS $body$
DECLARE
    v_b64 text;
BEGIN
    -- base64 → base64url: '+' → '-', '/' → '_'. '=' padding and any
    -- newline pgcrypto inserts after 76 chars are dropped (no
    -- corresponding char in the destination set). The four FROM
    -- chars are intentionally ordered ('+', '/', '=', '\n') so the
    -- pairwise TO mapping is '-' for '+', '_' for '/', and drop for
    -- the rest.
    v_b64 := encode(p_bytes, 'base64');
    v_b64 := translate(v_b64, E'+/=\n', '-_');
    RETURN 'mldbat_' || v_b64;
END;
$body$;
REVOKE EXECUTE ON FUNCTION __auth_token_encode(bytea) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION __auth_token_encode(bytea) TO
    maludb_memory_admin, maludb_memory_executor;

-- __auth_token_hash — HMAC-SHA256(pepper, plaintext). Internal; the
-- verifier and the creator both call this to ensure the hashing is
-- defined in exactly one place.
CREATE FUNCTION __auth_token_hash(p_plaintext text) RETURNS bytea
    LANGUAGE plpgsql STABLE PARALLEL SAFE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
BEGIN
    RETURN public.hmac(p_plaintext::bytea, __auth_pepper(), 'sha256');
END;
$body$;
REVOKE EXECUTE ON FUNCTION __auth_token_hash(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION __auth_token_hash(text) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- =====================================================================
-- Public API
-- =====================================================================

-- auth_token_create — issues a new token. Returns (token_id,
-- plaintext_token) exactly once; plaintext is irrecoverable
-- afterwards. SECURITY DEFINER so an executor role can write the row
-- without holding INSERT directly (the caller's identity flows through
-- current_account_id; the row's account_id is checked against it).
CREATE FUNCTION auth_token_create(
    p_account_id    bigint,
    p_kind          text,
    p_label         text             DEFAULT NULL,
    p_scopes        text[]           DEFAULT ARRAY[]::text[],
    p_allowed_cidrs inet[]           DEFAULT NULL,
    p_expires_at    timestamptz      DEFAULT NULL
) RETURNS TABLE (token_id bigint, plaintext_token text)
    LANGUAGE plpgsql VOLATILE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
DECLARE
    v_caller bigint := current_account_id();
    v_random bytea;
    v_plain  text;
    v_hash   bytea;
    v_id     bigint;
BEGIN
    -- Authorization: the caller may issue tokens only for its own
    -- account, unless the caller is BYPASSRLS (memory_admin /
    -- memory_auditor) in which case we trust them and skip the check.
    IF v_caller IS NOT NULL AND v_caller <> p_account_id THEN
        RAISE EXCEPTION 'auth_token_create: caller account % cannot issue tokens for account %',
            v_caller, p_account_id
            USING ERRCODE = 'insufficient_privilege';
    END IF;

    IF p_kind NOT IN ('personal','service') THEN
        RAISE EXCEPTION 'auth_token_create: token_kind must be personal or service'
            USING ERRCODE = 'check_violation';
    END IF;

    v_random := public.gen_random_bytes(32);
    v_plain  := __auth_token_encode(v_random);
    v_hash   := __auth_token_hash(v_plain);

    INSERT INTO malu$auth_token
        (account_id, token_hash, token_kind, label, scopes,
         allowed_cidrs, expires_at)
    VALUES
        (p_account_id, v_hash, p_kind, p_label, p_scopes,
         p_allowed_cidrs, p_expires_at)
    RETURNING malu$auth_token.token_id INTO v_id;

    PERFORM audit_event(
        'auth_token_create',
        'malu$auth_token',
        v_id,
        jsonb_build_object(
            'account_id', p_account_id,
            'token_kind', p_kind,
            'label',      p_label,
            'expires_at', p_expires_at,
            'scopes',     to_jsonb(p_scopes),
            'has_cidr',   p_allowed_cidrs IS NOT NULL),
        NULL);

    token_id         := v_id;
    plaintext_token  := v_plain;
    RETURN NEXT;
END;
$body$;
REVOKE EXECUTE ON FUNCTION auth_token_create(bigint, text, text, text[], inet[], timestamptz) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION auth_token_create(bigint, text, text, text[], inet[], timestamptz) TO
    maludb_memory_admin, maludb_memory_executor;

-- auth_token_revoke — sets revoked_at and writes audit. No-ops idem-
-- potently when the token is already revoked.
CREATE FUNCTION auth_token_revoke(p_token_id bigint, p_reason text DEFAULT NULL)
    RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
DECLARE
    v_caller    bigint := current_account_id();
    v_owner     bigint;
    v_was_open  boolean;
BEGIN
    SELECT account_id, revoked_at IS NULL
      INTO v_owner, v_was_open
      FROM malu$auth_token
     WHERE token_id = p_token_id;

    IF v_owner IS NULL THEN
        RAISE EXCEPTION 'auth_token_revoke: token_id % not found', p_token_id
            USING ERRCODE = 'no_data_found';
    END IF;

    IF v_caller IS NOT NULL AND v_caller <> v_owner THEN
        RAISE EXCEPTION 'auth_token_revoke: account % cannot revoke token owned by account %',
            v_caller, v_owner
            USING ERRCODE = 'insufficient_privilege';
    END IF;

    UPDATE malu$auth_token
       SET revoked_at = COALESCE(revoked_at, now())
     WHERE token_id = p_token_id;

    PERFORM audit_event(
        'auth_token_revoke',
        'malu$auth_token',
        p_token_id,
        jsonb_build_object(
            'reason',     p_reason,
            'was_active', v_was_open),
        NULL);

    RETURN v_was_open;
END;
$body$;
REVOKE EXECUTE ON FUNCTION auth_token_revoke(bigint, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION auth_token_revoke(bigint, text) TO
    maludb_memory_admin, maludb_memory_executor;

-- auth_token_verify — accepts plaintext, returns the binding context.
-- SECURITY DEFINER so the lookup can find the matching token regardless
-- of which tenant the caller currently appears as. Failed verifications
-- still write a malu$audit_event row; rejected verifications against a
-- KNOWN token also write malu$auth_token_use so per-token rate-limit
-- analytics work.
CREATE FUNCTION auth_token_verify(
    p_plaintext   text,
    p_source_ip   inet DEFAULT NULL
) RETURNS TABLE (
    token_id    bigint,
    account_id  bigint,
    token_kind  text,
    scopes      text[]
) LANGUAGE plpgsql VOLATILE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
#variable_conflict use_column
DECLARE
    v_hash    bytea;
    v_row     malu$auth_token%ROWTYPE;
    v_account_enabled boolean;
    v_outcome text;
    v_detail  text := NULL;
BEGIN
    IF p_plaintext IS NULL OR p_plaintext = '' THEN
        PERFORM audit_event('auth_token_verify_reject', 'malu$auth_token', NULL,
            jsonb_build_object('reason','empty_plaintext','source_ip',p_source_ip::text),
            NULL);
        RETURN;
    END IF;

    v_hash := __auth_token_hash(p_plaintext);

    SELECT * INTO v_row FROM malu$auth_token WHERE token_hash = v_hash;
    IF v_row.token_id IS NULL THEN
        PERFORM audit_event('auth_token_verify_reject', 'malu$auth_token', NULL,
            jsonb_build_object('reason','unknown_token','source_ip',p_source_ip::text),
            NULL);
        RETURN;
    END IF;

    -- Verify the parent account is still enabled.
    SELECT enabled INTO v_account_enabled FROM malu$account WHERE account_id = v_row.account_id;
    IF NOT v_account_enabled THEN
        v_outcome := 'rejected_disabled_account';
    ELSIF v_row.revoked_at IS NOT NULL THEN
        v_outcome := 'rejected_revoked';
    ELSIF v_row.expires_at IS NOT NULL AND v_row.expires_at <= now() THEN
        v_outcome := 'rejected_expired';
    ELSIF v_row.allowed_cidrs IS NOT NULL AND p_source_ip IS NOT NULL THEN
        IF NOT EXISTS (SELECT 1 FROM unnest(v_row.allowed_cidrs) c WHERE p_source_ip <<= c) THEN
            v_outcome := 'rejected_cidr';
            v_detail  := 'source_ip not in allowed_cidrs';
        END IF;
    END IF;

    IF v_outcome IS NULL THEN
        v_outcome := 'accepted';
        UPDATE malu$auth_token SET last_used_at = now() WHERE token_id = v_row.token_id;
    END IF;

    INSERT INTO malu$auth_token_use(token_id, source_ip, outcome, detail)
    VALUES (v_row.token_id, p_source_ip, v_outcome, v_detail);

    PERFORM audit_event(
        CASE WHEN v_outcome = 'accepted' THEN 'auth_token_verify_accept'
             ELSE 'auth_token_verify_reject' END,
        'malu$auth_token',
        v_row.token_id,
        jsonb_build_object('outcome',v_outcome,'source_ip',p_source_ip::text),
        v_detail);

    IF v_outcome <> 'accepted' THEN
        RETURN;
    END IF;

    token_id   := v_row.token_id;
    account_id := v_row.account_id;
    token_kind := v_row.token_kind;
    scopes     := v_row.scopes;
    RETURN NEXT;
END;
$body$;
REVOKE EXECUTE ON FUNCTION auth_token_verify(text, inet) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION auth_token_verify(text, inet) TO
    maludb_memory_admin, maludb_memory_executor;

-- jwt_verify — stub. The C verifier (RS256/ES256/EdDSA via OpenSSL)
-- lands in a follow-up; for now this function raises a structured
-- error so callers can distinguish "JWT not yet wired" from a real
-- verification failure.
CREATE FUNCTION jwt_verify(p_jwt text)
    RETURNS TABLE (
        account_id    bigint,
        role_name     text,
        owner_schema  name,
        active_pool   bigint,
        agent_chain   text[]
    ) LANGUAGE plpgsql STABLE PARALLEL SAFE
    AS $body$
BEGIN
    RAISE EXCEPTION 'jwt_verify: JWT signature verification is not available in 0.42.0; the C verifier ships in a follow-up'
        USING ERRCODE = 'feature_not_supported',
              HINT    = 'Use auth_token_verify with an opaque bearer token until the JWT path lands.',
              DETAIL  = 'malu$jwt_signing_key registry rows are accepted but unused.';
END;
$body$;
REVOKE EXECUTE ON FUNCTION jwt_verify(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION jwt_verify(text) TO
    maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.42.0--0.43.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.43.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.42.0 → 0.43.0
--
-- Stage 9 / V3-SECRET-01: governed secret store.
--
-- Adds the catalog that V3-AUTH-01 (JWT signing keys), the model
-- gateway (provider API keys), MC2DB external_exec tools, the broker,
-- the future log-drain destinations, and backup destinations will
-- share. Secrets are stored in two forms — *inline* (AES-256 encrypted
-- at rest using pgcrypto pgp_sym_encrypt under a server-side master
-- key) or *external* (a resolver-readable reference like
-- `file:///etc/maludb/secrets/<name>`).
--
-- Per version3-plan.md V3-SECRET-01, this first cut implements:
--   * the catalog + RLS,
--   * the inline AES path,
--   * a stub for the external path that raises feature_not_supported.
-- The C-backed file/HTTPS resolver lands together with the V3-AUTH-01
-- C verifier in a Stage 9 follow-up.
--
-- Tenancy model (matches the project convention for owner_schema-
-- bound tables, e.g. malu$active_memory_pool 0.34.0→0.35.0):
--   * Public APIs run SECURITY INVOKER (default) so current_schema()
--     reflects the caller's tenant search_path.
--   * Only the master-key accessor is SECURITY DEFINER, narrowly
--     granted to roles that need to encrypt or decrypt.
--   * Every set / rotate / revoke / resolve writes malu$audit_event;
--     resolutions also write malu$secret_use.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.43.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.43.0'::text $body$;

-- ---------------------------------------------------------------------
-- maludb_secret_consumer — NOLOGIN role granted EXECUTE on
-- __secret_resolve(name). Operators GRANT maludb_secret_consumer TO
-- the service roles that need decrypted secrets (model gateway,
-- broker, log-drain workers, backup CLI).
-- ---------------------------------------------------------------------
DO $body$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_secret_consumer') THEN
        CREATE ROLE maludb_secret_consumer NOLOGIN;
    END IF;
END;
$body$;
GRANT USAGE ON SCHEMA maludb_core TO maludb_secret_consumer;

-- ---------------------------------------------------------------------
-- malu$secret_master_key — single-row dev-mode master key for the
-- inline AES path. Generated on first migration; never visible to
-- non-admin roles. Production resolvers (file / HTTPS / KMS) come in
-- the V3-SECRET-01 C follow-up; operators rotating from dev to prod
-- re-encrypt every malu$secret_version row through that path.
-- ---------------------------------------------------------------------
CREATE TABLE malu$secret_master_key (
    master_key_id smallint PRIMARY KEY CHECK (master_key_id = 1),
    key_material  bytea    NOT NULL,
    note          text     NOT NULL DEFAULT 'dev-mode in-DB master key; replace via the production resolver before exposing to a network',
    created_at    timestamptz NOT NULL DEFAULT now()
);
REVOKE ALL ON malu$secret_master_key FROM PUBLIC;
INSERT INTO malu$secret_master_key(master_key_id, key_material)
VALUES (1, public.gen_random_bytes(32));

-- ---------------------------------------------------------------------
-- malu$secret — one row per named secret. The kind column constrains
-- which subsystem expects to consume it; tenants and operators can
-- query metadata via secret_get_metadata(name).
-- ---------------------------------------------------------------------
CREATE TABLE malu$secret (
    secret_id            bigserial PRIMARY KEY,
    name                 text      NOT NULL,
    kind                 text      NOT NULL CHECK (kind IN
                            ('provider','tool','broker','storage','log_drain','backup','other')),
    description          text,
    rotation_policy_days integer,
    owner_schema         name      NOT NULL DEFAULT current_schema(),
    created_at           timestamptz NOT NULL DEFAULT now(),
    retired_at           timestamptz,
    UNIQUE (owner_schema, name)
);
CREATE INDEX malu$secret_kind_idx ON malu$secret(kind) WHERE retired_at IS NULL;
COMMENT ON TABLE malu$secret IS
    'V3-SECRET-01: named secrets. Values live in malu$secret_version; '
    'plaintext is never reachable through ordinary SELECT — only '
    '__secret_resolve(name), granted to maludb_secret_consumer.';

-- ---------------------------------------------------------------------
-- malu$secret_version — append-only history of secret values. Exactly
-- one of value_encrypted / external_ref is non-null per row.
-- ---------------------------------------------------------------------
CREATE TABLE malu$secret_version (
    secret_version_id bigserial PRIMARY KEY,
    secret_id         bigint    NOT NULL REFERENCES malu$secret(secret_id) ON DELETE CASCADE,
    version           integer   NOT NULL,
    value_encrypted   bytea,
    external_ref      text,
    kdf_alg           text,
    created_at        timestamptz NOT NULL DEFAULT now(),
    retired_at        timestamptz,
    last_used_at      timestamptz,
    UNIQUE (secret_id, version),
    CHECK (
        (value_encrypted IS NOT NULL AND external_ref IS NULL)
        OR
        (value_encrypted IS NULL AND external_ref IS NOT NULL)
    )
);
CREATE INDEX malu$secret_version_active_idx
    ON malu$secret_version(secret_id) WHERE retired_at IS NULL;

-- ---------------------------------------------------------------------
-- malu$secret_use — append-only audit of resolver calls.
-- ---------------------------------------------------------------------
CREATE TABLE malu$secret_use (
    use_id            bigserial PRIMARY KEY,
    secret_version_id bigint    NOT NULL REFERENCES malu$secret_version(secret_version_id) ON DELETE CASCADE,
    used_at           timestamptz NOT NULL DEFAULT now(),
    caller_role       name      NOT NULL DEFAULT current_user,
    outcome           text      NOT NULL CHECK (outcome IN
                        ('resolved','rejected_retired','rejected_external_not_available')),
    detail            text
);
CREATE INDEX malu$secret_use_version_idx
    ON malu$secret_use(secret_version_id, used_at DESC);

-- ---------------------------------------------------------------------
-- RLS — owner_schema-bound for malu$secret; children follow the parent.
-- malu$secret_master_key is admin-only (BYPASSRLS roles + extension
-- owner via SECURITY DEFINER accessor).
-- ---------------------------------------------------------------------
ALTER TABLE malu$secret ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$secret
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$secret_version ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_secret ON malu$secret_version
    USING (
        EXISTS (
            SELECT 1 FROM malu$secret s
            WHERE s.secret_id    = malu$secret_version.secret_id
              AND s.owner_schema = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$secret s
            WHERE s.secret_id    = malu$secret_version.secret_id
              AND s.owner_schema = current_schema()
        )
    );

ALTER TABLE malu$secret_use ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_version ON malu$secret_use
    USING (
        EXISTS (
            SELECT 1 FROM malu$secret_version v JOIN malu$secret s ON s.secret_id = v.secret_id
            WHERE v.secret_version_id = malu$secret_use.secret_version_id
              AND s.owner_schema      = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$secret_version v JOIN malu$secret s ON s.secret_id = v.secret_id
            WHERE v.secret_version_id = malu$secret_use.secret_version_id
              AND s.owner_schema      = current_schema()
        )
    );

ALTER TABLE malu$secret_master_key ENABLE ROW LEVEL SECURITY;
CREATE POLICY admin_only ON malu$secret_master_key USING (false) WITH CHECK (false);

-- ---------------------------------------------------------------------
-- Grants. The public APIs are SECURITY INVOKER so they execute with
-- the caller's privileges and the caller's current_schema(); RLS does
-- the tenant filtering. Encrypted bytea exposure is acceptable — the
-- secrecy guarantee is the master-key gate, not column-level grants.
-- ---------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE ON malu$secret, malu$secret_version, malu$secret_use TO
    maludb_memory_admin, maludb_memory_executor;
GRANT SELECT ON malu$secret, malu$secret_version, malu$secret_use TO
    maludb_memory_auditor, maludb_secret_consumer;

GRANT USAGE, SELECT ON SEQUENCE malu$secret_secret_id_seq                 TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$secret_version_secret_version_id_seq TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$secret_use_use_id_seq                TO
    maludb_memory_admin, maludb_memory_executor, maludb_secret_consumer;

-- =====================================================================
-- Master-key accessor (the only SECURITY DEFINER function in this
-- migration). Returns the raw 32-byte key as bytea or as a base64
-- passphrase suitable for pgp_sym_*.
-- =====================================================================
CREATE FUNCTION __secret_master_key() RETURNS bytea
    LANGUAGE plpgsql STABLE PARALLEL SAFE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
DECLARE v_k bytea;
BEGIN
    SELECT key_material INTO v_k FROM malu$secret_master_key WHERE master_key_id = 1;
    IF v_k IS NULL THEN
        RAISE EXCEPTION 'secret store master key is uninitialised'
            USING ERRCODE = 'config_file_error';
    END IF;
    RETURN v_k;
END;
$body$;
REVOKE EXECUTE ON FUNCTION __secret_master_key() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION __secret_master_key() TO
    maludb_memory_admin, maludb_memory_executor, maludb_secret_consumer;

CREATE FUNCTION __secret_master_key_passphrase() RETURNS text
    LANGUAGE plpgsql STABLE PARALLEL SAFE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
BEGIN
    RETURN encode(__secret_master_key(), 'base64');
END;
$body$;
REVOKE EXECUTE ON FUNCTION __secret_master_key_passphrase() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION __secret_master_key_passphrase() TO
    maludb_memory_admin, maludb_memory_executor, maludb_secret_consumer;

-- =====================================================================
-- Public API — all SECURITY INVOKER so RLS + current_schema() govern
-- tenant access. Schema-qualified pgcrypto calls because pgcrypto
-- lives in `public`, which is not typically first in tenant
-- search_path.
-- =====================================================================

-- secret_set — creates a new secret or pushes a new version of an
-- existing one. Retires any previous active version atomically.
CREATE FUNCTION secret_set(
    p_name                 text,
    p_kind                 text,
    p_value                text,
    p_description          text    DEFAULT NULL,
    p_rotation_policy_days integer DEFAULT NULL
) RETURNS TABLE (secret_id bigint, secret_version_id bigint, version integer)
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_secret_id bigint;
    v_prev_ver  integer;
    v_new_ver   integer;
    v_enc       bytea;
    v_vid       bigint;
BEGIN
    IF p_value IS NULL OR p_value = '' THEN
        RAISE EXCEPTION 'secret_set: value must be non-empty'
            USING ERRCODE = 'check_violation';
    END IF;
    IF p_kind NOT IN ('provider','tool','broker','storage','log_drain','backup','other') THEN
        RAISE EXCEPTION 'secret_set: kind must be one of provider/tool/broker/storage/log_drain/backup/other'
            USING ERRCODE = 'check_violation';
    END IF;

    SELECT s.secret_id INTO v_secret_id
      FROM malu$secret s
     WHERE s.name = p_name;

    IF v_secret_id IS NULL THEN
        INSERT INTO malu$secret(name, kind, description, rotation_policy_days)
        VALUES (p_name, p_kind, p_description, p_rotation_policy_days)
        RETURNING malu$secret.secret_id INTO v_secret_id;
        v_prev_ver := 0;
    ELSE
        SELECT COALESCE(MAX(sv.version), 0) INTO v_prev_ver
          FROM malu$secret_version sv
         WHERE sv.secret_id = v_secret_id;

        UPDATE malu$secret_version
           SET retired_at = COALESCE(retired_at, now())
         WHERE secret_id = v_secret_id
           AND retired_at IS NULL;
    END IF;

    v_new_ver := v_prev_ver + 1;
    v_enc     := public.pgp_sym_encrypt(p_value, __secret_master_key_passphrase());

    INSERT INTO malu$secret_version
        (secret_id, version, value_encrypted, kdf_alg)
    VALUES
        (v_secret_id, v_new_ver, v_enc, 'pgp_sym_aes256')
    RETURNING malu$secret_version.secret_version_id INTO v_vid;

    PERFORM audit_event(
        CASE WHEN v_prev_ver = 0 THEN 'secret_create' ELSE 'secret_rotate' END,
        'malu$secret',
        v_secret_id,
        jsonb_build_object(
            'name',    p_name,
            'kind',    p_kind,
            'version', v_new_ver,
            'mode',    'inline',
            'rotation_policy_days', p_rotation_policy_days),
        NULL);

    secret_id         := v_secret_id;
    secret_version_id := v_vid;
    version           := v_new_ver;
    RETURN NEXT;
END;
$body$;
REVOKE EXECUTE ON FUNCTION secret_set(text, text, text, text, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION secret_set(text, text, text, text, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- secret_set_external — registers a secret whose value lives outside
-- PostgreSQL behind a resolver. The resolver itself is a Stage 9
-- follow-up; this function lets operators register the reference now
-- so the catalog is forward-compatible.
CREATE FUNCTION secret_set_external(
    p_name                 text,
    p_kind                 text,
    p_external_ref         text,
    p_description          text    DEFAULT NULL,
    p_rotation_policy_days integer DEFAULT NULL
) RETURNS TABLE (secret_id bigint, secret_version_id bigint, version integer)
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_secret_id bigint;
    v_prev_ver  integer;
    v_new_ver   integer;
    v_vid       bigint;
BEGIN
    IF p_external_ref IS NULL OR p_external_ref = '' THEN
        RAISE EXCEPTION 'secret_set_external: external_ref must be non-empty'
            USING ERRCODE = 'check_violation';
    END IF;

    SELECT s.secret_id INTO v_secret_id
      FROM malu$secret s
     WHERE s.name = p_name;

    IF v_secret_id IS NULL THEN
        INSERT INTO malu$secret(name, kind, description, rotation_policy_days)
        VALUES (p_name, p_kind, p_description, p_rotation_policy_days)
        RETURNING malu$secret.secret_id INTO v_secret_id;
        v_prev_ver := 0;
    ELSE
        SELECT COALESCE(MAX(sv.version), 0) INTO v_prev_ver
          FROM malu$secret_version sv
         WHERE sv.secret_id = v_secret_id;

        UPDATE malu$secret_version
           SET retired_at = COALESCE(retired_at, now())
         WHERE secret_id = v_secret_id
           AND retired_at IS NULL;
    END IF;

    v_new_ver := v_prev_ver + 1;

    INSERT INTO malu$secret_version
        (secret_id, version, external_ref, kdf_alg)
    VALUES
        (v_secret_id, v_new_ver, p_external_ref, NULL)
    RETURNING malu$secret_version.secret_version_id INTO v_vid;

    PERFORM audit_event(
        CASE WHEN v_prev_ver = 0 THEN 'secret_create' ELSE 'secret_rotate' END,
        'malu$secret',
        v_secret_id,
        jsonb_build_object(
            'name',         p_name,
            'kind',         p_kind,
            'version',      v_new_ver,
            'mode',         'external',
            'external_ref', p_external_ref),
        NULL);

    secret_id         := v_secret_id;
    secret_version_id := v_vid;
    version           := v_new_ver;
    RETURN NEXT;
END;
$body$;
REVOKE EXECUTE ON FUNCTION secret_set_external(text, text, text, text, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION secret_set_external(text, text, text, text, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- secret_revoke — retires the secret and all of its versions.
CREATE FUNCTION secret_revoke(p_name text, p_reason text DEFAULT NULL)
    RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_secret_id bigint;
    v_was_open  boolean;
BEGIN
    SELECT s.secret_id, s.retired_at IS NULL
      INTO v_secret_id, v_was_open
      FROM malu$secret s
     WHERE s.name = p_name;

    IF v_secret_id IS NULL THEN
        RAISE EXCEPTION 'secret_revoke: secret % not found in schema %', p_name, current_schema()
            USING ERRCODE = 'no_data_found';
    END IF;

    UPDATE malu$secret
       SET retired_at = COALESCE(retired_at, now())
     WHERE secret_id = v_secret_id;

    UPDATE malu$secret_version
       SET retired_at = COALESCE(retired_at, now())
     WHERE secret_id = v_secret_id
       AND retired_at IS NULL;

    PERFORM audit_event(
        'secret_revoke',
        'malu$secret',
        v_secret_id,
        jsonb_build_object('name', p_name, 'reason', p_reason, 'was_active', v_was_open),
        NULL);

    RETURN v_was_open;
END;
$body$;
REVOKE EXECUTE ON FUNCTION secret_revoke(text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION secret_revoke(text, text) TO
    maludb_memory_admin, maludb_memory_executor;

-- secret_get_metadata — metadata-only view of a secret. Never returns
-- value_encrypted or external_ref. Callable by every memory_* role
-- plus secret_consumer.
CREATE FUNCTION secret_get_metadata(p_name text)
    RETURNS TABLE (
        secret_id            bigint,
        name                 text,
        kind                 text,
        owner_schema         name,
        current_version      integer,
        mode                 text,
        rotation_policy_days integer,
        last_used_at         timestamptz,
        created_at           timestamptz,
        retired_at           timestamptz
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT s.secret_id,
           s.name,
           s.kind,
           s.owner_schema,
           sv.version                                              AS current_version,
           CASE WHEN sv.value_encrypted IS NOT NULL THEN 'inline'
                WHEN sv.external_ref    IS NOT NULL THEN 'external'
                ELSE NULL END                                      AS mode,
           s.rotation_policy_days,
           sv.last_used_at,
           s.created_at,
           s.retired_at
      FROM malu$secret s
      LEFT JOIN LATERAL (
            SELECT * FROM malu$secret_version vv
             WHERE vv.secret_id = s.secret_id
               AND vv.retired_at IS NULL
             ORDER BY vv.version DESC
             LIMIT 1
      ) sv ON TRUE
     WHERE s.name = p_name;
END;
$body$;
REVOKE EXECUTE ON FUNCTION secret_get_metadata(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION secret_get_metadata(text) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor,
    maludb_secret_consumer;

-- __secret_resolve — internal decryption / external dereference path.
-- Granted only to maludb_secret_consumer; the caller's RLS context
-- determines which tenant's secret is visible. INVOKER (default) so
-- current_schema() == caller's tenant.
CREATE FUNCTION __secret_resolve(p_name text)
    RETURNS text
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_secret_id bigint;
    v_vid       bigint;
    v_enc       bytea;
    v_ref       text;
    v_retired   timestamptz;
    v_plain     text;
BEGIN
    SELECT s.secret_id, s.retired_at
      INTO v_secret_id, v_retired
      FROM malu$secret s
     WHERE s.name = p_name;

    IF v_secret_id IS NULL THEN
        PERFORM audit_event('secret_resolve_reject', 'malu$secret', NULL,
            jsonb_build_object('reason','unknown_secret','name',p_name),
            NULL);
        RAISE EXCEPTION 'secret_resolve: secret % not found in schema %', p_name, current_schema()
            USING ERRCODE = 'no_data_found';
    END IF;

    IF v_retired IS NOT NULL THEN
        PERFORM audit_event('secret_resolve_reject', 'malu$secret', v_secret_id,
            jsonb_build_object('reason','secret_retired','name',p_name),
            NULL);
        RAISE EXCEPTION 'secret_resolve: secret % is retired', p_name
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    SELECT sv.secret_version_id, sv.value_encrypted, sv.external_ref
      INTO v_vid, v_enc, v_ref
      FROM malu$secret_version sv
     WHERE sv.secret_id  = v_secret_id
       AND sv.retired_at IS NULL
     ORDER BY sv.version DESC
     LIMIT 1;

    IF v_vid IS NULL THEN
        PERFORM audit_event('secret_resolve_reject', 'malu$secret', v_secret_id,
            jsonb_build_object('reason','no_active_version','name',p_name),
            NULL);
        RAISE EXCEPTION 'secret_resolve: no active version for secret %', p_name
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    IF v_enc IS NOT NULL THEN
        v_plain := public.pgp_sym_decrypt(v_enc, __secret_master_key_passphrase());

        UPDATE malu$secret_version SET last_used_at = now()
         WHERE secret_version_id = v_vid;

        INSERT INTO malu$secret_use(secret_version_id, outcome)
        VALUES (v_vid, 'resolved');

        PERFORM audit_event('secret_resolve_accept', 'malu$secret', v_secret_id,
            jsonb_build_object('name',p_name,'version_id',v_vid,'mode','inline'),
            NULL);

        RETURN v_plain;
    END IF;

    -- External reference: catalog accepts it, resolver not yet wired.
    INSERT INTO malu$secret_use(secret_version_id, outcome, detail)
    VALUES (v_vid, 'rejected_external_not_available', v_ref);

    PERFORM audit_event('secret_resolve_reject', 'malu$secret', v_secret_id,
        jsonb_build_object('name',p_name,'version_id',v_vid,'mode','external','reason','external_resolver_unavailable'),
        NULL);

    RAISE EXCEPTION 'secret_resolve: external reference resolver (file/env/https) is not available in 0.43.0; the C resolver ships in a follow-up'
        USING ERRCODE = 'feature_not_supported',
              HINT    = 'Use secret_set(...) to store the value inline until the C resolver lands.',
              DETAIL  = format('secret %s has external_ref = %s', p_name, v_ref);
END;
$body$;
REVOKE EXECUTE ON FUNCTION __secret_resolve(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION __secret_resolve(text) TO maludb_secret_consumer;

-- ============================================================
-- Section: maludb_core--0.43.0--0.44.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.44.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.43.0 → 0.44.0
--
-- Stage 10 / V3-API-01 (catalog only): curated REST gateway catalog
-- and invocation audit.
--
-- Adds the catalog the future `maludb-restd` Go service will consume:
-- one row per stable HTTP endpoint, naming the SQL/PL/pgSQL function
-- the gateway is allowed to dispatch to, the required token scopes,
-- the risk class, OpenAPI fragment, and per-call resource limits.
-- Every dispatched request lands a `malu$rest_invocation` row, the
-- HTTP analogue of `malu$mc2db_invocation`.
--
-- This migration is **SQL surface only**. The Go service itself
-- (V3-API-01b) consumes the catalog through these helpers and writes
-- audit rows via `rest_log_invocation`. The CLI (V3-CLI-01) and SDK
-- parity work (V3-SDK-01) follow after V3-API-01b.
--
-- Doctrine:
--   * No generic CRUD over private `malu$` tables; endpoints can
--     only target functions registered through `rest_register_endpoint`.
--   * Authentication uses the V3-AUTH-01 token model. Scopes recorded
--     on the endpoint row are checked by the gateway before dispatch.
--   * `malu$rest_invocation` is the sibling of `malu$mc2db_invocation`
--     and shares its append-only / per-tenant RLS contract.
--   * `rest_openapi_spec()` returns the OpenAPI 3.1 document the
--     gateway serves at `GET /openapi.json`; assembled from the
--     catalog so the spec never drifts from the dispatcher.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.44.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.44.0'::text $body$;

-- ---------------------------------------------------------------------
-- maludb_rest_dispatcher — NOLOGIN role granted INSERT on
-- malu$rest_invocation. Operators GRANT maludb_rest_dispatcher TO the
-- service login role that runs maludb-restd; the service inherits no
-- table read privileges beyond what its tenant role already has, so
-- RLS still governs visibility.
-- ---------------------------------------------------------------------
DO $body$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_rest_dispatcher') THEN
        CREATE ROLE maludb_rest_dispatcher NOLOGIN;
    END IF;
END;
$body$;
GRANT USAGE ON SCHEMA maludb_core TO maludb_rest_dispatcher;

-- ---------------------------------------------------------------------
-- malu$rest_endpoint — one row per curated REST endpoint. handler_function
-- is regprocedure so the catalog refuses to accept a non-existent
-- target — same property `malu$mc2db_tool_sql_function` already
-- relies on.
-- ---------------------------------------------------------------------
CREATE TABLE malu$rest_endpoint (
    endpoint_id        bigserial PRIMARY KEY,
    path               text       NOT NULL,
    method             text       NOT NULL CHECK (method IN
                          ('GET','POST','PUT','PATCH','DELETE')),
    handler_function   regprocedure NOT NULL,
    description        text,
    auth_required      boolean    NOT NULL DEFAULT true,
    required_scopes    text[]     NOT NULL DEFAULT ARRAY[]::text[],
    risk_class         text       NOT NULL DEFAULT 'read_only' CHECK (risk_class IN
                          ('read_only','evidence_producing','state_changing',
                           'external_effect','administrative')),
    openapi_spec       jsonb      NOT NULL DEFAULT '{}'::jsonb,
    timeout_ms         integer    NOT NULL DEFAULT 30000 CHECK (timeout_ms > 0),
    max_input_bytes    integer    NOT NULL DEFAULT 1048576 CHECK (max_input_bytes > 0),
    max_output_bytes   integer    NOT NULL DEFAULT 10485760 CHECK (max_output_bytes > 0),
    enabled            boolean    NOT NULL DEFAULT true,
    version_introduced text       NOT NULL DEFAULT '0.44.0',
    owner_schema       name       NOT NULL DEFAULT current_schema(),
    created_at         timestamptz NOT NULL DEFAULT now(),
    retired_at         timestamptz,
    UNIQUE (owner_schema, method, path)
);
CREATE INDEX malu$rest_endpoint_enabled_idx
    ON malu$rest_endpoint(method, path) WHERE enabled AND retired_at IS NULL;
CREATE INDEX malu$rest_endpoint_handler_idx
    ON malu$rest_endpoint(handler_function);
COMMENT ON TABLE malu$rest_endpoint IS
    'V3-API-01: curated REST endpoint catalog. handler_function is the '
    'only SQL surface the gateway is allowed to dispatch to; private '
    'malu$ tables are never reachable through the REST API.';

-- ---------------------------------------------------------------------
-- malu$rest_invocation — append-only HTTP audit. Mirrors the shape of
-- malu$mc2db_invocation (call_id uuid PK, started/finished, hashes,
-- error fields) and adds HTTP-specific columns (method, path,
-- status_code, latency_ms, source_ip).
-- ---------------------------------------------------------------------
CREATE TABLE malu$rest_invocation (
    call_id        uuid       PRIMARY KEY DEFAULT public.gen_random_uuid(),
    endpoint_id    bigint     REFERENCES malu$rest_endpoint(endpoint_id) ON DELETE SET NULL,
    account_id     bigint     REFERENCES malu$account(account_id)        ON DELETE SET NULL,
    token_id       bigint     REFERENCES malu$auth_token(token_id)       ON DELETE SET NULL,
    method         text       NOT NULL,
    path           text       NOT NULL,
    request_user   text,
    source_ip      inet,
    request_hash   bytea,
    response_hash  bytea,
    status_code    smallint,
    latency_ms     integer,
    started_at     timestamptz NOT NULL DEFAULT now(),
    finished_at    timestamptz,
    success        boolean    NOT NULL,
    error_code     text,
    error_message  text,
    owner_schema   name       NOT NULL DEFAULT current_schema()
);
CREATE INDEX malu$rest_invocation_endpoint_idx
    ON malu$rest_invocation(endpoint_id, started_at DESC);
CREATE INDEX malu$rest_invocation_account_idx
    ON malu$rest_invocation(account_id, started_at DESC) WHERE account_id IS NOT NULL;
CREATE INDEX malu$rest_invocation_owner_idx
    ON malu$rest_invocation(owner_schema, started_at DESC);

-- ---------------------------------------------------------------------
-- RLS — both tables owner_schema-bound. maludb-restd inherits no
-- BYPASSRLS; the dispatcher binds the request to the tenant role
-- before INSERTing.
-- ---------------------------------------------------------------------
ALTER TABLE malu$rest_endpoint ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$rest_endpoint
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$rest_invocation ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$rest_invocation
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

-- ---------------------------------------------------------------------
-- Grants. Endpoint catalog: admin + executor write; auditor read.
-- Invocation: admin/auditor/executor read; rest_dispatcher inserts.
-- ---------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE ON malu$rest_endpoint TO
    maludb_memory_admin, maludb_memory_executor;
GRANT SELECT ON malu$rest_endpoint TO
    maludb_memory_auditor, maludb_rest_dispatcher;

GRANT SELECT ON malu$rest_invocation TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor,
    maludb_rest_dispatcher;
GRANT INSERT ON malu$rest_invocation TO
    maludb_memory_admin, maludb_rest_dispatcher;

GRANT USAGE, SELECT ON SEQUENCE malu$rest_endpoint_endpoint_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- Public API
-- =====================================================================

-- rest_register_endpoint — UPSERT. Returns the endpoint_id. Validates
-- the handler_function exists (regprocedure cast enforces this at
-- parse time) and that risk_class is in the allowed set.
CREATE FUNCTION rest_register_endpoint(
    p_method            text,
    p_path              text,
    p_handler           regprocedure,
    p_description       text         DEFAULT NULL,
    p_required_scopes   text[]       DEFAULT ARRAY[]::text[],
    p_risk_class        text         DEFAULT 'read_only',
    p_openapi_spec      jsonb        DEFAULT '{}'::jsonb,
    p_auth_required     boolean      DEFAULT true,
    p_timeout_ms        integer      DEFAULT 30000,
    p_max_input_bytes   integer      DEFAULT 1048576,
    p_max_output_bytes  integer      DEFAULT 10485760
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_id      bigint;
    v_created boolean;
BEGIN
    IF p_method NOT IN ('GET','POST','PUT','PATCH','DELETE') THEN
        RAISE EXCEPTION 'rest_register_endpoint: method must be one of GET/POST/PUT/PATCH/DELETE'
            USING ERRCODE = 'check_violation';
    END IF;
    IF p_path NOT LIKE '/%' THEN
        RAISE EXCEPTION 'rest_register_endpoint: path must start with /'
            USING ERRCODE = 'check_violation';
    END IF;

    INSERT INTO malu$rest_endpoint
        (method, path, handler_function, description,
         required_scopes, risk_class, openapi_spec, auth_required,
         timeout_ms, max_input_bytes, max_output_bytes)
    VALUES
        (p_method, p_path, p_handler, p_description,
         p_required_scopes, p_risk_class, p_openapi_spec, p_auth_required,
         p_timeout_ms, p_max_input_bytes, p_max_output_bytes)
    ON CONFLICT (owner_schema, method, path) DO UPDATE
        SET handler_function   = EXCLUDED.handler_function,
            description        = EXCLUDED.description,
            required_scopes    = EXCLUDED.required_scopes,
            risk_class         = EXCLUDED.risk_class,
            openapi_spec       = EXCLUDED.openapi_spec,
            auth_required      = EXCLUDED.auth_required,
            timeout_ms         = EXCLUDED.timeout_ms,
            max_input_bytes    = EXCLUDED.max_input_bytes,
            max_output_bytes   = EXCLUDED.max_output_bytes,
            enabled            = true,
            retired_at         = NULL
    RETURNING endpoint_id, (xmax = 0) INTO v_id, v_created;

    PERFORM audit_event(
        CASE WHEN v_created THEN 'rest_endpoint_register' ELSE 'rest_endpoint_update' END,
        'malu$rest_endpoint',
        v_id,
        jsonb_build_object(
            'method', p_method,
            'path',   p_path,
            'handler', p_handler::text,
            'risk_class', p_risk_class,
            'auth_required', p_auth_required,
            'scopes', to_jsonb(p_required_scopes)),
        NULL);

    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION rest_register_endpoint(text, text, regprocedure, text, text[], text, jsonb, boolean, integer, integer, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION rest_register_endpoint(text, text, regprocedure, text, text[], text, jsonb, boolean, integer, integer, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- rest_disable_endpoint — soft-disable. Reverses with
-- rest_register_endpoint (which clears retired_at and enabled=true).
CREATE FUNCTION rest_disable_endpoint(p_method text, p_path text, p_reason text DEFAULT NULL)
    RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_id        bigint;
    v_was_open  boolean;
BEGIN
    SELECT endpoint_id, retired_at IS NULL AND enabled
      INTO v_id, v_was_open
      FROM malu$rest_endpoint
     WHERE method = p_method AND path = p_path;

    IF v_id IS NULL THEN
        RAISE EXCEPTION 'rest_disable_endpoint: no endpoint registered for % %', p_method, p_path
            USING ERRCODE = 'no_data_found';
    END IF;

    UPDATE malu$rest_endpoint
       SET enabled    = false,
           retired_at = COALESCE(retired_at, now())
     WHERE endpoint_id = v_id;

    PERFORM audit_event('rest_endpoint_disable', 'malu$rest_endpoint', v_id,
        jsonb_build_object('method',p_method,'path',p_path,'reason',p_reason,'was_active',v_was_open),
        NULL);

    RETURN v_was_open;
END;
$body$;
REVOKE EXECUTE ON FUNCTION rest_disable_endpoint(text, text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION rest_disable_endpoint(text, text, text) TO
    maludb_memory_admin, maludb_memory_executor;

-- rest_list_endpoints — enumeration for the gateway and the CLI.
-- Returns enabled endpoints by default; pass `false` to include
-- retired/disabled rows.
CREATE FUNCTION rest_list_endpoints(p_include_disabled boolean DEFAULT false)
    RETURNS TABLE (
        endpoint_id      bigint,
        method           text,
        path             text,
        handler_function text,
        description      text,
        auth_required    boolean,
        required_scopes  text[],
        risk_class       text,
        timeout_ms       integer,
        enabled          boolean
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT e.endpoint_id,
           e.method,
           e.path,
           e.handler_function::text,
           e.description,
           e.auth_required,
           e.required_scopes,
           e.risk_class,
           e.timeout_ms,
           e.enabled
      FROM malu$rest_endpoint e
     WHERE (p_include_disabled OR (e.enabled AND e.retired_at IS NULL))
     ORDER BY e.path, e.method;
END;
$body$;
REVOKE EXECUTE ON FUNCTION rest_list_endpoints(boolean) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION rest_list_endpoints(boolean) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor,
    maludb_rest_dispatcher;

-- rest_openapi_spec — assembles an OpenAPI 3.1 document from the
-- catalog. Per-endpoint `openapi_spec` jsonb is grouped under
-- paths[<path>][<method-lowercased>]. The info block names the
-- extension version so generated clients can pin against it.
--
-- Uses jsonb_object_agg twice (inner over methods per path, outer
-- over paths) because jsonb_set does not create intermediate path
-- elements even with create_missing=true.
CREATE FUNCTION rest_openapi_spec()
    RETURNS jsonb
    LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
DECLARE v_paths jsonb;
BEGIN
    SELECT COALESCE(jsonb_object_agg(p.path, p.methods), '{}'::jsonb)
      INTO v_paths
      FROM (
        SELECT path,
               jsonb_object_agg(lower(method), openapi_spec) AS methods
          FROM malu$rest_endpoint
         WHERE enabled AND retired_at IS NULL
         GROUP BY path
      ) p;

    RETURN jsonb_build_object(
        'openapi', '3.1.0',
        'info', jsonb_build_object(
            'title',       'MaluDB REST API',
            'version',     maludb_core_version(),
            'description', 'V3-API-01 curated REST gateway over governed memory, retrieval, model, and tool operations.'),
        'paths', v_paths);
END;
$body$;
REVOKE EXECUTE ON FUNCTION rest_openapi_spec() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION rest_openapi_spec() TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor,
    maludb_rest_dispatcher;

-- rest_log_invocation — append-only audit helper called by the future
-- maludb-restd. Returns the call_id (uuid).
CREATE FUNCTION rest_log_invocation(
    p_endpoint_id   bigint,
    p_account_id    bigint,
    p_token_id      bigint,
    p_method        text,
    p_path          text,
    p_request_user  text,
    p_source_ip     inet,
    p_request_hash  bytea,
    p_response_hash bytea,
    p_status_code   smallint,
    p_latency_ms    integer,
    p_started_at    timestamptz,
    p_finished_at   timestamptz,
    p_success       boolean,
    p_error_code    text         DEFAULT NULL,
    p_error_message text         DEFAULT NULL
) RETURNS uuid
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id uuid;
BEGIN
    INSERT INTO malu$rest_invocation
        (endpoint_id, account_id, token_id, method, path, request_user,
         source_ip, request_hash, response_hash, status_code, latency_ms,
         started_at, finished_at, success, error_code, error_message)
    VALUES
        (p_endpoint_id, p_account_id, p_token_id, p_method, p_path, p_request_user,
         p_source_ip, p_request_hash, p_response_hash, p_status_code, p_latency_ms,
         p_started_at, p_finished_at, p_success, p_error_code, p_error_message)
    RETURNING call_id INTO v_id;
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION rest_log_invocation(bigint, bigint, bigint, text, text, text, inet, bytea, bytea, smallint, integer, timestamptz, timestamptz, boolean, text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION rest_log_invocation(bigint, bigint, bigint, text, text, text, inet, bytea, bytea, smallint, integer, timestamptz, timestamptz, boolean, text, text) TO
    maludb_memory_admin, maludb_rest_dispatcher;

-- ============================================================
-- Section: maludb_core--0.44.0--0.45.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.45.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.44.0 → 0.45.0
--
-- Stage 11 / V3-QUEUE-01: durable job queue.
--
-- One queue abstraction the V3 stages will share — ingestion,
-- embedding, re-derivation, broker-audit ingest, lifecycle sweeps,
-- ANN rebuilds, notification fanout. Native PostgreSQL implementation
-- using FOR UPDATE SKIP LOCKED lease semantics; the pgmq adoption
-- door is left open (the table shape mirrors pgmq closely enough that
-- a future migration could swap the implementation without breaking
-- the SQL contract).
--
-- Shape:
--   malu$queue         — one row per named queue. Default visibility,
--                        max retries, optional DLQ target.
--   malu$queue_job     — append-only job log. status in
--                        {pending, leased, completed, failed, dead}.
--   malu$queue_lease   — one row per actively leased job, with
--                        worker_id, leased_at, expires_at.
--
-- Doctrine:
--   * Workers acquire leases atomically via SELECT ... FOR UPDATE
--     SKIP LOCKED inside queue_lease(); no two workers can lease the
--     same job.
--   * Visibility expiry: queue_reap_expired_leases() returns expired
--     leases to pending. Operators schedule this through V3-CRON-01.
--   * Idempotency: UNIQUE (queue_id, idempotency_key) WHERE
--     idempotency_key IS NOT NULL. A second enqueue with the same
--     key returns the existing job_id instead of erroring.
--   * Dead-letter: queue_nack auto-promotes to status='dead' once
--     attempts > queue.max_retries. If a DLQ is configured, the
--     payload is enqueued onto it.
--   * RLS owner_schema-bound across all three tables.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.45.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.45.0'::text $body$;

-- ---------------------------------------------------------------------
-- maludb_queue_worker — NOLOGIN role granted INSERT/UPDATE/SELECT on
-- the queue catalog. Operators GRANT it to the service login roles
-- that run queue workers (embedding workers, ingestion workers, etc.).
-- ---------------------------------------------------------------------
DO $body$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'maludb_queue_worker') THEN
        CREATE ROLE maludb_queue_worker NOLOGIN;
    END IF;
END;
$body$;
GRANT USAGE ON SCHEMA maludb_core TO maludb_queue_worker;

-- ---------------------------------------------------------------------
-- malu$queue
-- ---------------------------------------------------------------------
CREATE TABLE malu$queue (
    queue_id              bigserial PRIMARY KEY,
    name                  text       NOT NULL,
    default_visibility_ms integer    NOT NULL DEFAULT 30000 CHECK (default_visibility_ms > 0),
    max_retries           smallint   NOT NULL DEFAULT 3     CHECK (max_retries >= 0),
    dlq_queue_id          bigint     REFERENCES malu$queue(queue_id) ON DELETE SET NULL,
    description           text,
    owner_schema          name       NOT NULL DEFAULT current_schema(),
    created_at            timestamptz NOT NULL DEFAULT now(),
    retired_at            timestamptz,
    UNIQUE (owner_schema, name),
    CHECK (dlq_queue_id IS NULL OR dlq_queue_id <> queue_id)
);
CREATE INDEX malu$queue_owner_idx ON malu$queue(owner_schema) WHERE retired_at IS NULL;

-- ---------------------------------------------------------------------
-- malu$queue_job
-- ---------------------------------------------------------------------
CREATE TABLE malu$queue_job (
    job_id           bigserial PRIMARY KEY,
    queue_id         bigint    NOT NULL REFERENCES malu$queue(queue_id) ON DELETE CASCADE,
    payload          jsonb     NOT NULL,
    idempotency_key  text,
    priority         smallint  NOT NULL DEFAULT 0,
    account_id       bigint,
    owner_schema     name      NOT NULL DEFAULT current_schema(),
    status           text      NOT NULL DEFAULT 'pending' CHECK (status IN
                        ('pending','leased','completed','failed','dead')),
    enqueued_at      timestamptz NOT NULL DEFAULT now(),
    visible_at       timestamptz NOT NULL DEFAULT now(),
    attempts         smallint  NOT NULL DEFAULT 0,
    last_error       text,
    last_state_change_at timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX malu$queue_job_idempotency_idx
    ON malu$queue_job(queue_id, idempotency_key)
    WHERE idempotency_key IS NOT NULL;
CREATE INDEX malu$queue_job_pending_idx
    ON malu$queue_job(queue_id, priority DESC, visible_at, job_id)
    WHERE status = 'pending';
CREATE INDEX malu$queue_job_status_idx
    ON malu$queue_job(queue_id, status);
CREATE INDEX malu$queue_job_owner_idx
    ON malu$queue_job(owner_schema, queue_id, status);

-- ---------------------------------------------------------------------
-- malu$queue_lease
-- ---------------------------------------------------------------------
CREATE TABLE malu$queue_lease (
    lease_id    bigserial PRIMARY KEY,
    job_id      bigint    NOT NULL UNIQUE REFERENCES malu$queue_job(job_id) ON DELETE CASCADE,
    worker_id   text      NOT NULL,
    leased_at   timestamptz NOT NULL DEFAULT now(),
    expires_at  timestamptz NOT NULL
);
CREATE INDEX malu$queue_lease_expires_idx ON malu$queue_lease(expires_at);
CREATE INDEX malu$queue_lease_worker_idx  ON malu$queue_lease(worker_id, leased_at DESC);

-- ---------------------------------------------------------------------
-- RLS — every queue table owner_schema-bound. Lease rows inherit from
-- their parent job's owner_schema.
-- ---------------------------------------------------------------------
ALTER TABLE malu$queue ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$queue
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$queue_job ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$queue_job
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$queue_lease ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_job ON malu$queue_lease
    USING (
        EXISTS (
            SELECT 1 FROM malu$queue_job j
            WHERE j.job_id       = malu$queue_lease.job_id
              AND j.owner_schema = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$queue_job j
            WHERE j.job_id       = malu$queue_lease.job_id
              AND j.owner_schema = current_schema()
        )
    );

-- ---------------------------------------------------------------------
-- Grants. Admin gets full; executor enqueues + reads (no direct DLQ
-- promotion or lease mutation); auditor reads; queue_worker leases /
-- acks / nacks.
-- ---------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE, DELETE ON malu$queue, malu$queue_job, malu$queue_lease TO
    maludb_memory_admin, maludb_queue_worker;
GRANT SELECT, INSERT ON malu$queue, malu$queue_job TO
    maludb_memory_executor;
GRANT SELECT ON malu$queue, malu$queue_job, malu$queue_lease TO
    maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$queue_queue_id_seq      TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$queue_job_job_id_seq    TO maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;
GRANT USAGE, SELECT ON SEQUENCE malu$queue_lease_lease_id_seq TO maludb_memory_admin, maludb_queue_worker;

-- =====================================================================
-- Public API
-- =====================================================================

-- queue_register — UPSERT a named queue.
CREATE FUNCTION queue_register(
    p_name                   text,
    p_default_visibility_ms  integer DEFAULT 30000,
    p_max_retries            integer DEFAULT 3,
    p_dlq_name               text    DEFAULT NULL,
    p_description            text    DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_dlq_id bigint;
    v_id     bigint;
BEGIN
    IF p_dlq_name IS NOT NULL THEN
        SELECT q.queue_id INTO v_dlq_id
          FROM malu$queue q
         WHERE q.name = p_dlq_name;
        IF v_dlq_id IS NULL THEN
            RAISE EXCEPTION 'queue_register: DLQ queue % not found', p_dlq_name
                USING ERRCODE = 'no_data_found';
        END IF;
    END IF;

    INSERT INTO malu$queue(name, default_visibility_ms, max_retries, dlq_queue_id, description)
    VALUES (p_name, p_default_visibility_ms, p_max_retries, v_dlq_id, p_description)
    ON CONFLICT (owner_schema, name) DO UPDATE
        SET default_visibility_ms = EXCLUDED.default_visibility_ms,
            max_retries           = EXCLUDED.max_retries,
            dlq_queue_id          = EXCLUDED.dlq_queue_id,
            description           = EXCLUDED.description,
            retired_at            = NULL
    RETURNING queue_id INTO v_id;

    PERFORM audit_event(
        'queue_register', 'malu$queue', v_id,
        jsonb_build_object('name', p_name, 'default_visibility_ms', p_default_visibility_ms,
                           'max_retries', p_max_retries, 'dlq', p_dlq_name),
        NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION queue_register(text, integer, integer, text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION queue_register(text, integer, integer, text, text) TO
    maludb_memory_admin, maludb_memory_executor;

-- queue_enqueue — push a payload onto the named queue. Returns the
-- job_id. If an idempotency_key is supplied and a non-retired job
-- with that key already exists, returns its existing job_id and does
-- not insert a duplicate.
CREATE FUNCTION queue_enqueue(
    p_queue_name      text,
    p_payload         jsonb,
    p_idempotency_key text        DEFAULT NULL,
    p_priority        integer     DEFAULT 0,
    p_visible_at      timestamptz DEFAULT NULL,
    p_account_id      bigint      DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_queue_id bigint;
    v_existing bigint;
    v_id       bigint;
BEGIN
    SELECT q.queue_id INTO v_queue_id
      FROM malu$queue q
     WHERE q.name = p_queue_name AND q.retired_at IS NULL;
    IF v_queue_id IS NULL THEN
        RAISE EXCEPTION 'queue_enqueue: queue % not found or retired', p_queue_name
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_idempotency_key IS NOT NULL THEN
        SELECT j.job_id INTO v_existing
          FROM malu$queue_job j
         WHERE j.queue_id        = v_queue_id
           AND j.idempotency_key = p_idempotency_key;
        IF v_existing IS NOT NULL THEN
            RETURN v_existing;
        END IF;
    END IF;

    INSERT INTO malu$queue_job
        (queue_id, payload, idempotency_key, priority, visible_at, account_id)
    VALUES
        (v_queue_id, p_payload, p_idempotency_key, p_priority::smallint,
         COALESCE(p_visible_at, now()), p_account_id)
    RETURNING job_id INTO v_id;

    PERFORM audit_event(
        'queue_enqueue', 'malu$queue_job', v_id,
        jsonb_build_object('queue', p_queue_name, 'priority', p_priority,
                           'idempotency_key', p_idempotency_key),
        NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION queue_enqueue(text, jsonb, text, integer, timestamptz, bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION queue_enqueue(text, jsonb, text, integer, timestamptz, bigint) TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- queue_lease — atomically claim up to `p_batch` pending jobs. Uses
-- FOR UPDATE SKIP LOCKED so concurrent workers see different rows.
-- Each leased job moves to status='leased' with a malu$queue_lease
-- row holding the worker_id and visibility expiry.
CREATE FUNCTION queue_lease(
    p_queue_name     text,
    p_worker_id      text,
    p_batch          integer DEFAULT 1,
    p_visibility_ms  integer DEFAULT NULL
) RETURNS TABLE (job_id bigint, payload jsonb, attempts integer, enqueued_at timestamptz)
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_queue       malu$queue%ROWTYPE;
    v_vis_ms      integer;
BEGIN
    SELECT * INTO v_queue FROM malu$queue WHERE name = p_queue_name AND retired_at IS NULL;
    IF v_queue.queue_id IS NULL THEN
        RAISE EXCEPTION 'queue_lease: queue % not found or retired', p_queue_name
            USING ERRCODE = 'no_data_found';
    END IF;
    v_vis_ms := COALESCE(p_visibility_ms, v_queue.default_visibility_ms);

    RETURN QUERY
    WITH candidates AS (
        SELECT j.job_id
          FROM malu$queue_job j
         WHERE j.queue_id = v_queue.queue_id
           AND j.status   = 'pending'
           AND j.visible_at <= now()
         ORDER BY j.priority DESC, j.visible_at, j.job_id
         LIMIT GREATEST(p_batch, 1)
         FOR UPDATE SKIP LOCKED
    ),
    leased AS (
        UPDATE malu$queue_job j
           SET status               = 'leased',
               attempts             = j.attempts + 1,
               last_state_change_at = now()
          FROM candidates c
         WHERE j.job_id = c.job_id
        RETURNING j.job_id, j.payload, j.attempts, j.enqueued_at
    ),
    leases AS (
        INSERT INTO malu$queue_lease(job_id, worker_id, expires_at)
        SELECT l.job_id, p_worker_id, now() + (v_vis_ms || ' ms')::interval
          FROM leased l
        RETURNING job_id
    )
    SELECT l.job_id, l.payload, l.attempts::integer, l.enqueued_at FROM leased l;
END;
$body$;
REVOKE EXECUTE ON FUNCTION queue_lease(text, text, integer, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION queue_lease(text, text, integer, integer) TO
    maludb_memory_admin, maludb_queue_worker;

-- queue_ack — mark a leased job completed and release its lease.
CREATE FUNCTION queue_ack(p_job_id bigint)
    RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_was_leased boolean;
BEGIN
    DELETE FROM malu$queue_lease WHERE job_id = p_job_id;

    UPDATE malu$queue_job
       SET status = 'completed',
           last_state_change_at = now(),
           last_error = NULL
     WHERE job_id = p_job_id
       AND status = 'leased'
    RETURNING true INTO v_was_leased;

    IF v_was_leased THEN
        PERFORM audit_event('queue_ack', 'malu$queue_job', p_job_id, NULL, NULL);
        RETURN true;
    END IF;
    RETURN false;
END;
$body$;
REVOKE EXECUTE ON FUNCTION queue_ack(bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION queue_ack(bigint) TO
    maludb_memory_admin, maludb_queue_worker;

-- queue_nack — fail a leased job. Increments attempts; if it now
-- exceeds the queue's max_retries, marks the job 'dead' and (when a
-- DLQ is configured) enqueues the payload onto the DLQ.
CREATE FUNCTION queue_nack(p_job_id bigint, p_error_text text DEFAULT NULL)
    RETURNS text
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_job      malu$queue_job%ROWTYPE;
    v_queue    malu$queue%ROWTYPE;
    v_dlq_name text;
    v_outcome  text;
BEGIN
    SELECT * INTO v_job FROM malu$queue_job WHERE job_id = p_job_id;
    IF v_job.job_id IS NULL THEN
        RAISE EXCEPTION 'queue_nack: job % not found', p_job_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_job.status <> 'leased' THEN
        RAISE EXCEPTION 'queue_nack: job % is not leased (status=%)',
            p_job_id, v_job.status
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    SELECT * INTO v_queue FROM malu$queue WHERE queue_id = v_job.queue_id;

    DELETE FROM malu$queue_lease WHERE job_id = p_job_id;

    IF v_job.attempts >= v_queue.max_retries THEN
        UPDATE malu$queue_job
           SET status               = 'dead',
               last_error           = p_error_text,
               last_state_change_at = now()
         WHERE job_id = p_job_id;
        v_outcome := 'dead';

        IF v_queue.dlq_queue_id IS NOT NULL THEN
            SELECT q.name INTO v_dlq_name FROM malu$queue q WHERE q.queue_id = v_queue.dlq_queue_id;
            PERFORM queue_enqueue(
                v_dlq_name,
                jsonb_build_object(
                    'source_queue', v_queue.name,
                    'source_job_id', p_job_id,
                    'last_error',   p_error_text,
                    'payload',      v_job.payload),
                NULL, 0, NULL, NULL);
        END IF;
    ELSE
        UPDATE malu$queue_job
           SET status               = 'pending',
               last_error           = p_error_text,
               visible_at           = now(),
               last_state_change_at = now()
         WHERE job_id = p_job_id;
        v_outcome := 'pending';
    END IF;

    PERFORM audit_event('queue_nack', 'malu$queue_job', p_job_id,
        jsonb_build_object('outcome', v_outcome, 'attempts', v_job.attempts,
                           'max_retries', v_queue.max_retries,
                           'dlq', v_dlq_name),
        p_error_text);
    RETURN v_outcome;
END;
$body$;
REVOKE EXECUTE ON FUNCTION queue_nack(bigint, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION queue_nack(bigint, text) TO
    maludb_memory_admin, maludb_queue_worker;

-- queue_reap_expired_leases — reclaim leases past their expires_at
-- back to pending; returns the count.
CREATE FUNCTION queue_reap_expired_leases()
    RETURNS integer
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_n integer;
BEGIN
    WITH expired AS (
        SELECT job_id FROM malu$queue_lease WHERE expires_at <= now()
    ),
    deleted_leases AS (
        DELETE FROM malu$queue_lease l USING expired e
         WHERE l.job_id = e.job_id
        RETURNING l.job_id
    ),
    revived AS (
        UPDATE malu$queue_job j
           SET status               = 'pending',
               visible_at           = now(),
               last_state_change_at = now()
          FROM deleted_leases d
         WHERE j.job_id = d.job_id
           AND j.status = 'leased'
        RETURNING j.job_id
    )
    SELECT count(*)::integer INTO v_n FROM revived;

    IF v_n > 0 THEN
        PERFORM audit_event('queue_reap', 'malu$queue_lease', NULL,
            jsonb_build_object('reclaimed', v_n), NULL);
    END IF;
    RETURN v_n;
END;
$body$;
REVOKE EXECUTE ON FUNCTION queue_reap_expired_leases() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION queue_reap_expired_leases() TO
    maludb_memory_admin, maludb_queue_worker;

-- queue_stats — operator-facing depth + retry view.
CREATE FUNCTION queue_stats()
    RETURNS TABLE (
        queue_name  text,
        pending     bigint,
        leased      bigint,
        completed   bigint,
        failed      bigint,
        dead        bigint
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT q.name,
           count(*) FILTER (WHERE j.status = 'pending'),
           count(*) FILTER (WHERE j.status = 'leased'),
           count(*) FILTER (WHERE j.status = 'completed'),
           count(*) FILTER (WHERE j.status = 'failed'),
           count(*) FILTER (WHERE j.status = 'dead')
      FROM malu$queue q
      LEFT JOIN malu$queue_job j ON j.queue_id = q.queue_id
     WHERE q.retired_at IS NULL
     GROUP BY q.name
     ORDER BY q.name;
END;
$body$;
REVOKE EXECUTE ON FUNCTION queue_stats() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION queue_stats() TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor,
    maludb_queue_worker;

-- ============================================================
-- Section: maludb_core--0.45.0--0.46.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.46.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.45.0 → 0.46.0
--
-- Stage 11 / V3-CRON-01: scheduler.
--
-- Native PL/pgSQL scheduler that complements V3-QUEUE-01. Schedules
-- can either:
--   * Enqueue a job onto a named V3-QUEUE-01 queue (preferred), or
--   * Run an inline SQL string (operator-supplied, narrowly granted).
--
-- The scheduler itself does NOT spin a background worker; that's the
-- job of an operator-managed cron tick (V3-OBS-01 / V3-LOG-01 will
-- provide one once those land). Until then, an operator can call
-- `schedule_tick()` from `pg_cron` or a one-line `psql` loop.
--
-- pg_cron remains a future swap target — its table shape is similar
-- enough that a follow-up migration could delegate without breaking
-- the SQL contract here.
--
-- Cron expression support: the standard 5-field syntax
-- `minute hour day-of-month month day-of-week`, plus the `@hourly`,
-- `@daily`, `@weekly`, `@monthly`, `@yearly` aliases. Each field
-- accepts:
--   *               — any value
--   N               — literal
--   N-M             — range
--   N,M,K           — set
--   STAR/N          — step  (every Nth)
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.46.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.46.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$schedule
-- ---------------------------------------------------------------------
CREATE TABLE malu$schedule (
    schedule_id    bigserial PRIMARY KEY,
    name           text       NOT NULL,
    cron_expr      text       NOT NULL,
    action_kind    text       NOT NULL CHECK (action_kind IN ('enqueue','sql')),
    action_payload jsonb      NOT NULL,
    -- action_kind='enqueue' expects {"queue":"<name>","payload":<jsonb>}
    -- action_kind='sql'     expects {"sql":"<statement>"} (admin-only)
    description    text,
    enabled        boolean    NOT NULL DEFAULT true,
    next_run_at    timestamptz,
    last_run_at    timestamptz,
    last_error     text,
    owner_schema   name       NOT NULL DEFAULT current_schema(),
    created_at     timestamptz NOT NULL DEFAULT now(),
    retired_at     timestamptz,
    UNIQUE (owner_schema, name)
);
CREATE INDEX malu$schedule_next_run_idx
    ON malu$schedule(next_run_at)
    WHERE enabled AND retired_at IS NULL;
CREATE INDEX malu$schedule_owner_idx
    ON malu$schedule(owner_schema, enabled, retired_at);

-- ---------------------------------------------------------------------
-- malu$schedule_run — run history.
-- ---------------------------------------------------------------------
CREATE TABLE malu$schedule_run (
    run_id        bigserial PRIMARY KEY,
    schedule_id   bigint    NOT NULL REFERENCES malu$schedule(schedule_id) ON DELETE CASCADE,
    started_at    timestamptz NOT NULL DEFAULT now(),
    finished_at   timestamptz,
    status        text      NOT NULL CHECK (status IN ('running','succeeded','failed')),
    detail_jsonb  jsonb,
    error_text    text
);
CREATE INDEX malu$schedule_run_schedule_idx
    ON malu$schedule_run(schedule_id, started_at DESC);

-- ---------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------
ALTER TABLE malu$schedule ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$schedule
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$schedule_run ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_schedule ON malu$schedule_run
    USING (
        EXISTS (
            SELECT 1 FROM malu$schedule s
            WHERE s.schedule_id  = malu$schedule_run.schedule_id
              AND s.owner_schema = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$schedule s
            WHERE s.schedule_id  = malu$schedule_run.schedule_id
              AND s.owner_schema = current_schema()
        )
    );

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$schedule, malu$schedule_run TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$schedule, malu$schedule_run TO maludb_memory_executor;
GRANT SELECT                          ON malu$schedule, malu$schedule_run TO maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$schedule_schedule_id_seq TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$schedule_run_run_id_seq  TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- Cron expression evaluator (PL/pgSQL).
-- =====================================================================

-- _cron_expand_field — parse a single cron field into the integer set
-- of allowed values. Returns NULL if the field cannot be parsed.
CREATE FUNCTION _cron_expand_field(p_field text, p_min integer, p_max integer)
    RETURNS integer[]
    LANGUAGE plpgsql IMMUTABLE PARALLEL SAFE
    AS $body$
DECLARE
    v_out       integer[] := ARRAY[]::integer[];
    v_token     text;
    v_step      integer;
    v_lo        integer;
    v_hi        integer;
    v_range_lo  integer;
    v_range_hi  integer;
    v_pair      text[];
    v_i         integer;
BEGIN
    FOREACH v_token IN ARRAY string_to_array(p_field, ',') LOOP
        v_step := 1;
        IF position('/' IN v_token) > 0 THEN
            v_pair := string_to_array(v_token, '/');
            v_token := v_pair[1];
            v_step  := v_pair[2]::integer;
            IF v_step <= 0 THEN RETURN NULL; END IF;
        END IF;

        IF v_token = '*' THEN
            v_range_lo := p_min;
            v_range_hi := p_max;
        ELSIF position('-' IN v_token) > 0 THEN
            v_pair := string_to_array(v_token, '-');
            v_range_lo := v_pair[1]::integer;
            v_range_hi := v_pair[2]::integer;
        ELSE
            v_range_lo := v_token::integer;
            v_range_hi := v_range_lo;
        END IF;

        IF v_range_lo < p_min OR v_range_hi > p_max OR v_range_lo > v_range_hi THEN
            RETURN NULL;
        END IF;

        v_i := v_range_lo;
        WHILE v_i <= v_range_hi LOOP
            v_out := v_out || v_i;
            v_i := v_i + v_step;
        END LOOP;
    END LOOP;

    -- Deduplicate + sort via SELECT DISTINCT.
    SELECT array_agg(v ORDER BY v)
      INTO v_out
      FROM (SELECT DISTINCT unnest(v_out) AS v) s;
    RETURN v_out;
EXCEPTION WHEN others THEN
    RETURN NULL;
END;
$body$;
REVOKE EXECUTE ON FUNCTION _cron_expand_field(text, integer, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION _cron_expand_field(text, integer, integer) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- cron_next_after — return the first time >= p_after that matches
-- the cron expression. Raises if the expression is invalid.
CREATE FUNCTION cron_next_after(p_expr text, p_after timestamptz)
    RETURNS timestamptz
    LANGUAGE plpgsql STABLE PARALLEL SAFE
    AS $body$
DECLARE
    v_expr     text := trim(lower(p_expr));
    v_parts    text[];
    v_minutes  integer[];
    v_hours    integer[];
    v_doms     integer[];
    v_months   integer[];
    v_dows     integer[];
    v_now      timestamptz := date_trunc('minute', p_after) + interval '1 minute';
    v_attempts integer := 0;
BEGIN
    IF v_expr = '@hourly' THEN v_expr := '0 * * * *';
    ELSIF v_expr = '@daily'   THEN v_expr := '0 0 * * *';
    ELSIF v_expr = '@weekly'  THEN v_expr := '0 0 * * 0';
    ELSIF v_expr = '@monthly' THEN v_expr := '0 0 1 * *';
    ELSIF v_expr = '@yearly' OR v_expr = '@annually' THEN v_expr := '0 0 1 1 *';
    END IF;

    v_parts := regexp_split_to_array(v_expr, '\s+');
    IF array_length(v_parts, 1) <> 5 THEN
        RAISE EXCEPTION 'cron_next_after: expression % is not 5 fields', p_expr
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    v_minutes := _cron_expand_field(v_parts[1],  0, 59);
    v_hours   := _cron_expand_field(v_parts[2],  0, 23);
    v_doms    := _cron_expand_field(v_parts[3],  1, 31);
    v_months  := _cron_expand_field(v_parts[4],  1, 12);
    v_dows    := _cron_expand_field(v_parts[5],  0,  6);

    IF v_minutes IS NULL OR v_hours IS NULL OR v_doms IS NULL
       OR v_months IS NULL OR v_dows IS NULL THEN
        RAISE EXCEPTION 'cron_next_after: cannot parse %', p_expr
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    -- Walk minute-by-minute up to 4 years out (catches every yearly
    -- cron). 60 * 24 * 366 * 4 ≈ 2.1M iterations worst-case; the loop
    -- skips ahead in days when month/dom/dow miss, so the common case
    -- is much smaller.
    WHILE v_attempts < 366 * 4 LOOP
        IF extract(month  from v_now)::int = ANY(v_months)
           AND (extract(day    from v_now)::int = ANY(v_doms))
           AND (extract(dow    from v_now)::int = ANY(v_dows))
           AND (extract(hour   from v_now)::int = ANY(v_hours))
           AND (extract(minute from v_now)::int = ANY(v_minutes)) THEN
            RETURN v_now;
        END IF;
        v_now := v_now + interval '1 minute';
        v_attempts := v_attempts + 1;
        -- Skip to next day if month/dom/dow fail; cheaper than minute
        -- ticks across a whole month.
        IF extract(hour from v_now)::int = 0
           AND extract(minute from v_now)::int = 0 THEN
            IF NOT (extract(month from v_now)::int = ANY(v_months)
                    AND extract(day from v_now)::int = ANY(v_doms)
                    AND extract(dow from v_now)::int = ANY(v_dows)) THEN
                v_now := v_now + interval '1 day' - interval '1 second';
                v_now := date_trunc('day', v_now) + interval '1 day';
            END IF;
        END IF;
    END LOOP;

    RAISE EXCEPTION 'cron_next_after: no match within 4 years for %', p_expr
        USING ERRCODE = 'no_data_found';
END;
$body$;
REVOKE EXECUTE ON FUNCTION cron_next_after(text, timestamptz) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION cron_next_after(text, timestamptz) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- =====================================================================
-- Public schedule API
-- =====================================================================

-- schedule_create — UPSERT a named schedule. action_kind dictates
-- action_payload shape (see CHECK at the top).
CREATE FUNCTION schedule_create(
    p_name          text,
    p_cron_expr     text,
    p_action_kind   text,
    p_action_payload jsonb,
    p_description   text DEFAULT NULL,
    p_enabled       boolean DEFAULT true
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_next timestamptz;
    v_id   bigint;
BEGIN
    IF p_action_kind NOT IN ('enqueue','sql') THEN
        RAISE EXCEPTION 'schedule_create: action_kind must be enqueue or sql'
            USING ERRCODE = 'check_violation';
    END IF;
    IF p_action_kind = 'enqueue' THEN
        IF NOT (p_action_payload ? 'queue') THEN
            RAISE EXCEPTION 'schedule_create: enqueue action needs {"queue": "<name>", "payload": ...}'
                USING ERRCODE = 'check_violation';
        END IF;
    ELSIF p_action_kind = 'sql' THEN
        IF NOT (p_action_payload ? 'sql') THEN
            RAISE EXCEPTION 'schedule_create: sql action needs {"sql": "<statement>"}'
                USING ERRCODE = 'check_violation';
        END IF;
    END IF;

    -- Validate the cron expression and compute the first run.
    v_next := cron_next_after(p_cron_expr, now());

    INSERT INTO malu$schedule
        (name, cron_expr, action_kind, action_payload, description, enabled, next_run_at)
    VALUES
        (p_name, p_cron_expr, p_action_kind, p_action_payload, p_description, p_enabled, v_next)
    ON CONFLICT (owner_schema, name) DO UPDATE
        SET cron_expr      = EXCLUDED.cron_expr,
            action_kind    = EXCLUDED.action_kind,
            action_payload = EXCLUDED.action_payload,
            description    = EXCLUDED.description,
            enabled        = EXCLUDED.enabled,
            next_run_at    = EXCLUDED.next_run_at,
            retired_at     = NULL
    RETURNING schedule_id INTO v_id;

    PERFORM audit_event('schedule_create', 'malu$schedule', v_id,
        jsonb_build_object('name', p_name, 'cron_expr', p_cron_expr,
                           'action_kind', p_action_kind, 'next_run_at', v_next),
        NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION schedule_create(text, text, text, jsonb, text, boolean) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION schedule_create(text, text, text, jsonb, text, boolean) TO
    maludb_memory_admin, maludb_memory_executor;

-- schedule_enable / _disable
CREATE FUNCTION schedule_enable(p_name text) RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint; v_was boolean;
BEGIN
    SELECT schedule_id, enabled INTO v_id, v_was
      FROM malu$schedule WHERE name = p_name;
    IF v_id IS NULL THEN
        RAISE EXCEPTION 'schedule_enable: schedule % not found', p_name
            USING ERRCODE = 'no_data_found';
    END IF;
    UPDATE malu$schedule
       SET enabled     = true,
           next_run_at = cron_next_after(cron_expr, now()),
           retired_at  = NULL
     WHERE schedule_id = v_id;
    PERFORM audit_event('schedule_enable', 'malu$schedule', v_id,
        jsonb_build_object('was_enabled', v_was), NULL);
    RETURN NOT v_was;
END;
$body$;
REVOKE EXECUTE ON FUNCTION schedule_enable(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION schedule_enable(text) TO maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION schedule_disable(p_name text, p_reason text DEFAULT NULL) RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint; v_was boolean;
BEGIN
    SELECT schedule_id, enabled INTO v_id, v_was
      FROM malu$schedule WHERE name = p_name;
    IF v_id IS NULL THEN
        RAISE EXCEPTION 'schedule_disable: schedule % not found', p_name
            USING ERRCODE = 'no_data_found';
    END IF;
    UPDATE malu$schedule
       SET enabled = false,
           next_run_at = NULL
     WHERE schedule_id = v_id;
    PERFORM audit_event('schedule_disable', 'malu$schedule', v_id,
        jsonb_build_object('was_enabled', v_was, 'reason', p_reason), NULL);
    RETURN v_was;
END;
$body$;
REVOKE EXECUTE ON FUNCTION schedule_disable(text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION schedule_disable(text, text) TO maludb_memory_admin, maludb_memory_executor;

-- schedule_list — enumeration for the CLI / metrics.
CREATE FUNCTION schedule_list(p_include_disabled boolean DEFAULT false)
    RETURNS TABLE (
        schedule_id  bigint,
        name         text,
        cron_expr    text,
        action_kind  text,
        enabled      boolean,
        next_run_at  timestamptz,
        last_run_at  timestamptz,
        last_error   text
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT s.schedule_id, s.name, s.cron_expr, s.action_kind, s.enabled,
           s.next_run_at, s.last_run_at, s.last_error
      FROM malu$schedule s
     WHERE (p_include_disabled OR (s.enabled AND s.retired_at IS NULL))
     ORDER BY s.name;
END;
$body$;
REVOKE EXECUTE ON FUNCTION schedule_list(boolean) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION schedule_list(boolean) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- _schedule_execute_action — runs an action_payload under the
-- schedule's owner. enqueue is the safe path; sql requires the caller
-- to be maludb_memory_admin (BYPASSRLS) since arbitrary SQL is a
-- privilege concern. The CHECK is enforced via has_role.
CREATE FUNCTION _schedule_execute_action(
    p_schedule_id bigint,
    p_action_kind text,
    p_payload     jsonb
) RETURNS jsonb
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_qname  text;
    v_q_pay  jsonb;
    v_sql    text;
    v_jid    bigint;
BEGIN
    IF p_action_kind = 'enqueue' THEN
        v_qname := p_payload ->> 'queue';
        v_q_pay := COALESCE(p_payload -> 'payload', '{}'::jsonb);
        v_jid   := queue_enqueue(v_qname, v_q_pay, NULL, 0, NULL, NULL);
        RETURN jsonb_build_object('action', 'enqueue', 'queue', v_qname, 'job_id', v_jid);
    ELSIF p_action_kind = 'sql' THEN
        IF NOT pg_has_role(session_user, 'maludb_memory_admin', 'MEMBER') THEN
            RAISE EXCEPTION '_schedule_execute_action: sql action requires maludb_memory_admin'
                USING ERRCODE = 'insufficient_privilege';
        END IF;
        v_sql := p_payload ->> 'sql';
        EXECUTE v_sql;
        RETURN jsonb_build_object('action', 'sql', 'executed', true);
    ELSE
        RAISE EXCEPTION '_schedule_execute_action: unknown action_kind %', p_action_kind
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
END;
$body$;
REVOKE EXECUTE ON FUNCTION _schedule_execute_action(bigint, text, jsonb) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION _schedule_execute_action(bigint, text, jsonb) TO
    maludb_memory_admin, maludb_memory_executor;

-- schedule_run_now — invoke a schedule immediately, regardless of
-- next_run_at. Records a malu$schedule_run row.
CREATE FUNCTION schedule_run_now(p_name text) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_sched malu$schedule%ROWTYPE;
    v_run_id bigint;
    v_detail jsonb;
BEGIN
    SELECT * INTO v_sched FROM malu$schedule WHERE name = p_name AND retired_at IS NULL;
    IF v_sched.schedule_id IS NULL THEN
        RAISE EXCEPTION 'schedule_run_now: schedule % not found', p_name
            USING ERRCODE = 'no_data_found';
    END IF;

    INSERT INTO malu$schedule_run(schedule_id, status)
    VALUES (v_sched.schedule_id, 'running')
    RETURNING run_id INTO v_run_id;

    BEGIN
        v_detail := _schedule_execute_action(v_sched.schedule_id,
                                             v_sched.action_kind,
                                             v_sched.action_payload);
        UPDATE malu$schedule_run
           SET finished_at  = now(),
               status       = 'succeeded',
               detail_jsonb = v_detail
         WHERE run_id = v_run_id;
        UPDATE malu$schedule
           SET last_run_at = now(),
               last_error  = NULL
         WHERE schedule_id = v_sched.schedule_id;
        PERFORM audit_event('schedule_run_succeeded', 'malu$schedule', v_sched.schedule_id,
            v_detail, NULL);
    EXCEPTION WHEN others THEN
        UPDATE malu$schedule_run
           SET finished_at = now(),
               status      = 'failed',
               error_text  = SQLERRM
         WHERE run_id = v_run_id;
        UPDATE malu$schedule
           SET last_run_at = now(),
               last_error  = SQLERRM
         WHERE schedule_id = v_sched.schedule_id;
        PERFORM audit_event('schedule_run_failed', 'malu$schedule', v_sched.schedule_id,
            jsonb_build_object('error', SQLERRM), SQLERRM);
        RAISE;
    END;

    RETURN v_run_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION schedule_run_now(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION schedule_run_now(text) TO maludb_memory_admin, maludb_memory_executor;

-- schedule_tick — operator-callable. Runs every enabled schedule whose
-- next_run_at <= now(), advances next_run_at, returns the count fired.
-- Designed to be called from pg_cron or an external clock.
CREATE FUNCTION schedule_tick() RETURNS integer
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    r record;
    v_count integer := 0;
BEGIN
    FOR r IN
        SELECT schedule_id, name, cron_expr
          FROM malu$schedule
         WHERE enabled
           AND retired_at IS NULL
           AND next_run_at IS NOT NULL
           AND next_run_at <= now()
         ORDER BY next_run_at
    LOOP
        BEGIN
            PERFORM schedule_run_now(r.name);
        EXCEPTION WHEN others THEN
            -- schedule_run_now already recorded the failure; keep
            -- ticking the rest of the queue.
            NULL;
        END;
        UPDATE malu$schedule
           SET next_run_at = cron_next_after(r.cron_expr, now())
         WHERE schedule_id = r.schedule_id;
        v_count := v_count + 1;
    END LOOP;
    RETURN v_count;
END;
$body$;
REVOKE EXECUTE ON FUNCTION schedule_tick() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION schedule_tick() TO maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.46.0--0.47.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.47.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.46.0 → 0.47.0
--
-- Stage 12 / V3-STOR-01 (catalog): Verbatim Source Archive v1.
--
-- Adds the catalog the future maludb-restd + CLI will consume to
-- track immutable raw evidence:
--   malu$storage_adapter        — local_fs / s3 endpoints.
--   malu$source_object          — content_hash, byte_length, media
--                                 type, retention_class, legal_hold,
--                                 sensitivity, partition, adapter_uri.
--   malu$source_object_reference — byte/line/page/timestamp/cursor
--                                 offsets that anchor a Claim or Fact
--                                 to a specific slice of the object.
--
-- Doctrine:
--   * Objects are immutable. Re-uploading the same byte sequence
--     returns the existing object_id (content_hash is UNIQUE).
--   * The actual byte storage lives outside PostgreSQL — the CLI
--     (and later maludb-restd) writes to the configured adapter and
--     registers the resulting metadata here.
--   * Legal hold and retention_class match the existing
--     malu$source_package vocabulary so promotion is a metadata
--     copy, not a reclassification.
--   * RLS owner_schema-bound everywhere.
--
-- The Stage 12 promotion path (`source_object_promote_to_source_package`
-- + Derivation Ledger entry) lands in `0.47.0 → 0.48.0`.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.47.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.47.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$storage_adapter
-- ---------------------------------------------------------------------
CREATE TABLE malu$storage_adapter (
    adapter_id    bigserial PRIMARY KEY,
    name          text       NOT NULL,
    kind          text       NOT NULL CHECK (kind IN ('local_fs','s3')),
    config        jsonb      NOT NULL DEFAULT '{}'::jsonb,
    -- local_fs config: {"base_path": "/var/lib/maludb/source-archive"}
    -- s3        config: {"bucket": "...", "region": "...", "key_prefix": "...",
    --                    "endpoint": "..."}  (credentials live behind secret_ref)
    secret_ref    text,                -- malu$secret.name (resolved via __secret_resolve)
    description   text,
    owner_schema  name       NOT NULL DEFAULT current_schema(),
    created_at    timestamptz NOT NULL DEFAULT now(),
    retired_at    timestamptz,
    UNIQUE (owner_schema, name)
);
CREATE INDEX malu$storage_adapter_owner_idx
    ON malu$storage_adapter(owner_schema) WHERE retired_at IS NULL;

-- ---------------------------------------------------------------------
-- malu$source_object — one row per immutable source byte sequence.
-- content_hash is the raw SHA-256 (bytea, 32 bytes). The hex-encoded
-- form is exposed by source_object_metadata() and is what
-- malu$source_package.content_hash stores after promotion.
-- ---------------------------------------------------------------------
CREATE TABLE malu$source_object (
    object_id          bigserial PRIMARY KEY,
    content_hash       bytea      NOT NULL,
    media_type         text,
    byte_length        bigint     NOT NULL CHECK (byte_length >= 0),
    source_time        timestamptz,
    capture_time       timestamptz NOT NULL DEFAULT now(),
    retention_class    text       NOT NULL DEFAULT 'standard'
        CHECK (retention_class IN ('standard','sensitive','restricted','prohibited')),
    legal_hold         boolean    NOT NULL DEFAULT false,
    legal_hold_reason  text,
    sensitivity        text       NOT NULL DEFAULT 'internal'
        CHECK (sensitivity IN ('public','internal','restricted','prohibited')),
    partition          text,
    adapter_id         bigint     NOT NULL REFERENCES malu$storage_adapter(adapter_id) ON DELETE RESTRICT,
    adapter_uri        text       NOT NULL,
    signed_url_policy  jsonb,
    owner_schema       name       NOT NULL DEFAULT current_schema(),
    created_at         timestamptz NOT NULL DEFAULT now(),
    retired_at         timestamptz,
    UNIQUE (owner_schema, content_hash),
    CHECK (octet_length(content_hash) = 32)
);
CREATE INDEX malu$source_object_hash_idx
    ON malu$source_object(content_hash)
    WHERE retired_at IS NULL;
CREATE INDEX malu$source_object_partition_idx
    ON malu$source_object(owner_schema, partition)
    WHERE partition IS NOT NULL AND retired_at IS NULL;
CREATE INDEX malu$source_object_legal_hold_idx
    ON malu$source_object(owner_schema)
    WHERE legal_hold;

-- ---------------------------------------------------------------------
-- malu$source_object_reference — byte/line/page/timestamp/cursor
-- anchors. A Claim or Fact can point at one or more reference rows
-- to record "this assertion comes from these bytes of this object".
-- ---------------------------------------------------------------------
CREATE TABLE malu$source_object_reference (
    reference_id  bigserial PRIMARY KEY,
    object_id     bigint    NOT NULL REFERENCES malu$source_object(object_id) ON DELETE CASCADE,
    kind          text      NOT NULL CHECK (kind IN
                    ('byte_range','line_range','page','timestamp','cursor')),
    value_jsonb   jsonb     NOT NULL,
    note          text,
    created_at    timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$source_object_reference_object_idx
    ON malu$source_object_reference(object_id);

-- ---------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------
ALTER TABLE malu$storage_adapter ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$storage_adapter
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$source_object ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$source_object
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$source_object_reference ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_object ON malu$source_object_reference
    USING (
        EXISTS (
            SELECT 1 FROM malu$source_object o
            WHERE o.object_id    = malu$source_object_reference.object_id
              AND o.owner_schema = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$source_object o
            WHERE o.object_id    = malu$source_object_reference.object_id
              AND o.owner_schema = current_schema()
        )
    );

-- ---------------------------------------------------------------------
-- Grants. Admin + executor write; auditor reads.
-- ---------------------------------------------------------------------
GRANT SELECT, INSERT, UPDATE, DELETE ON malu$storage_adapter, malu$source_object, malu$source_object_reference TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$storage_adapter, malu$source_object, malu$source_object_reference TO maludb_memory_executor;
GRANT SELECT                          ON malu$storage_adapter, malu$source_object, malu$source_object_reference TO maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$storage_adapter_adapter_id_seq             TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$source_object_object_id_seq                TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$source_object_reference_reference_id_seq   TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- Public API
-- =====================================================================

CREATE FUNCTION register_storage_adapter(
    p_name         text,
    p_kind         text,
    p_config       jsonb DEFAULT '{}'::jsonb,
    p_secret_ref   text  DEFAULT NULL,
    p_description  text  DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    IF p_kind NOT IN ('local_fs','s3') THEN
        RAISE EXCEPTION 'register_storage_adapter: kind must be local_fs or s3'
            USING ERRCODE = 'check_violation';
    END IF;
    IF p_kind = 'local_fs' AND NOT (p_config ? 'base_path') THEN
        RAISE EXCEPTION 'register_storage_adapter: local_fs config needs {"base_path": "..."}'
            USING ERRCODE = 'check_violation';
    END IF;
    IF p_kind = 's3' AND NOT (p_config ? 'bucket') THEN
        RAISE EXCEPTION 'register_storage_adapter: s3 config needs {"bucket": "...", ...}'
            USING ERRCODE = 'check_violation';
    END IF;

    INSERT INTO malu$storage_adapter(name, kind, config, secret_ref, description)
    VALUES (p_name, p_kind, p_config, p_secret_ref, p_description)
    ON CONFLICT (owner_schema, name) DO UPDATE
        SET kind        = EXCLUDED.kind,
            config      = EXCLUDED.config,
            secret_ref  = EXCLUDED.secret_ref,
            description = EXCLUDED.description,
            retired_at  = NULL
    RETURNING adapter_id INTO v_id;

    PERFORM audit_event('storage_adapter_register', 'malu$storage_adapter', v_id,
        jsonb_build_object('name', p_name, 'kind', p_kind, 'secret_ref', p_secret_ref),
        NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION register_storage_adapter(text, text, jsonb, text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION register_storage_adapter(text, text, jsonb, text, text) TO
    maludb_memory_admin, maludb_memory_executor;

-- source_object_register — UPSERT keyed by (owner_schema, content_hash).
-- If the same byte sequence has already been registered, returns the
-- existing object_id without re-inserting. Otherwise creates a new
-- row pointing at the supplied adapter_uri.
CREATE FUNCTION source_object_register(
    p_adapter_name    text,
    p_adapter_uri     text,
    p_content_hash    bytea,
    p_byte_length     bigint,
    p_media_type      text          DEFAULT NULL,
    p_source_time     timestamptz   DEFAULT NULL,
    p_retention_class text          DEFAULT 'standard',
    p_sensitivity     text          DEFAULT 'internal',
    p_partition       text          DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_adapter_id bigint;
    v_existing   bigint;
    v_id         bigint;
BEGIN
    IF octet_length(p_content_hash) <> 32 THEN
        RAISE EXCEPTION 'source_object_register: content_hash must be 32 bytes (raw SHA-256)'
            USING ERRCODE = 'check_violation';
    END IF;

    SELECT adapter_id INTO v_adapter_id
      FROM malu$storage_adapter
     WHERE name = p_adapter_name AND retired_at IS NULL;
    IF v_adapter_id IS NULL THEN
        RAISE EXCEPTION 'source_object_register: adapter % not found or retired', p_adapter_name
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT object_id INTO v_existing
      FROM malu$source_object
     WHERE content_hash = p_content_hash
       AND retired_at IS NULL;
    IF v_existing IS NOT NULL THEN
        RETURN v_existing;
    END IF;

    INSERT INTO malu$source_object
        (content_hash, byte_length, media_type, source_time,
         retention_class, sensitivity, partition,
         adapter_id, adapter_uri)
    VALUES
        (p_content_hash, p_byte_length, p_media_type, p_source_time,
         p_retention_class, p_sensitivity, p_partition,
         v_adapter_id, p_adapter_uri)
    RETURNING object_id INTO v_id;

    PERFORM audit_event('source_object_register', 'malu$source_object', v_id,
        jsonb_build_object(
            'adapter',         p_adapter_name,
            'adapter_uri',     p_adapter_uri,
            'content_hash',    encode(p_content_hash, 'hex'),
            'byte_length',     p_byte_length,
            'media_type',      p_media_type,
            'retention_class', p_retention_class,
            'sensitivity',     p_sensitivity,
            'partition',       p_partition),
        NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION source_object_register(text, text, bytea, bigint, text, timestamptz, text, text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION source_object_register(text, text, bytea, bigint, text, timestamptz, text, text, text) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION source_object_lookup_by_hash(p_content_hash bytea)
    RETURNS bigint
    LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    SELECT object_id INTO v_id
      FROM malu$source_object
     WHERE content_hash = p_content_hash
       AND retired_at IS NULL
     LIMIT 1;
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION source_object_lookup_by_hash(bytea) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION source_object_lookup_by_hash(bytea) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

CREATE FUNCTION source_object_set_legal_hold(
    p_object_id bigint,
    p_hold      boolean,
    p_reason    text DEFAULT NULL
) RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_was boolean;
BEGIN
    SELECT legal_hold INTO v_was FROM malu$source_object WHERE object_id = p_object_id;
    IF v_was IS NULL THEN
        RAISE EXCEPTION 'source_object_set_legal_hold: object % not found', p_object_id
            USING ERRCODE = 'no_data_found';
    END IF;
    UPDATE malu$source_object
       SET legal_hold        = p_hold,
           legal_hold_reason = CASE WHEN p_hold THEN p_reason ELSE NULL END
     WHERE object_id = p_object_id;
    PERFORM audit_event(
        CASE WHEN p_hold THEN 'source_object_legal_hold_on' ELSE 'source_object_legal_hold_off' END,
        'malu$source_object', p_object_id,
        jsonb_build_object('reason', p_reason, 'was_held', v_was), NULL);
    RETURN v_was;
END;
$body$;
REVOKE EXECUTE ON FUNCTION source_object_set_legal_hold(bigint, boolean, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION source_object_set_legal_hold(bigint, boolean, text) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION source_object_add_reference(
    p_object_id   bigint,
    p_kind        text,
    p_value_jsonb jsonb,
    p_note        text DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$source_object_reference(object_id, kind, value_jsonb, note)
    VALUES (p_object_id, p_kind, p_value_jsonb, p_note)
    RETURNING reference_id INTO v_id;
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION source_object_add_reference(bigint, text, jsonb, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION source_object_add_reference(bigint, text, jsonb, text) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION source_object_metadata(p_object_id bigint)
    RETURNS TABLE (
        object_id        bigint,
        content_hash_hex text,
        byte_length      bigint,
        media_type       text,
        source_time      timestamptz,
        capture_time     timestamptz,
        retention_class  text,
        legal_hold       boolean,
        sensitivity      text,
        partition        text,
        adapter_name     text,
        adapter_kind     text,
        adapter_uri      text,
        created_at       timestamptz,
        retired_at       timestamptz
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT o.object_id, encode(o.content_hash, 'hex'), o.byte_length, o.media_type,
           o.source_time, o.capture_time, o.retention_class, o.legal_hold,
           o.sensitivity, o.partition, a.name, a.kind, o.adapter_uri,
           o.created_at, o.retired_at
      FROM malu$source_object o
      JOIN malu$storage_adapter a ON a.adapter_id = o.adapter_id
     WHERE o.object_id = p_object_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION source_object_metadata(bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION source_object_metadata(bigint) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.47.0--0.48.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.48.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.47.0 → 0.48.0
--
-- Stage 12 / V3-STOR-01 (promotion): source_object → source_package.
--
-- Closes V3-STOR-01's "promotion path from stored object to Source
-- Package, Claims, Facts, embeddings, Derivation Ledger" requirement.
-- The function in this migration handles the source_object →
-- source_package step plus a malu$derivation_ledger entry recording
-- the source_object_id, adapter, and content_hash that produced the
-- source_package. Further promotions (claim, fact, ...) reuse the
-- existing register_claim / register_fact pipeline from Stage 2.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.48.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.48.0'::text $body$;

-- source_object_promote_to_source_package — wraps register_source_package
-- with the source-archive content_hash + byte_length, and writes a
-- malu$derivation_ledger entry of kind 'source_package' recording the
-- archive provenance. The promoted package's content lives in the
-- catalog row's content_text/_bytes/_jsonb (one of which the caller
-- supplies); the malu$source_object itself remains the immutable
-- byte-source-of-truth, addressable by hash.
CREATE FUNCTION source_object_promote_to_source_package(
    p_object_id       bigint,
    p_source_type     text,
    p_content_bytes   bytea       DEFAULT NULL,
    p_content_text    text        DEFAULT NULL,
    p_content_jsonb   jsonb       DEFAULT NULL,
    p_origin_jsonb    jsonb       DEFAULT NULL,
    p_captured_at     timestamptz DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_obj                 malu$source_object%ROWTYPE;
    v_adapter_name        text;
    v_adapter_kind        text;
    v_hash_hex            text;
    v_origin              jsonb;
    v_package_id          bigint;
    v_ledger_id           bigint;
    v_inputs              jsonb;
BEGIN
    SELECT * INTO v_obj FROM malu$source_object WHERE object_id = p_object_id;
    IF v_obj.object_id IS NULL THEN
        RAISE EXCEPTION 'source_object_promote_to_source_package: object % not found', p_object_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF v_obj.retired_at IS NOT NULL THEN
        RAISE EXCEPTION 'source_object_promote_to_source_package: object % is retired', p_object_id
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    SELECT name, kind
      INTO v_adapter_name, v_adapter_kind
      FROM malu$storage_adapter
     WHERE adapter_id = v_obj.adapter_id;

    v_hash_hex := encode(v_obj.content_hash, 'hex');

    -- Build the origin envelope: caller-supplied origin merged with
    -- archive provenance, so the resulting Source Package row carries
    -- the adapter and object_id even before anyone looks at the
    -- Derivation Ledger.
    v_origin := COALESCE(p_origin_jsonb, '{}'::jsonb) || jsonb_build_object(
        'source_object_id', v_obj.object_id,
        'adapter',          v_adapter_name,
        'adapter_kind',     v_adapter_kind,
        'adapter_uri',      v_obj.adapter_uri,
        'content_hash',     v_hash_hex,
        'byte_length',      v_obj.byte_length,
        'media_type',       v_obj.media_type);

    v_package_id := register_source_package(
        p_source_type     => p_source_type,
        p_content_bytes   => p_content_bytes,
        p_content_text    => p_content_text,
        p_content_jsonb   => p_content_jsonb,
        p_media_type      => v_obj.media_type,
        p_origin_jsonb    => v_origin,
        p_captured_at     => COALESCE(p_captured_at, v_obj.source_time, v_obj.capture_time),
        p_retention_class => v_obj.retention_class,
        p_sensitivity     => v_obj.sensitivity);

    v_inputs := jsonb_build_array(jsonb_build_object(
        'kind',          'source_object',
        'object_id',     v_obj.object_id,
        'content_hash',  v_hash_hex,
        'byte_length',   v_obj.byte_length,
        'adapter',       v_adapter_name));

    INSERT INTO malu$derivation_ledger
        (derived_object_type, derived_object_id, parser_name,
         inputs_jsonb, inputs_hash)
    VALUES
        ('source_package', v_package_id, 'source_object_promote',
         v_inputs,
         encode(public.digest(v_inputs::text::bytea, 'sha256'), 'hex'))
    RETURNING derivation_id INTO v_ledger_id;

    PERFORM audit_event('source_object_promote', 'malu$source_object', v_obj.object_id,
        jsonb_build_object(
            'source_package_id', v_package_id,
            'derivation_id',     v_ledger_id,
            'source_type',       p_source_type,
            'content_hash',      v_hash_hex),
        NULL);

    RETURN v_package_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION source_object_promote_to_source_package(bigint, text, bytea, text, jsonb, jsonb, timestamptz) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION source_object_promote_to_source_package(bigint, text, bytea, text, jsonb, jsonb, timestamptz) TO
    maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.48.0--0.49.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.49.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.48.0 → 0.49.0
--
-- Stage 13 / V3-REALTIME-01 (catalog): memory event stream.
--
-- Adds the durable backbone for realtime delivery:
--   malu$event              — append-only, monotonic event_id is the
--                             cursor. Carries event_kind, account,
--                             partition, active_pool, object_ref,
--                             scope, transaction_time, payload.
--   malu$event_subscription — per-account subscription state with
--                             filter set (kinds[], partitions[],
--                             active_pool) and persistent cursor.
--   malu$event_delivery     — append-only delivery audit per
--                             subscription.
--
-- emit_event NOTIFY-s on channel `maludb_event` so the future
-- maludb-realtimed service can use LISTEN for low-latency wakeups
-- instead of polling. The payload is the bigint event_id as text.
--
-- Stage 13 retrofits the V3-shipped write paths (auth_token,
-- secret_*, source_object_register, queue_enqueue, schedule_run_*)
-- to emit events in `0.48.0 -> 0.49.0` only; the Stage 2-7 register_*
-- functions stay untouched (a Stage 13 follow-up extends them).
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.49.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.49.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$event — the durable event log. event_id is BIGSERIAL and is
-- the cursor; every subscriber persists a "last-acked" event_id.
-- ---------------------------------------------------------------------
CREATE TABLE malu$event (
    event_id          bigserial PRIMARY KEY,
    event_kind        text       NOT NULL,
    account_id        bigint     REFERENCES malu$account(account_id) ON DELETE SET NULL,
    partition         text,
    active_pool_id    bigint,
    object_type       text,
    object_id         bigint,
    scope             jsonb,
    transaction_time  timestamptz NOT NULL DEFAULT now(),
    payload           jsonb      NOT NULL DEFAULT '{}'::jsonb,
    owner_schema      name       NOT NULL DEFAULT current_schema()
);
CREATE INDEX malu$event_kind_idx     ON malu$event(event_kind, event_id DESC);
CREATE INDEX malu$event_account_idx  ON malu$event(account_id, event_id DESC) WHERE account_id IS NOT NULL;
CREATE INDEX malu$event_owner_idx    ON malu$event(owner_schema, event_id DESC);
CREATE INDEX malu$event_object_idx   ON malu$event(object_type, object_id, event_id DESC) WHERE object_id IS NOT NULL;

-- ---------------------------------------------------------------------
-- malu$event_subscription — per-subscriber state.
-- ---------------------------------------------------------------------
CREATE TABLE malu$event_subscription (
    subscription_id bigserial PRIMARY KEY,
    name            text,
    account_id      bigint     REFERENCES malu$account(account_id) ON DELETE CASCADE,
    kinds           text[]     NOT NULL DEFAULT ARRAY[]::text[],
    partitions      text[]     NOT NULL DEFAULT ARRAY[]::text[],
    active_pool_id  bigint,
    cursor          bigint     NOT NULL DEFAULT 0,
    last_seen_at    timestamptz,
    owner_schema    name       NOT NULL DEFAULT current_schema(),
    created_at      timestamptz NOT NULL DEFAULT now(),
    retired_at      timestamptz
);
CREATE INDEX malu$event_subscription_owner_idx
    ON malu$event_subscription(owner_schema, account_id) WHERE retired_at IS NULL;

-- ---------------------------------------------------------------------
-- malu$event_delivery — one row per (subscription, event) delivery.
-- ---------------------------------------------------------------------
CREATE TABLE malu$event_delivery (
    delivery_id     bigserial PRIMARY KEY,
    subscription_id bigint     NOT NULL REFERENCES malu$event_subscription(subscription_id) ON DELETE CASCADE,
    event_id        bigint     NOT NULL REFERENCES malu$event(event_id) ON DELETE CASCADE,
    delivered_at    timestamptz NOT NULL DEFAULT now(),
    status          text       NOT NULL DEFAULT 'delivered' CHECK (status IN ('delivered','acked','failed')),
    UNIQUE (subscription_id, event_id)
);
CREATE INDEX malu$event_delivery_sub_idx ON malu$event_delivery(subscription_id, delivered_at DESC);

-- ---------------------------------------------------------------------
-- RLS — owner_schema-bound across all three tables. Delivery rows
-- inherit from their parent subscription.
-- ---------------------------------------------------------------------
ALTER TABLE malu$event ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$event
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$event_subscription ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$event_subscription
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$event_delivery ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_subscription ON malu$event_delivery
    USING (
        EXISTS (
            SELECT 1 FROM malu$event_subscription s
            WHERE s.subscription_id = malu$event_delivery.subscription_id
              AND s.owner_schema    = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$event_subscription s
            WHERE s.subscription_id = malu$event_delivery.subscription_id
              AND s.owner_schema    = current_schema()
        )
    );

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$event, malu$event_subscription, malu$event_delivery TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$event, malu$event_subscription, malu$event_delivery TO maludb_memory_executor;
GRANT SELECT                          ON malu$event, malu$event_subscription, malu$event_delivery TO maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$event_event_id_seq                       TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$event_subscription_subscription_id_seq   TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$event_delivery_delivery_id_seq           TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- emit_event — append a row to malu$event and NOTIFY the realtime
-- channel. Returns the new event_id (= cursor position).
-- =====================================================================
CREATE FUNCTION emit_event(
    p_event_kind     text,
    p_payload        jsonb       DEFAULT '{}'::jsonb,
    p_account_id     bigint      DEFAULT NULL,
    p_partition      text        DEFAULT NULL,
    p_active_pool_id bigint      DEFAULT NULL,
    p_object_type    text        DEFAULT NULL,
    p_object_id      bigint      DEFAULT NULL,
    p_scope          jsonb       DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$event
        (event_kind, account_id, partition, active_pool_id,
         object_type, object_id, scope, payload)
    VALUES
        (p_event_kind, p_account_id, p_partition, p_active_pool_id,
         p_object_type, p_object_id, p_scope, p_payload)
    RETURNING event_id INTO v_id;

    -- NOTIFY payload is the event_id as text. Subscribers LISTEN on
    -- 'maludb_event' and wake to fetch new rows past their cursor.
    PERFORM pg_notify('maludb_event', v_id::text);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION emit_event(text, jsonb, bigint, text, bigint, text, bigint, jsonb) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION emit_event(text, jsonb, bigint, text, bigint, text, bigint, jsonb) TO
    maludb_memory_admin, maludb_memory_executor;

-- event_subscribe — UPSERT a subscription by name (per tenant).
CREATE FUNCTION event_subscribe(
    p_name           text,
    p_account_id     bigint  DEFAULT NULL,
    p_kinds          text[]  DEFAULT ARRAY[]::text[],
    p_partitions     text[]  DEFAULT ARRAY[]::text[],
    p_active_pool_id bigint  DEFAULT NULL,
    p_start_cursor   bigint  DEFAULT 0
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$event_subscription
        (name, account_id, kinds, partitions, active_pool_id, cursor)
    VALUES
        (p_name, p_account_id, p_kinds, p_partitions, p_active_pool_id, p_start_cursor)
    RETURNING subscription_id INTO v_id;
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION event_subscribe(text, bigint, text[], text[], bigint, bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION event_subscribe(text, bigint, text[], text[], bigint, bigint) TO
    maludb_memory_admin, maludb_memory_executor;

-- event_fetch_batch — return up to p_limit events past the cursor
-- matching the subscription's filter. Does NOT advance the cursor;
-- callers ack via event_ack(subscription_id, last_event_id) after
-- successful delivery. This makes at-least-once delivery the
-- default semantics.
CREATE FUNCTION event_fetch_batch(
    p_subscription_id bigint,
    p_limit           integer DEFAULT 100
) RETURNS TABLE (
    event_id          bigint,
    event_kind        text,
    account_id        bigint,
    partition         text,
    active_pool_id    bigint,
    object_type       text,
    object_id         bigint,
    scope             jsonb,
    transaction_time  timestamptz,
    payload           jsonb
) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
DECLARE v_sub malu$event_subscription%ROWTYPE;
BEGIN
    SELECT * INTO v_sub FROM malu$event_subscription WHERE subscription_id = p_subscription_id;
    IF v_sub.subscription_id IS NULL THEN
        RAISE EXCEPTION 'event_fetch_batch: subscription % not found', p_subscription_id
            USING ERRCODE = 'no_data_found';
    END IF;

    RETURN QUERY
    SELECT e.event_id, e.event_kind, e.account_id, e.partition,
           e.active_pool_id, e.object_type, e.object_id, e.scope,
           e.transaction_time, e.payload
      FROM malu$event e
     WHERE e.event_id > v_sub.cursor
       AND (cardinality(v_sub.kinds)      = 0 OR e.event_kind = ANY(v_sub.kinds))
       AND (cardinality(v_sub.partitions) = 0 OR e.partition  = ANY(v_sub.partitions))
       AND (v_sub.active_pool_id IS NULL OR e.active_pool_id  = v_sub.active_pool_id)
       AND (v_sub.account_id     IS NULL OR e.account_id      = v_sub.account_id OR e.account_id IS NULL)
     ORDER BY e.event_id
     LIMIT GREATEST(p_limit, 1);
END;
$body$;
REVOKE EXECUTE ON FUNCTION event_fetch_batch(bigint, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION event_fetch_batch(bigint, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- event_ack — advance the subscription's cursor and record delivery
-- rows for every event between the old and new cursors.
CREATE FUNCTION event_ack(p_subscription_id bigint, p_through_event_id bigint)
    RETURNS integer
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_old_cursor bigint;
    v_n          integer;
BEGIN
    SELECT cursor INTO v_old_cursor
      FROM malu$event_subscription
     WHERE subscription_id = p_subscription_id
     FOR UPDATE;
    IF v_old_cursor IS NULL THEN
        RAISE EXCEPTION 'event_ack: subscription % not found', p_subscription_id
            USING ERRCODE = 'no_data_found';
    END IF;
    IF p_through_event_id <= v_old_cursor THEN
        RETURN 0;
    END IF;

    WITH ins AS (
        INSERT INTO malu$event_delivery(subscription_id, event_id, status)
        SELECT p_subscription_id, e.event_id, 'acked'
          FROM malu$event e
         WHERE e.event_id > v_old_cursor
           AND e.event_id <= p_through_event_id
        ON CONFLICT (subscription_id, event_id) DO UPDATE
            SET delivered_at = now(),
                status       = 'acked'
        RETURNING 1
    )
    SELECT count(*)::integer INTO v_n FROM ins;

    UPDATE malu$event_subscription
       SET cursor       = p_through_event_id,
           last_seen_at = now()
     WHERE subscription_id = p_subscription_id;

    RETURN v_n;
END;
$body$;
REVOKE EXECUTE ON FUNCTION event_ack(bigint, bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION event_ack(bigint, bigint) TO
    maludb_memory_admin, maludb_memory_executor;

-- event_list_subscriptions — enumeration for the CLI / metrics.
CREATE FUNCTION event_list_subscriptions(p_include_retired boolean DEFAULT false)
    RETURNS TABLE (
        subscription_id bigint,
        name            text,
        account_id      bigint,
        kinds           text[],
        partitions      text[],
        active_pool_id  bigint,
        cursor          bigint,
        last_seen_at    timestamptz,
        retired_at      timestamptz
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT s.subscription_id, s.name, s.account_id, s.kinds, s.partitions,
           s.active_pool_id, s.cursor, s.last_seen_at, s.retired_at
      FROM malu$event_subscription s
     WHERE (p_include_retired OR s.retired_at IS NULL)
     ORDER BY s.subscription_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION event_list_subscriptions(boolean) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION event_list_subscriptions(boolean) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- =====================================================================
-- V3-REALTIME-01b — retrofit the V3-shipped write paths to emit
-- events alongside their existing audit_event call. Stage 2-7
-- register_* functions remain untouched (Stage 13 follow-up).
-- =====================================================================

CREATE OR REPLACE FUNCTION auth_token_create(
    p_account_id    bigint,
    p_kind          text,
    p_label         text             DEFAULT NULL,
    p_scopes        text[]           DEFAULT ARRAY[]::text[],
    p_allowed_cidrs inet[]           DEFAULT NULL,
    p_expires_at    timestamptz      DEFAULT NULL
) RETURNS TABLE (token_id bigint, plaintext_token text)
    LANGUAGE plpgsql VOLATILE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
DECLARE
    v_caller bigint := current_account_id();
    v_random bytea;
    v_plain  text;
    v_hash   bytea;
    v_id     bigint;
BEGIN
    IF v_caller IS NOT NULL AND v_caller <> p_account_id THEN
        RAISE EXCEPTION 'auth_token_create: caller account % cannot issue tokens for account %',
            v_caller, p_account_id
            USING ERRCODE = 'insufficient_privilege';
    END IF;
    IF p_kind NOT IN ('personal','service') THEN
        RAISE EXCEPTION 'auth_token_create: token_kind must be personal or service'
            USING ERRCODE = 'check_violation';
    END IF;

    v_random := public.gen_random_bytes(32);
    v_plain  := __auth_token_encode(v_random);
    v_hash   := __auth_token_hash(v_plain);

    INSERT INTO malu$auth_token
        (account_id, token_hash, token_kind, label, scopes,
         allowed_cidrs, expires_at)
    VALUES
        (p_account_id, v_hash, p_kind, p_label, p_scopes,
         p_allowed_cidrs, p_expires_at)
    RETURNING malu$auth_token.token_id INTO v_id;

    PERFORM audit_event(
        'auth_token_create',
        'malu$auth_token',
        v_id,
        jsonb_build_object(
            'account_id', p_account_id,
            'token_kind', p_kind,
            'label',      p_label,
            'expires_at', p_expires_at,
            'scopes',     to_jsonb(p_scopes),
            'has_cidr',   p_allowed_cidrs IS NOT NULL),
        NULL);

    PERFORM emit_event(
        'auth_token_create',
        jsonb_build_object('token_id', v_id, 'token_kind', p_kind, 'label', p_label),
        p_account_id, NULL, NULL, 'malu$auth_token', v_id, NULL);

    token_id         := v_id;
    plaintext_token  := v_plain;
    RETURN NEXT;
END;
$body$;

CREATE OR REPLACE FUNCTION queue_enqueue(
    p_queue_name      text,
    p_payload         jsonb,
    p_idempotency_key text        DEFAULT NULL,
    p_priority        integer     DEFAULT 0,
    p_visible_at      timestamptz DEFAULT NULL,
    p_account_id      bigint      DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_queue_id bigint;
    v_existing bigint;
    v_id       bigint;
BEGIN
    SELECT q.queue_id INTO v_queue_id
      FROM malu$queue q
     WHERE q.name = p_queue_name AND q.retired_at IS NULL;
    IF v_queue_id IS NULL THEN
        RAISE EXCEPTION 'queue_enqueue: queue % not found or retired', p_queue_name
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_idempotency_key IS NOT NULL THEN
        SELECT j.job_id INTO v_existing
          FROM malu$queue_job j
         WHERE j.queue_id        = v_queue_id
           AND j.idempotency_key = p_idempotency_key;
        IF v_existing IS NOT NULL THEN
            RETURN v_existing;
        END IF;
    END IF;

    INSERT INTO malu$queue_job
        (queue_id, payload, idempotency_key, priority, visible_at, account_id)
    VALUES
        (v_queue_id, p_payload, p_idempotency_key, p_priority::smallint,
         COALESCE(p_visible_at, now()), p_account_id)
    RETURNING job_id INTO v_id;

    PERFORM audit_event(
        'queue_enqueue', 'malu$queue_job', v_id,
        jsonb_build_object('queue', p_queue_name, 'priority', p_priority,
                           'idempotency_key', p_idempotency_key),
        NULL);

    PERFORM emit_event(
        'queue_enqueue',
        jsonb_build_object('queue', p_queue_name, 'job_id', v_id, 'priority', p_priority),
        p_account_id, NULL, NULL, 'malu$queue_job', v_id, NULL);

    RETURN v_id;
END;
$body$;

CREATE OR REPLACE FUNCTION source_object_register(
    p_adapter_name    text,
    p_adapter_uri     text,
    p_content_hash    bytea,
    p_byte_length     bigint,
    p_media_type      text          DEFAULT NULL,
    p_source_time     timestamptz   DEFAULT NULL,
    p_retention_class text          DEFAULT 'standard',
    p_sensitivity     text          DEFAULT 'internal',
    p_partition       text          DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_adapter_id bigint;
    v_existing   bigint;
    v_id         bigint;
BEGIN
    IF octet_length(p_content_hash) <> 32 THEN
        RAISE EXCEPTION 'source_object_register: content_hash must be 32 bytes (raw SHA-256)'
            USING ERRCODE = 'check_violation';
    END IF;

    SELECT adapter_id INTO v_adapter_id
      FROM malu$storage_adapter
     WHERE name = p_adapter_name AND retired_at IS NULL;
    IF v_adapter_id IS NULL THEN
        RAISE EXCEPTION 'source_object_register: adapter % not found or retired', p_adapter_name
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT object_id INTO v_existing
      FROM malu$source_object
     WHERE content_hash = p_content_hash
       AND retired_at IS NULL;
    IF v_existing IS NOT NULL THEN
        RETURN v_existing;
    END IF;

    INSERT INTO malu$source_object
        (content_hash, byte_length, media_type, source_time,
         retention_class, sensitivity, partition,
         adapter_id, adapter_uri)
    VALUES
        (p_content_hash, p_byte_length, p_media_type, p_source_time,
         p_retention_class, p_sensitivity, p_partition,
         v_adapter_id, p_adapter_uri)
    RETURNING object_id INTO v_id;

    PERFORM audit_event('source_object_register', 'malu$source_object', v_id,
        jsonb_build_object(
            'adapter',         p_adapter_name,
            'adapter_uri',     p_adapter_uri,
            'content_hash',    encode(p_content_hash, 'hex'),
            'byte_length',     p_byte_length,
            'media_type',      p_media_type,
            'retention_class', p_retention_class,
            'sensitivity',     p_sensitivity,
            'partition',       p_partition),
        NULL);

    PERFORM emit_event(
        'source_object_register',
        jsonb_build_object('adapter', p_adapter_name, 'object_id', v_id,
                           'content_hash', encode(p_content_hash, 'hex'),
                           'byte_length', p_byte_length),
        NULL, p_partition, NULL, 'malu$source_object', v_id, NULL);

    RETURN v_id;
END;
$body$;

-- ============================================================
-- Section: maludb_core--0.49.0--0.50.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.50.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.49.0 → 0.50.0
--
-- Stage 13 / V3-PRESENCE-01: active memory pool presence.
--
-- Tracks human / agent / tool participants attached to a malu$active_memory_pool.
-- Presence transitions emit V3-REALTIME-01 events so subscribed
-- clients see joins / updates / leaves in real time.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.50.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.50.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$pool_presence — one row per (pool, participant). UPSERT on
-- (pool_id, participant_kind, participant_ref).
-- ---------------------------------------------------------------------
CREATE TABLE malu$pool_presence (
    presence_id      bigserial PRIMARY KEY,
    pool_id          bigint    NOT NULL REFERENCES malu$active_memory_pool(pool_id) ON DELETE CASCADE,
    participant_kind text      NOT NULL CHECK (participant_kind IN ('human','agent','tool')),
    participant_ref  text      NOT NULL,
    role             text,
    declared_task    text,
    cursor_jsonb     jsonb,
    last_seen_at     timestamptz NOT NULL DEFAULT now(),
    left_at          timestamptz,
    owner_schema     name      NOT NULL DEFAULT current_schema(),
    UNIQUE (pool_id, participant_kind, participant_ref)
);
CREATE INDEX malu$pool_presence_pool_idx
    ON malu$pool_presence(pool_id, last_seen_at DESC) WHERE left_at IS NULL;

-- ---------------------------------------------------------------------
-- malu$pool_presence_event — append-only log of join / update / leave.
-- ---------------------------------------------------------------------
CREATE TABLE malu$pool_presence_event (
    event_id     bigserial PRIMARY KEY,
    presence_id  bigint    NOT NULL REFERENCES malu$pool_presence(presence_id) ON DELETE CASCADE,
    kind         text      NOT NULL CHECK (kind IN ('join','update','leave')),
    event_time   timestamptz NOT NULL DEFAULT now(),
    detail_jsonb jsonb
);
CREATE INDEX malu$pool_presence_event_presence_idx
    ON malu$pool_presence_event(presence_id, event_time DESC);

-- ---------------------------------------------------------------------
-- RLS — owner_schema-bound. Presence-event rows inherit from parent.
-- ---------------------------------------------------------------------
ALTER TABLE malu$pool_presence ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$pool_presence
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$pool_presence_event ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_presence ON malu$pool_presence_event
    USING (
        EXISTS (
            SELECT 1 FROM malu$pool_presence p
            WHERE p.presence_id  = malu$pool_presence_event.presence_id
              AND p.owner_schema = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$pool_presence p
            WHERE p.presence_id  = malu$pool_presence_event.presence_id
              AND p.owner_schema = current_schema()
        )
    );

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$pool_presence, malu$pool_presence_event TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$pool_presence, malu$pool_presence_event TO maludb_memory_executor;
GRANT SELECT                          ON malu$pool_presence, malu$pool_presence_event TO maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$pool_presence_presence_id_seq      TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$pool_presence_event_event_id_seq   TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- Public API
-- =====================================================================

CREATE FUNCTION presence_update(
    p_pool_id          bigint,
    p_participant_kind text,
    p_participant_ref  text,
    p_role             text DEFAULT NULL,
    p_declared_task    text DEFAULT NULL,
    p_cursor_jsonb     jsonb DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_pid    bigint;
    v_kind   text;
    v_was    boolean;
BEGIN
    -- Verify the pool exists and the caller is allowed to see it
    -- (RLS would have hidden it otherwise; this gives a cleaner error).
    PERFORM 1 FROM malu$active_memory_pool WHERE pool_id = p_pool_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'presence_update: pool % not found or not visible to caller', p_pool_id
            USING ERRCODE = 'no_data_found';
    END IF;

    SELECT presence_id, (left_at IS NULL) INTO v_pid, v_was
      FROM malu$pool_presence
     WHERE pool_id          = p_pool_id
       AND participant_kind = p_participant_kind
       AND participant_ref  = p_participant_ref;

    IF v_pid IS NULL THEN
        INSERT INTO malu$pool_presence
            (pool_id, participant_kind, participant_ref, role, declared_task, cursor_jsonb)
        VALUES
            (p_pool_id, p_participant_kind, p_participant_ref, p_role, p_declared_task, p_cursor_jsonb)
        RETURNING presence_id INTO v_pid;
        v_kind := 'join';
    ELSE
        UPDATE malu$pool_presence
           SET role          = COALESCE(p_role,          role),
               declared_task = COALESCE(p_declared_task, declared_task),
               cursor_jsonb  = COALESCE(p_cursor_jsonb,  cursor_jsonb),
               last_seen_at  = now(),
               left_at       = NULL
         WHERE presence_id = v_pid;
        v_kind := CASE WHEN v_was THEN 'update' ELSE 'join' END;
    END IF;

    INSERT INTO malu$pool_presence_event(presence_id, kind, detail_jsonb)
    VALUES (v_pid, v_kind,
            jsonb_build_object('role', p_role, 'declared_task', p_declared_task,
                               'cursor', p_cursor_jsonb));

    PERFORM emit_event(
        'pool_presence_' || v_kind,
        jsonb_build_object('presence_id', v_pid,
                           'pool_id', p_pool_id,
                           'participant_kind', p_participant_kind,
                           'participant_ref',  p_participant_ref,
                           'role',             p_role,
                           'declared_task',    p_declared_task),
        NULL, NULL, p_pool_id, 'malu$pool_presence', v_pid, NULL);

    PERFORM audit_event('pool_presence_' || v_kind, 'malu$pool_presence', v_pid,
        jsonb_build_object('pool_id', p_pool_id,
                           'participant_kind', p_participant_kind,
                           'participant_ref', p_participant_ref),
        NULL);

    RETURN v_pid;
END;
$body$;
REVOKE EXECUTE ON FUNCTION presence_update(bigint, text, text, text, text, jsonb) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION presence_update(bigint, text, text, text, text, jsonb) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION presence_leave(
    p_pool_id          bigint,
    p_participant_kind text,
    p_participant_ref  text,
    p_reason           text DEFAULT NULL
) RETURNS boolean
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_pid bigint;
    v_was boolean;
BEGIN
    SELECT presence_id, (left_at IS NULL) INTO v_pid, v_was
      FROM malu$pool_presence
     WHERE pool_id          = p_pool_id
       AND participant_kind = p_participant_kind
       AND participant_ref  = p_participant_ref;
    IF v_pid IS NULL OR NOT v_was THEN
        RETURN false;
    END IF;
    UPDATE malu$pool_presence SET left_at = now() WHERE presence_id = v_pid;

    INSERT INTO malu$pool_presence_event(presence_id, kind, detail_jsonb)
    VALUES (v_pid, 'leave', jsonb_build_object('reason', p_reason));

    PERFORM emit_event(
        'pool_presence_leave',
        jsonb_build_object('presence_id', v_pid, 'pool_id', p_pool_id,
                           'participant_kind', p_participant_kind,
                           'participant_ref',  p_participant_ref,
                           'reason', p_reason),
        NULL, NULL, p_pool_id, 'malu$pool_presence', v_pid, NULL);

    PERFORM audit_event('pool_presence_leave', 'malu$pool_presence', v_pid,
        jsonb_build_object('pool_id', p_pool_id, 'reason', p_reason), NULL);
    RETURN true;
END;
$body$;
REVOKE EXECUTE ON FUNCTION presence_leave(bigint, text, text, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION presence_leave(bigint, text, text, text) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION presence_list(p_pool_id bigint, p_include_left boolean DEFAULT false)
    RETURNS TABLE (
        presence_id      bigint,
        participant_kind text,
        participant_ref  text,
        role             text,
        declared_task    text,
        last_seen_at     timestamptz,
        left_at          timestamptz
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT p.presence_id, p.participant_kind, p.participant_ref, p.role,
           p.declared_task, p.last_seen_at, p.left_at
      FROM malu$pool_presence p
     WHERE p.pool_id = p_pool_id
       AND (p_include_left OR p.left_at IS NULL)
     ORDER BY p.last_seen_at DESC;
END;
$body$;
REVOKE EXECUTE ON FUNCTION presence_list(bigint, boolean) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION presence_list(bigint, boolean) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.50.0--0.51.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.51.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.50.0 → 0.51.0
--
-- Stage 14 / V3-VEC-01 (catalog): vector index status + metadata filter.
--
-- Adds two surfaces to the existing Stage 1.7 vector substrate:
--
--   1. `metadata jsonb` column on malu$vector_chunk + a
--      `search_memory_filter(...)` helper that combines the auth-aware
--      compartment search with a jsonb-contains filter (`@>`). The
--      filter is applied AFTER the existing three-stage authorization
--      gate inside the retrieval coordinator, never as a substitute.
--
--   2. `malu$vector_index_status` — one row per compartment with an
--      index built (or scheduled). Records kind in {exact, nsw,
--      hnsw_local, hnsw_pgvector}, build_started_at, build_finished_at,
--      delta_count, tombstone_count, last_rebuild_at, recall_sample.
--      `vector_index_status()` returns the matrix for the CLI and
--      Stage 15's V3-OBS-01 metrics scrape.
--
-- The HNSW upgrade decision (multilevel-NSW vs pgvector HNSW) is
-- deferred to a Stage 14 follow-up; the catalog supports either path
-- once the implementation lands.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.51.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.51.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$vector_chunk.metadata — jsonb attached to every chunk so the
-- post-authorization metadata_filter can `@>` against it.
-- ---------------------------------------------------------------------
ALTER TABLE malu$vector_chunk
    ADD COLUMN metadata jsonb NOT NULL DEFAULT '{}'::jsonb;

CREATE INDEX malu$vector_chunk_metadata_gin
    ON malu$vector_chunk USING gin (metadata jsonb_path_ops);

-- ---------------------------------------------------------------------
-- malu$vector_index_status — per-compartment index health.
-- ---------------------------------------------------------------------
CREATE TABLE malu$vector_index_status (
    status_id            bigserial PRIMARY KEY,
    compartment_id       bigint    NOT NULL UNIQUE REFERENCES malu$vector_compartment(compartment_id) ON DELETE CASCADE,
    kind                 text      NOT NULL CHECK (kind IN
                            ('exact','nsw','hnsw_local','hnsw_pgvector')),
    build_started_at     timestamptz,
    build_finished_at    timestamptz,
    last_rebuild_at      timestamptz,
    delta_count          bigint    NOT NULL DEFAULT 0,
    tombstone_count      bigint    NOT NULL DEFAULT 0,
    recall_sample        jsonb,
    owner_schema         name      NOT NULL DEFAULT current_schema(),
    created_at           timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$vector_index_status_kind_idx
    ON malu$vector_index_status(owner_schema, kind);

ALTER TABLE malu$vector_index_status ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$vector_index_status
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$vector_index_status TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$vector_index_status TO maludb_memory_executor;
GRANT SELECT                          ON malu$vector_index_status TO maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$vector_index_status_status_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- vector_index_record — record/refresh a per-compartment status row.
-- Called by ann_build / ann_rebuild and by future HNSW-builders.
-- =====================================================================
CREATE FUNCTION vector_index_record(
    p_compartment_id      bigint,
    p_kind                text,
    p_build_finished      boolean DEFAULT true,
    p_delta_count         bigint  DEFAULT 0,
    p_tombstone_count     bigint  DEFAULT 0,
    p_recall_sample       jsonb   DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    IF p_kind NOT IN ('exact','nsw','hnsw_local','hnsw_pgvector') THEN
        RAISE EXCEPTION 'vector_index_record: kind must be exact/nsw/hnsw_local/hnsw_pgvector'
            USING ERRCODE = 'check_violation';
    END IF;

    INSERT INTO malu$vector_index_status
        (compartment_id, kind, build_started_at, build_finished_at,
         last_rebuild_at, delta_count, tombstone_count, recall_sample)
    VALUES
        (p_compartment_id, p_kind, now(),
         CASE WHEN p_build_finished THEN now() ELSE NULL END,
         CASE WHEN p_build_finished THEN now() ELSE NULL END,
         p_delta_count, p_tombstone_count, p_recall_sample)
    ON CONFLICT (compartment_id) DO UPDATE
        SET kind              = EXCLUDED.kind,
            build_started_at  = COALESCE(EXCLUDED.build_started_at, malu$vector_index_status.build_started_at),
            build_finished_at = CASE WHEN p_build_finished THEN now()
                                     ELSE malu$vector_index_status.build_finished_at END,
            last_rebuild_at   = CASE WHEN p_build_finished THEN now()
                                     ELSE malu$vector_index_status.last_rebuild_at END,
            delta_count       = EXCLUDED.delta_count,
            tombstone_count   = EXCLUDED.tombstone_count,
            recall_sample     = COALESCE(EXCLUDED.recall_sample, malu$vector_index_status.recall_sample)
    RETURNING status_id INTO v_id;

    PERFORM audit_event('vector_index_record', 'malu$vector_index_status', v_id,
        jsonb_build_object('compartment_id', p_compartment_id, 'kind', p_kind,
                           'delta_count', p_delta_count,
                           'tombstone_count', p_tombstone_count,
                           'build_finished', p_build_finished),
        NULL);
    PERFORM emit_event('vector_index_record',
        jsonb_build_object('compartment_id', p_compartment_id, 'kind', p_kind),
        NULL, NULL, NULL, 'malu$vector_index_status', v_id, NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION vector_index_record(bigint, text, boolean, bigint, bigint, jsonb) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION vector_index_record(bigint, text, boolean, bigint, bigint, jsonb) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION vector_index_status()
    RETURNS TABLE (
        compartment_id   bigint,
        namespace        text,
        subject          text,
        verb             text,
        kind             text,
        vector_count     bigint,
        delta_count      bigint,
        tombstone_count  bigint,
        last_rebuild_at  timestamptz,
        rebuild_age_sec  bigint
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT c.compartment_id,
           c.namespace,
           s.subject_name,
           v.verb_name,
           COALESCE(st.kind, c.search_mode),
           c.vector_count,
           COALESCE(st.delta_count, 0),
           COALESCE(st.tombstone_count, 0),
           st.last_rebuild_at,
           CASE WHEN st.last_rebuild_at IS NULL THEN NULL
                ELSE EXTRACT(EPOCH FROM (now() - st.last_rebuild_at))::bigint
           END
      FROM malu$vector_compartment c
      JOIN malu$vector_subject     s ON s.subject_id = c.subject_id
      JOIN malu$vector_verb        v ON v.verb_id    = c.verb_id
      LEFT JOIN malu$vector_index_status st ON st.compartment_id = c.compartment_id
     ORDER BY c.namespace, s.subject_name, v.verb_name;
END;
$body$;
REVOKE EXECUTE ON FUNCTION vector_index_status() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION vector_index_status() TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- =====================================================================
-- search_memory_filter — search_memory_exact + jsonb metadata filter.
-- The filter is `metadata @> p_metadata_filter` so callers can pass
-- partial documents (e.g. {"language":"en","domain":"ops"}).
-- =====================================================================
CREATE FUNCTION search_memory_filter(
    p_namespace        text,
    p_subject          text,
    p_verb             text,
    p_query            malu_vector,
    p_metadata_filter  jsonb,
    p_limit            integer DEFAULT 10,
    p_metric           text    DEFAULT NULL
) RETURNS TABLE (
    chunk_id     bigint,
    source_text  text,
    distance     double precision,
    similarity   double precision,
    rank_no      integer,
    metadata     jsonb
) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    -- Two-stage: pull up to 4x the requested limit from the existing
    -- auth-aware search, then re-rank/filter by metadata containment.
    -- The 4x overfetch is a heuristic; rebuild candidate pruning is a
    -- Stage 14 follow-up if the filter shape proves selective.
    RETURN QUERY
    WITH hits AS (
        SELECT h.chunk_id, h.source_text, h.distance, h.similarity, h.rank_no
          FROM search_memory_exact(p_namespace, p_subject, p_verb,
                                   p_query, p_limit * 4, p_metric) h
    )
    SELECT h.chunk_id, h.source_text, h.distance, h.similarity,
           ROW_NUMBER() OVER (ORDER BY h.distance ASC, h.chunk_id ASC)::integer,
           c.metadata
      FROM hits h
      JOIN malu$vector_chunk c ON c.chunk_id = h.chunk_id
     WHERE p_metadata_filter IS NULL
        OR c.metadata @> p_metadata_filter
     ORDER BY h.distance ASC, h.chunk_id ASC
     LIMIT p_limit;
END;
$body$;
REVOKE EXECUTE ON FUNCTION search_memory_filter(text, text, text, malu_vector, jsonb, integer, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION search_memory_filter(text, text, text, malu_vector, jsonb, integer, text) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.51.0--0.52.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.52.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.51.0 → 0.52.0
--
-- Stage 14 / V3-EMBED-01: embedding job pipeline.
--
-- Wires the V3-QUEUE-01 substrate into a typed embedding workflow:
--   malu$embedding_job     — one row per scheduled embedding. Carries
--                            target_kind (source_excerpt / memory_chunk /
--                            workflow_trace / summary / query_envelope),
--                            target_id, model_alias, embedding_space,
--                            prompt_template_version, input_hash, status.
--   malu$embedding_output  — one row per produced vector. Records the
--                            vector + svpor_frame_text + input/output
--                            hashes + a derivation_ledger entry.
--
-- embedding_enqueue creates a job row and enqueues a payload on the
-- V3-QUEUE-01 'embed' queue (registered on demand). Workers pull jobs,
-- run inference, and call embedding_record_output to persist the
-- vector with a malu$derivation_ledger entry of kind
-- 'memory_detail_object' (the closest existing derived_object_type
-- the ledger accepts; a future ledger migration may add 'embedding'
-- as its own kind).
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.52.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.52.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$embedding_job
-- ---------------------------------------------------------------------
CREATE TABLE malu$embedding_job (
    job_id                   bigserial PRIMARY KEY,
    target_kind              text      NOT NULL CHECK (target_kind IN
                                ('source_excerpt','memory_chunk','workflow_trace',
                                 'summary','query_envelope')),
    target_id                bigint    NOT NULL,
    model_alias              text      NOT NULL,
    embedding_space          text      NOT NULL,
    prompt_template_version  text,
    input_hash               bytea,
    queue_job_id             bigint,
    status                   text      NOT NULL DEFAULT 'pending' CHECK (status IN
                                ('pending','running','completed','failed')),
    enqueued_at              timestamptz NOT NULL DEFAULT now(),
    started_at               timestamptz,
    finished_at              timestamptz,
    last_error               text,
    owner_schema             name      NOT NULL DEFAULT current_schema()
);
CREATE INDEX malu$embedding_job_target_idx
    ON malu$embedding_job(target_kind, target_id, embedding_space);
CREATE INDEX malu$embedding_job_status_idx
    ON malu$embedding_job(status, enqueued_at);

-- ---------------------------------------------------------------------
-- malu$embedding_output
-- ---------------------------------------------------------------------
CREATE TABLE malu$embedding_output (
    output_id            bigserial PRIMARY KEY,
    job_id               bigint    NOT NULL REFERENCES malu$embedding_job(job_id) ON DELETE CASCADE,
    target_kind          text      NOT NULL,
    target_id            bigint    NOT NULL,
    model_alias          text      NOT NULL,
    embedding_space      text      NOT NULL,
    vector_dim           integer   NOT NULL CHECK (vector_dim > 0),
    vector               bytea     NOT NULL,
    svpor_frame_text     text      NOT NULL,
    input_hash           bytea     NOT NULL,
    output_hash          bytea     NOT NULL,
    derivation_id        bigint    REFERENCES malu$derivation_ledger(derivation_id) ON DELETE SET NULL,
    created_at           timestamptz NOT NULL DEFAULT now(),
    owner_schema         name      NOT NULL DEFAULT current_schema(),
    CHECK (octet_length(vector) = vector_dim * 4)
);
CREATE INDEX malu$embedding_output_target_idx
    ON malu$embedding_output(target_kind, target_id, embedding_space);
CREATE INDEX malu$embedding_output_job_idx
    ON malu$embedding_output(job_id);

-- ---------------------------------------------------------------------
-- RLS — owner_schema-bound. Output rows are tenant-bound.
-- ---------------------------------------------------------------------
ALTER TABLE malu$embedding_job    ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$embedding_job
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$embedding_output ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$embedding_output
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$embedding_job, malu$embedding_output TO
    maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$embedding_job, malu$embedding_output TO
    maludb_memory_executor, maludb_queue_worker;
GRANT SELECT                          ON malu$embedding_job, malu$embedding_output TO
    maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$embedding_job_job_id_seq       TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;
GRANT USAGE, SELECT ON SEQUENCE malu$embedding_output_output_id_seq TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- =====================================================================
-- embedding_enqueue — record a malu$embedding_job and push it onto
-- the V3-QUEUE-01 'embed' queue. Registers the queue on first use.
-- =====================================================================
CREATE FUNCTION embedding_enqueue(
    p_target_kind              text,
    p_target_id                bigint,
    p_model_alias              text,
    p_embedding_space          text,
    p_input_hash               bytea   DEFAULT NULL,
    p_prompt_template_version  text    DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_job_id     bigint;
    v_queue_job  bigint;
BEGIN
    IF p_target_kind NOT IN ('source_excerpt','memory_chunk','workflow_trace','summary','query_envelope') THEN
        RAISE EXCEPTION 'embedding_enqueue: target_kind must be one of source_excerpt/memory_chunk/workflow_trace/summary/query_envelope'
            USING ERRCODE = 'check_violation';
    END IF;

    -- Auto-register the embed queue (idempotent).
    PERFORM queue_register('embed', 60000, 3, NULL, 'V3-EMBED-01 embedding job queue');

    INSERT INTO malu$embedding_job
        (target_kind, target_id, model_alias, embedding_space,
         prompt_template_version, input_hash, status)
    VALUES
        (p_target_kind, p_target_id, p_model_alias, p_embedding_space,
         p_prompt_template_version, p_input_hash, 'pending')
    RETURNING job_id INTO v_job_id;

    v_queue_job := queue_enqueue(
        'embed',
        jsonb_build_object(
            'embedding_job_id', v_job_id,
            'target_kind',      p_target_kind,
            'target_id',        p_target_id,
            'model_alias',      p_model_alias,
            'embedding_space',  p_embedding_space,
            'prompt_template_version', p_prompt_template_version),
        format('embed:%s:%s:%s:%s', p_target_kind, p_target_id, p_model_alias, p_embedding_space),
        0, NULL, NULL);

    UPDATE malu$embedding_job
       SET queue_job_id = v_queue_job
     WHERE job_id = v_job_id;

    PERFORM audit_event('embedding_enqueue', 'malu$embedding_job', v_job_id,
        jsonb_build_object('target_kind', p_target_kind, 'target_id', p_target_id,
                           'model_alias', p_model_alias, 'embedding_space', p_embedding_space,
                           'queue_job_id', v_queue_job),
        NULL);

    RETURN v_job_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION embedding_enqueue(text, bigint, text, text, bytea, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION embedding_enqueue(text, bigint, text, text, bytea, text) TO
    maludb_memory_admin, maludb_memory_executor;

-- embedding_record_output — workers call this after running inference.
-- Writes the vector + svpor frame and a malu$derivation_ledger entry.
-- Returns (output_id, derivation_id).
CREATE FUNCTION embedding_record_output(
    p_job_id           bigint,
    p_vector           malu_vector,
    p_vector_dim       integer,
    p_svpor_frame_text text,
    p_output_hash      bytea
) RETURNS TABLE (output_id bigint, derivation_id bigint)
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_job    malu$embedding_job%ROWTYPE;
    v_oid    bigint;
    v_did    bigint;
    v_inputs jsonb;
BEGIN
    SELECT * INTO v_job FROM malu$embedding_job WHERE job_id = p_job_id;
    IF v_job.job_id IS NULL THEN
        RAISE EXCEPTION 'embedding_record_output: job % not found', p_job_id
            USING ERRCODE = 'no_data_found';
    END IF;

    -- SVPOR frame must be present per requirements.md §3.2.
    IF p_svpor_frame_text IS NULL OR length(p_svpor_frame_text) = 0 THEN
        RAISE EXCEPTION 'embedding_record_output: svpor_frame_text is required'
            USING ERRCODE = 'check_violation';
    END IF;

    v_inputs := jsonb_build_array(jsonb_build_object(
        'kind',                    'embedding_input',
        'target_kind',             v_job.target_kind,
        'target_id',               v_job.target_id,
        'model_alias',             v_job.model_alias,
        'embedding_space',         v_job.embedding_space,
        'prompt_template_version', v_job.prompt_template_version,
        'input_hash',              encode(COALESCE(v_job.input_hash, '\x00'::bytea), 'hex'),
        'svpor_frame_hash',        encode(public.digest(p_svpor_frame_text::bytea, 'sha256'), 'hex')));

    -- The Stage 2 ledger CHECK constraint accepts only the seven kinds
    -- {source_package, claim, fact, memory, episode_object,
    --  memory_detail_object, relationship_edge}. We map embedding
    -- artefacts to memory_detail_object — they're addressable derived
    -- detail rows under §3.7. A future ledger migration may add
    -- 'embedding' as its own kind.
    INSERT INTO malu$derivation_ledger
        (derived_object_type, derived_object_id, parser_name,
         model_alias_id, prompt_template_id, inputs_jsonb, inputs_hash)
    VALUES
        ('memory_detail_object', 0, 'embedding_runner',
         (SELECT alias_id FROM malu$model_alias WHERE alias_name = v_job.model_alias),
         NULL, v_inputs,
         encode(public.digest(v_inputs::text::bytea, 'sha256'), 'hex'))
    RETURNING malu$derivation_ledger.derivation_id INTO v_did;

    INSERT INTO malu$embedding_output
        (job_id, target_kind, target_id, model_alias, embedding_space,
         vector_dim, vector, svpor_frame_text,
         input_hash, output_hash, derivation_id)
    VALUES
        (p_job_id, v_job.target_kind, v_job.target_id, v_job.model_alias,
         v_job.embedding_space, p_vector_dim, p_vector, p_svpor_frame_text,
         COALESCE(v_job.input_hash, public.digest(p_svpor_frame_text::bytea, 'sha256')),
         p_output_hash, v_did)
    RETURNING malu$embedding_output.output_id INTO v_oid;

    -- Patch the ledger entry's derived_object_id to point at the
    -- output row (we inserted 0 as a placeholder above because the
    -- output_id was not yet known).
    UPDATE malu$derivation_ledger
       SET derived_object_id = v_oid
     WHERE derivation_id = v_did;

    UPDATE malu$embedding_job
       SET status      = 'completed',
           finished_at = now(),
           last_error  = NULL
     WHERE job_id = p_job_id;

    PERFORM audit_event('embedding_record_output', 'malu$embedding_output', v_oid,
        jsonb_build_object('job_id', p_job_id, 'derivation_id', v_did,
                           'vector_dim', p_vector_dim),
        NULL);

    output_id     := v_oid;
    derivation_id := v_did;
    RETURN NEXT;
END;
$body$;
REVOKE EXECUTE ON FUNCTION embedding_record_output(bigint, malu_vector, integer, text, bytea) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION embedding_record_output(bigint, malu_vector, integer, text, bytea) TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

CREATE FUNCTION embedding_results(
    p_target_kind     text,
    p_target_id       bigint,
    p_embedding_space text DEFAULT NULL
) RETURNS TABLE (
    output_id        bigint,
    model_alias      text,
    embedding_space  text,
    vector_dim       integer,
    derivation_id    bigint,
    created_at       timestamptz
) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT o.output_id, o.model_alias, o.embedding_space, o.vector_dim,
           o.derivation_id, o.created_at
      FROM malu$embedding_output o
     WHERE o.target_kind = p_target_kind
       AND o.target_id   = p_target_id
       AND (p_embedding_space IS NULL OR o.embedding_space = p_embedding_space)
     ORDER BY o.created_at DESC;
END;
$body$;
REVOKE EXECUTE ON FUNCTION embedding_results(text, bigint, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION embedding_results(text, bigint, text) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.52.0--0.53.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.53.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.52.0 → 0.53.0
--
-- Stage 14 / V3-RET-01: public retrieval endpoint + envelope.
--
-- Stage 4 already defined `malu$retrieval_envelope` as a plan record
-- (cue_text, object_types, hints, plan_jsonb, actor_role). This
-- migration EXTENDS that table with the V3 fields the public retrieval
-- endpoint needs — account_id, partitions, temporal_mode, started_at,
-- finished_at, candidate_counts, final_count, authz_decisions — and
-- adds malu$retrieval_decision_audit for per-stage authz breadcrumbs.
--
-- retrieve_with_envelope wraps the existing execute_retrieval, records
-- the envelope, and emits planning/assembly decision rows.
-- retrieve_envelope_debug exposes the per-stage breakdown to
-- maludb_memory_auditor members only.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.53.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.53.0'::text $body$;

-- ---------------------------------------------------------------------
-- Extend malu$retrieval_envelope (Stage 4) with V3 fields.
-- ---------------------------------------------------------------------
ALTER TABLE malu$retrieval_envelope
    ADD COLUMN account_id        bigint,
    ADD COLUMN partitions        text[]      NOT NULL DEFAULT ARRAY[]::text[],
    ADD COLUMN temporal_mode     text        NOT NULL DEFAULT 'current_valid'
        CHECK (temporal_mode IN
            ('current_valid','historical_valid','as_of_transaction_time','full_bitemporal')),
    ADD COLUMN started_at        timestamptz,
    ADD COLUMN finished_at       timestamptz,
    ADD COLUMN candidate_counts  jsonb,
    ADD COLUMN final_count       integer,
    ADD COLUMN authz_decisions   jsonb;

CREATE INDEX malu$retrieval_envelope_account_idx
    ON malu$retrieval_envelope(account_id, created_at DESC) WHERE account_id IS NOT NULL;
CREATE INDEX malu$retrieval_envelope_partitions_gin
    ON malu$retrieval_envelope USING gin (partitions)
    WHERE partitions IS NOT NULL AND cardinality(partitions) > 0;

-- ---------------------------------------------------------------------
-- malu$retrieval_decision_audit
-- ---------------------------------------------------------------------
CREATE TABLE malu$retrieval_decision_audit (
    decision_id    bigserial PRIMARY KEY,
    envelope_id    bigint    NOT NULL REFERENCES malu$retrieval_envelope(envelope_id) ON DELETE CASCADE,
    stage          text      NOT NULL CHECK (stage IN ('planning','expansion','assembly')),
    allowed        boolean   NOT NULL,
    reason         text,
    object_type    text,
    object_id      bigint,
    decided_at     timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$retrieval_decision_audit_envelope_idx
    ON malu$retrieval_decision_audit(envelope_id, decided_at);

ALTER TABLE malu$retrieval_decision_audit ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_envelope ON malu$retrieval_decision_audit
    USING (
        EXISTS (
            SELECT 1 FROM malu$retrieval_envelope e
            WHERE e.envelope_id  = malu$retrieval_decision_audit.envelope_id
              AND e.owner_schema = current_schema()
        )
    )
    WITH CHECK (
        EXISTS (
            SELECT 1 FROM malu$retrieval_envelope e
            WHERE e.envelope_id  = malu$retrieval_decision_audit.envelope_id
              AND e.owner_schema = current_schema()
        )
    );

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$retrieval_decision_audit TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$retrieval_decision_audit TO maludb_memory_executor;
GRANT SELECT                          ON malu$retrieval_decision_audit TO maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$retrieval_decision_audit_decision_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- retrieve_with_envelope — wraps execute_retrieval; records envelope.
-- =====================================================================
CREATE FUNCTION retrieve_with_envelope(
    p_cue_text          text,
    p_object_types      text[]      DEFAULT NULL,
    p_valid_as_of       timestamptz DEFAULT NULL,
    p_transaction_as_of timestamptz DEFAULT NULL,
    p_confidence_floor  numeric     DEFAULT NULL,
    p_hints             jsonb       DEFAULT '{}'::jsonb,
    p_partitions        text[]      DEFAULT ARRAY[]::text[],
    p_hint_name         text        DEFAULT NULL,
    p_limit             integer     DEFAULT 20,
    p_temporal_mode     text        DEFAULT 'current_valid'
) RETURNS SETOF malu$retrieval_hit
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_envelope_id  bigint;
    v_envelope     malu$retrieval_envelope_t;
    v_started      timestamptz := now();
    v_count        integer;
BEGIN
    INSERT INTO malu$retrieval_envelope
        (account_id, cue_text, hints, partitions, temporal_mode,
         object_types, valid_as_of, transaction_as_of, confidence_floor,
         started_at)
    VALUES
        (current_account_id(), p_cue_text,
         COALESCE(p_hints, '{}'::jsonb),
         COALESCE(p_partitions, ARRAY[]::text[]),
         p_temporal_mode,
         COALESCE(p_object_types, ARRAY['claim','fact','memory','episode_object']),
         p_valid_as_of, p_transaction_as_of, p_confidence_floor,
         v_started)
    RETURNING envelope_id INTO v_envelope_id;

    INSERT INTO malu$retrieval_decision_audit
        (envelope_id, stage, allowed, reason)
    VALUES
        (v_envelope_id, 'planning', true,
         CASE WHEN p_hint_name IS NULL THEN 'no_hint'
              ELSE 'hint:'||p_hint_name END);

    v_envelope := ROW(p_cue_text, p_object_types,
                      p_valid_as_of, p_transaction_as_of,
                      p_confidence_floor, p_hints)::malu$retrieval_envelope_t;

    CREATE TEMP TABLE _retrieval_tmp ON COMMIT DROP AS
        SELECT row_number() OVER ()::int AS rn, h.*
          FROM execute_retrieval(v_envelope, p_hint_name, p_limit) h;

    SELECT count(*)::integer INTO v_count FROM _retrieval_tmp;

    INSERT INTO malu$retrieval_decision_audit
        (envelope_id, stage, allowed, reason, object_type, object_id)
    SELECT v_envelope_id, 'assembly', true, 'object included',
           t.object_type, t.object_id
      FROM _retrieval_tmp t;

    UPDATE malu$retrieval_envelope
       SET finished_at      = now(),
           final_count      = v_count,
           candidate_counts = jsonb_build_object('final_count', v_count, 'limit', p_limit),
           authz_decisions  = jsonb_build_object('stages',
                                jsonb_build_array(
                                    jsonb_build_object('stage','planning',  'allowed', true),
                                    jsonb_build_object('stage','expansion', 'allowed', true),
                                    jsonb_build_object('stage','assembly',  'allowed', true)))
     WHERE envelope_id = v_envelope_id;

    PERFORM audit_event('retrieve_with_envelope', 'malu$retrieval_envelope', v_envelope_id,
        jsonb_build_object('cue_text', p_cue_text, 'limit', p_limit,
                           'temporal_mode', p_temporal_mode,
                           'final_count', v_count),
        NULL);

    RETURN QUERY
    SELECT object_type, object_id, title, snippet, rank, strategy, metadata
      FROM _retrieval_tmp ORDER BY rn;

    DROP TABLE _retrieval_tmp;
END;
$body$;
REVOKE EXECUTE ON FUNCTION retrieve_with_envelope(text, text[], timestamptz, timestamptz, numeric, jsonb, text[], text, integer, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION retrieve_with_envelope(text, text[], timestamptz, timestamptz, numeric, jsonb, text[], text, integer, text) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION retrieve_envelope_debug(p_envelope_id bigint)
    RETURNS TABLE (
        envelope_id      bigint,
        cue_text         text,
        partitions       text[],
        temporal_mode    text,
        started_at       timestamptz,
        finished_at      timestamptz,
        final_count      integer,
        candidate_counts jsonb,
        authz_decisions  jsonb,
        per_stage        jsonb
    ) LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
BEGIN
    IF NOT pg_has_role(session_user, 'maludb_memory_auditor', 'MEMBER') THEN
        RAISE EXCEPTION 'retrieve_envelope_debug: requires maludb_memory_auditor membership'
            USING ERRCODE = 'insufficient_privilege';
    END IF;

    RETURN QUERY
    SELECT e.envelope_id, e.cue_text, e.partitions, e.temporal_mode,
           e.started_at, e.finished_at, e.final_count,
           e.candidate_counts, e.authz_decisions,
           COALESCE((
                SELECT jsonb_agg(jsonb_build_object(
                            'stage', d.stage,
                            'allowed', d.allowed,
                            'reason', d.reason,
                            'object_type', d.object_type,
                            'object_id', d.object_id))
                  FROM malu$retrieval_decision_audit d
                 WHERE d.envelope_id = e.envelope_id),
                '[]'::jsonb)
      FROM malu$retrieval_envelope e
     WHERE e.envelope_id = p_envelope_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION retrieve_envelope_debug(bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION retrieve_envelope_debug(bigint) TO
    maludb_memory_admin, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.53.0--0.54.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.54.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.53.0 → 0.54.0
--
-- Stage 15 / V3-OBS-01: metric definitions + scrape function.
--
-- The CLI's `maludb metrics scrape` has shipped a Prometheus-flavoured
-- preview since Stage 10. This migration promotes that surface to a
-- server-side concern:
--
--   malu$metric_definition  — one row per metric the project exposes,
--                              with kind, help text, and label set.
--                              Seeded with the families enumerated in
--                              version3-plan.md V3-OBS-01.
--   metrics_prometheus_scrape() — returns a single text blob in
--                              prom exposition format, assembled from
--                              live counters across audit / queue /
--                              REST / MC2DB / auth / secret / vector /
--                              event / source / schedule tables.
--                              The REST gateway (V3-API-01) wires
--                              GET /metrics to this function.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.54.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.54.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$metric_definition
-- ---------------------------------------------------------------------
CREATE TABLE malu$metric_definition (
    metric_id    bigserial PRIMARY KEY,
    name         text       NOT NULL UNIQUE,
    kind         text       NOT NULL CHECK (kind IN ('counter','gauge','histogram')),
    help_text    text       NOT NULL,
    labels       text[]     NOT NULL DEFAULT ARRAY[]::text[],
    created_at   timestamptz NOT NULL DEFAULT now(),
    retired_at   timestamptz
);

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$metric_definition TO maludb_memory_admin;
GRANT SELECT                          ON malu$metric_definition TO maludb_memory_executor, maludb_memory_auditor, maludb_rest_dispatcher;
GRANT USAGE, SELECT ON SEQUENCE malu$metric_definition_metric_id_seq TO maludb_memory_admin;

-- Seed the V3-OBS-01 metric families. INSERT IF NOT EXISTS so re-runs
-- of the migration on an installed cluster don't error (would never
-- happen for a single migration step, but defensive).
INSERT INTO malu$metric_definition(name, kind, help_text, labels) VALUES
    ('maludb_extension_version',                 'gauge',   'Always 1; the version is a label.',                        ARRAY['version']),
    ('maludb_catalog_tables',                    'gauge',   'Count of malu$ tables in the maludb_core schema.',         ARRAY[]::text[]),
    ('maludb_audit_event_total',                 'counter', 'Total audit events recorded.',                             ARRAY[]::text[]),
    ('maludb_audit_event_by_kind_total',         'counter', 'Audit events recorded, labeled by event_kind.',            ARRAY['event_kind']),
    ('maludb_mc2db_invocation_total',            'counter', 'MC2DB tool invocations.',                                  ARRAY[]::text[]),
    ('maludb_mc2db_invocation_outcome_total',    'counter', 'MC2DB invocations by outcome.',                            ARRAY['outcome']),
    ('maludb_rest_invocation_total',             'counter', 'REST gateway invocations.',                                ARRAY[]::text[]),
    ('maludb_rest_invocation_outcome_total',     'counter', 'REST invocations by outcome.',                             ARRAY['outcome']),
    ('maludb_auth_token_total',                  'gauge',   'API tokens by state.',                                     ARRAY['state']),
    ('maludb_secret_total',                      'gauge',   'Secrets by state.',                                        ARRAY['state']),
    ('maludb_queue_depth',                       'gauge',   'Queue depth by queue name and status.',                    ARRAY['queue','status']),
    ('maludb_cron_schedule_total',               'gauge',   'Schedules by enabled state.',                              ARRAY['enabled']),
    ('maludb_source_object_total',               'gauge',   'Source archive objects by retention class.',               ARRAY['retention_class']),
    ('maludb_event_total',                       'counter', 'Realtime event rows.',                                     ARRAY[]::text[]),
    ('maludb_event_subscription_total',          'gauge',   'Active event subscriptions.',                              ARRAY[]::text[]),
    ('maludb_vector_compartment_total',          'gauge',   'Vector compartments by search mode.',                      ARRAY['search_mode']),
    ('maludb_embedding_job_total',               'gauge',   'Embedding jobs by status.',                                ARRAY['status'])
ON CONFLICT (name) DO NOTHING;

-- =====================================================================
-- metrics_prometheus_scrape — returns the full exposition text.
-- =====================================================================
CREATE FUNCTION metrics_prometheus_scrape()
    RETURNS text
    LANGUAGE plpgsql STABLE
    AS $body$
#variable_conflict use_column
DECLARE
    v_buf text := '';
    r record;
    v_ext_version text;
BEGIN
    SELECT maludb_core_version() INTO v_ext_version;

    -- HELP/TYPE block per metric.
    FOR r IN SELECT name, kind, help_text FROM malu$metric_definition WHERE retired_at IS NULL ORDER BY name LOOP
        v_buf := v_buf || format('# HELP %s %s%s# TYPE %s %s%s',
                                 r.name, r.help_text, E'\n',
                                 r.name, r.kind, E'\n');
    END LOOP;

    v_buf := v_buf || format('maludb_extension_version{version="%s"} 1%s', v_ext_version, E'\n');

    -- catalog_tables
    v_buf := v_buf || format('maludb_catalog_tables %s%s',
        (SELECT count(*) FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
         WHERE n.nspname = 'maludb_core' AND c.relkind = 'r' AND c.relname LIKE 'malu$%'),
        E'\n');

    v_buf := v_buf || format('maludb_audit_event_total %s%s',
        (SELECT count(*) FROM malu$audit_event), E'\n');

    FOR r IN SELECT event_kind, count(*) AS n FROM malu$audit_event GROUP BY event_kind ORDER BY event_kind LOOP
        v_buf := v_buf || format('maludb_audit_event_by_kind_total{event_kind="%s"} %s%s',
                                 r.event_kind, r.n, E'\n');
    END LOOP;

    v_buf := v_buf || format('maludb_mc2db_invocation_total %s%s',
        (SELECT count(*) FROM malu$mc2db_invocation), E'\n');
    FOR r IN SELECT CASE WHEN success THEN 'success' ELSE 'failure' END AS outcome,
                    count(*) AS n
               FROM malu$mc2db_invocation GROUP BY 1 LOOP
        v_buf := v_buf || format('maludb_mc2db_invocation_outcome_total{outcome="%s"} %s%s',
                                 r.outcome, r.n, E'\n');
    END LOOP;

    v_buf := v_buf || format('maludb_rest_invocation_total %s%s',
        (SELECT count(*) FROM malu$rest_invocation), E'\n');
    FOR r IN SELECT CASE WHEN success THEN 'success' ELSE 'failure' END AS outcome,
                    count(*) AS n
               FROM malu$rest_invocation GROUP BY 1 LOOP
        v_buf := v_buf || format('maludb_rest_invocation_outcome_total{outcome="%s"} %s%s',
                                 r.outcome, r.n, E'\n');
    END LOOP;

    FOR r IN
        SELECT CASE WHEN revoked_at IS NULL AND (expires_at IS NULL OR expires_at > now())
                    THEN 'active' ELSE 'revoked' END AS state,
               count(*) AS n
          FROM malu$auth_token GROUP BY 1
    LOOP
        v_buf := v_buf || format('maludb_auth_token_total{state="%s"} %s%s',
                                 r.state, r.n, E'\n');
    END LOOP;

    FOR r IN
        SELECT CASE WHEN retired_at IS NULL THEN 'active' ELSE 'retired' END AS state,
               count(*) AS n
          FROM malu$secret GROUP BY 1
    LOOP
        v_buf := v_buf || format('maludb_secret_total{state="%s"} %s%s',
                                 r.state, r.n, E'\n');
    END LOOP;

    FOR r IN
        SELECT q.name AS queue, j.status, count(*) AS n
          FROM malu$queue q
          JOIN malu$queue_job j ON j.queue_id = q.queue_id
         WHERE q.retired_at IS NULL
         GROUP BY q.name, j.status
    LOOP
        v_buf := v_buf || format('maludb_queue_depth{queue="%s",status="%s"} %s%s',
                                 r.queue, r.status, r.n, E'\n');
    END LOOP;

    FOR r IN
        SELECT CASE WHEN enabled THEN 'true' ELSE 'false' END AS enabled, count(*) AS n
          FROM malu$schedule WHERE retired_at IS NULL GROUP BY enabled
    LOOP
        v_buf := v_buf || format('maludb_cron_schedule_total{enabled="%s"} %s%s',
                                 r.enabled, r.n, E'\n');
    END LOOP;

    FOR r IN
        SELECT retention_class, count(*) AS n
          FROM malu$source_object WHERE retired_at IS NULL GROUP BY retention_class
    LOOP
        v_buf := v_buf || format('maludb_source_object_total{retention_class="%s"} %s%s',
                                 r.retention_class, r.n, E'\n');
    END LOOP;

    v_buf := v_buf || format('maludb_event_total %s%s',
        (SELECT count(*) FROM malu$event), E'\n');
    v_buf := v_buf || format('maludb_event_subscription_total %s%s',
        (SELECT count(*) FROM malu$event_subscription WHERE retired_at IS NULL), E'\n');

    FOR r IN
        SELECT search_mode, count(*) AS n FROM malu$vector_compartment GROUP BY search_mode
    LOOP
        v_buf := v_buf || format('maludb_vector_compartment_total{search_mode="%s"} %s%s',
                                 r.search_mode, r.n, E'\n');
    END LOOP;

    FOR r IN
        SELECT status, count(*) AS n FROM malu$embedding_job GROUP BY status
    LOOP
        v_buf := v_buf || format('maludb_embedding_job_total{status="%s"} %s%s',
                                 r.status, r.n, E'\n');
    END LOOP;

    RETURN v_buf;
END;
$body$;
REVOKE EXECUTE ON FUNCTION metrics_prometheus_scrape() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION metrics_prometheus_scrape() TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor,
    maludb_rest_dispatcher;

-- ============================================================
-- Section: maludb_core--0.54.0--0.55.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.55.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.54.0 → 0.55.0
--
-- Stage 15 / V3-LOG-01: log drain catalog.
--
-- Records the destination configurations for the future log-drain
-- service that tails PostgreSQL / audit / model / MC2DB / REST /
-- broker logs and batches them to HTTP, file, S3-compatible, or
-- OTLP-HTTP destinations. Destination credentials are referenced by
-- malu$secret name; the catalog never stores plaintext.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.55.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.55.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$log_drain
-- ---------------------------------------------------------------------
CREATE TABLE malu$log_drain (
    drain_id          bigserial PRIMARY KEY,
    name              text       NOT NULL,
    kind              text       NOT NULL CHECK (kind IN ('http','file','s3','otlp_http')),
    destination       jsonb      NOT NULL,
    destination_secret_ref text,
    source_streams    text[]     NOT NULL DEFAULT ARRAY[]::text[],
    -- source_streams entries: 'pg_log','audit_event','mc2db_invocation',
    -- 'rest_invocation','model_gateway','broker','secret_use'.
    redaction_rules   jsonb      NOT NULL DEFAULT '[]'::jsonb,
    enabled           boolean    NOT NULL DEFAULT true,
    batch_size        integer    NOT NULL DEFAULT 100 CHECK (batch_size > 0),
    flush_interval_ms integer    NOT NULL DEFAULT 5000 CHECK (flush_interval_ms > 0),
    owner_schema      name       NOT NULL DEFAULT current_schema(),
    created_at        timestamptz NOT NULL DEFAULT now(),
    retired_at        timestamptz,
    UNIQUE (owner_schema, name)
);
CREATE INDEX malu$log_drain_owner_idx
    ON malu$log_drain(owner_schema, enabled) WHERE retired_at IS NULL;

-- ---------------------------------------------------------------------
-- malu$log_drain_run — append-only run history.
-- ---------------------------------------------------------------------
CREATE TABLE malu$log_drain_run (
    run_id      bigserial PRIMARY KEY,
    drain_id    bigint     NOT NULL REFERENCES malu$log_drain(drain_id) ON DELETE CASCADE,
    started_at  timestamptz NOT NULL DEFAULT now(),
    finished_at timestamptz,
    batches     integer    NOT NULL DEFAULT 0,
    bytes       bigint     NOT NULL DEFAULT 0,
    records     integer    NOT NULL DEFAULT 0,
    errors      integer    NOT NULL DEFAULT 0,
    last_error  text
);
CREATE INDEX malu$log_drain_run_drain_idx
    ON malu$log_drain_run(drain_id, started_at DESC);

-- ---------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------
ALTER TABLE malu$log_drain ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$log_drain
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$log_drain_run ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_drain ON malu$log_drain_run
    USING (
        EXISTS (SELECT 1 FROM malu$log_drain d
                WHERE d.drain_id = malu$log_drain_run.drain_id
                  AND d.owner_schema = current_schema()))
    WITH CHECK (
        EXISTS (SELECT 1 FROM malu$log_drain d
                WHERE d.drain_id = malu$log_drain_run.drain_id
                  AND d.owner_schema = current_schema()));

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$log_drain, malu$log_drain_run TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$log_drain, malu$log_drain_run TO maludb_memory_executor;
GRANT SELECT                          ON malu$log_drain, malu$log_drain_run TO maludb_memory_auditor;
GRANT USAGE, SELECT ON SEQUENCE malu$log_drain_drain_id_seq          TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$log_drain_run_run_id_seq        TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- log_drain_set — UPSERT a drain.
-- =====================================================================
CREATE FUNCTION log_drain_set(
    p_name              text,
    p_kind              text,
    p_destination       jsonb,
    p_source_streams    text[],
    p_destination_secret_ref text DEFAULT NULL,
    p_redaction_rules   jsonb   DEFAULT '[]'::jsonb,
    p_batch_size        integer DEFAULT 100,
    p_flush_interval_ms integer DEFAULT 5000
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    IF p_kind NOT IN ('http','file','s3','otlp_http') THEN
        RAISE EXCEPTION 'log_drain_set: kind must be http/file/s3/otlp_http'
            USING ERRCODE = 'check_violation';
    END IF;
    IF cardinality(p_source_streams) = 0 THEN
        RAISE EXCEPTION 'log_drain_set: at least one source_stream required'
            USING ERRCODE = 'check_violation';
    END IF;

    INSERT INTO malu$log_drain
        (name, kind, destination, source_streams,
         destination_secret_ref, redaction_rules,
         batch_size, flush_interval_ms)
    VALUES
        (p_name, p_kind, p_destination, p_source_streams,
         p_destination_secret_ref, p_redaction_rules,
         p_batch_size, p_flush_interval_ms)
    ON CONFLICT (owner_schema, name) DO UPDATE
        SET kind                    = EXCLUDED.kind,
            destination             = EXCLUDED.destination,
            source_streams          = EXCLUDED.source_streams,
            destination_secret_ref  = EXCLUDED.destination_secret_ref,
            redaction_rules         = EXCLUDED.redaction_rules,
            batch_size              = EXCLUDED.batch_size,
            flush_interval_ms       = EXCLUDED.flush_interval_ms,
            retired_at              = NULL
    RETURNING drain_id INTO v_id;

    PERFORM audit_event('log_drain_set', 'malu$log_drain', v_id,
        jsonb_build_object('name', p_name, 'kind', p_kind,
                           'source_streams', to_jsonb(p_source_streams),
                           'has_secret_ref', p_destination_secret_ref IS NOT NULL),
        NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION log_drain_set(text, text, jsonb, text[], text, jsonb, integer, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION log_drain_set(text, text, jsonb, text[], text, jsonb, integer, integer) TO
    maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION log_drain_enable(p_name text)  RETURNS boolean
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE v_id bigint; v_was boolean;
BEGIN
    SELECT drain_id, enabled INTO v_id, v_was FROM malu$log_drain WHERE name = p_name;
    IF v_id IS NULL THEN RAISE EXCEPTION 'log_drain_enable: % not found', p_name USING ERRCODE='no_data_found'; END IF;
    UPDATE malu$log_drain SET enabled = true, retired_at = NULL WHERE drain_id = v_id;
    PERFORM audit_event('log_drain_enable', 'malu$log_drain', v_id,
        jsonb_build_object('was_enabled', v_was), NULL);
    RETURN NOT v_was;
END;
$body$;

CREATE FUNCTION log_drain_disable(p_name text, p_reason text DEFAULT NULL)  RETURNS boolean
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE v_id bigint; v_was boolean;
BEGIN
    SELECT drain_id, enabled INTO v_id, v_was FROM malu$log_drain WHERE name = p_name;
    IF v_id IS NULL THEN RAISE EXCEPTION 'log_drain_disable: % not found', p_name USING ERRCODE='no_data_found'; END IF;
    UPDATE malu$log_drain SET enabled = false WHERE drain_id = v_id;
    PERFORM audit_event('log_drain_disable', 'malu$log_drain', v_id,
        jsonb_build_object('was_enabled', v_was, 'reason', p_reason), NULL);
    RETURN v_was;
END;
$body$;

CREATE FUNCTION log_drain_list(p_include_disabled boolean DEFAULT false)
RETURNS TABLE (drain_id bigint, name text, kind text, source_streams text[], enabled boolean, retired_at timestamptz)
LANGUAGE plpgsql STABLE AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT d.drain_id, d.name, d.kind, d.source_streams, d.enabled, d.retired_at
      FROM malu$log_drain d
     WHERE (p_include_disabled OR (d.enabled AND d.retired_at IS NULL))
     ORDER BY d.name;
END;
$body$;

CREATE FUNCTION log_drain_record_run(
    p_drain_id  bigint,
    p_batches   integer,
    p_bytes     bigint,
    p_records   integer,
    p_errors    integer DEFAULT 0,
    p_last_error text   DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$log_drain_run(drain_id, finished_at, batches, bytes, records, errors, last_error)
    VALUES (p_drain_id, now(), p_batches, p_bytes, p_records, p_errors, p_last_error)
    RETURNING run_id INTO v_id;
    RETURN v_id;
END;
$body$;

REVOKE EXECUTE ON FUNCTION log_drain_enable(text) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION log_drain_disable(text, text) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION log_drain_list(boolean) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION log_drain_record_run(bigint, integer, bigint, integer, integer, text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION log_drain_enable(text)                                                TO maludb_memory_admin, maludb_memory_executor;
GRANT  EXECUTE ON FUNCTION log_drain_disable(text, text)                                         TO maludb_memory_admin, maludb_memory_executor;
GRANT  EXECUTE ON FUNCTION log_drain_list(boolean)                                               TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT  EXECUTE ON FUNCTION log_drain_record_run(bigint, integer, bigint, integer, integer, text) TO maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.55.0--0.56.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.56.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.55.0 → 0.56.0
--
-- Stage 15 / V3-BACKUP-01: backup manifest + verification catalog.
--
-- The CLI's `maludb db backup` has emitted a sidecar manifest.json
-- since Stage 10. This migration adds the durable catalog so that
-- multiple manifests across a host's history are queryable, can
-- carry verification status, and can feed observability.
--
-- malu$backup_manifest enumerates every artifact that a full
-- maludb backup must capture:
--   * postgres_state_uri    (pg_dump | pg_basebackup)
--   * wal_archive_uri       (WAL archive base path)
--   * etc_maludb_uri        (/etc/maludb config tree)
--   * source_archive_manifest_uri (per V3-STOR-01)
--   * model_configs_uri     (provider/alias catalogs export)
--   * tls_uri               (TLS material)
--   * tool_binaries_uri     (external_exec helpers)
--   * broker_configs_uri    (mcp-broker config tree)
--
-- malu$backup_verification records the result of a restore-check.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.56.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.56.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$backup_manifest
-- ---------------------------------------------------------------------
CREATE TABLE malu$backup_manifest (
    manifest_id              bigserial PRIMARY KEY,
    label                    text,
    postgres_state_kind      text       NOT NULL CHECK (postgres_state_kind IN ('dump','basebackup')),
    postgres_state_uri       text       NOT NULL,
    wal_archive_uri          text,
    etc_maludb_uri           text,
    source_archive_manifest_uri text,
    model_configs_uri        text,
    tls_uri                  text,
    tool_binaries_uri        text,
    broker_configs_uri       text,
    extension_version        text       NOT NULL,
    hash_summary             jsonb      NOT NULL DEFAULT '{}'::jsonb,
    owner_schema             name       NOT NULL DEFAULT current_schema(),
    created_at               timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$backup_manifest_owner_idx
    ON malu$backup_manifest(owner_schema, created_at DESC);

-- ---------------------------------------------------------------------
-- malu$backup_verification
-- ---------------------------------------------------------------------
CREATE TABLE malu$backup_verification (
    verification_id bigserial PRIMARY KEY,
    manifest_id     bigint     NOT NULL REFERENCES malu$backup_manifest(manifest_id) ON DELETE CASCADE,
    started_at      timestamptz NOT NULL DEFAULT now(),
    finished_at     timestamptz,
    status          text       NOT NULL CHECK (status IN ('running','passed','failed')) DEFAULT 'running',
    errors_jsonb    jsonb,
    notes           text
);
CREATE INDEX malu$backup_verification_manifest_idx
    ON malu$backup_verification(manifest_id, started_at DESC);

ALTER TABLE malu$backup_manifest ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$backup_manifest
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$backup_verification ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_manifest ON malu$backup_verification
    USING (
        EXISTS (SELECT 1 FROM malu$backup_manifest m
                WHERE m.manifest_id = malu$backup_verification.manifest_id
                  AND m.owner_schema = current_schema()))
    WITH CHECK (
        EXISTS (SELECT 1 FROM malu$backup_manifest m
                WHERE m.manifest_id = malu$backup_verification.manifest_id
                  AND m.owner_schema = current_schema()));

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$backup_manifest, malu$backup_verification TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$backup_manifest, malu$backup_verification TO maludb_memory_executor;
GRANT SELECT                          ON malu$backup_manifest, malu$backup_verification TO maludb_memory_auditor;

GRANT USAGE, SELECT ON SEQUENCE malu$backup_manifest_manifest_id_seq         TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$backup_verification_verification_id_seq TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- backup_manifest_record — records a manifest. The CLI/operator
-- prepares URIs + hashes; PG stores the catalog.
-- =====================================================================
CREATE FUNCTION backup_manifest_record(
    p_label                  text,
    p_postgres_state_kind    text,
    p_postgres_state_uri     text,
    p_hash_summary           jsonb,
    p_wal_archive_uri        text DEFAULT NULL,
    p_etc_maludb_uri         text DEFAULT NULL,
    p_source_archive_manifest_uri text DEFAULT NULL,
    p_model_configs_uri      text DEFAULT NULL,
    p_tls_uri                text DEFAULT NULL,
    p_tool_binaries_uri      text DEFAULT NULL,
    p_broker_configs_uri     text DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$backup_manifest
        (label, postgres_state_kind, postgres_state_uri, hash_summary,
         wal_archive_uri, etc_maludb_uri, source_archive_manifest_uri,
         model_configs_uri, tls_uri, tool_binaries_uri, broker_configs_uri,
         extension_version)
    VALUES
        (p_label, p_postgres_state_kind, p_postgres_state_uri, p_hash_summary,
         p_wal_archive_uri, p_etc_maludb_uri, p_source_archive_manifest_uri,
         p_model_configs_uri, p_tls_uri, p_tool_binaries_uri, p_broker_configs_uri,
         maludb_core_version())
    RETURNING manifest_id INTO v_id;

    PERFORM audit_event('backup_manifest_record', 'malu$backup_manifest', v_id,
        jsonb_build_object('label', p_label, 'kind', p_postgres_state_kind,
                           'extension_version', maludb_core_version()),
        NULL);
    RETURN v_id;
END;
$body$;

CREATE FUNCTION backup_verification_record(
    p_manifest_id bigint,
    p_status      text,
    p_errors      jsonb DEFAULT NULL,
    p_notes       text  DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$backup_verification
        (manifest_id, finished_at, status, errors_jsonb, notes)
    VALUES
        (p_manifest_id, now(), p_status, p_errors, p_notes)
    RETURNING verification_id INTO v_id;
    PERFORM audit_event('backup_verification_record', 'malu$backup_verification', v_id,
        jsonb_build_object('manifest_id', p_manifest_id, 'status', p_status),
        NULL);
    RETURN v_id;
END;
$body$;

CREATE FUNCTION backup_manifest_latest()
    RETURNS TABLE (
        manifest_id          bigint,
        label                text,
        postgres_state_kind  text,
        postgres_state_uri   text,
        extension_version    text,
        created_at           timestamptz,
        last_verification    text,
        last_verification_at timestamptz
    ) LANGUAGE plpgsql STABLE AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT m.manifest_id, m.label, m.postgres_state_kind, m.postgres_state_uri,
           m.extension_version, m.created_at,
           v.status, v.finished_at
      FROM malu$backup_manifest m
      LEFT JOIN LATERAL (
            SELECT status, finished_at FROM malu$backup_verification vv
             WHERE vv.manifest_id = m.manifest_id
             ORDER BY vv.started_at DESC LIMIT 1
      ) v ON true
     ORDER BY m.created_at DESC
     LIMIT 1;
END;
$body$;

REVOKE EXECUTE ON FUNCTION backup_manifest_record(text, text, text, jsonb, text, text, text, text, text, text, text) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION backup_verification_record(bigint, text, jsonb, text) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION backup_manifest_latest() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION backup_manifest_record(text, text, text, jsonb, text, text, text, text, text, text, text) TO maludb_memory_admin, maludb_memory_executor;
GRANT  EXECUTE ON FUNCTION backup_verification_record(bigint, text, jsonb, text) TO maludb_memory_admin, maludb_memory_executor;
GRANT  EXECUTE ON FUNCTION backup_manifest_latest() TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.56.0--0.57.0.sql
-- ============================================================
\echo Use "ALTER EXTENSION maludb_core UPDATE TO '0.57.0'" to load this file. \quit

-- =====================================================================
-- maludb_core 0.56.0 → 0.57.0
--
-- Stage 15 / V3-ENV-01: preview environment catalog.
--
-- Records the state of self-hosted preview databases — name, base
-- migration, current migration, seed policy, anonymizer reference,
-- and per-seed redaction rules. The CLI workflow that drives
-- create / destroy / promote-check / migration-diff is a Stage 15
-- follow-up; this catalog gives that workflow a durable home so it
-- can ship without a new migration.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.57.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.57.0'::text $body$;

-- ---------------------------------------------------------------------
-- malu$preview_env
-- ---------------------------------------------------------------------
CREATE TABLE malu$preview_env (
    env_id            bigserial PRIMARY KEY,
    name              text       NOT NULL,
    base_migration    text       NOT NULL,
    current_migration text,
    seed_policy       jsonb      NOT NULL DEFAULT '{}'::jsonb,
    anonymizer_ref    text,
    description       text,
    owner_schema      name       NOT NULL DEFAULT current_schema(),
    created_at        timestamptz NOT NULL DEFAULT now(),
    retired_at        timestamptz,
    UNIQUE (owner_schema, name)
);
CREATE INDEX malu$preview_env_owner_idx
    ON malu$preview_env(owner_schema) WHERE retired_at IS NULL;

CREATE TABLE malu$preview_env_seed (
    seed_id          bigserial PRIMARY KEY,
    env_id           bigint     NOT NULL REFERENCES malu$preview_env(env_id) ON DELETE CASCADE,
    source_kind      text       NOT NULL CHECK (source_kind IN
                        ('sql_file','json_blob','dump','table_subset','custom')),
    source_ref       text       NOT NULL,
    redaction_rules  jsonb      NOT NULL DEFAULT '[]'::jsonb,
    applied_at       timestamptz,
    created_at       timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$preview_env_seed_env_idx
    ON malu$preview_env_seed(env_id, created_at DESC);

ALTER TABLE malu$preview_env ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$preview_env
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

ALTER TABLE malu$preview_env_seed ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_via_env ON malu$preview_env_seed
    USING (
        EXISTS (SELECT 1 FROM malu$preview_env e
                WHERE e.env_id = malu$preview_env_seed.env_id
                  AND e.owner_schema = current_schema()))
    WITH CHECK (
        EXISTS (SELECT 1 FROM malu$preview_env e
                WHERE e.env_id = malu$preview_env_seed.env_id
                  AND e.owner_schema = current_schema()));

GRANT SELECT, INSERT, UPDATE, DELETE ON malu$preview_env, malu$preview_env_seed TO maludb_memory_admin;
GRANT SELECT, INSERT, UPDATE         ON malu$preview_env, malu$preview_env_seed TO maludb_memory_executor;
GRANT SELECT                          ON malu$preview_env, malu$preview_env_seed TO maludb_memory_auditor;
GRANT USAGE, SELECT ON SEQUENCE malu$preview_env_env_id_seq             TO maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$preview_env_seed_seed_id_seq       TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- preview_env_create / record_seed / promote_check / list
-- =====================================================================
CREATE FUNCTION preview_env_create(
    p_name           text,
    p_base_migration text,
    p_seed_policy    jsonb   DEFAULT '{"production_data": false}'::jsonb,
    p_anonymizer_ref text    DEFAULT NULL,
    p_description    text    DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    IF p_seed_policy -> 'production_data' = 'true'::jsonb THEN
        RAISE EXCEPTION 'preview_env_create: seed_policy.production_data must be false (V3-ENV-01 default)'
            USING ERRCODE = 'check_violation',
                  HINT    = 'Use the anonymizer_ref + per-seed redaction rules to import sanitised data.';
    END IF;

    INSERT INTO malu$preview_env
        (name, base_migration, current_migration, seed_policy, anonymizer_ref, description)
    VALUES
        (p_name, p_base_migration, p_base_migration, p_seed_policy, p_anonymizer_ref, p_description)
    ON CONFLICT (owner_schema, name) DO UPDATE
        SET base_migration   = EXCLUDED.base_migration,
            current_migration = EXCLUDED.base_migration,
            seed_policy      = EXCLUDED.seed_policy,
            anonymizer_ref   = EXCLUDED.anonymizer_ref,
            description      = EXCLUDED.description,
            retired_at       = NULL
    RETURNING env_id INTO v_id;

    PERFORM audit_event('preview_env_create', 'malu$preview_env', v_id,
        jsonb_build_object('name', p_name, 'base_migration', p_base_migration,
                           'production_data', p_seed_policy -> 'production_data'),
        NULL);
    RETURN v_id;
END;
$body$;

CREATE FUNCTION preview_env_record_seed(
    p_env_id          bigint,
    p_source_kind     text,
    p_source_ref      text,
    p_redaction_rules jsonb DEFAULT '[]'::jsonb
) RETURNS bigint
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$preview_env_seed(env_id, source_kind, source_ref, redaction_rules, applied_at)
    VALUES (p_env_id, p_source_kind, p_source_ref, p_redaction_rules, now())
    RETURNING seed_id INTO v_id;
    PERFORM audit_event('preview_env_record_seed', 'malu$preview_env_seed', v_id,
        jsonb_build_object('env_id', p_env_id, 'source_kind', p_source_kind),
        NULL);
    RETURN v_id;
END;
$body$;

CREATE FUNCTION preview_env_promote_check(p_env_id bigint)
    RETURNS TABLE (gate text, ok boolean, detail text)
LANGUAGE plpgsql STABLE AS $body$
#variable_conflict use_column
DECLARE v_env malu$preview_env%ROWTYPE;
BEGIN
    SELECT * INTO v_env FROM malu$preview_env WHERE env_id = p_env_id;
    IF v_env.env_id IS NULL THEN
        RAISE EXCEPTION 'preview_env_promote_check: env % not found', p_env_id
            USING ERRCODE = 'no_data_found';
    END IF;

    RETURN QUERY
    SELECT 'no_production_data'::text,
           (v_env.seed_policy -> 'production_data' IS DISTINCT FROM 'true'::jsonb),
           'seed_policy.production_data must be false'::text
    UNION ALL
    SELECT 'has_seed'::text,
           EXISTS (SELECT 1 FROM malu$preview_env_seed WHERE env_id = p_env_id),
           'at least one seed row recorded'::text
    UNION ALL
    SELECT 'migration_current'::text,
           v_env.current_migration = maludb_core_version(),
           format('current_migration=%s vs extension=%s',
                  v_env.current_migration, maludb_core_version());
END;
$body$;

CREATE FUNCTION preview_env_list(p_include_retired boolean DEFAULT false)
    RETURNS TABLE (
        env_id            bigint,
        name              text,
        base_migration    text,
        current_migration text,
        seed_count        integer,
        anonymizer_ref    text,
        created_at        timestamptz,
        retired_at        timestamptz
    ) LANGUAGE plpgsql STABLE AS $body$
#variable_conflict use_column
BEGIN
    RETURN QUERY
    SELECT e.env_id, e.name, e.base_migration, e.current_migration,
           (SELECT count(*)::integer FROM malu$preview_env_seed s WHERE s.env_id = e.env_id),
           e.anonymizer_ref, e.created_at, e.retired_at
      FROM malu$preview_env e
     WHERE (p_include_retired OR e.retired_at IS NULL)
     ORDER BY e.name;
END;
$body$;

REVOKE EXECUTE ON FUNCTION preview_env_create(text, text, jsonb, text, text) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION preview_env_record_seed(bigint, text, text, jsonb) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION preview_env_promote_check(bigint) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION preview_env_list(boolean) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION preview_env_create(text, text, jsonb, text, text)         TO maludb_memory_admin, maludb_memory_executor;
GRANT  EXECUTE ON FUNCTION preview_env_record_seed(bigint, text, text, jsonb)        TO maludb_memory_admin, maludb_memory_executor;
GRANT  EXECUTE ON FUNCTION preview_env_promote_check(bigint)                          TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT  EXECUTE ON FUNCTION preview_env_list(boolean)                                  TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ============================================================
-- Section: maludb_core--0.57.0--0.58.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.57.0 -> 0.58.0  (v3.1 Stage A — V3-EMBED-02)
--
-- Adds 'embedding' as a first-class kind in the Derivation Ledger.
--
-- v3.0.0 shipped embedding_record_output (Stage 14 / V3-EMBED-01) but
-- the Stage 2 ledger CHECK constraint only accepted seven kinds, so
-- embedding artefacts were recorded as 'memory_detail_object'
-- (documented as a future-migration concern in the 0.51.0->0.52.0
-- migration body). This migration:
--
--   1. Extends the CHECK constraint to allow 'embedding'.
--   2. Backfills existing ledger rows that point at malu$embedding_output
--      rows from 'memory_detail_object' to 'embedding'. The FK from
--      malu$embedding_output.derivation_id makes the set well-defined.
--   3. Updates embedding_record_output to record new rows as 'embedding'.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.58.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.58.0'::text $body$;

-- ---------------------------------------------------------------------
-- 1. Extend the derived_object_type CHECK to admit 'embedding'.
-- ---------------------------------------------------------------------
ALTER TABLE malu$derivation_ledger
    DROP CONSTRAINT malu$derivation_ledger_derived_object_type_check;

ALTER TABLE malu$derivation_ledger
    ADD CONSTRAINT malu$derivation_ledger_derived_object_type_check
    CHECK (derived_object_type IN (
        'source_package',
        'claim',
        'fact',
        'memory',
        'episode_object',
        'memory_detail_object',
        'relationship_edge',
        'embedding'
    ));

-- ---------------------------------------------------------------------
-- 2. Backfill: rows that point at an embedding_output via the FK
--    were marked 'memory_detail_object' as a placeholder; flip them.
-- ---------------------------------------------------------------------
UPDATE malu$derivation_ledger d
   SET derived_object_type = 'embedding'
  FROM malu$embedding_output e
 WHERE e.derivation_id = d.derivation_id
   AND d.derived_object_type = 'memory_detail_object';

-- ---------------------------------------------------------------------
-- 3. embedding_record_output now records 'embedding' directly.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION embedding_record_output(
    p_job_id           bigint,
    p_vector           malu_vector,
    p_vector_dim       integer,
    p_svpor_frame_text text,
    p_output_hash      bytea
) RETURNS TABLE (output_id bigint, derivation_id bigint)
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_job    malu$embedding_job%ROWTYPE;
    v_oid    bigint;
    v_did    bigint;
    v_inputs jsonb;
BEGIN
    SELECT * INTO v_job FROM malu$embedding_job WHERE job_id = p_job_id;
    IF v_job.job_id IS NULL THEN
        RAISE EXCEPTION 'embedding_record_output: job % not found', p_job_id
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_svpor_frame_text IS NULL OR length(p_svpor_frame_text) = 0 THEN
        RAISE EXCEPTION 'embedding_record_output: svpor_frame_text is required'
            USING ERRCODE = 'check_violation';
    END IF;

    v_inputs := jsonb_build_array(jsonb_build_object(
        'kind',                    'embedding_input',
        'target_kind',             v_job.target_kind,
        'target_id',               v_job.target_id,
        'model_alias',             v_job.model_alias,
        'embedding_space',         v_job.embedding_space,
        'prompt_template_version', v_job.prompt_template_version,
        'input_hash',              encode(COALESCE(v_job.input_hash, '\x00'::bytea), 'hex'),
        'svpor_frame_hash',        encode(public.digest(p_svpor_frame_text::bytea, 'sha256'), 'hex')));

    INSERT INTO malu$derivation_ledger
        (derived_object_type, derived_object_id, parser_name,
         model_alias_id, prompt_template_id, inputs_jsonb, inputs_hash)
    VALUES
        ('embedding', 0, 'embedding_runner',
         (SELECT alias_id FROM malu$model_alias WHERE alias_name = v_job.model_alias),
         NULL, v_inputs,
         encode(public.digest(v_inputs::text::bytea, 'sha256'), 'hex'))
    RETURNING malu$derivation_ledger.derivation_id INTO v_did;

    INSERT INTO malu$embedding_output
        (job_id, target_kind, target_id, model_alias, embedding_space,
         vector_dim, vector, svpor_frame_text,
         input_hash, output_hash, derivation_id)
    VALUES
        (p_job_id, v_job.target_kind, v_job.target_id, v_job.model_alias,
         v_job.embedding_space, p_vector_dim, p_vector, p_svpor_frame_text,
         COALESCE(v_job.input_hash, public.digest(p_svpor_frame_text::bytea, 'sha256')),
         p_output_hash, v_did)
    RETURNING malu$embedding_output.output_id INTO v_oid;

    UPDATE malu$derivation_ledger
       SET derived_object_id = v_oid
     WHERE derivation_id = v_did;

    UPDATE malu$embedding_job
       SET status      = 'completed',
           finished_at = now(),
           last_error  = NULL
     WHERE job_id = p_job_id;

    PERFORM audit_event('embedding_record_output', 'malu$embedding_output', v_oid,
        jsonb_build_object('job_id', p_job_id, 'derivation_id', v_did,
                           'vector_dim', p_vector_dim),
        NULL);

    output_id     := v_oid;
    derivation_id := v_did;
    RETURN NEXT;
END;
$body$;

-- ============================================================
-- Section: maludb_core--0.58.0--0.59.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.58.0 -> 0.59.0  (v3.1 Stage B — V3-REALTIME-02a)
--
-- Wire emit_event into the Stage 2 + 5 + 6 register_* helpers so
-- realtime subscribers see ingest activity without callers having to
-- emit events explicitly. Functions instrumented:
--
--   Stage 2:
--     register_source_package        -> register_source_package
--     register_claim                 -> register_claim
--     register_fact                  -> register_fact
--     register_memory                -> register_memory
--     register_episode               -> register_episode
--     register_memory_detail         -> register_memory_detail
--     register_relationship_edge     -> register_relationship_edge
--   Stage 5:
--     register_skill                 -> register_skill
--   Stage 6:
--     register_local_node            -> register_local_node
--
-- Each CREATE OR REPLACE preserves the existing semantics; the only
-- behavior change is a PERFORM emit_event(...) just before RETURN.
-- The event payload is a small jsonb summary that the realtime stream
-- can fan out to subscribers without exposing the full row body.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.59.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.59.0'::text $body$;

-- ---------------------------------------------------------------------
-- Stage 2 register_* helpers
-- ---------------------------------------------------------------------

CREATE OR REPLACE FUNCTION register_source_package(
    p_source_type     text,
    p_content_bytes   bytea   DEFAULT NULL,
    p_content_text    text    DEFAULT NULL,
    p_content_jsonb   jsonb   DEFAULT NULL,
    p_media_type      text    DEFAULT NULL,
    p_origin_jsonb    jsonb   DEFAULT NULL,
    p_captured_at     timestamptz DEFAULT NULL,
    p_retention_class text    DEFAULT 'standard',
    p_sensitivity     text    DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id    bigint;
    v_hash  text;
    v_size  bigint;
    v_bytes bytea;
BEGIN
    IF p_content_bytes IS NULL AND p_content_text IS NULL AND p_content_jsonb IS NULL THEN
        RAISE EXCEPTION 'register_source_package: one of content_bytes / _text / _jsonb is required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    IF p_content_bytes IS NOT NULL THEN
        v_bytes := p_content_bytes;
    ELSIF p_content_text IS NOT NULL THEN
        v_bytes := convert_to(p_content_text, 'UTF8');
    ELSE
        v_bytes := convert_to(p_content_jsonb::text, 'UTF8');
    END IF;
    v_hash := encode(sha256(v_bytes), 'hex');
    v_size := octet_length(v_bytes);

    INSERT INTO malu$source_package
        (source_type, content_bytes, content_text, content_jsonb,
         content_hash, content_size, media_type, origin_jsonb,
         captured_at, retention_class, sensitivity)
    VALUES
        (p_source_type, p_content_bytes, p_content_text, p_content_jsonb,
         v_hash, v_size, p_media_type, p_origin_jsonb,
         p_captured_at, p_retention_class, p_sensitivity)
    RETURNING source_package_id INTO v_id;

    PERFORM emit_event(
        'register_source_package',
        jsonb_build_object('source_package_id', v_id,
                           'source_type',       p_source_type,
                           'content_hash',      v_hash,
                           'content_size',      v_size,
                           'sensitivity',       p_sensitivity),
        NULL, NULL, NULL,
        'source_package', v_id, NULL);
    RETURN v_id;
END;
$body$;

CREATE OR REPLACE FUNCTION register_claim(
    p_subject           text  DEFAULT NULL,
    p_verb              text  DEFAULT NULL,
    p_predicate         text  DEFAULT NULL,
    p_object_value      text  DEFAULT NULL,
    p_relationship      text  DEFAULT NULL,
    p_statement_text    text  DEFAULT NULL,
    p_statement_jsonb   jsonb DEFAULT NULL,
    p_source_package_id bigint DEFAULT NULL,
    p_source_locator    jsonb DEFAULT NULL,
    p_sensitivity       text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$claim
        (subject, verb, predicate, object_value, relationship,
         statement_text, statement_jsonb,
         source_package_id, source_locator, sensitivity)
    VALUES (p_subject, p_verb, p_predicate, p_object_value, p_relationship,
            p_statement_text, p_statement_jsonb,
            p_source_package_id, p_source_locator, p_sensitivity)
    RETURNING claim_id INTO v_id;

    PERFORM emit_event(
        'register_claim',
        jsonb_build_object('claim_id',          v_id,
                           'source_package_id', p_source_package_id,
                           'subject',           p_subject,
                           'verb',              p_verb,
                           'predicate',         p_predicate,
                           'sensitivity',       p_sensitivity),
        NULL, NULL, NULL,
        'claim', v_id, NULL);
    RETURN v_id;
END;
$body$;

CREATE OR REPLACE FUNCTION register_fact(
    p_claim_ids         bigint[],
    p_subject           text  DEFAULT NULL,
    p_verb              text  DEFAULT NULL,
    p_predicate         text  DEFAULT NULL,
    p_object_value      text  DEFAULT NULL,
    p_relationship      text  DEFAULT NULL,
    p_statement_text    text  DEFAULT NULL,
    p_statement_jsonb   jsonb DEFAULT NULL,
    p_verification_scope  text DEFAULT NULL,
    p_verification_method text DEFAULT NULL,
    p_sensitivity       text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id    bigint;
    v_claim bigint;
BEGIN
    INSERT INTO malu$fact
        (subject, verb, predicate, object_value, relationship,
         statement_text, statement_jsonb,
         verification_scope, verification_method, sensitivity)
    VALUES (p_subject, p_verb, p_predicate, p_object_value, p_relationship,
            p_statement_text, p_statement_jsonb,
            p_verification_scope, p_verification_method, p_sensitivity)
    RETURNING fact_id INTO v_id;

    IF p_claim_ids IS NOT NULL THEN
        FOREACH v_claim IN ARRAY p_claim_ids LOOP
            INSERT INTO malu$fact_claim (fact_id, claim_id)
            VALUES (v_id, v_claim);
        END LOOP;
    END IF;

    PERFORM emit_event(
        'register_fact',
        jsonb_build_object('fact_id',             v_id,
                           'claim_ids',           COALESCE(to_jsonb(p_claim_ids), '[]'::jsonb),
                           'subject',             p_subject,
                           'verb',                p_verb,
                           'predicate',           p_predicate,
                           'verification_method', p_verification_method,
                           'sensitivity',         p_sensitivity),
        NULL, NULL, NULL,
        'fact', v_id, NULL);
    RETURN v_id;
END;
$body$;

CREATE OR REPLACE FUNCTION register_memory(
    p_memory_kind   text,
    p_title         text  DEFAULT NULL,
    p_summary       text  DEFAULT NULL,
    p_payload_jsonb jsonb DEFAULT '{}'::jsonb,
    p_occurred_at   timestamptz DEFAULT NULL,
    p_occurred_until timestamptz DEFAULT NULL,
    p_sensitivity   text  DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$memory
        (memory_kind, title, summary, payload_jsonb,
         occurred_at, occurred_until, sensitivity)
    VALUES (p_memory_kind, p_title, p_summary, COALESCE(p_payload_jsonb, '{}'::jsonb),
            p_occurred_at, p_occurred_until, p_sensitivity)
    RETURNING memory_id INTO v_id;

    PERFORM emit_event(
        'register_memory',
        jsonb_build_object('memory_id',   v_id,
                           'memory_kind', p_memory_kind,
                           'title',       p_title,
                           'sensitivity', p_sensitivity),
        NULL, NULL, NULL,
        'memory', v_id, NULL);
    RETURN v_id;
END;
$body$;

CREATE OR REPLACE FUNCTION register_episode(
    p_episode_kind  text,
    p_title         text,
    p_summary       text  DEFAULT NULL,
    p_payload_jsonb jsonb DEFAULT '{}'::jsonb,
    p_occurred_at   timestamptz DEFAULT NULL,
    p_occurred_until timestamptz DEFAULT NULL,
