) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$episode_object
        (episode_kind, title, summary, payload_jsonb,
         occurred_at, occurred_until, sensitivity)
    VALUES (p_episode_kind, p_title, p_summary, COALESCE(p_payload_jsonb, '{}'::jsonb),
            p_occurred_at, p_occurred_until, p_sensitivity)
    RETURNING episode_id INTO v_id;

    PERFORM emit_event(
        'register_episode',
        jsonb_build_object('episode_id',   v_id,
                           'episode_kind', p_episode_kind,
                           'title',        p_title,
                           'sensitivity',  p_sensitivity),
        NULL, NULL, NULL,
        'episode_object', v_id, NULL);
    RETURN v_id;
END;
$body$;

CREATE OR REPLACE FUNCTION register_memory_detail(
    p_detail_kind   text,
    p_parent_mdo_id bigint DEFAULT NULL,
    p_memory_id     bigint DEFAULT NULL,
    p_episode_id    bigint DEFAULT NULL,
    p_ordinal       integer DEFAULT NULL,
    p_title         text   DEFAULT NULL,
    p_body_text     text   DEFAULT NULL,
    p_body_jsonb    jsonb  DEFAULT NULL,
    p_sensitivity   text   DEFAULT 'internal'
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    IF p_parent_mdo_id IS NULL AND p_memory_id IS NULL AND p_episode_id IS NULL THEN
        RAISE EXCEPTION
          'register_memory_detail: at least one of parent_mdo_id / memory_id / episode_id required'
          USING ERRCODE = 'invalid_parameter_value';
    END IF;
    INSERT INTO malu$memory_detail_object
        (parent_mdo_id, memory_id, episode_id, detail_kind,
         ordinal, title, body_text, body_jsonb, sensitivity)
    VALUES (p_parent_mdo_id, p_memory_id, p_episode_id, p_detail_kind,
            p_ordinal, p_title, p_body_text, p_body_jsonb, p_sensitivity)
    RETURNING mdo_id INTO v_id;

    PERFORM emit_event(
        'register_memory_detail',
        jsonb_build_object('mdo_id',        v_id,
                           'detail_kind',   p_detail_kind,
                           'parent_mdo_id', p_parent_mdo_id,
                           'memory_id',     p_memory_id,
                           'episode_id',    p_episode_id,
                           'sensitivity',   p_sensitivity),
        NULL, NULL, NULL,
        'memory_detail_object', v_id, NULL);
    RETURN v_id;
END;
$body$;

CREATE OR REPLACE FUNCTION register_relationship_edge(
    p_source_object_type text,
    p_source_object_id   bigint,
    p_target_object_type text,
    p_target_object_id   bigint,
    p_relationship_type  text,
    p_label              text   DEFAULT NULL,
    p_edge_jsonb         jsonb  DEFAULT NULL,
    p_confidence         numeric DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$relationship_edge
        (relationship_type, source_object_type, source_object_id,
         target_object_type, target_object_id,
         label, edge_jsonb, confidence)
    VALUES (p_relationship_type, p_source_object_type, p_source_object_id,
            p_target_object_type, p_target_object_id,
            p_label, p_edge_jsonb, p_confidence)
    RETURNING edge_id INTO v_id;

    PERFORM emit_event(
        'register_relationship_edge',
        jsonb_build_object('edge_id',             v_id,
                           'relationship_type',   p_relationship_type,
                           'source_object_type',  p_source_object_type,
                           'source_object_id',    p_source_object_id,
                           'target_object_type',  p_target_object_type,
                           'target_object_id',    p_target_object_id),
        NULL, NULL, NULL,
        'relationship_edge', v_id, NULL);
    RETURN v_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- Stage 5 register_skill
-- ---------------------------------------------------------------------

CREATE OR REPLACE FUNCTION register_skill(
    p_skill_name           text,
    p_version              text DEFAULT '1.0.0',
    p_description          text DEFAULT NULL,
    p_packaging_kind       text DEFAULT 'markdown',
    p_applicability_jsonb  jsonb DEFAULT '{}'::jsonb,
    p_precondition_jsonb   jsonb DEFAULT '[]'::jsonb
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$skill_package
        (skill_name, version, description, packaging_kind,
         applicability_jsonb, precondition_jsonb)
    VALUES (p_skill_name, p_version, p_description, p_packaging_kind,
            p_applicability_jsonb, p_precondition_jsonb)
    ON CONFLICT (owner_schema, skill_name, version) DO UPDATE
        SET description          = COALESCE(EXCLUDED.description,         malu$skill_package.description),
            packaging_kind       = EXCLUDED.packaging_kind,
            applicability_jsonb  = EXCLUDED.applicability_jsonb,
            precondition_jsonb   = EXCLUDED.precondition_jsonb,
            updated_at           = now()
    RETURNING skill_id INTO v_id;

    PERFORM emit_event(
        'register_skill',
        jsonb_build_object('skill_id',       v_id,
                           'skill_name',     p_skill_name,
                           'version',        p_version,
                           'packaging_kind', p_packaging_kind),
        NULL, NULL, NULL,
        'skill_package', v_id, NULL);
    RETURN v_id;
END;
$body$;

-- ---------------------------------------------------------------------
-- Stage 6 register_local_node
-- ---------------------------------------------------------------------

CREATE OR REPLACE FUNCTION register_local_node(
    p_node_name    text,
    p_fingerprint  text,
    p_uri          text DEFAULT NULL,
    p_description  text DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_id bigint;
BEGIN
    INSERT INTO malu$local_memory_node
        (node_name, fingerprint, uri, description)
    VALUES (p_node_name, p_fingerprint, p_uri, p_description)
    ON CONFLICT (owner_schema, node_name) DO UPDATE
        SET uri          = COALESCE(EXCLUDED.uri,         malu$local_memory_node.uri),
            description  = COALESCE(EXCLUDED.description, malu$local_memory_node.description),
            last_seen_at = now()
        WHERE malu$local_memory_node.fingerprint = EXCLUDED.fingerprint
    RETURNING node_id INTO v_id;

    IF v_id IS NULL THEN
        RAISE EXCEPTION 'register_local_node: fingerprint mismatch for node %', p_node_name
            USING ERRCODE = 'unique_violation';
    END IF;

    PERFORM audit_event('local_node_registered', NULL, NULL,
        jsonb_build_object('node_id', v_id, 'node_name', p_node_name));

    PERFORM emit_event(
        'register_local_node',
        jsonb_build_object('node_id',   v_id,
                           'node_name', p_node_name,
                           'uri',       p_uri),
        NULL, NULL, NULL,
        'local_memory_node', v_id, NULL);
    RETURN v_id;
END;
$body$;

-- ============================================================
-- Section: maludb_core--0.59.0--0.60.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.59.0 -> 0.60.0  (v3.1 Stage C — V3-PRESENCE-02)
--
-- Adds an optional TTL to malu$pool_presence rows and a sweeper
-- function that auto-marks expired rows as left.
--
-- Why: long-running active memory pools accumulate stale presence
-- rows (humans whose tab closed, agents whose host died) that never
-- emit an explicit presence_leave. Without TTL, presence_list()
-- continues to report them as active forever.
--
-- Design:
--   * malu$pool_presence gains ttl_seconds (nullable). NULL preserves
--     today's behavior (no auto-expiry) — existing rows are unchanged.
--   * presence_update takes an optional p_ttl_seconds; supplying it
--     stamps the row with that TTL on each touch.
--   * presence_sweep() finds rows whose last_seen_at + ttl_seconds is
--     in the past and (a) sets left_at = now(), (b) inserts a 'leave'
--     event with reason='ttl_expired', (c) emits the realtime event,
--     (d) records an audit row. Returns the number of rows swept.
--     Idempotent and authorization-aware (RLS still applies — it
--     only sweeps rows the caller can see, but is intended to be
--     called by maludb_memory_admin which has BYPASSRLS).
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.60.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.60.0'::text $body$;

-- ---------------------------------------------------------------------
-- 1. Column. nullable; NULL = no TTL.
-- ---------------------------------------------------------------------
ALTER TABLE malu$pool_presence
    ADD COLUMN IF NOT EXISTS ttl_seconds integer
    CHECK (ttl_seconds IS NULL OR ttl_seconds > 0);

-- ---------------------------------------------------------------------
-- 2. presence_update — accepts an optional TTL.
--    Backward-compatible: the prior 6-arg signature is dropped and
--    replaced by a 7-arg one with p_ttl_seconds defaulting to NULL.
--    Callers using positional args continue to work because all
--    prior args keep their positions and the new one is at the tail.
-- ---------------------------------------------------------------------
DROP FUNCTION presence_update(bigint, text, text, text, text, jsonb);

CREATE FUNCTION presence_update(
    p_pool_id          bigint,
    p_participant_kind text,
    p_participant_ref  text,
    p_role             text DEFAULT NULL,
    p_declared_task    text DEFAULT NULL,
    p_cursor_jsonb     jsonb DEFAULT NULL,
    p_ttl_seconds      integer DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_pid    bigint;
    v_kind   text;
    v_was    boolean;
BEGIN
    PERFORM 1 FROM malu$active_memory_pool WHERE pool_id = p_pool_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'presence_update: pool % not found or not visible to caller', p_pool_id
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_ttl_seconds IS NOT NULL AND p_ttl_seconds <= 0 THEN
        RAISE EXCEPTION 'presence_update: ttl_seconds must be > 0'
            USING ERRCODE = 'check_violation';
    END IF;

    SELECT presence_id, (left_at IS NULL) INTO v_pid, v_was
      FROM malu$pool_presence
     WHERE pool_id          = p_pool_id
       AND participant_kind = p_participant_kind
       AND participant_ref  = p_participant_ref;

    IF v_pid IS NULL THEN
        INSERT INTO malu$pool_presence
            (pool_id, participant_kind, participant_ref, role, declared_task, cursor_jsonb, ttl_seconds)
        VALUES
            (p_pool_id, p_participant_kind, p_participant_ref, p_role, p_declared_task, p_cursor_jsonb, p_ttl_seconds)
        RETURNING presence_id INTO v_pid;
        v_kind := 'join';
    ELSE
        UPDATE malu$pool_presence
           SET role          = COALESCE(p_role,          role),
               declared_task = COALESCE(p_declared_task, declared_task),
               cursor_jsonb  = COALESCE(p_cursor_jsonb,  cursor_jsonb),
               ttl_seconds   = COALESCE(p_ttl_seconds,   ttl_seconds),
               last_seen_at  = now(),
               left_at       = NULL
         WHERE presence_id = v_pid;
        v_kind := CASE WHEN v_was THEN 'update' ELSE 'join' END;
    END IF;

    INSERT INTO malu$pool_presence_event(presence_id, kind, detail_jsonb)
    VALUES (v_pid, v_kind,
            jsonb_build_object('role', p_role, 'declared_task', p_declared_task,
                               'cursor', p_cursor_jsonb,
                               'ttl_seconds', p_ttl_seconds));

    PERFORM emit_event(
        'pool_presence_' || v_kind,
        jsonb_build_object('presence_id', v_pid,
                           'pool_id', p_pool_id,
                           'participant_kind', p_participant_kind,
                           'participant_ref',  p_participant_ref,
                           'role',             p_role,
                           'declared_task',    p_declared_task,
                           'ttl_seconds',      p_ttl_seconds),
        NULL, NULL, p_pool_id, 'malu$pool_presence', v_pid, NULL);

    PERFORM audit_event('pool_presence_' || v_kind, 'malu$pool_presence', v_pid,
        jsonb_build_object('pool_id', p_pool_id,
                           'participant_kind', p_participant_kind,
                           'participant_ref', p_participant_ref,
                           'ttl_seconds', p_ttl_seconds),
        NULL);

    RETURN v_pid;
END;
$body$;
REVOKE EXECUTE ON FUNCTION presence_update(bigint, text, text, text, text, jsonb, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION presence_update(bigint, text, text, text, text, jsonb, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- ---------------------------------------------------------------------
-- 3. presence_sweep — mark TTL-expired rows as left.
--    Returns the number of rows swept. Callable as part of a cron
--    schedule (V3-CRON-01) or invoked manually by an admin.
-- ---------------------------------------------------------------------
CREATE FUNCTION presence_sweep()
    RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_row malu$pool_presence%ROWTYPE;
    v_n   bigint := 0;
BEGIN
    FOR v_row IN
        SELECT * FROM malu$pool_presence
         WHERE left_at IS NULL
           AND ttl_seconds IS NOT NULL
           AND last_seen_at + make_interval(secs => ttl_seconds) < now()
         FOR UPDATE
    LOOP
        UPDATE malu$pool_presence
           SET left_at = now()
         WHERE presence_id = v_row.presence_id;

        INSERT INTO malu$pool_presence_event(presence_id, kind, detail_jsonb)
        VALUES (v_row.presence_id, 'leave',
                jsonb_build_object('reason', 'ttl_expired',
                                   'ttl_seconds', v_row.ttl_seconds,
                                   'last_seen_at', v_row.last_seen_at));

        PERFORM emit_event(
            'pool_presence_leave',
            jsonb_build_object('presence_id', v_row.presence_id,
                               'pool_id',     v_row.pool_id,
                               'participant_kind', v_row.participant_kind,
                               'participant_ref',  v_row.participant_ref,
                               'reason',           'ttl_expired',
                               'ttl_seconds',      v_row.ttl_seconds),
            NULL, NULL, v_row.pool_id, 'malu$pool_presence', v_row.presence_id, NULL);

        PERFORM audit_event('pool_presence_leave', 'malu$pool_presence', v_row.presence_id,
            jsonb_build_object('pool_id', v_row.pool_id,
                               'reason',  'ttl_expired',
                               'ttl_seconds', v_row.ttl_seconds),
            NULL);

        v_n := v_n + 1;
    END LOOP;

    RETURN v_n;
END;
$body$;
REVOKE EXECUTE ON FUNCTION presence_sweep() FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION presence_sweep() TO
    maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.60.0--0.61.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.60.0 -> 0.61.0  (v3.1 Stage E — V3-LOG-02 storage hooks)
--
-- Adds the catalog hooks the maludb-logsd service runner needs:
--   * malu$log_drain.cursor_jsonb — per-stream cursor map
--   * log_drain_advance_cursor(drain_id, stream, last_id)
--   * log_drain_fetch_batch(drain_id, stream, limit) -> (record_id, payload)
--
-- Supported streams in this migration: 'audit' (malu$audit_event) and
-- 'realtime_event' (malu$event). Queue / mc2db / postgres streams are
-- followup tickets and will raise an explicit error from
-- log_drain_fetch_batch for now.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.61.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.61.0'::text $body$;

-- ---------------------------------------------------------------------
-- 1. cursor_jsonb column on malu$log_drain.
-- ---------------------------------------------------------------------
ALTER TABLE malu$log_drain
    ADD COLUMN IF NOT EXISTS cursor_jsonb jsonb NOT NULL DEFAULT '{}'::jsonb;

-- ---------------------------------------------------------------------
-- 2. log_drain_advance_cursor — set the last delivered id for a stream.
--    Idempotent; only moves the cursor forward.
-- ---------------------------------------------------------------------
CREATE FUNCTION log_drain_advance_cursor(
    p_drain_id bigint,
    p_stream   text,
    p_last_id  bigint
) RETURNS bigint
LANGUAGE plpgsql VOLATILE AS $body$
#variable_conflict use_column
DECLARE
    v_existing bigint;
    v_new      bigint;
BEGIN
    SELECT COALESCE((cursor_jsonb ->> p_stream)::bigint, 0)
      INTO v_existing
      FROM malu$log_drain
     WHERE drain_id = p_drain_id;
    IF v_existing IS NULL THEN
        RAISE EXCEPTION 'log_drain_advance_cursor: drain % not found', p_drain_id
            USING ERRCODE = 'no_data_found';
    END IF;
    v_new := GREATEST(v_existing, p_last_id);
    UPDATE malu$log_drain
       SET cursor_jsonb = jsonb_set(cursor_jsonb, ARRAY[p_stream], to_jsonb(v_new))
     WHERE drain_id = p_drain_id;
    RETURN v_new;
END;
$body$;
REVOKE EXECUTE ON FUNCTION log_drain_advance_cursor(bigint, text, bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION log_drain_advance_cursor(bigint, text, bigint) TO
    maludb_memory_admin, maludb_memory_executor;

-- ---------------------------------------------------------------------
-- 3. log_drain_fetch_batch — pull the next N rows for a stream.
--    Returns (record_id, payload jsonb). Payload shape is stream-specific
--    but always includes 'event_kind' for routing/filtering.
-- ---------------------------------------------------------------------
CREATE FUNCTION log_drain_fetch_batch(
    p_drain_id bigint,
    p_stream   text,
    p_limit    integer DEFAULT 100
) RETURNS TABLE (record_id bigint, payload jsonb)
LANGUAGE plpgsql STABLE AS $body$
#variable_conflict use_column
DECLARE
    v_cursor bigint;
BEGIN
    IF p_limit IS NULL OR p_limit <= 0 THEN
        RAISE EXCEPTION 'log_drain_fetch_batch: limit must be > 0'
            USING ERRCODE = 'check_violation';
    END IF;

    SELECT COALESCE((cursor_jsonb ->> p_stream)::bigint, 0)
      INTO v_cursor
      FROM malu$log_drain
     WHERE drain_id = p_drain_id;
    IF v_cursor IS NULL THEN
        RAISE EXCEPTION 'log_drain_fetch_batch: drain % not found', p_drain_id
            USING ERRCODE = 'no_data_found';
    END IF;

    IF p_stream = 'audit' THEN
        RETURN QUERY
        SELECT a.event_id,
               jsonb_build_object(
                 'stream',             'audit',
                 'event_id',           a.event_id,
                 'event_kind',         a.event_kind,
                 'target_object_type', a.target_object_type,
                 'target_object_id',   a.target_object_id,
                 'event_jsonb',        a.event_jsonb,
                 'error_text',         a.error_text,
                 'occurred_at',        a.occurred_at,
                 'actor_role',         a.actor_role,
                 'owner_schema',       a.owner_schema)
          FROM malu$audit_event a
         WHERE a.event_id > v_cursor
         ORDER BY a.event_id
         LIMIT p_limit;
    ELSIF p_stream = 'realtime_event' THEN
        RETURN QUERY
        SELECT e.event_id,
               jsonb_build_object(
                 'stream',           'realtime_event',
                 'event_id',         e.event_id,
                 'event_kind',       e.event_kind,
                 'account_id',       e.account_id,
                 'active_pool_id',   e.active_pool_id,
                 'object_type',      e.object_type,
                 'object_id',        e.object_id,
                 'partition',        e.partition,
                 'scope',            e.scope,
                 'payload',          e.payload,
                 'transaction_time', e.transaction_time)
          FROM malu$event e
         WHERE e.event_id > v_cursor
         ORDER BY e.event_id
         LIMIT p_limit;
    ELSE
        RAISE EXCEPTION 'log_drain_fetch_batch: stream % not yet supported (audit / realtime_event only in 0.61.0)', p_stream
            USING ERRCODE = 'feature_not_supported';
    END IF;
END;
$body$;
REVOKE EXECUTE ON FUNCTION log_drain_fetch_batch(bigint, text, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION log_drain_fetch_batch(bigint, text, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.61.0--0.62.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.61.0 -> 0.62.0  (v3.1 Stage F — V3-API-02)
--
-- Adds typed argument schemas to malu$rest_endpoint and seeds the
-- curated v3 REST surface. Closes the V3-API-01b follow-up note.
--
-- arg_schema is a JSON array. Each element describes one SQL
-- parameter (PL/pgSQL function arg) and how the dispatcher should
-- source its value from the HTTP request:
--
--   [
--     { "name":  "p_memory_kind",
--       "type":  "text" | "bigint" | "integer" | "boolean"
--                | "numeric" | "jsonb" | "text[]" | "bytea_hex"
--                | "timestamptz",
--       "in":    "body" | "query",
--       "required": true | false,
--       "default":  <value> | null
--     },
--     ...
--   ]
--
-- The dispatcher calls the handler with named args:
--   SELECT <handler>(<name> := $1, <name> := $2, ...)
-- so positional ordering inside arg_schema is not load-bearing.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.62.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.62.0'::text $body$;

-- ---------------------------------------------------------------------
-- 1. arg_schema column.
-- ---------------------------------------------------------------------
ALTER TABLE malu$rest_endpoint
    ADD COLUMN IF NOT EXISTS arg_schema jsonb NOT NULL DEFAULT '[]'::jsonb;

-- ---------------------------------------------------------------------
-- 2. Replace rest_register_endpoint to accept arg_schema. The prior
--    11-arg signature is dropped; a new 12-arg form with p_arg_schema
--    defaulting to '[]'::jsonb keeps existing callers working.
-- ---------------------------------------------------------------------
DROP FUNCTION rest_register_endpoint(text, text, regprocedure, text,
                                     text[], text, jsonb, boolean,
                                     integer, integer, integer);

CREATE FUNCTION rest_register_endpoint(
    p_method            text,
    p_path              text,
    p_handler           regprocedure,
    p_description       text         DEFAULT NULL,
    p_required_scopes   text[]       DEFAULT ARRAY[]::text[],
    p_risk_class        text         DEFAULT 'read_only',
    p_openapi_spec      jsonb        DEFAULT '{}'::jsonb,
    p_auth_required     boolean      DEFAULT true,
    p_timeout_ms        integer      DEFAULT 30000,
    p_max_input_bytes   integer      DEFAULT 1048576,
    p_max_output_bytes  integer      DEFAULT 10485760,
    p_arg_schema        jsonb        DEFAULT '[]'::jsonb
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_id      bigint;
    v_created boolean;
BEGIN
    IF p_method NOT IN ('GET','POST','PUT','PATCH','DELETE') THEN
        RAISE EXCEPTION 'rest_register_endpoint: method must be one of GET/POST/PUT/PATCH/DELETE'
            USING ERRCODE = 'check_violation';
    END IF;
    IF p_path NOT LIKE '/%' THEN
        RAISE EXCEPTION 'rest_register_endpoint: path must start with /'
            USING ERRCODE = 'check_violation';
    END IF;
    IF jsonb_typeof(p_arg_schema) <> 'array' THEN
        RAISE EXCEPTION 'rest_register_endpoint: arg_schema must be a JSON array'
            USING ERRCODE = 'check_violation';
    END IF;

    INSERT INTO malu$rest_endpoint
        (method, path, handler_function, description,
         required_scopes, risk_class, openapi_spec, auth_required,
         timeout_ms, max_input_bytes, max_output_bytes,
         version_introduced, arg_schema)
    VALUES
        (p_method, p_path, p_handler, p_description,
         p_required_scopes, p_risk_class, p_openapi_spec, p_auth_required,
         p_timeout_ms, p_max_input_bytes, p_max_output_bytes,
         maludb_core_version(), p_arg_schema)
    ON CONFLICT (owner_schema, method, path) DO UPDATE
        SET handler_function   = EXCLUDED.handler_function,
            description        = EXCLUDED.description,
            required_scopes    = EXCLUDED.required_scopes,
            risk_class         = EXCLUDED.risk_class,
            openapi_spec       = EXCLUDED.openapi_spec,
            auth_required      = EXCLUDED.auth_required,
            timeout_ms         = EXCLUDED.timeout_ms,
            max_input_bytes    = EXCLUDED.max_input_bytes,
            max_output_bytes   = EXCLUDED.max_output_bytes,
            arg_schema         = EXCLUDED.arg_schema,
            enabled            = true,
            retired_at         = NULL
    RETURNING endpoint_id, (xmax = 0) INTO v_id, v_created;

    PERFORM audit_event(
        CASE WHEN v_created THEN 'rest_endpoint_register' ELSE 'rest_endpoint_update' END,
        'malu$rest_endpoint',
        v_id,
        jsonb_build_object(
            'method', p_method,
            'path',   p_path,
            'handler', p_handler::text,
            'risk_class', p_risk_class,
            'auth_required', p_auth_required,
            'scopes', to_jsonb(p_required_scopes),
            'arg_schema', p_arg_schema),
        NULL);
    RETURN v_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION rest_register_endpoint(text, text, regprocedure, text,
    text[], text, jsonb, boolean, integer, integer, integer, jsonb) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION rest_register_endpoint(text, text, regprocedure, text,
    text[], text, jsonb, boolean, integer, integer, integer, jsonb) TO
    maludb_memory_admin;

-- ---------------------------------------------------------------------
-- 3. Seed the curated v3 endpoint set. ~20 endpoints across memory
--    model / retrieval / auth / secret / queue / cron / realtime /
--    observability. Each row uses ON CONFLICT to be idempotent.
-- ---------------------------------------------------------------------

-- Helper: build a single arg spec.
CREATE OR REPLACE FUNCTION _v3_api_arg(
    p_name text, p_type text, p_required boolean DEFAULT true,
    p_in   text DEFAULT 'body', p_default jsonb DEFAULT 'null'::jsonb)
    RETURNS jsonb
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$
    SELECT jsonb_build_object(
        'name',     p_name,
        'type',     p_type,
        'in',       p_in,
        'required', p_required,
        'default',  p_default)
$body$;

-- Memory model surface (Stage 2-3) -----------------------------------
SELECT rest_register_endpoint(
    'POST', '/v3/source', 'register_source_package(text,bytea,text,jsonb,text,jsonb,timestamptz,text,text)'::regprocedure,
    'Register a Source Package (verbatim archive).',
    ARRAY['source.write']::text[], 'state_changing', '{}'::jsonb, true,
    30000, 8388608, 1048576,
    jsonb_build_array(
        _v3_api_arg('p_source_type',     'text'),
        _v3_api_arg('p_content_bytes',   'bytea_hex',   false),
        _v3_api_arg('p_content_text',    'text',        false),
        _v3_api_arg('p_content_jsonb',   'jsonb',       false),
        _v3_api_arg('p_media_type',      'text',        false),
        _v3_api_arg('p_origin_jsonb',    'jsonb',       false),
        _v3_api_arg('p_captured_at',     'timestamptz', false),
        _v3_api_arg('p_retention_class', 'text',        false),
        _v3_api_arg('p_sensitivity',     'text',        false)));

SELECT rest_register_endpoint(
    'POST', '/v3/claim', 'register_claim(text,text,text,text,text,text,jsonb,bigint,jsonb,text)'::regprocedure,
    'Register a Claim.',
    ARRAY['claim.write']::text[], 'state_changing', '{}'::jsonb, true,
    30000, 1048576, 65536,
    jsonb_build_array(
        _v3_api_arg('p_subject',           'text',  false),
        _v3_api_arg('p_verb',              'text',  false),
        _v3_api_arg('p_predicate',         'text',  false),
        _v3_api_arg('p_object_value',      'text',  false),
        _v3_api_arg('p_relationship',      'text',  false),
        _v3_api_arg('p_statement_text',    'text',  false),
        _v3_api_arg('p_statement_jsonb',   'jsonb', false),
        _v3_api_arg('p_source_package_id', 'bigint',false),
        _v3_api_arg('p_source_locator',    'jsonb', false),
        _v3_api_arg('p_sensitivity',       'text',  false)));

SELECT rest_register_endpoint(
    'POST', '/v3/fact', 'register_fact(bigint[],text,text,text,text,text,text,jsonb,text,text,text)'::regprocedure,
    'Register a verified Fact.',
    ARRAY['fact.write']::text[], 'state_changing', '{}'::jsonb, true,
    30000, 1048576, 65536,
    jsonb_build_array(
        _v3_api_arg('p_claim_ids',           'bigint[]'),
        _v3_api_arg('p_subject',             'text',  false),
        _v3_api_arg('p_verb',                'text',  false),
        _v3_api_arg('p_predicate',           'text',  false),
        _v3_api_arg('p_object_value',        'text',  false),
        _v3_api_arg('p_relationship',        'text',  false),
        _v3_api_arg('p_statement_text',      'text',  false),
        _v3_api_arg('p_statement_jsonb',     'jsonb', false),
        _v3_api_arg('p_verification_scope',  'text',  false),
        _v3_api_arg('p_verification_method', 'text',  false),
        _v3_api_arg('p_sensitivity',         'text',  false)));

SELECT rest_register_endpoint(
    'POST', '/v3/memory', 'register_memory(text,text,text,jsonb,timestamptz,timestamptz,text)'::regprocedure,
    'Register a Memory.',
    ARRAY['memory.write']::text[], 'state_changing', '{}'::jsonb, true,
    30000, 1048576, 65536,
    jsonb_build_array(
        _v3_api_arg('p_memory_kind',     'text'),
        _v3_api_arg('p_title',           'text',        false),
        _v3_api_arg('p_summary',         'text',        false),
        _v3_api_arg('p_payload_jsonb',   'jsonb',       false),
        _v3_api_arg('p_occurred_at',     'timestamptz', false),
        _v3_api_arg('p_occurred_until',  'timestamptz', false),
        _v3_api_arg('p_sensitivity',     'text',        false)));

SELECT rest_register_endpoint(
    'POST', '/v3/episode', 'register_episode(text,text,text,jsonb,timestamptz,timestamptz,text)'::regprocedure,
    'Register an Episode.',
    ARRAY['episode.write']::text[], 'state_changing', '{}'::jsonb, true,
    30000, 1048576, 65536,
    jsonb_build_array(
        _v3_api_arg('p_episode_kind',    'text'),
        _v3_api_arg('p_title',           'text'),
        _v3_api_arg('p_summary',         'text',        false),
        _v3_api_arg('p_payload_jsonb',   'jsonb',       false),
        _v3_api_arg('p_occurred_at',     'timestamptz', false),
        _v3_api_arg('p_occurred_until',  'timestamptz', false),
