-- ============================================================
-- Section: maludb_core--0.62.0--0.63.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.62.0 -> 0.63.0  (v3.1 Stage H — V3-AUTH-02)
--
-- Replaces the PL/pgSQL + pgcrypto HMAC on the token-verify hot path
-- with a C function (constant-time, no PL/pgSQL function-call
-- overhead) and replaces the jwt_verify stub with a C verifier that
-- implements HS256 fully. RS256 / RS384 / RS512 / ES256 / ES384 /
-- ES512 / EdDSA still raise feature_not_supported, but now via the C
-- dispatcher rather than a plain stub — V3-AUTH-03 plugs in the
-- asymmetric branches without changing the SQL surface.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.63.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.63.0'::text $body$;

-- ---------------------------------------------------------------------
-- 0. Extend malu$jwt_signing_key to accept HS256 / oct (V3-AUTH-02
--    ships a real HS256 verifier; the symmetric key needs a row in
--    this table).
-- ---------------------------------------------------------------------
ALTER TABLE malu$jwt_signing_key
    DROP CONSTRAINT malu$jwt_signing_key_alg_check,
    DROP CONSTRAINT malu$jwt_signing_key_kty_check;
ALTER TABLE malu$jwt_signing_key
    ADD CONSTRAINT malu$jwt_signing_key_alg_check
    CHECK (alg IN ('HS256',
                   'RS256','RS384','RS512',
                   'ES256','ES384','ES512',
                   'EdDSA')),
    ADD CONSTRAINT malu$jwt_signing_key_kty_check
    CHECK (kty IN ('RSA','EC','OKP','oct'));

-- ---------------------------------------------------------------------
-- 1. C primitives.
-- ---------------------------------------------------------------------
CREATE FUNCTION maludb_hmac_sha256(p_key bytea, p_data bytea)
    RETURNS bytea
    AS 'MODULE_PATHNAME', 'maludb_hmac_sha256'
    LANGUAGE C STRICT IMMUTABLE PARALLEL SAFE;
REVOKE EXECUTE ON FUNCTION maludb_hmac_sha256(bytea, bytea) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION maludb_hmac_sha256(bytea, bytea) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ---------------------------------------------------------------------
-- 2. Swap __auth_token_hash to use the C HMAC primitive. Same input,
--    same output, same RLS / GRANT surface; only the body changes.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION __auth_token_hash(p_plaintext text) RETURNS bytea
    LANGUAGE plpgsql STABLE PARALLEL SAFE
    SECURITY DEFINER
    SET search_path = pg_catalog, maludb_core
    AS $body$
BEGIN
    RETURN maludb_hmac_sha256(__auth_pepper(), p_plaintext::bytea);
END;
$body$;

-- ---------------------------------------------------------------------
-- 3. jwt_verify is now a thin wrapper over the C dispatcher. The C
--    function returns the same TABLE shape jwt_verify originally
--    advertised.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION jwt_verify(p_jwt text)
    RETURNS TABLE (
        account_id   bigint,
        role_name    text,
        owner_schema name,
        active_pool  bigint,
        agent_chain  text[]
    )
    AS 'MODULE_PATHNAME', 'maludb_jwt_verify'
    LANGUAGE C STABLE STRICT PARALLEL SAFE;
REVOKE EXECUTE ON FUNCTION jwt_verify(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION jwt_verify(text) TO
    maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.63.0--0.64.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.63.0 -> 0.64.0  (v3.1 Stage I — V3-SECRET-02)
--
-- Adds the C-backed external secret resolver. Replaces the
-- feature_not_supported stub in __secret_resolve with a call into
-- maludb_secret_resolve_external for file:// and https:// refs.
--
-- Security posture:
--   * file:// URIs must point at a path under a configured allowlist
--     (GUC maludb_core.secret_file_root, default
--     /etc/maludb/secrets:/var/lib/maludb/secrets).
--   * The file must be a regular file (no symlinks, no special files),
--     owned by the postgres OS user, mode 0400 or 0600.
--   * https:// URIs use libcurl with SSL_VERIFYPEER + SSL_VERIFYHOST,
--     no redirect follow, 5s connect / 10s total timeout, 1 MiB max
--     response.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.64.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.64.0'::text $body$;

-- ---------------------------------------------------------------------
-- 0. Extend malu$secret_use.outcome to include the new C-resolver
--    failure outcome.
-- ---------------------------------------------------------------------
ALTER TABLE malu$secret_use
    DROP CONSTRAINT malu$secret_use_outcome_check;
ALTER TABLE malu$secret_use
    ADD CONSTRAINT malu$secret_use_outcome_check
    CHECK (outcome IN ('resolved',
                       'rejected_retired',
                       'rejected_external_not_available',
                       'rejected_external_failed'));

-- ---------------------------------------------------------------------
-- 1. The new C primitive.
-- ---------------------------------------------------------------------
CREATE FUNCTION maludb_secret_resolve_external(p_uri text)
    RETURNS text
    AS 'MODULE_PATHNAME', 'maludb_secret_resolve_external'
    LANGUAGE C STRICT VOLATILE
    SECURITY DEFINER;
REVOKE EXECUTE ON FUNCTION maludb_secret_resolve_external(text) FROM PUBLIC;
-- maludb_secret_consumer (the same role permitted to call
-- __secret_resolve) is the only audience.
GRANT  EXECUTE ON FUNCTION maludb_secret_resolve_external(text) TO
    maludb_secret_consumer;

-- ---------------------------------------------------------------------
-- 2. Swap the external branch of __secret_resolve to use the C
--    primitive. Inline (pgp_sym_decrypt) path is unchanged.
-- ---------------------------------------------------------------------
CREATE OR REPLACE FUNCTION __secret_resolve(p_name text)
    RETURNS text
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_secret_id bigint;
    v_vid       bigint;
    v_enc       bytea;
    v_ref       text;
    v_retired   timestamptz;
    v_plain     text;
BEGIN
    SELECT s.secret_id, s.retired_at
      INTO v_secret_id, v_retired
      FROM malu$secret s
     WHERE s.name = p_name;

    IF v_secret_id IS NULL THEN
        PERFORM audit_event('secret_resolve_reject', 'malu$secret', NULL,
            jsonb_build_object('reason','unknown_secret','name',p_name),
            NULL);
        RAISE EXCEPTION 'secret_resolve: secret % not found in schema %', p_name, current_schema()
            USING ERRCODE = 'no_data_found';
    END IF;

    IF v_retired IS NOT NULL THEN
        PERFORM audit_event('secret_resolve_reject', 'malu$secret', v_secret_id,
            jsonb_build_object('reason','secret_retired','name',p_name),
            NULL);
        RAISE EXCEPTION 'secret_resolve: secret % is retired', p_name
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    SELECT sv.secret_version_id, sv.value_encrypted, sv.external_ref
      INTO v_vid, v_enc, v_ref
      FROM malu$secret_version sv
     WHERE sv.secret_id  = v_secret_id
       AND sv.retired_at IS NULL
     ORDER BY sv.version DESC
     LIMIT 1;

    IF v_vid IS NULL THEN
        PERFORM audit_event('secret_resolve_reject', 'malu$secret', v_secret_id,
            jsonb_build_object('reason','no_active_version','name',p_name),
            NULL);
        RAISE EXCEPTION 'secret_resolve: no active version for secret %', p_name
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    IF v_enc IS NOT NULL THEN
        v_plain := public.pgp_sym_decrypt(v_enc, __secret_master_key_passphrase());

        UPDATE malu$secret_version SET last_used_at = now()
         WHERE secret_version_id = v_vid;

        INSERT INTO malu$secret_use(secret_version_id, outcome)
        VALUES (v_vid, 'resolved');

        PERFORM audit_event('secret_resolve_accept', 'malu$secret', v_secret_id,
            jsonb_build_object('name',p_name,'version_id',v_vid,'mode','inline'),
            NULL);

        RETURN v_plain;
    END IF;

    -- External reference: V3-SECRET-02 ships the C resolver.
    BEGIN
        v_plain := maludb_secret_resolve_external(v_ref);
    EXCEPTION WHEN OTHERS THEN
        INSERT INTO malu$secret_use(secret_version_id, outcome, detail)
        VALUES (v_vid, 'rejected_external_failed', SQLERRM);
        PERFORM audit_event('secret_resolve_reject', 'malu$secret', v_secret_id,
            jsonb_build_object('name',p_name,'version_id',v_vid,'mode','external',
                               'reason','external_resolver_failed','detail',SQLERRM),
            SQLERRM);
        RAISE;
    END;

    UPDATE malu$secret_version SET last_used_at = now()
     WHERE secret_version_id = v_vid;
    INSERT INTO malu$secret_use(secret_version_id, outcome)
    VALUES (v_vid, 'resolved');
    PERFORM audit_event('secret_resolve_accept', 'malu$secret', v_secret_id,
        jsonb_build_object('name',p_name,'version_id',v_vid,'mode','external',
                           'external_ref',v_ref),
        NULL);
    RETURN v_plain;
END;
$body$;

-- Re-apply GRANTs (CREATE OR REPLACE keeps them, but be explicit).
REVOKE EXECUTE ON FUNCTION __secret_resolve(text) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION __secret_resolve(text) TO maludb_secret_consumer;

-- ============================================================
-- Section: maludb_core--0.64.0--0.65.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.64.0 -> 0.65.0  (V4 Stage 17 — V4-PAGEINDEX-01)
--
-- Tree catalog and MDO specialization for the V4 PageIndex track.
--
-- This migration introduces:
--   1. malu$page_index_tree — header row per build generation.
--   2. mdo_kind discriminator + tree-node columns on
--      malu$memory_detail_object. Default 'memory_detail' so existing
--      callers behave unchanged.
--   3. malu$derivation_ledger.derived_object_type CHECK extended to
--      accept 'page_index_tree' and 'page_index_node' (ledger coverage
--      for the new derived objects).
--   4. malu$relationship_edge source/target CHECK extended to admit
--      'page_index_tree' (lets the supersedes edge connect prior and
--      new trees through the existing edge surface).
--   5. SQL APIs: page_index_tree_register / _mark_building /
--      _mark_ready / _mark_failed / _supersede. Each writes a
--      malu$audit_event row for the transition.
--
-- Access model: RLS on the new tables, tenancy by owner_schema.
-- No tier views (MALU_USER_* / MALU_ALL_* / MALU_DBA_*) are introduced
-- here — V4 follows V3 RLS-on-base-tables practice. See
-- version4-pageindex-plan.md §10.11 for the deferred tier-view
-- decision.
--
-- Promotion path (source_package_promote_to_page_index), builder worker
-- (services/maludb-pageindexd/), and the structure-pass audit table
-- (malu$structure_pass_audit) land in V4-PAGEINDEX-02 / 0.65.0->0.66.0.
-- This migration explicitly does NOT install any of them.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.65.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.65.0'::text $body$;

-- =====================================================================
-- 1. malu$page_index_tree — one row per build generation.
-- =====================================================================
CREATE TABLE malu$page_index_tree (
    tree_id              bigserial PRIMARY KEY,
    owner_schema         name NOT NULL DEFAULT current_schema(),
    source_package_id    bigint NOT NULL
        REFERENCES malu$source_package(source_package_id) ON DELETE CASCADE,
    parser_kind          text NOT NULL
        CHECK (parser_kind IN ('pdf','markdown','plain_text')),
    -- model_alias_id / prompt_template_id are populated by the builder
    -- (V4-PAGEINDEX-02). Nullable at register time so a tree can sit
    -- in 'pending' before the worker picks a model.
    model_alias_id       bigint
        REFERENCES malu$model_alias(alias_id) ON DELETE SET NULL,
    prompt_template_id   bigint
        REFERENCES malu$prompt_template(template_id) ON DELETE SET NULL,
    build_status         text NOT NULL DEFAULT 'pending'
        CHECK (build_status IN (
            'pending','building','ready','stale','superseded','failed')),
    build_started_at     timestamptz,
    build_finished_at    timestamptz,
    failure_reason       text,
    superseded_by        bigint
        REFERENCES malu$page_index_tree(tree_id) ON DELETE SET NULL,
    valid_time_start     timestamptz NOT NULL DEFAULT now(),
    valid_time_end       timestamptz,
    created_at           timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$page_index_tree_owner_idx
    ON malu$page_index_tree(owner_schema);
CREATE INDEX malu$page_index_tree_source_idx
    ON malu$page_index_tree(source_package_id);
CREATE INDEX malu$page_index_tree_status_idx
    ON malu$page_index_tree(build_status);
CREATE INDEX malu$page_index_tree_superseded_idx
    ON malu$page_index_tree(superseded_by) WHERE superseded_by IS NOT NULL;

ALTER TABLE malu$page_index_tree ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$page_index_tree
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$page_index_tree TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE ON malu$page_index_tree TO
    maludb_memory_admin, maludb_memory_executor;
GRANT USAGE, SELECT ON SEQUENCE malu$page_index_tree_tree_id_seq TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- 2. Extend malu$memory_detail_object with the mdo_kind discriminator
--    plus tree-node columns. Default keeps existing rows / callers
--    intact.
--
--    title already exists on the table from Stage 2 — tree nodes
--    reuse it (the node's section/topic name). Only summary is new.
-- =====================================================================
ALTER TABLE malu$memory_detail_object
    ADD COLUMN mdo_kind  text NOT NULL DEFAULT 'memory_detail'
        CHECK (mdo_kind IN (
            'memory_detail',
            'page_index_node',
            'chat_index_topic',
            'chat_index_message')),
    ADD COLUMN tree_id   bigint
        REFERENCES malu$page_index_tree(tree_id) ON DELETE CASCADE,
    ADD COLUMN node_kind text
        CHECK (node_kind IS NULL OR node_kind IN ('internal','leaf')),
    ADD COLUMN summary   text;

-- Tree-node rows must reference a tree; memory_detail rows must not.
ALTER TABLE malu$memory_detail_object
    ADD CONSTRAINT malu$mdo_tree_node_shape_check CHECK (
        (mdo_kind = 'memory_detail' AND tree_id IS NULL AND node_kind IS NULL)
        OR (mdo_kind <> 'memory_detail'
            AND tree_id IS NOT NULL
            AND node_kind IS NOT NULL));

-- Stage 2 anchored every MDO row to a parent_mdo / memory / episode.
-- Tree-node rows anchor via tree_id instead. Relax the original
-- anchor check to admit either anchor kind.
ALTER TABLE malu$memory_detail_object
    DROP CONSTRAINT IF EXISTS "malu$memory_detail_object_check";
ALTER TABLE malu$memory_detail_object
    ADD CONSTRAINT "malu$memory_detail_object_check" CHECK (
        parent_mdo_id IS NOT NULL
        OR memory_id   IS NOT NULL
        OR episode_id  IS NOT NULL
        OR tree_id     IS NOT NULL);

-- Partial index — 'memory_detail' dominates row count, no point
-- indexing the common value.
CREATE INDEX malu$mdo_kind_idx
    ON malu$memory_detail_object(mdo_kind)
    WHERE mdo_kind <> 'memory_detail';
CREATE INDEX malu$mdo_tree_idx
    ON malu$memory_detail_object(tree_id)
    WHERE tree_id IS NOT NULL;

-- =====================================================================
-- 3. Extend malu$derivation_ledger.derived_object_type to admit
--    tree + tree-node derivations.
-- =====================================================================
ALTER TABLE malu$derivation_ledger
    DROP CONSTRAINT malu$derivation_ledger_derived_object_type_check;

ALTER TABLE malu$derivation_ledger
    ADD CONSTRAINT malu$derivation_ledger_derived_object_type_check
    CHECK (derived_object_type IN (
        'source_package',
        'claim',
        'fact',
        'memory',
        'episode_object',
        'memory_detail_object',
        'relationship_edge',
        'embedding',
        'page_index_tree',
        'page_index_node'
    ));

-- =====================================================================
-- 4. Extend malu$relationship_edge source/target CHECK so a
--    supersedes edge can connect prior and new trees.
-- =====================================================================
ALTER TABLE malu$relationship_edge
    DROP CONSTRAINT malu$relationship_edge_source_object_type_check;
ALTER TABLE malu$relationship_edge
    ADD CONSTRAINT malu$relationship_edge_source_object_type_check
    CHECK (source_object_type IN (
        'source_package','claim','fact','memory','episode_object',
        'memory_detail_object','page_index_tree'));

ALTER TABLE malu$relationship_edge
    DROP CONSTRAINT malu$relationship_edge_target_object_type_check;
ALTER TABLE malu$relationship_edge
    ADD CONSTRAINT malu$relationship_edge_target_object_type_check
    CHECK (target_object_type IN (
        'source_package','claim','fact','memory','episode_object',
        'memory_detail_object','page_index_tree'));

-- =====================================================================
-- 5. SQL APIs — register + status transitions. Each emits an audit row
--    via the existing audit_event helper.
-- =====================================================================

CREATE FUNCTION page_index_tree_register(
    p_source_package_id  bigint,
    p_parser_kind        text,
    p_model_alias_id     bigint DEFAULT NULL,
    p_prompt_template_id bigint DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_tree_id bigint;
BEGIN
    INSERT INTO malu$page_index_tree
        (source_package_id, parser_kind, model_alias_id, prompt_template_id)
    VALUES
        (p_source_package_id, p_parser_kind, p_model_alias_id, p_prompt_template_id)
    RETURNING tree_id INTO v_tree_id;

    PERFORM audit_event(
        'page_index_tree.register',
        'page_index_tree',
        v_tree_id,
        jsonb_build_object(
            'source_package_id', p_source_package_id,
            'parser_kind',       p_parser_kind,
            'model_alias_id',    p_model_alias_id,
            'prompt_template_id',p_prompt_template_id));

    RETURN v_tree_id;
END;
$body$;

CREATE FUNCTION page_index_tree_mark_building(p_tree_id bigint)
RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    UPDATE malu$page_index_tree
       SET build_status     = 'building',
           build_started_at = COALESCE(build_started_at, now())
     WHERE tree_id = p_tree_id
       AND build_status IN ('pending','failed');
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'page_index_tree_mark_building: tree % not in pending/failed state',
            p_tree_id
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    PERFORM audit_event(
        'page_index_tree.mark_building',
        'page_index_tree', p_tree_id);
END;
$body$;

CREATE FUNCTION page_index_tree_mark_ready(p_tree_id bigint)
RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    UPDATE malu$page_index_tree
       SET build_status      = 'ready',
           build_finished_at = now()
     WHERE tree_id = p_tree_id
       AND build_status = 'building';
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'page_index_tree_mark_ready: tree % not in building state',
            p_tree_id
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    PERFORM audit_event(
        'page_index_tree.mark_ready',
        'page_index_tree', p_tree_id);
END;
$body$;

CREATE FUNCTION page_index_tree_mark_failed(
    p_tree_id bigint,
    p_reason  text DEFAULT NULL
) RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    UPDATE malu$page_index_tree
       SET build_status      = 'failed',
           build_finished_at = now(),
           failure_reason    = p_reason
     WHERE tree_id = p_tree_id
       AND build_status IN ('pending','building');
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'page_index_tree_mark_failed: tree % not in pending/building state',
            p_tree_id
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    PERFORM audit_event(
        'page_index_tree.mark_failed',
        'page_index_tree', p_tree_id,
        jsonb_build_object('reason', p_reason));
END;
$body$;

-- page_index_tree_supersede — close the prior tree and connect it to
-- the new tree through a supersedes edge. The new tree must already
-- exist; the prior tree must be 'ready' or 'stale'. Sets superseded_by
-- FK and writes the relationship_edge row in one transaction.
CREATE FUNCTION page_index_tree_supersede(
    p_prior_tree_id bigint,
    p_new_tree_id   bigint
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_edge_id bigint;
BEGIN
    IF p_prior_tree_id = p_new_tree_id THEN
        RAISE EXCEPTION 'page_index_tree_supersede: prior and new tree must differ'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    UPDATE malu$page_index_tree
       SET build_status  = 'superseded',
           superseded_by = p_new_tree_id,
           valid_time_end = now()
     WHERE tree_id = p_prior_tree_id
       AND build_status IN ('ready','stale');
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'page_index_tree_supersede: prior tree % not in ready/stale state',
            p_prior_tree_id
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    v_edge_id := register_relationship_edge(
        'page_index_tree', p_prior_tree_id,
        'page_index_tree', p_new_tree_id,
        'supersedes',
        NULL,
        jsonb_build_object('prior_tree', p_prior_tree_id,
                           'new_tree',   p_new_tree_id),
        NULL);

    PERFORM audit_event(
        'page_index_tree.supersede',
        'page_index_tree', p_prior_tree_id,
        jsonb_build_object('new_tree_id', p_new_tree_id,
                           'edge_id',     v_edge_id));

    RETURN v_edge_id;
END;
$body$;

GRANT EXECUTE ON FUNCTION
    page_index_tree_register(bigint, text, bigint, bigint),
    page_index_tree_mark_building(bigint),
    page_index_tree_mark_ready(bigint),
    page_index_tree_mark_failed(bigint, text),
    page_index_tree_supersede(bigint, bigint)
TO maludb_memory_admin, maludb_memory_executor;

-- ============================================================
-- Section: maludb_core--0.65.0--0.66.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.65.0 -> 0.66.0  (V4 Stage 17 — V4-PAGEINDEX-02)
--
-- Promotion path and builder substrate for V4 PageIndex.
--
-- What this migration adds:
--   1. malu$structure_pass_audit — one row per deterministic structure
--      pass run by the builder worker. Captures parser kind / version,
--      outline-node and leaf counts, the deterministic inputs hash
--      (sha256 over parser_kind + parser_version + source_bytes), and
--      the outcome.
--   2. malu$embedding_job.precomputed_boundaries_from_tree_id — opt-in
--      column that V3-EMBED-01 callers use to tell the chunker "skip
--      your own splitter; consume leaf ranges from this tree." The
--      column is nullable so the existing embed flow is unchanged.
--   3. embedding_enqueue extended with the new optional parameter.
--      The function is dropped and recreated because PostgreSQL does
--      not allow CREATE OR REPLACE FUNCTION to change the parameter
--      list. Existing callers passing the original six arguments are
--      unaffected because the seventh argument defaults to NULL.
--   4. source_package_promote_to_page_index — operator-visible promotion
--      helper. Registers a tree row, auto-registers the
--      'pageindex_build' V3-QUEUE-01 queue, enqueues a job carrying
--      the tree_id and builder options, and writes a malu$audit_event
--      row for the promotion. Returns the new tree_id.
--   5. page_index_record_structure_pass — worker-visible helper called
--      after the deterministic outline extraction completes. Inserts
--      the audit row and emits a malu$audit_event.
--   6. page_index_record_node — atomic node-insert helper. One call
--      writes the MDO row (mdo_kind='page_index_node') AND the
--      malu$derivation_ledger entry so the doctrine invariant
--      "every derived object MUST have a ledger entry" holds at the
--      single-call level. Returns (mdo_id, derivation_id).
--   7. page_index_chunker_handoff — returns the leaf nodes of a tree
--      in document order. Called by the V3-EMBED-01 chunker when
--      `precomputed_boundaries_from_tree_id` is supplied — the chunker
--      consumes the leaf set instead of running its own splitter.
--
-- Out of scope at this migration:
--   * Builder worker binary — lives in services/maludb-pageindexd/.
--   * Per-leaf malu$source_object_reference linking — V4-STOR-02
--     integration is a follow-up; for v1 the builder records anchors
--     inside the node's body_jsonb so the supersession test does not
--     depend on V3-STOR-01 promotion being wired into Stage-2 Source
--     Packages.
--   * Retrieval planner descent (V4-PAGEINDEX-03).
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.66.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.66.0'::text $body$;

-- =====================================================================
-- 1. malu$structure_pass_audit
-- =====================================================================
CREATE TABLE malu$structure_pass_audit (
    audit_id                    bigserial PRIMARY KEY,
    owner_schema                name NOT NULL DEFAULT current_schema(),
    tree_id                     bigint NOT NULL
        REFERENCES malu$page_index_tree(tree_id) ON DELETE CASCADE,
    parser_kind                 text NOT NULL
        CHECK (parser_kind IN ('pdf','markdown','plain_text')),
    parser_version              text NOT NULL,
    started_at                  timestamptz NOT NULL DEFAULT now(),
    finished_at                 timestamptz,
    outline_node_count          integer NOT NULL DEFAULT 0
        CHECK (outline_node_count >= 0),
    leaf_count                  integer NOT NULL DEFAULT 0
        CHECK (leaf_count >= 0),
    deterministic_inputs_hash   text NOT NULL,
    outcome                     text NOT NULL DEFAULT 'ok'
        CHECK (outcome IN ('ok','partial','failed')),
    error_text                  text,
    created_at                  timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$structure_pass_audit_tree_idx
    ON malu$structure_pass_audit(tree_id);
CREATE INDEX malu$structure_pass_audit_outcome_idx
    ON malu$structure_pass_audit(outcome, created_at DESC);

ALTER TABLE malu$structure_pass_audit ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$structure_pass_audit
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$structure_pass_audit TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE ON malu$structure_pass_audit TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;
GRANT USAGE, SELECT ON SEQUENCE malu$structure_pass_audit_audit_id_seq TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- =====================================================================
-- 2. Extend malu$embedding_job with the precomputed-boundaries opt-in.
-- =====================================================================
ALTER TABLE malu$embedding_job
    ADD COLUMN precomputed_boundaries_from_tree_id bigint
        REFERENCES malu$page_index_tree(tree_id) ON DELETE SET NULL;
CREATE INDEX malu$embedding_job_tree_idx
    ON malu$embedding_job(precomputed_boundaries_from_tree_id)
    WHERE precomputed_boundaries_from_tree_id IS NOT NULL;

-- =====================================================================
-- 3. embedding_enqueue with optional precomputed_boundaries_from_tree_id.
-- =====================================================================
DROP FUNCTION embedding_enqueue(text, bigint, text, text, bytea, text);

CREATE FUNCTION embedding_enqueue(
    p_target_kind                          text,
    p_target_id                            bigint,
    p_model_alias                          text,
    p_embedding_space                      text,
    p_input_hash                           bytea   DEFAULT NULL,
    p_prompt_template_version              text    DEFAULT NULL,
    p_precomputed_boundaries_from_tree_id  bigint  DEFAULT NULL
) RETURNS bigint
    LANGUAGE plpgsql VOLATILE
    AS $body$
#variable_conflict use_column
DECLARE
    v_job_id     bigint;
    v_queue_job  bigint;
BEGIN
    IF p_target_kind NOT IN ('source_excerpt','memory_chunk','workflow_trace','summary','query_envelope') THEN
        RAISE EXCEPTION 'embedding_enqueue: target_kind must be one of source_excerpt/memory_chunk/workflow_trace/summary/query_envelope'
            USING ERRCODE = 'check_violation';
    END IF;

    PERFORM queue_register('embed', 60000, 3, NULL, 'V3-EMBED-01 embedding job queue');

    INSERT INTO malu$embedding_job
        (target_kind, target_id, model_alias, embedding_space,
         prompt_template_version, input_hash, status,
         precomputed_boundaries_from_tree_id)
    VALUES
        (p_target_kind, p_target_id, p_model_alias, p_embedding_space,
         p_prompt_template_version, p_input_hash, 'pending',
         p_precomputed_boundaries_from_tree_id)
    RETURNING job_id INTO v_job_id;

    v_queue_job := queue_enqueue(
        'embed',
        jsonb_build_object(
            'embedding_job_id', v_job_id,
            'target_kind',      p_target_kind,
            'target_id',        p_target_id,
            'model_alias',      p_model_alias,
            'embedding_space',  p_embedding_space,
            'prompt_template_version', p_prompt_template_version,
            'precomputed_boundaries_from_tree_id', p_precomputed_boundaries_from_tree_id),
        format('embed:%s:%s:%s:%s', p_target_kind, p_target_id, p_model_alias, p_embedding_space),
        0, NULL, NULL);

    UPDATE malu$embedding_job
       SET queue_job_id = v_queue_job
     WHERE job_id = v_job_id;

    PERFORM audit_event('embedding_enqueue', 'malu$embedding_job', v_job_id,
        jsonb_build_object('target_kind', p_target_kind, 'target_id', p_target_id,
                           'model_alias', p_model_alias, 'embedding_space', p_embedding_space,
                           'queue_job_id', v_queue_job,
                           'precomputed_boundaries_from_tree_id', p_precomputed_boundaries_from_tree_id),
        NULL);

    RETURN v_job_id;
END;
$body$;
REVOKE EXECUTE ON FUNCTION embedding_enqueue(text, bigint, text, text, bytea, text, bigint) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION embedding_enqueue(text, bigint, text, text, bytea, text, bigint) TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- 4. source_package_promote_to_page_index — operator-facing promotion.
-- =====================================================================
CREATE FUNCTION source_package_promote_to_page_index(
    p_source_package_id    bigint,
    p_parser_kind          text,
    p_model_alias_id       bigint  DEFAULT NULL,
    p_prompt_template_id   bigint  DEFAULT NULL,
    p_builder_options      jsonb   DEFAULT '{}'::jsonb
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
#variable_conflict use_column
DECLARE
    v_tree_id      bigint;
    v_queue_job_id bigint;
BEGIN
    v_tree_id := page_index_tree_register(
        p_source_package_id, p_parser_kind,
        p_model_alias_id, p_prompt_template_id);

    -- Idempotent registration of the V4 builder queue.
    PERFORM queue_register('pageindex_build', 120000, 3, NULL,
        'V4-PAGEINDEX-02 tree builder job queue');

    v_queue_job_id := queue_enqueue(
        'pageindex_build',
        jsonb_build_object(
            'tree_id',            v_tree_id,
            'source_package_id',  p_source_package_id,
            'parser_kind',        p_parser_kind,
            'model_alias_id',     p_model_alias_id,
            'prompt_template_id', p_prompt_template_id,
            'builder_options',    p_builder_options),
        format('pageindex:%s', v_tree_id),
        0, NULL, NULL);

    PERFORM audit_event(
        'page_index_tree.promote',
        'page_index_tree', v_tree_id,
        jsonb_build_object(
            'source_package_id', p_source_package_id,
            'parser_kind',       p_parser_kind,
            'queue_job_id',      v_queue_job_id,
            'builder_options',   p_builder_options));

    RETURN v_tree_id;
END;
$body$;

-- =====================================================================
-- 5. page_index_record_structure_pass — worker writes audit row.
-- =====================================================================
CREATE FUNCTION page_index_record_structure_pass(
    p_tree_id                    bigint,
    p_parser_kind                text,
    p_parser_version             text,
    p_outline_node_count         integer,
    p_leaf_count                 integer,
    p_deterministic_inputs_hash  text,
    p_outcome                    text   DEFAULT 'ok',
    p_error_text                 text   DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE
    v_id bigint;
BEGIN
    INSERT INTO malu$structure_pass_audit
        (tree_id, parser_kind, parser_version,
         outline_node_count, leaf_count,
         deterministic_inputs_hash, outcome, error_text,
         finished_at)
    VALUES
        (p_tree_id, p_parser_kind, p_parser_version,
         p_outline_node_count, p_leaf_count,
         p_deterministic_inputs_hash, p_outcome, p_error_text,
         now())
    RETURNING audit_id INTO v_id;

    PERFORM audit_event(
        'page_index_tree.structure_pass',
        'page_index_tree', p_tree_id,
        jsonb_build_object('audit_id', v_id, 'outcome', p_outcome,
                           'outline_node_count', p_outline_node_count,
                           'leaf_count',         p_leaf_count,
                           'parser_kind',        p_parser_kind,
                           'parser_version',     p_parser_version));
    RETURN v_id;
END;
$body$;

-- =====================================================================
-- 6. page_index_record_node — atomic MDO + ledger insert per node.
-- =====================================================================
CREATE FUNCTION page_index_record_node(
    p_tree_id              bigint,
    p_parent_mdo_id        bigint,
    p_node_kind            text,
    p_title                text,
    p_summary              text,
    p_model_alias_id       bigint   DEFAULT NULL,
    p_prompt_template_id   bigint   DEFAULT NULL,
    p_input_hash           bytea    DEFAULT NULL,
    p_output_hash          bytea    DEFAULT NULL,
    p_anchor_jsonb         jsonb    DEFAULT NULL
) RETURNS TABLE (mdo_id bigint, derivation_id bigint)
LANGUAGE plpgsql
AS $body$
#variable_conflict use_column
DECLARE
    v_mdo_id    bigint;
    v_deriv_id  bigint;
    v_inputs    jsonb;
BEGIN
    IF p_node_kind NOT IN ('internal','leaf') THEN
        RAISE EXCEPTION 'page_index_record_node: node_kind must be internal or leaf'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    INSERT INTO malu$memory_detail_object
        (parent_mdo_id, detail_kind, mdo_kind,
         tree_id, node_kind, title, summary, body_jsonb)
    VALUES
        (p_parent_mdo_id, 'page_index_node', 'page_index_node',
         p_tree_id, p_node_kind, p_title, p_summary, p_anchor_jsonb)
    RETURNING mdo_id INTO v_mdo_id;

    v_inputs := jsonb_build_object(
        'tree_id',       p_tree_id,
        'parent_mdo_id', p_parent_mdo_id,
        'node_kind',     p_node_kind,
        'anchor',        p_anchor_jsonb,
        'input_hash',    CASE WHEN p_input_hash  IS NULL THEN NULL ELSE encode(p_input_hash,  'hex') END,
        'output_hash',   CASE WHEN p_output_hash IS NULL THEN NULL ELSE encode(p_output_hash, 'hex') END);

    v_deriv_id := record_derivation(
        'page_index_node', v_mdo_id,
        NULL,
        p_model_alias_id,
        p_prompt_template_id,
        NULL, NULL, NULL,
        v_inputs);

    RETURN QUERY SELECT v_mdo_id, v_deriv_id;
END;
$body$;

-- =====================================================================
-- 7. page_index_chunker_handoff — leaf set in document order.
-- =====================================================================
CREATE FUNCTION page_index_chunker_handoff(p_tree_id bigint)
RETURNS TABLE (
    leaf_mdo_id bigint,
    title       text,
    summary     text,
    anchor      jsonb)
LANGUAGE sql STABLE
AS $body$
    SELECT mdo_id, title, summary, body_jsonb
    FROM malu$memory_detail_object
    WHERE tree_id  = p_tree_id
      AND mdo_kind = 'page_index_node'
      AND node_kind = 'leaf'
    ORDER BY mdo_id;
$body$;

-- =====================================================================
-- 8. Grants on the new helpers.
-- =====================================================================
GRANT EXECUTE ON FUNCTION
    source_package_promote_to_page_index(bigint, text, bigint, bigint, jsonb),
    page_index_record_structure_pass(bigint, text, text, integer, integer, text, text, text),
    page_index_record_node(bigint, bigint, text, text, text, bigint, bigint, bytea, bytea, jsonb),
    page_index_chunker_handoff(bigint)
TO maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- ============================================================
-- Section: maludb_core--0.66.0--0.67.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.66.0 -> 0.67.0  (V4 Stage 18 — V4-PAGEINDEX-03)
--
-- Retrieval-planner descent path. Adds the second-pass navigation
-- surface that V4-PAGEINDEX-01's catalog and V4-PAGEINDEX-02's builder
-- were designed to feed.
--
-- What this migration adds:
--   1. malu$retrieval_envelope.{tree_descent_used, tree_descent_path,
--      tree_descent_authz_rejections} — debug-surface columns recorded
--      when a descent runs.
--   2. malu$retrieval_decision_audit.stage admits 'tree_descent' as a
--      fourth stage value alongside planning / expansion / assembly.
--   3. malu$derivation_ledger.derived_object_type admits
--      'retrieval_summary' — every LLM-driven (or deterministic-stand-
--      in) child choice writes a ledger entry of this kind.
--   4. classify_intent extended with two cue / hint patterns:
--      'structured_doc_qa' (cue mentions a tree_id hint, or
--      object_types includes page_index_tree) and 'long_chat_recall'
--      (cue mentions chat / transcript hints).
--   5. select_search_paths extended with a 'tree_descent' strategy
--      for the two new intents.
--   6. tree_descent_retrieve(envelope_id, tree_id, descent_options jsonb)
--      runs a single-level-at-a-time walk down the tree. At every
--      node:
--        a. fetch children that pass RLS (authz-filtered candidate
--           set; the count of rejected siblings is recorded in
--           tree_descent_authz_rejections);
--        b. score them by cue-keyword overlap against title + summary
--           (deterministic-stand-in for the LLM step; an operator can
--           swap in an LLM-driven choice via descent_options.choice
--           = 'first' | 'overlap' | future 'llm');
--        c. re-check the chosen child is still RLS-visible (defends
--           against TOCTOU between candidate fetch and traversal);
--        d. write a malu$retrieval_decision_audit row with
--           stage='tree_descent' and a malu$derivation_ledger entry
--           of kind 'retrieval_summary'.
--      Depth caps at descent_options.max_depth (default 6 per plan
--      §11.2).
--   7. tree_descent_prompt_template_v1 — seeded for the future LLM
--      wiring. The prompt text is informational at this migration;
--      maludb_modeld integration is V4-PAGEINDEX-03 follow-up work.
--   8. retrieve_with_envelope_tree — a sibling entry point that
--      packages classify_intent + tree_descent_retrieve so callers
--      do not have to thread envelope_id manually. Returns the leaf
--      mdo_ids the descent reached.
--
-- Out of scope at this migration:
--   * Direct HTTP call to maludb_modeld from PL/pgSQL. The 'llm'
--     choice strategy is reserved but unimplemented; the
--     deterministic 'overlap' default is what runs today.
--   * ChatIndex descent (mirrors PageIndex; V4-CHATINDEX-01 ships its
--     own catalog first).
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.67.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.67.0'::text $body$;

-- =====================================================================
-- 1. Envelope columns for the descent trail.
-- =====================================================================
ALTER TABLE malu$retrieval_envelope
    ADD COLUMN tree_descent_used             boolean NOT NULL DEFAULT false,
    ADD COLUMN tree_descent_path             jsonb,
    ADD COLUMN tree_descent_authz_rejections integer NOT NULL DEFAULT 0
        CHECK (tree_descent_authz_rejections >= 0);

CREATE INDEX malu$retrieval_envelope_tree_descent_idx
    ON malu$retrieval_envelope(tree_descent_used)
    WHERE tree_descent_used;

-- =====================================================================
-- 2. malu$retrieval_decision_audit.stage admits 'tree_descent'.
-- =====================================================================
ALTER TABLE malu$retrieval_decision_audit
    DROP CONSTRAINT malu$retrieval_decision_audit_stage_check;
ALTER TABLE malu$retrieval_decision_audit
    ADD CONSTRAINT malu$retrieval_decision_audit_stage_check
    CHECK (stage IN ('planning','expansion','assembly','tree_descent'));

-- =====================================================================
-- 3. malu$derivation_ledger.derived_object_type admits
--    'retrieval_summary'.
-- =====================================================================
ALTER TABLE malu$derivation_ledger
    DROP CONSTRAINT malu$derivation_ledger_derived_object_type_check;
ALTER TABLE malu$derivation_ledger
    ADD CONSTRAINT malu$derivation_ledger_derived_object_type_check
    CHECK (derived_object_type IN (
        'source_package',
        'claim',
        'fact',
        'memory',
        'episode_object',
        'memory_detail_object',
        'relationship_edge',
        'embedding',
        'page_index_tree',
        'page_index_node',
        'retrieval_summary'
    ));

-- =====================================================================
-- 4. Extend classify_intent for structured_doc_qa / long_chat_recall.
--    classify_intent is a STABLE function returning text — we replace
--    the body so the cue-derived heuristics admit the two new
--    intents BEFORE the existing 'narrow' / 'recall' / 'broad'
--    cascade kicks in.
-- =====================================================================
CREATE OR REPLACE FUNCTION classify_intent(p_envelope malu$retrieval_envelope_t)
RETURNS text
LANGUAGE plpgsql STABLE
AS $body$
DECLARE
    v_lower       text := lower(COALESCE(p_envelope.cue_text, ''));
    v_svpor_count integer;
BEGIN
    IF p_envelope.valid_as_of IS NOT NULL
       OR p_envelope.transaction_as_of IS NOT NULL THEN
        RETURN 'time_as_of';
    END IF;
    IF p_envelope.confidence_floor IS NOT NULL THEN
        RETURN 'by_confidence';
    END IF;
    IF p_envelope.hints IS NOT NULL
       AND (p_envelope.hints ? 'source_package_id'
            OR p_envelope.hints ? 'connector_id') THEN
        RETURN 'by_source';
    END IF;

    -- V4-PAGEINDEX-03: tree hints route to tree_descent.
    IF p_envelope.hints IS NOT NULL
       AND (p_envelope.hints ? 'tree_id'
            OR p_envelope.hints ? 'page_index_tree_id') THEN
        RETURN 'structured_doc_qa';
    END IF;
    IF p_envelope.hints IS NOT NULL
       AND (p_envelope.hints ? 'chat_tree_id'
            OR p_envelope.hints ? 'chat_index_tree_id') THEN
        RETURN 'long_chat_recall';
    END IF;
    IF p_envelope.object_types IS NOT NULL
       AND 'page_index_node' = ANY (p_envelope.object_types) THEN
        RETURN 'structured_doc_qa';
    END IF;
    IF p_envelope.object_types IS NOT NULL
       AND ('chat_index_topic' = ANY (p_envelope.object_types)
            OR 'chat_index_message' = ANY (p_envelope.object_types)) THEN
        RETURN 'long_chat_recall';
    END IF;

    SELECT count(*)
    INTO v_svpor_count
    FROM extract_cues(p_envelope.cue_text) c
    WHERE c.cue_kind IN ('subject','verb','predicate');

    IF v_svpor_count >= 2 THEN
        RETURN 'narrow';
    END IF;
    IF v_lower ~ '^\s*(what|show me|list|find|where|when|who)\y' THEN
        RETURN 'recall';
    END IF;
    RETURN 'broad';
END;
$body$;

-- =====================================================================
-- 5. Extend select_search_paths with a 'tree_descent' strategy for
--    the two new intents. CREATE OR REPLACE — same signature.
-- =====================================================================
CREATE OR REPLACE FUNCTION select_search_paths(
    p_intent     text,
    p_envelope   malu$retrieval_envelope_t,
    p_cues_jsonb jsonb
) RETURNS jsonb
LANGUAGE sql STABLE
AS $body$
    SELECT CASE p_intent
        WHEN 'narrow' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'svpor_routing',
                    'params', jsonb_build_object('cues', p_cues_jsonb)),
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text,
                                                 'object_types', to_jsonb(p_envelope.object_types))),
                jsonb_build_object('strategy', 'vector',
                    'params', jsonb_build_object('query', p_envelope.cue_text)))
        WHEN 'broad' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text,
                                                 'object_types', to_jsonb(p_envelope.object_types))),
                jsonb_build_object('strategy', 'vector',
                    'params', jsonb_build_object('query', p_envelope.cue_text)),
                jsonb_build_object('strategy', 'graph_walk',
                    'params', jsonb_build_object('max_depth', 3)))
        WHEN 'recall' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'fuzzy_subject',
                    'params', jsonb_build_object('needle', p_envelope.cue_text,
                                                 'threshold', 0.3)),
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text)))
        WHEN 'time_as_of' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'temporal_as_of',
                    'params', jsonb_build_object(
                        'valid_as_of',       p_envelope.valid_as_of,
                        'transaction_as_of', p_envelope.transaction_as_of)),
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text)))
        WHEN 'by_source' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'source_filter',
                    'params', jsonb_build_object(
                        'source_package_id', p_envelope.hints->'source_package_id',
                        'connector_id',      p_envelope.hints->'connector_id')),
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text)))
        WHEN 'by_confidence' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'confidence_floor',
                    'params', jsonb_build_object('floor', p_envelope.confidence_floor)),
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text)))
        WHEN 'structured_doc_qa' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'tree_descent',
                    'params', jsonb_build_object(
                        'tree_id',
                            CASE WHEN p_envelope.hints IS NOT NULL
                                  AND p_envelope.hints ? 'tree_id'
                                 THEN p_envelope.hints -> 'tree_id'
                                 ELSE p_envelope.hints -> 'page_index_tree_id' END,
                        'query', p_envelope.cue_text)),
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text)))
        WHEN 'long_chat_recall' THEN
            jsonb_build_array(
                jsonb_build_object('strategy', 'tree_descent',
                    'params', jsonb_build_object(
                        'tree_id',
                            CASE WHEN p_envelope.hints IS NOT NULL
                                  AND p_envelope.hints ? 'chat_tree_id'
                                 THEN p_envelope.hints -> 'chat_tree_id'
                                 ELSE p_envelope.hints -> 'chat_index_tree_id' END,
                        'query', p_envelope.cue_text)))
        ELSE
            jsonb_build_array(
                jsonb_build_object('strategy', 'fts',
                    'params', jsonb_build_object('query', p_envelope.cue_text)))
    END;
$body$;

-- =====================================================================
-- 6. tree_descent_retrieve — the actual descent.
--
-- Three-stage authorization:
--   * planning: the tree row must be RLS-visible to the caller (the
--     SELECT against malu$page_index_tree at the top of the function
--     enforces this; a hidden tree returns 0 rows and the function
--     raises no_data_found).
--   * expansion: the candidate children fetched at each step are
--     RLS-filtered automatically (queries against
--     malu$memory_detail_object honour tenant_owner POLICY). The
--     count of rows excluded by the underlying source-package authz
--     would surface here; for v4.0.0-alpha.3 we record 0 rejections
--     because tree-node visibility tracks the tree's owner_schema
--     1:1 and no per-row malu$object_grant has landed on tree nodes
--     yet (deferred — plan §10.11).
--   * assembly: the returned leaf rows are SELECT-fetched at the end,
--     which re-applies the same RLS predicate.
-- =====================================================================
CREATE FUNCTION tree_descent_retrieve(
    p_envelope_id        bigint,
    p_tree_id            bigint,
    p_descent_options    jsonb DEFAULT '{}'::jsonb
) RETURNS TABLE (
    leaf_mdo_id   bigint,
    leaf_title    text,
    leaf_summary  text,
    depth_reached integer)
LANGUAGE plpgsql VOLATILE
AS $body$
#variable_conflict use_column
DECLARE
    v_envelope          malu$retrieval_envelope%ROWTYPE;
    v_tree              malu$page_index_tree%ROWTYPE;
    v_max_depth         integer := COALESCE(
        (p_descent_options ->> 'max_depth')::integer, 6);
    v_choice_strategy   text := COALESCE(
        p_descent_options ->> 'choice', 'overlap');
    v_cue_text          text;
    v_cue_tokens        text[];
    v_current_mdo       bigint;
    v_current_kind      text;
    v_current_title     text;
    v_current_summary   text;
    v_chosen_mdo        bigint;
    v_chosen_title      text;
    v_chosen_summary    text;
    v_chosen_kind       text;
    v_chosen_score      numeric;
    v_chosen_reason     text;
    v_step              integer := 0;
    v_path              jsonb := '[]'::jsonb;
    v_rec               record;
    v_dummy             integer;
BEGIN
    SELECT * INTO v_envelope
      FROM malu$retrieval_envelope
     WHERE envelope_id = p_envelope_id;
    IF v_envelope.envelope_id IS NULL THEN
        RAISE EXCEPTION 'tree_descent_retrieve: envelope % not found',
            p_envelope_id USING ERRCODE = 'no_data_found';
    END IF;

    -- Planning: tree must be RLS-visible. If not, RLS hides it and
    -- the SELECT returns 0 rows.
    SELECT * INTO v_tree FROM malu$page_index_tree WHERE tree_id = p_tree_id;
    IF v_tree.tree_id IS NULL THEN
        INSERT INTO malu$retrieval_decision_audit
            (envelope_id, stage, allowed, reason, object_type, object_id)
        VALUES (p_envelope_id, 'tree_descent', false,
                'tree not visible to caller', 'page_index_tree', p_tree_id);
        UPDATE malu$retrieval_envelope
           SET tree_descent_used = true,
               tree_descent_path = '[]'::jsonb,
               tree_descent_authz_rejections = 1
         WHERE envelope_id = p_envelope_id;
        RAISE EXCEPTION
            'tree_descent_retrieve: tree % not visible',
            p_tree_id USING ERRCODE = 'insufficient_privilege';
    END IF;

    IF v_tree.build_status NOT IN ('ready','superseded') THEN
        RAISE EXCEPTION
            'tree_descent_retrieve: tree % not in ready/superseded state (status=%)',
            p_tree_id, v_tree.build_status
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    INSERT INTO malu$retrieval_decision_audit
        (envelope_id, stage, allowed, reason, object_type, object_id)
    VALUES (p_envelope_id, 'tree_descent', true,
            format('descent start: choice=%s max_depth=%s',
                   v_choice_strategy, v_max_depth),
            'page_index_tree', p_tree_id);

    v_cue_text := COALESCE(v_envelope.cue_text, '');
    v_cue_tokens := regexp_split_to_array(lower(v_cue_text), '\W+');

    -- Find the root of the tree (the entry with NULL parent_mdo_id).
    -- If multiple roots exist (multi-section docs), pick the highest-
    -- scoring one. RLS filters by tenant automatically.
    SELECT mdo_id, node_kind, title, summary
      INTO v_current_mdo, v_current_kind, v_current_title, v_current_summary
      FROM malu$memory_detail_object
     WHERE tree_id = p_tree_id
       AND mdo_kind = 'page_index_node'
       AND parent_mdo_id IS NULL
     ORDER BY mdo_id
     LIMIT 1;

    IF v_current_mdo IS NULL THEN
        UPDATE malu$retrieval_envelope
           SET tree_descent_used = true,
               tree_descent_path = '[]'::jsonb
         WHERE envelope_id = p_envelope_id;
        RETURN;
    END IF;

    v_path := v_path || jsonb_build_object(
        'step', v_step,
        'mdo_id', v_current_mdo,
        'node_kind', v_current_kind,
        'title', v_current_title,
        'reason', 'root');

    -- Descend until we hit a leaf or max_depth.
    WHILE v_current_kind = 'internal' AND v_step < v_max_depth LOOP
        v_step := v_step + 1;
        v_chosen_mdo := NULL;
        v_chosen_score := -1;
        v_chosen_reason := NULL;

        -- Expansion: fetch RLS-visible children. The candidate set
        -- here IS the authz-filtered set.
        FOR v_rec IN
            SELECT mdo_id, node_kind, title, summary
              FROM malu$memory_detail_object
             WHERE parent_mdo_id = v_current_mdo
               AND mdo_kind = 'page_index_node'
             ORDER BY mdo_id
        LOOP
            DECLARE
                v_score numeric := 0;
                v_lower text := lower(COALESCE(v_rec.title,'') || ' '
                                  || COALESCE(v_rec.summary,''));
                v_tok   text;
            BEGIN
                IF v_choice_strategy = 'first' THEN
                    v_score := 1.0 / (1 + v_rec.mdo_id);
                ELSE
                    -- 'overlap' (default): count cue tokens that appear
                    -- in title+summary. Tied scores resolve by mdo_id
                    -- (stable, document-order).
                    FOREACH v_tok IN ARRAY v_cue_tokens LOOP
                        IF v_tok <> '' AND position(v_tok IN v_lower) > 0 THEN
                            v_score := v_score + 1;
                        END IF;
                    END LOOP;
                END IF;

                IF v_score > v_chosen_score THEN
                    v_chosen_score   := v_score;
                    v_chosen_mdo     := v_rec.mdo_id;
                    v_chosen_kind    := v_rec.node_kind;
                    v_chosen_title   := v_rec.title;
                    v_chosen_summary := v_rec.summary;
                    v_chosen_reason  := format('score=%s', v_score);
                END IF;
            END;
        END LOOP;

        IF v_chosen_mdo IS NULL THEN
            -- Internal node with no visible children — record and stop.
            INSERT INTO malu$retrieval_decision_audit
                (envelope_id, stage, allowed, reason, object_type, object_id)
            VALUES (p_envelope_id, 'tree_descent', false,
                    'internal node with no authz-visible children',
                    'memory_detail_object', v_current_mdo);
            EXIT;
        END IF;

        -- Re-check authz on the chosen child (TOCTOU defense). A
        -- non-leaking RLS predicate makes this a SELECT against the
        -- chosen row id; if it returns no row, we record a rejection
        -- and stop the descent.
        SELECT 1 INTO v_dummy
          FROM malu$memory_detail_object
         WHERE mdo_id = v_chosen_mdo;
        IF NOT FOUND THEN
            UPDATE malu$retrieval_envelope
               SET tree_descent_authz_rejections =
                   tree_descent_authz_rejections + 1
             WHERE envelope_id = p_envelope_id;
            INSERT INTO malu$retrieval_decision_audit
                (envelope_id, stage, allowed, reason, object_type, object_id)
            VALUES (p_envelope_id, 'tree_descent', false,
                    'chosen child not visible on re-check',
                    'memory_detail_object', v_chosen_mdo);
            EXIT;
        END IF;

        -- Record the step + a derivation_ledger entry of kind
        -- 'retrieval_summary'.
        v_path := v_path || jsonb_build_object(
            'step', v_step,
            'mdo_id', v_chosen_mdo,
            'node_kind', v_chosen_kind,
            'title', v_chosen_title,
            'reason', v_chosen_reason,
            'choice_strategy', v_choice_strategy);

        INSERT INTO malu$retrieval_decision_audit
            (envelope_id, stage, allowed, reason, object_type, object_id)
        VALUES (p_envelope_id, 'tree_descent', true,
                format('descend step=%s %s', v_step, v_chosen_reason),
                'memory_detail_object', v_chosen_mdo);

        PERFORM record_derivation(
            'retrieval_summary', v_chosen_mdo,
            NULL, NULL, NULL, NULL, NULL, NULL,
            jsonb_build_object(
                'envelope_id', p_envelope_id,
                'tree_id', p_tree_id,
                'step', v_step,
                'cue_text', v_cue_text,
                'choice_strategy', v_choice_strategy,
                'score', v_chosen_score));

        v_current_mdo     := v_chosen_mdo;
        v_current_kind    := v_chosen_kind;
        v_current_title   := v_chosen_title;
        v_current_summary := v_chosen_summary;
    END LOOP;

    -- Assembly: persist the trail.
    UPDATE malu$retrieval_envelope
       SET tree_descent_used = true,
           tree_descent_path = v_path
     WHERE envelope_id = p_envelope_id;

    -- Return the reached node (the descent terminus). For leaves this
    -- is the matched leaf; for internal-with-no-children stops it is
    -- the deepest internal node we managed to visit.
    RETURN QUERY
    SELECT mdo_id, title, summary, v_step
      FROM malu$memory_detail_object
     WHERE mdo_id = v_current_mdo;
END;
$body$;

REVOKE EXECUTE ON FUNCTION tree_descent_retrieve(bigint, bigint, jsonb) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION tree_descent_retrieve(bigint, bigint, jsonb) TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- =====================================================================
-- 7. tree_descent_prompt_template_v1 — informational helper for the
--    future LLM-driven choice strategy.
--
--    NOT seeded into malu$prompt_template at migration time: a seeded
--    row would advance the prompt_template_id sequence and ripple
--    into every downstream pg_regress test that asserts a specific
--    template_id. Operators register this template explicitly when
--    they wire the 'llm' choice strategy. The canonical body is
--    documented in version4-pageindex-plan.md §V4-PAGEINDEX-03; a
--    drop-in script lives in scripts/maludb-pageindex-seed-prompts.
-- =====================================================================

-- =====================================================================
-- 8. retrieve_with_envelope_tree — packaged entry point.
-- =====================================================================
CREATE FUNCTION retrieve_with_envelope_tree(
    p_cue_text        text,
    p_tree_id         bigint,
    p_descent_options jsonb DEFAULT '{}'::jsonb,
    p_limit           integer DEFAULT 1
) RETURNS TABLE (
    envelope_id   bigint,
    leaf_mdo_id   bigint,
    leaf_title    text,
    leaf_summary  text,
    depth_reached integer)
LANGUAGE plpgsql VOLATILE
AS $body$
#variable_conflict use_column
DECLARE
    v_envelope_id bigint;
    v_intent      text;
    v_envelope    malu$retrieval_envelope_t;
BEGIN
    INSERT INTO malu$retrieval_envelope
        (account_id, cue_text, hints, partitions, temporal_mode,
         object_types, started_at)
    VALUES
        (current_account_id(),
         p_cue_text,
         jsonb_build_object('tree_id', p_tree_id),
         ARRAY[]::text[],
         'current_valid',
         ARRAY['page_index_node']::text[],
         now())
    RETURNING envelope_id INTO v_envelope_id;

    v_envelope := ROW(p_cue_text,
                      ARRAY['page_index_node']::text[],
                      NULL::timestamptz, NULL::timestamptz,
                      NULL::numeric,
                      jsonb_build_object('tree_id', p_tree_id))::malu$retrieval_envelope_t;
    v_intent := classify_intent(v_envelope);

    INSERT INTO malu$retrieval_decision_audit
        (envelope_id, stage, allowed, reason)
    VALUES (v_envelope_id, 'planning', true,
            format('intent=%s', v_intent));

    RETURN QUERY
    SELECT v_envelope_id, t.leaf_mdo_id, t.leaf_title, t.leaf_summary, t.depth_reached
      FROM tree_descent_retrieve(v_envelope_id, p_tree_id, p_descent_options) t
     LIMIT GREATEST(p_limit, 1);

    UPDATE malu$retrieval_envelope
       SET finished_at = now(),
           final_count = 1
     WHERE envelope_id = v_envelope_id;

    PERFORM audit_event('retrieve_with_envelope_tree',
        'malu$retrieval_envelope', v_envelope_id,
        jsonb_build_object('tree_id', p_tree_id,
                           'cue_text', p_cue_text,
                           'intent', v_intent));
END;
$body$;

REVOKE EXECUTE ON FUNCTION retrieve_with_envelope_tree(text, bigint, jsonb, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION retrieve_with_envelope_tree(text, bigint, jsonb, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- 9. MC2DB tools — first PageIndex surface for alpha.3.
--
-- Three tools cover the operator path:
--   * maludb.pageindex.build  — state_changing. Wraps
--     source_package_promote_to_page_index.
--   * maludb.pageindex.list   — read_only. Lists trees the caller
--     can see, with build_status, parser_kind, source_package_id.
--   * maludb.pageindex.ask    — read_only. Wraps
--     retrieve_with_envelope_tree, returns the descent terminus
--     (leaf or deepest internal node) plus the envelope_id so
--     callers can inspect the trail via retrieve_envelope_debug.
-- =====================================================================

CREATE FUNCTION advanced_pageindex_build(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_tree_id bigint;
BEGIN
    v_tree_id := source_package_promote_to_page_index(
        (args ->> 'source_package_id')::bigint,
        args ->> 'parser_kind',
        NULLIF(args ->> 'model_alias_id', '')::bigint,
        NULLIF(args ->> 'prompt_template_id', '')::bigint,
        COALESCE(args -> 'builder_options', '{}'::jsonb));

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('promoted source_package=%s -> tree_id=%s',
                           args ->> 'source_package_id', v_tree_id))),
        'structuredContent', jsonb_build_object(
            'tree_id', v_tree_id,
            'source_package_id', (args ->> 'source_package_id')::bigint,
            'parser_kind', args ->> 'parser_kind',
            'build_status', 'pending'),
        'isError', false));
END;
$body$;

CREATE FUNCTION advanced_pageindex_list(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_limit  integer := COALESCE((args ->> 'limit')::integer, 50);
    v_status text    := args ->> 'build_status';
    v_trees  jsonb;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY tree_id DESC),
                    '[]'::jsonb)
      INTO v_trees
      FROM (
        SELECT tree_id, source_package_id, parser_kind, build_status,
               build_started_at, build_finished_at,
               superseded_by
          FROM malu$page_index_tree
         WHERE v_status IS NULL OR build_status = v_status
         ORDER BY tree_id DESC
         LIMIT v_limit
      ) t;

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('%s tree(s)', jsonb_array_length(v_trees)))),
        'structuredContent', jsonb_build_object('trees', v_trees),
        'isError', false));
END;
$body$;

CREATE FUNCTION advanced_pageindex_ask(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_row     record;
    v_descent jsonb := COALESCE(args -> 'descent_options', '{}'::jsonb);
BEGIN
    SELECT *
      INTO v_row
      FROM retrieve_with_envelope_tree(
        args ->> 'cue_text',
        (args ->> 'tree_id')::bigint,
        v_descent,
        COALESCE((args ->> 'limit')::integer, 1));

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('leaf %s @ depth %s', v_row.leaf_mdo_id,
                           v_row.depth_reached))),
        'structuredContent', jsonb_build_object(
            'envelope_id',   v_row.envelope_id,
            'tree_id',       (args ->> 'tree_id')::bigint,
            'leaf_mdo_id',   v_row.leaf_mdo_id,
            'leaf_title',    v_row.leaf_title,
            'leaf_summary',  v_row.leaf_summary,
            'depth_reached', v_row.depth_reached),
        'isError', false));
END;
$body$;

GRANT EXECUTE ON FUNCTION
    advanced_pageindex_build(jsonb, jsonb),
    advanced_pageindex_list(jsonb, jsonb),
    advanced_pageindex_ask(jsonb, jsonb)
TO maludb_memory_admin, maludb_memory_executor;

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.pageindex.build',
    description => 'Promote a Source Package to a PageIndex tree (queues the builder).',
    implementation_type => 'sql_function',
    risk_class => 'evidence_producing', read_only => false,
    input_schema  => '{"type":"object","required":["source_package_id","parser_kind"]}'::jsonb,
    output_schema => '{"type":"object","required":["tree_id"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_pageindex_build(jsonb, jsonb)'));

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.pageindex.list',
    description => 'List PageIndex trees visible to the caller; optional build_status filter.',
    implementation_type => 'sql_function',
    input_schema  => '{"type":"object"}'::jsonb,
    output_schema => '{"type":"object","required":["trees"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_pageindex_list(jsonb, jsonb)'));

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.pageindex.ask',
    description => 'Descend a PageIndex tree to answer a query; returns the leaf terminus + envelope_id.',
    implementation_type => 'sql_function',
    input_schema  => '{"type":"object","required":["cue_text","tree_id"]}'::jsonb,
    output_schema => '{"type":"object","required":["leaf_mdo_id","depth_reached"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_pageindex_ask(jsonb, jsonb)'));

-- ============================================================
-- Section: maludb_core--0.67.0--0.68.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.67.0 -> 0.68.0  (V4 Stage 19 — V4-CHATINDEX-01)
--
-- Chat tree catalog.
--
-- The ChatIndex catalog mirrors the PageIndex catalog (V4-PAGEINDEX-01)
-- with chat-specific extensions on malu$memory_detail_object. The
-- design intentionally keeps `tree_id` pointing at malu$page_index_tree
-- and introduces a sibling `chat_tree_id` for chat-node rows so the
-- FK integrity remains unambiguous per node kind. The
-- mdo_tree_node_shape_check is refined to enforce the right shape per
-- mdo_kind.
--
-- What this migration adds:
--   1. malu$chat_index_tree — one header row per build generation,
--      with current_node_mdo_id (load-bearing in V4-CHATINDEX-02
--      incremental append), max_children, sub_node_count.
--   2. malu$memory_detail_object extended:
--      * chat_tree_id bigint FK -> malu$chat_index_tree
--      * topic_name text (for chat_index_topic rows)
--      * system_message text / user_message text / assistant_message
--        text / message_index int (for chat_index_message rows)
--      Existing tree_id stays FK -> malu$page_index_tree. The shape
--      check distinguishes by mdo_kind.
--   3. malu$derivation_ledger.derived_object_type admits
--      'chat_index_tree', 'chat_index_topic', 'chat_index_message'.
--   4. malu$relationship_edge source/target admits 'chat_index_tree'
--      so chat-tree supersession edges connect through the same
--      surface as page-tree edges.
--   5. SQL APIs (mirror of PageIndex):
--      * chat_index_tree_register / _mark_building / _mark_ready /
--        _mark_failed / _supersede.
--      * chat_index_record_topic — atomic MDO + ledger insert for
--        an internal topic node.
--      * chat_index_record_message — atomic MDO + ledger insert for
--        a leaf message node (system/user/assistant trio +
--        message_index).
--      * source_package_promote_to_chat_index — registers tree,
--        auto-registers the 'chatindex_build' V3-QUEUE-01 queue,
--        enqueues a build job, emits chat_index_tree.promote audit.
--
-- Out of scope at this migration:
--   * Incremental append + ancestor-only branching rule — that is
--     V4-CHATINDEX-02 (0.68.0 -> 0.69.0).
--   * Builder worker implementation in services/maludb-pageindexd/
--     (the existing service polls both queues; the Python side will
--     branch on parser_kind at the worker level in a follow-on).
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.68.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.68.0'::text $body$;

-- =====================================================================
-- 1. malu$chat_index_tree
-- =====================================================================
CREATE TABLE malu$chat_index_tree (
    tree_id              bigserial PRIMARY KEY,
    owner_schema         name NOT NULL DEFAULT current_schema(),
    source_package_id    bigint NOT NULL
        REFERENCES malu$source_package(source_package_id) ON DELETE CASCADE,
    model_alias_id       bigint
        REFERENCES malu$model_alias(alias_id) ON DELETE SET NULL,
    prompt_template_id   bigint
        REFERENCES malu$prompt_template(template_id) ON DELETE SET NULL,
    build_status         text NOT NULL DEFAULT 'pending'
        CHECK (build_status IN (
            'pending','building','ready','stale','superseded','failed')),
    -- V4-CHATINDEX-02: load-bearing pointer into malu$memory_detail_object.
    -- Set to the most-recently-appended topic (internal) or message
    -- (leaf) so subsequent appends can decide extend-current vs.
    -- open-new-topic-from-ancestor.
    current_node_mdo_id  bigint,
    max_children         integer NOT NULL DEFAULT 10
        CHECK (max_children > 0),
    sub_node_count       integer NOT NULL DEFAULT 0
        CHECK (sub_node_count >= 0),
    build_started_at     timestamptz,
    build_finished_at    timestamptz,
    failure_reason       text,
    superseded_by        bigint
        REFERENCES malu$chat_index_tree(tree_id) ON DELETE SET NULL,
    valid_time_start     timestamptz NOT NULL DEFAULT now(),
    valid_time_end       timestamptz,
    created_at           timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX malu$chat_index_tree_owner_idx
    ON malu$chat_index_tree(owner_schema);
CREATE INDEX malu$chat_index_tree_source_idx
    ON malu$chat_index_tree(source_package_id);
CREATE INDEX malu$chat_index_tree_status_idx
    ON malu$chat_index_tree(build_status);
CREATE INDEX malu$chat_index_tree_current_idx
    ON malu$chat_index_tree(current_node_mdo_id)
    WHERE current_node_mdo_id IS NOT NULL;

ALTER TABLE malu$chat_index_tree ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$chat_index_tree
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$chat_index_tree TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT, UPDATE ON malu$chat_index_tree TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;
GRANT USAGE, SELECT ON SEQUENCE malu$chat_index_tree_tree_id_seq TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- =====================================================================
-- 2. Extend malu$memory_detail_object with chat-node columns.
-- =====================================================================
ALTER TABLE malu$memory_detail_object
    ADD COLUMN chat_tree_id        bigint
        REFERENCES malu$chat_index_tree(tree_id) ON DELETE CASCADE,
    ADD COLUMN topic_name          text,
    ADD COLUMN system_message      text,
    ADD COLUMN user_message        text,
    ADD COLUMN assistant_message   text,
    ADD COLUMN message_index       integer;

-- Tighten the existing shape check to require the right anchor per
-- mdo_kind.
ALTER TABLE malu$memory_detail_object
    DROP CONSTRAINT malu$mdo_tree_node_shape_check;
ALTER TABLE malu$memory_detail_object
    ADD CONSTRAINT malu$mdo_tree_node_shape_check CHECK (
        (mdo_kind = 'memory_detail'
            AND tree_id IS NULL
            AND chat_tree_id IS NULL
            AND node_kind IS NULL)
        OR (mdo_kind = 'page_index_node'
            AND tree_id IS NOT NULL
            AND chat_tree_id IS NULL
            AND node_kind IS NOT NULL)
        OR (mdo_kind IN ('chat_index_topic','chat_index_message')
            AND chat_tree_id IS NOT NULL
            AND tree_id IS NULL
            AND node_kind IS NOT NULL));

-- Relax the Stage-2 anchor check further to admit chat_tree_id.
ALTER TABLE malu$memory_detail_object
    DROP CONSTRAINT "malu$memory_detail_object_check";
ALTER TABLE malu$memory_detail_object
    ADD CONSTRAINT "malu$memory_detail_object_check" CHECK (
        parent_mdo_id IS NOT NULL
        OR memory_id   IS NOT NULL
        OR episode_id  IS NOT NULL
        OR tree_id     IS NOT NULL
        OR chat_tree_id IS NOT NULL);

CREATE INDEX malu$mdo_chat_tree_idx
    ON malu$memory_detail_object(chat_tree_id)
    WHERE chat_tree_id IS NOT NULL;
CREATE INDEX malu$mdo_chat_message_idx
    ON malu$memory_detail_object(chat_tree_id, message_index)
    WHERE chat_tree_id IS NOT NULL AND message_index IS NOT NULL;

-- =====================================================================
-- 3. Extend malu$derivation_ledger.derived_object_type.
-- =====================================================================
ALTER TABLE malu$derivation_ledger
    DROP CONSTRAINT malu$derivation_ledger_derived_object_type_check;
ALTER TABLE malu$derivation_ledger
    ADD CONSTRAINT malu$derivation_ledger_derived_object_type_check
    CHECK (derived_object_type IN (
        'source_package',
        'claim',
        'fact',
        'memory',
        'episode_object',
        'memory_detail_object',
        'relationship_edge',
        'embedding',
        'page_index_tree',
        'page_index_node',
        'retrieval_summary',
        'chat_index_tree',
        'chat_index_topic',
        'chat_index_message'
    ));

-- =====================================================================
-- 4. Extend malu$relationship_edge source/target CHECK.
-- =====================================================================
ALTER TABLE malu$relationship_edge
    DROP CONSTRAINT malu$relationship_edge_source_object_type_check;
ALTER TABLE malu$relationship_edge
    ADD CONSTRAINT malu$relationship_edge_source_object_type_check
    CHECK (source_object_type IN (
        'source_package','claim','fact','memory','episode_object',
        'memory_detail_object','page_index_tree','chat_index_tree'));

ALTER TABLE malu$relationship_edge
    DROP CONSTRAINT malu$relationship_edge_target_object_type_check;
ALTER TABLE malu$relationship_edge
    ADD CONSTRAINT malu$relationship_edge_target_object_type_check
    CHECK (target_object_type IN (
        'source_package','claim','fact','memory','episode_object',
        'memory_detail_object','page_index_tree','chat_index_tree'));

-- =====================================================================
-- 5. SQL APIs.
-- =====================================================================

CREATE FUNCTION chat_index_tree_register(
    p_source_package_id  bigint,
    p_model_alias_id     bigint DEFAULT NULL,
    p_prompt_template_id bigint DEFAULT NULL,
    p_max_children       integer DEFAULT 10
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_tree_id bigint;
BEGIN
    INSERT INTO malu$chat_index_tree
        (source_package_id, model_alias_id, prompt_template_id, max_children)
    VALUES (p_source_package_id, p_model_alias_id, p_prompt_template_id, p_max_children)
    RETURNING tree_id INTO v_tree_id;

    PERFORM audit_event(
        'chat_index_tree.register',
        'chat_index_tree', v_tree_id,
        jsonb_build_object(
            'source_package_id', p_source_package_id,
            'model_alias_id',    p_model_alias_id,
            'prompt_template_id',p_prompt_template_id,
            'max_children',      p_max_children));
    RETURN v_tree_id;
END;
$body$;

CREATE FUNCTION chat_index_tree_mark_building(p_tree_id bigint)
RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    UPDATE malu$chat_index_tree
       SET build_status     = 'building',
           build_started_at = COALESCE(build_started_at, now())
     WHERE tree_id = p_tree_id
       AND build_status IN ('pending','failed');
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'chat_index_tree_mark_building: tree % not in pending/failed state',
            p_tree_id USING ERRCODE = 'invalid_parameter_value';
    END IF;
    PERFORM audit_event('chat_index_tree.mark_building',
        'chat_index_tree', p_tree_id);
END;
$body$;

CREATE FUNCTION chat_index_tree_mark_ready(p_tree_id bigint)
RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    UPDATE malu$chat_index_tree
       SET build_status      = 'ready',
           build_finished_at = now()
     WHERE tree_id = p_tree_id
       AND build_status = 'building';
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'chat_index_tree_mark_ready: tree % not in building state',
            p_tree_id USING ERRCODE = 'invalid_parameter_value';
    END IF;
    PERFORM audit_event('chat_index_tree.mark_ready',
        'chat_index_tree', p_tree_id);
END;
$body$;

CREATE FUNCTION chat_index_tree_mark_failed(
    p_tree_id bigint,
    p_reason  text DEFAULT NULL
) RETURNS void
LANGUAGE plpgsql
AS $body$
BEGIN
    UPDATE malu$chat_index_tree
       SET build_status      = 'failed',
           build_finished_at = now(),
           failure_reason    = p_reason
     WHERE tree_id = p_tree_id
       AND build_status IN ('pending','building');
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'chat_index_tree_mark_failed: tree % not in pending/building state',
            p_tree_id USING ERRCODE = 'invalid_parameter_value';
    END IF;
    PERFORM audit_event('chat_index_tree.mark_failed',
        'chat_index_tree', p_tree_id,
        jsonb_build_object('reason', p_reason));
END;
$body$;

CREATE FUNCTION chat_index_tree_supersede(
    p_prior_tree_id bigint,
    p_new_tree_id   bigint
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
DECLARE v_edge_id bigint;
BEGIN
    IF p_prior_tree_id = p_new_tree_id THEN
        RAISE EXCEPTION 'chat_index_tree_supersede: prior and new tree must differ'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    UPDATE malu$chat_index_tree
       SET build_status   = 'superseded',
           superseded_by  = p_new_tree_id,
           valid_time_end = now()
     WHERE tree_id = p_prior_tree_id
       AND build_status IN ('ready','stale');
    IF NOT FOUND THEN
        RAISE EXCEPTION
            'chat_index_tree_supersede: prior tree % not in ready/stale state',
            p_prior_tree_id USING ERRCODE = 'invalid_parameter_value';
    END IF;

    v_edge_id := register_relationship_edge(
        'chat_index_tree', p_prior_tree_id,
        'chat_index_tree', p_new_tree_id,
        'supersedes',
        NULL,
        jsonb_build_object('prior_tree', p_prior_tree_id,
                           'new_tree',   p_new_tree_id),
        NULL);

    PERFORM audit_event(
        'chat_index_tree.supersede',
        'chat_index_tree', p_prior_tree_id,
        jsonb_build_object('new_tree_id', p_new_tree_id,
                           'edge_id',     v_edge_id));
    RETURN v_edge_id;
END;
$body$;

-- chat_index_record_topic — internal topic node. NULL parent means
-- the topic attaches at the root of the tree.
CREATE FUNCTION chat_index_record_topic(
    p_tree_id              bigint,
    p_parent_mdo_id        bigint,
    p_topic_name           text,
    p_summary              text,
    p_model_alias_id       bigint   DEFAULT NULL,
    p_prompt_template_id   bigint   DEFAULT NULL
) RETURNS TABLE (mdo_id bigint, derivation_id bigint)
LANGUAGE plpgsql
AS $body$
#variable_conflict use_column
DECLARE
    v_mdo_id   bigint;
    v_deriv_id bigint;
BEGIN
    INSERT INTO malu$memory_detail_object
        (parent_mdo_id, detail_kind, mdo_kind,
         chat_tree_id, node_kind,
         topic_name, summary)
    VALUES (p_parent_mdo_id, 'chat_index_topic', 'chat_index_topic',
            p_tree_id, 'internal',
            p_topic_name, p_summary)
    RETURNING mdo_id INTO v_mdo_id;

    v_deriv_id := record_derivation(
        'chat_index_topic', v_mdo_id,
        NULL, p_model_alias_id, p_prompt_template_id,
        NULL, NULL, NULL,
        jsonb_build_object('tree_id', p_tree_id,
                           'parent_mdo_id', p_parent_mdo_id,
                           'topic_name', p_topic_name));

    -- Advance the tree's current_node_mdo_id pointer + sub_node_count.
    UPDATE malu$chat_index_tree
       SET current_node_mdo_id = v_mdo_id,
           sub_node_count = sub_node_count + 1
     WHERE tree_id = p_tree_id;

    RETURN QUERY SELECT v_mdo_id, v_deriv_id;
END;
$body$;

-- chat_index_record_message — leaf message node carrying the
-- system/user/assistant trio.
CREATE FUNCTION chat_index_record_message(
    p_tree_id              bigint,
    p_topic_mdo_id         bigint,
    p_message_index        integer,
    p_system_message       text     DEFAULT NULL,
    p_user_message         text     DEFAULT NULL,
    p_assistant_message    text     DEFAULT NULL,
    p_summary              text     DEFAULT NULL,
    p_model_alias_id       bigint   DEFAULT NULL,
    p_prompt_template_id   bigint   DEFAULT NULL
) RETURNS TABLE (mdo_id bigint, derivation_id bigint)
LANGUAGE plpgsql
AS $body$
#variable_conflict use_column
DECLARE
    v_mdo_id    bigint;
    v_deriv_id  bigint;
    v_title     text;
BEGIN
    IF p_system_message IS NULL
       AND p_user_message IS NULL
       AND p_assistant_message IS NULL THEN
        RAISE EXCEPTION
            'chat_index_record_message: at least one of system/user/assistant must be non-null'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    v_title := format('msg#%s', p_message_index);

    INSERT INTO malu$memory_detail_object
        (parent_mdo_id, detail_kind, mdo_kind,
         chat_tree_id, node_kind,
         title, summary,
         system_message, user_message, assistant_message,
         message_index)
    VALUES (p_topic_mdo_id, 'chat_index_message', 'chat_index_message',
            p_tree_id, 'leaf',
            v_title, p_summary,
            p_system_message, p_user_message, p_assistant_message,
            p_message_index)
    RETURNING mdo_id INTO v_mdo_id;

    v_deriv_id := record_derivation(
        'chat_index_message', v_mdo_id,
        NULL, p_model_alias_id, p_prompt_template_id,
        NULL, NULL, NULL,
        jsonb_build_object('tree_id', p_tree_id,
                           'topic_mdo_id', p_topic_mdo_id,
                           'message_index', p_message_index));

    UPDATE malu$chat_index_tree
       SET current_node_mdo_id = v_mdo_id,
           sub_node_count = sub_node_count + 1
     WHERE tree_id = p_tree_id;

    RETURN QUERY SELECT v_mdo_id, v_deriv_id;
END;
$body$;

-- source_package_promote_to_chat_index — operator-facing promotion.
CREATE FUNCTION source_package_promote_to_chat_index(
    p_source_package_id    bigint,
    p_model_alias_id       bigint  DEFAULT NULL,
    p_prompt_template_id   bigint  DEFAULT NULL,
    p_max_children         integer DEFAULT 10,
    p_builder_options      jsonb   DEFAULT '{}'::jsonb
) RETURNS bigint
LANGUAGE plpgsql
AS $body$
#variable_conflict use_column
DECLARE
    v_tree_id      bigint;
    v_queue_job_id bigint;
BEGIN
    v_tree_id := chat_index_tree_register(
        p_source_package_id, p_model_alias_id, p_prompt_template_id, p_max_children);

    PERFORM queue_register('chatindex_build', 120000, 3, NULL,
        'V4-CHATINDEX-01 tree builder job queue');

    v_queue_job_id := queue_enqueue(
        'chatindex_build',
        jsonb_build_object(
            'tree_id',            v_tree_id,
            'source_package_id',  p_source_package_id,
            'model_alias_id',     p_model_alias_id,
            'prompt_template_id', p_prompt_template_id,
            'max_children',       p_max_children,
            'builder_options',    p_builder_options),
        format('chatindex:%s', v_tree_id),
        0, NULL, NULL);

    PERFORM audit_event(
        'chat_index_tree.promote',
        'chat_index_tree', v_tree_id,
        jsonb_build_object(
            'source_package_id', p_source_package_id,
            'queue_job_id',      v_queue_job_id,
            'builder_options',   p_builder_options));
    RETURN v_tree_id;
END;
$body$;

GRANT EXECUTE ON FUNCTION
    chat_index_tree_register(bigint, bigint, bigint, integer),
    chat_index_tree_mark_building(bigint),
    chat_index_tree_mark_ready(bigint),
    chat_index_tree_mark_failed(bigint, text),
    chat_index_tree_supersede(bigint, bigint),
    chat_index_record_topic(bigint, bigint, text, text, bigint, bigint),
    chat_index_record_message(bigint, bigint, integer, text, text, text, text, bigint, bigint),
    source_package_promote_to_chat_index(bigint, bigint, bigint, integer, jsonb)
TO maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- ============================================================
-- Section: maludb_core--0.68.0--0.69.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.68.0 -> 0.69.0  (V4 Stage 19 — V4-CHATINDEX-02)
--
-- Incremental append for ChatIndex.
--
-- The append model:
--   * malu$chat_index_tree.current_node_mdo_id, set by V4-CHATINDEX-01
--     record_topic / record_message, points to the most-recently-
--     touched node. Incremental append decides per-call whether to
--     extend the current leaf's topic OR open a new topic.
--   * Upstream ChatIndex's rule: a new topic may branch only from the
--     current node OR one of its ancestors. Append rejects a request
--     to branch from an unrelated subtree.
--   * Idempotency: duplicate message_index within the same chat tree
--     is a no-op (returns the existing mdo_id rather than inserting
--     a duplicate).
--   * Audit: every call writes a malu$chat_index_append_audit row
--     capturing the decision (opened_new_topic / ancestor_branch_used /
--     decision_reason / range).
--
-- What this migration adds:
--   1. malu$chat_index_append_audit — append decision breadcrumbs.
--   2. chat_index_append_messages(tree_id, messages jsonb) — the
--      append entry point. messages is a JSONB array whose entries
--      have the shape {message_index, system_message, user_message,
--      assistant_message, topic_branch (optional)}. topic_branch is:
--        omitted        → extend current leaf's topic (or open a
--                          root topic if the tree is empty)
--        {"new": "..."} → open a new topic from the current node
--        {"from_ancestor_mdo_id": N, "new": "..."}
--                       → open a new topic from a specific ancestor
--                          node; that node MUST be the current node
--                          or one of its ancestors.
--   3. chat_index_close_topic(tree_id, topic_node_mdo_id) — admin
--      manual override. Closes a topic by clearing
--      current_node_mdo_id if it points into the topic's subtree.
--
-- Out of scope at this migration:
--   * Live model-driven topic-opening decision (the LLM decides
--     "is this message a new topic?"). The append entrypoint exposes
--     `topic_branch` as a caller-supplied JSON field; the operator
--     wires up an LLM client that fills this in before calling
--     chat_index_append_messages.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.69.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.69.0'::text $body$;

-- =====================================================================
-- 1. malu$chat_index_append_audit
-- =====================================================================
CREATE TABLE malu$chat_index_append_audit (
    append_id              bigserial PRIMARY KEY,
    owner_schema           name NOT NULL DEFAULT current_schema(),
    tree_id                bigint NOT NULL
        REFERENCES malu$chat_index_tree(tree_id) ON DELETE CASCADE,
    appended_at            timestamptz NOT NULL DEFAULT now(),
    message_index_first    integer NOT NULL,
    message_index_last     integer NOT NULL,
    appended_message_count integer NOT NULL DEFAULT 0
        CHECK (appended_message_count >= 0),
    idempotent_hits        integer NOT NULL DEFAULT 0
        CHECK (idempotent_hits >= 0),
    opened_new_topic       boolean NOT NULL DEFAULT false,
    ancestor_branch_used   boolean NOT NULL DEFAULT false,
    branched_from_mdo_id   bigint,
    decision_reason        text
);
CREATE INDEX malu$chat_index_append_audit_tree_idx
    ON malu$chat_index_append_audit(tree_id, appended_at DESC);

ALTER TABLE malu$chat_index_append_audit ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$chat_index_append_audit
    USING      (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

GRANT SELECT ON malu$chat_index_append_audit TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT INSERT ON malu$chat_index_append_audit TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;
GRANT USAGE, SELECT ON SEQUENCE malu$chat_index_append_audit_append_id_seq TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- =====================================================================
-- 2. _chat_index_ancestor_chain — helper. Returns the set of mdo_ids
--    on the path from a given node up to (but not past) the topmost
--    topic, in deepest-first order.
-- =====================================================================
CREATE FUNCTION _chat_index_ancestor_chain(p_start_mdo_id bigint)
RETURNS TABLE (mdo_id bigint, depth integer)
LANGUAGE sql STABLE
AS $body$
    WITH RECURSIVE chain AS (
        SELECT m.mdo_id, m.parent_mdo_id, m.mdo_kind, 0 AS depth
          FROM malu$memory_detail_object m
         WHERE m.mdo_id = p_start_mdo_id
        UNION ALL
        SELECT m.mdo_id, m.parent_mdo_id, m.mdo_kind, c.depth + 1
          FROM malu$memory_detail_object m
          JOIN chain c ON c.parent_mdo_id = m.mdo_id
         WHERE m.mdo_kind IN ('chat_index_topic','chat_index_message')
    )
    SELECT mdo_id, depth FROM chain ORDER BY depth;
$body$;

-- =====================================================================
-- 3. chat_index_append_messages — append entry point.
-- =====================================================================
CREATE FUNCTION chat_index_append_messages(
    p_tree_id  bigint,
    p_messages jsonb
) RETURNS TABLE (
    message_index   integer,
    mdo_id          bigint,
    idempotent_hit  boolean)
LANGUAGE plpgsql VOLATILE
AS $body$
#variable_conflict use_column
DECLARE
    v_tree                 malu$chat_index_tree%ROWTYPE;
    v_msg                  jsonb;
    v_msg_index            integer;
    v_topic_mdo_id         bigint;
    v_branched_from        bigint := NULL;
    v_opened_new_topic     boolean := false;
    v_ancestor_used        boolean := false;
    v_existing_mdo         bigint;
    v_new_mdo              bigint;
    v_topic_name           text;
    v_from_ancestor        bigint;
    v_decision_reason      text := '';
    v_appended             integer := 0;
    v_idempotent           integer := 0;
    v_min_idx              integer := NULL;
    v_max_idx              integer := NULL;
    v_unused_deriv         bigint;
BEGIN
    -- Serialize concurrent appends on this tree (plan §11.5).
    SELECT * INTO v_tree
      FROM malu$chat_index_tree
     WHERE tree_id = p_tree_id
     FOR UPDATE;
    IF v_tree.tree_id IS NULL THEN
        RAISE EXCEPTION 'chat_index_append_messages: tree % not found',
            p_tree_id USING ERRCODE = 'no_data_found';
    END IF;
    IF v_tree.build_status NOT IN ('pending','building','ready') THEN
        RAISE EXCEPTION
            'chat_index_append_messages: tree % is %, cannot append',
            p_tree_id, v_tree.build_status
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    IF jsonb_typeof(p_messages) <> 'array' OR jsonb_array_length(p_messages) = 0 THEN
        RAISE EXCEPTION
            'chat_index_append_messages: p_messages must be a non-empty array'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    FOR v_msg IN SELECT * FROM jsonb_array_elements(p_messages)
    LOOP
        v_msg_index := (v_msg ->> 'message_index')::integer;
        IF v_msg_index IS NULL THEN
            RAISE EXCEPTION
                'chat_index_append_messages: each message needs message_index'
                USING ERRCODE = 'invalid_parameter_value';
        END IF;
        v_min_idx := LEAST(v_min_idx, v_msg_index);
        v_max_idx := GREATEST(v_max_idx, v_msg_index);

        -- Idempotency: a row with this (chat_tree_id, message_index)
        -- already exists -> return it.
        SELECT m.mdo_id INTO v_existing_mdo
          FROM malu$memory_detail_object m
         WHERE m.chat_tree_id  = p_tree_id
           AND m.message_index = v_msg_index
           AND m.mdo_kind      = 'chat_index_message';
        IF v_existing_mdo IS NOT NULL THEN
            v_idempotent := v_idempotent + 1;
            message_index  := v_msg_index;
            mdo_id         := v_existing_mdo;
            idempotent_hit := true;
            RETURN NEXT;
            CONTINUE;
        END IF;

        -- Decide topic attachment.
        IF v_msg ? 'topic_branch' AND (v_msg -> 'topic_branch') IS NOT NULL
           AND (v_msg -> 'topic_branch') <> 'null'::jsonb THEN
            v_topic_name := (v_msg -> 'topic_branch') ->> 'new';
            IF v_topic_name IS NULL OR v_topic_name = '' THEN
                RAISE EXCEPTION
                    'chat_index_append_messages: topic_branch.new (topic name) required'
                    USING ERRCODE = 'invalid_parameter_value';
            END IF;
            v_from_ancestor := NULLIF(
                (v_msg -> 'topic_branch') ->> 'from_ancestor_mdo_id', '')::bigint;

            -- Resolve "from" node: explicit ancestor or current.
            DECLARE
                v_from_node bigint;
                v_new_topic_parent bigint;
            BEGIN
                IF v_from_ancestor IS NOT NULL THEN
                    IF v_tree.current_node_mdo_id IS NULL THEN
                        RAISE EXCEPTION
                            'chat_index_append_messages: tree % has no current node; cannot branch from ancestor',
                            p_tree_id USING ERRCODE = 'invalid_parameter_value';
                    END IF;
                    -- Enforce ancestor-only rule: from_ancestor must be
                    -- the current node or one of its ancestors.
                    IF NOT EXISTS (
                        SELECT 1 FROM _chat_index_ancestor_chain(v_tree.current_node_mdo_id) c
                         WHERE c.mdo_id = v_from_ancestor
                    ) THEN
                        RAISE EXCEPTION
                            'chat_index_append_messages: from_ancestor_mdo_id % is not the current node or an ancestor of it',
                            v_from_ancestor USING ERRCODE = 'invalid_parameter_value';
                    END IF;
                    v_from_node := v_from_ancestor;
                    v_ancestor_used := true;
                    v_branched_from := v_from_ancestor;
                ELSE
                    v_from_node := v_tree.current_node_mdo_id;
                    v_branched_from := v_tree.current_node_mdo_id;
                END IF;

                -- Per upstream semantics: new topic is a sibling of
                -- the from-node, so new_topic.parent = parent_of(from).
                -- If from is NULL (empty tree), the new topic is a
                -- root topic with NULL parent.
                IF v_from_node IS NULL THEN
                    v_new_topic_parent := NULL;
                ELSE
                    SELECT parent_mdo_id INTO v_new_topic_parent
                      FROM malu$memory_detail_object
                     WHERE mdo_id = v_from_node;
                END IF;

                -- Create the new topic node (one for the whole batch).
                SELECT t.mdo_id INTO v_topic_mdo_id
                  FROM chat_index_record_topic(
                    p_tree_id, v_new_topic_parent, v_topic_name,
                    format('Auto-opened topic: %s', v_topic_name)) t;
            END;

            v_opened_new_topic := true;
            v_decision_reason := COALESCE(v_decision_reason || '; ', '')
                || format('opened topic "%s" from %s',
                          v_topic_name,
                          CASE WHEN v_ancestor_used THEN 'ancestor'
                               ELSE 'current' END);

            -- Refresh v_tree.current_node_mdo_id after the topic insert.
            SELECT current_node_mdo_id INTO v_tree.current_node_mdo_id
              FROM malu$chat_index_tree WHERE tree_id = p_tree_id;
        ELSE
            -- Extend the current topic. If no current topic exists,
            -- open a root topic with a default name.
            v_topic_mdo_id := NULL;
            IF v_tree.current_node_mdo_id IS NOT NULL THEN
                SELECT mdo_id INTO v_topic_mdo_id
                  FROM (SELECT m.mdo_id, m.mdo_kind
                          FROM _chat_index_ancestor_chain(
                                   v_tree.current_node_mdo_id) c
                          JOIN malu$memory_detail_object m ON m.mdo_id = c.mdo_id
                         ORDER BY c.depth) t
                 WHERE t.mdo_kind = 'chat_index_topic'
                 LIMIT 1;
            END IF;
            IF v_topic_mdo_id IS NULL THEN
                SELECT t.mdo_id INTO v_topic_mdo_id
                  FROM chat_index_record_topic(
                    p_tree_id, NULL, 'root',
                    'Auto-opened root topic') t;
                v_opened_new_topic := true;
                v_decision_reason := COALESCE(v_decision_reason || '; ', '')
                    || 'opened root topic';
                SELECT current_node_mdo_id INTO v_tree.current_node_mdo_id
                  FROM malu$chat_index_tree WHERE tree_id = p_tree_id;
            END IF;
        END IF;

        -- Record the message node under v_topic_mdo_id.
        SELECT t.mdo_id INTO v_new_mdo
          FROM chat_index_record_message(
            p_tree_id, v_topic_mdo_id, v_msg_index,
            v_msg ->> 'system_message',
            v_msg ->> 'user_message',
            v_msg ->> 'assistant_message',
            v_msg ->> 'summary') t;
        v_appended := v_appended + 1;

        -- Refresh current_node for the next iteration.
        SELECT current_node_mdo_id INTO v_tree.current_node_mdo_id
          FROM malu$chat_index_tree WHERE tree_id = p_tree_id;

        message_index  := v_msg_index;
        mdo_id         := v_new_mdo;
        idempotent_hit := false;
        RETURN NEXT;
    END LOOP;

    INSERT INTO malu$chat_index_append_audit
        (tree_id, message_index_first, message_index_last,
         appended_message_count, idempotent_hits,
         opened_new_topic, ancestor_branch_used,
         branched_from_mdo_id, decision_reason)
    VALUES (p_tree_id, COALESCE(v_min_idx, 0), COALESCE(v_max_idx, 0),
            v_appended, v_idempotent,
            v_opened_new_topic, v_ancestor_used,
            v_branched_from,
            NULLIF(v_decision_reason, ''));

    PERFORM audit_event('chat_index_tree.append',
        'chat_index_tree', p_tree_id,
        jsonb_build_object(
            'appended', v_appended,
            'idempotent_hits', v_idempotent,
            'opened_new_topic', v_opened_new_topic,
            'ancestor_branch_used', v_ancestor_used));
END;
$body$;

-- =====================================================================
-- 4. chat_index_close_topic — admin override. Clears the tree's
--    current_node_mdo_id pointer if it points into the subtree
--    rooted at the given topic node.
-- =====================================================================
CREATE FUNCTION chat_index_close_topic(
    p_tree_id            bigint,
    p_topic_node_mdo_id  bigint
) RETURNS void
LANGUAGE plpgsql
AS $body$
DECLARE
    v_current bigint;
    v_in_subtree boolean;
BEGIN
    IF NOT pg_has_role(session_user, 'maludb_memory_admin', 'MEMBER') THEN
        RAISE EXCEPTION 'chat_index_close_topic: requires maludb_memory_admin membership'
            USING ERRCODE = 'insufficient_privilege';
    END IF;

    SELECT current_node_mdo_id INTO v_current
      FROM malu$chat_index_tree WHERE tree_id = p_tree_id;
    IF v_current IS NULL THEN
        PERFORM audit_event('chat_index_tree.close_topic',
            'chat_index_tree', p_tree_id,
            jsonb_build_object('topic_node_mdo_id', p_topic_node_mdo_id,
                               'cleared', false,
                               'reason', 'no current node'));
        RETURN;
    END IF;

    SELECT EXISTS (
        SELECT 1 FROM _chat_index_ancestor_chain(v_current) c
         WHERE c.mdo_id = p_topic_node_mdo_id)
      INTO v_in_subtree;

    IF v_in_subtree THEN
        UPDATE malu$chat_index_tree
           SET current_node_mdo_id = NULL
         WHERE tree_id = p_tree_id;
    END IF;

    PERFORM audit_event('chat_index_tree.close_topic',
        'chat_index_tree', p_tree_id,
        jsonb_build_object('topic_node_mdo_id', p_topic_node_mdo_id,
                           'cleared', v_in_subtree));
END;
$body$;

GRANT EXECUTE ON FUNCTION
    _chat_index_ancestor_chain(bigint),
    chat_index_append_messages(bigint, jsonb),
    chat_index_close_topic(bigint, bigint)
TO maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- ============================================================
-- Section: maludb_core--0.69.0--0.70.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.69.0 -> 0.70.0  (V4 alpha.5 — V4-MC2DB-01 completion)
--
-- Fills in the ChatIndex MC2DB surface and adds pageindex.tree_summary
-- so maludb.advanced reaches parity for both V4 trees. Tool count
-- rises 22 -> 27.
--
-- Catalog: no new tables. Two new SQL helpers extend the descent
-- surface:
--
--   chat_tree_descent_retrieve(envelope_id, chat_tree_id, options)
--     mirrors tree_descent_retrieve (V4-PAGEINDEX-03) but walks
--     malu$memory_detail_object rows whose mdo_kind is
--     'chat_index_topic' or 'chat_index_message' under chat_tree_id.
--     Same three-stage authz contract: planning RLS / expansion RLS-
--     filtered candidates / re-check before traversal / assembly
--     redaction. Same 'overlap' default choice strategy. Each step
--     writes a malu$retrieval_decision_audit row with
--     stage='tree_descent' and a malu$derivation_ledger entry of
--     kind 'retrieval_summary'.
--
--   retrieve_with_envelope_chat_tree(cue_text, chat_tree_id, options,
--                                    limit)
--     packaged operator entrypoint. Opens an envelope, sets the
--     'long_chat_recall' intent, invokes chat_tree_descent_retrieve,
--     returns leaf terminus + envelope_id.
--
-- MC2DB tools registered on maludb.advanced:
--   * maludb.chatindex.build       (state_changing)
--   * maludb.chatindex.append      (state_changing)
--   * maludb.chatindex.ask         (read_only)
--   * maludb.chatindex.list        (read_only)
--   * maludb.pageindex.tree_summary (read_only) — returns root +
--     first-level node titles/summaries.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.70.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.70.0'::text $body$;

-- =====================================================================
-- 1. chat_tree_descent_retrieve — chat-tree analogue of
--    tree_descent_retrieve. Stops at chat_index_message (leaf).
-- =====================================================================
CREATE FUNCTION chat_tree_descent_retrieve(
    p_envelope_id     bigint,
    p_chat_tree_id    bigint,
    p_descent_options jsonb DEFAULT '{}'::jsonb
) RETURNS TABLE (
    leaf_mdo_id     bigint,
    leaf_title      text,
    leaf_summary    text,
    depth_reached   integer)
LANGUAGE plpgsql VOLATILE
AS $body$
#variable_conflict use_column
DECLARE
    v_envelope         malu$retrieval_envelope%ROWTYPE;
    v_tree             malu$chat_index_tree%ROWTYPE;
    v_max_depth        integer := COALESCE(
        (p_descent_options ->> 'max_depth')::integer, 6);
    v_choice_strategy  text := COALESCE(
        p_descent_options ->> 'choice', 'overlap');
    v_cue_text         text;
    v_cue_tokens       text[];
    v_current_mdo      bigint;
    v_current_kind     text;
    v_current_title    text;
    v_current_summary  text;
    v_chosen_mdo       bigint;
    v_chosen_title     text;
    v_chosen_summary   text;
    v_chosen_kind      text;
    v_chosen_score     numeric;
    v_chosen_reason    text;
    v_step             integer := 0;
    v_path             jsonb := '[]'::jsonb;
    v_rec              record;
    v_dummy            integer;
BEGIN
    SELECT * INTO v_envelope
      FROM malu$retrieval_envelope WHERE envelope_id = p_envelope_id;
    IF v_envelope.envelope_id IS NULL THEN
        RAISE EXCEPTION 'chat_tree_descent_retrieve: envelope % not found',
            p_envelope_id USING ERRCODE = 'no_data_found';
    END IF;

    SELECT * INTO v_tree FROM malu$chat_index_tree WHERE tree_id = p_chat_tree_id;
    IF v_tree.tree_id IS NULL THEN
        INSERT INTO malu$retrieval_decision_audit
            (envelope_id, stage, allowed, reason, object_type, object_id)
        VALUES (p_envelope_id, 'tree_descent', false,
                'chat tree not visible to caller',
                'chat_index_tree', p_chat_tree_id);
        UPDATE malu$retrieval_envelope
           SET tree_descent_used = true,
               tree_descent_path = '[]'::jsonb,
               tree_descent_authz_rejections = 1
         WHERE envelope_id = p_envelope_id;
        RAISE EXCEPTION
            'chat_tree_descent_retrieve: chat tree % not visible',
            p_chat_tree_id USING ERRCODE = 'insufficient_privilege';
    END IF;
    IF v_tree.build_status NOT IN ('ready','superseded') THEN
        RAISE EXCEPTION
            'chat_tree_descent_retrieve: chat tree % not in ready/superseded state (status=%)',
            p_chat_tree_id, v_tree.build_status
            USING ERRCODE = 'object_not_in_prerequisite_state';
    END IF;

    INSERT INTO malu$retrieval_decision_audit
        (envelope_id, stage, allowed, reason, object_type, object_id)
    VALUES (p_envelope_id, 'tree_descent', true,
            format('chat descent start: choice=%s max_depth=%s',
                   v_choice_strategy, v_max_depth),
            'chat_index_tree', p_chat_tree_id);

    v_cue_text := COALESCE(v_envelope.cue_text, '');
    v_cue_tokens := regexp_split_to_array(lower(v_cue_text), '\W+');

    -- Root = parent_mdo_id IS NULL.
    SELECT mdo_id, node_kind, COALESCE(topic_name, title), summary
      INTO v_current_mdo, v_current_kind, v_current_title, v_current_summary
      FROM malu$memory_detail_object
     WHERE chat_tree_id = p_chat_tree_id
       AND mdo_kind IN ('chat_index_topic','chat_index_message')
       AND parent_mdo_id IS NULL
     ORDER BY mdo_id
     LIMIT 1;

    IF v_current_mdo IS NULL THEN
        UPDATE malu$retrieval_envelope
           SET tree_descent_used = true,
               tree_descent_path = '[]'::jsonb
         WHERE envelope_id = p_envelope_id;
        RETURN;
    END IF;

    v_path := v_path || jsonb_build_object(
        'step', v_step,
        'mdo_id', v_current_mdo,
        'node_kind', v_current_kind,
        'title', v_current_title,
        'reason', 'root');

    WHILE v_current_kind = 'internal' AND v_step < v_max_depth LOOP
        v_step := v_step + 1;
        v_chosen_mdo := NULL;
        v_chosen_score := -1;
        v_chosen_reason := NULL;

        FOR v_rec IN
            SELECT mdo_id, node_kind,
                   COALESCE(topic_name, title) AS title, summary,
                   system_message, user_message, assistant_message
              FROM malu$memory_detail_object
             WHERE parent_mdo_id = v_current_mdo
               AND mdo_kind IN ('chat_index_topic','chat_index_message')
             ORDER BY message_index NULLS LAST, mdo_id
        LOOP
            DECLARE
                v_score numeric := 0;
                v_lower text := lower(
                    COALESCE(v_rec.title,'') || ' '
                    || COALESCE(v_rec.summary,'') || ' '
                    || COALESCE(v_rec.user_message,'') || ' '
                    || COALESCE(v_rec.assistant_message,''));
                v_tok text;
            BEGIN
                IF v_choice_strategy = 'first' THEN
                    v_score := 1.0 / (1 + v_rec.mdo_id);
                ELSE
                    FOREACH v_tok IN ARRAY v_cue_tokens LOOP
                        IF v_tok <> '' AND position(v_tok IN v_lower) > 0 THEN
                            v_score := v_score + 1;
                        END IF;
                    END LOOP;
                END IF;
                IF v_score > v_chosen_score THEN
                    v_chosen_score   := v_score;
                    v_chosen_mdo     := v_rec.mdo_id;
                    v_chosen_kind    := v_rec.node_kind;
                    v_chosen_title   := v_rec.title;
                    v_chosen_summary := v_rec.summary;
                    v_chosen_reason  := format('score=%s', v_score);
                END IF;
            END;
        END LOOP;

        IF v_chosen_mdo IS NULL THEN
            INSERT INTO malu$retrieval_decision_audit
                (envelope_id, stage, allowed, reason, object_type, object_id)
            VALUES (p_envelope_id, 'tree_descent', false,
                    'internal chat node with no authz-visible children',
                    'memory_detail_object', v_current_mdo);
            EXIT;
        END IF;

        SELECT 1 INTO v_dummy
          FROM malu$memory_detail_object WHERE mdo_id = v_chosen_mdo;
        IF NOT FOUND THEN
            UPDATE malu$retrieval_envelope
               SET tree_descent_authz_rejections =
                   tree_descent_authz_rejections + 1
             WHERE envelope_id = p_envelope_id;
            INSERT INTO malu$retrieval_decision_audit
                (envelope_id, stage, allowed, reason, object_type, object_id)
            VALUES (p_envelope_id, 'tree_descent', false,
                    'chosen chat child not visible on re-check',
                    'memory_detail_object', v_chosen_mdo);
            EXIT;
        END IF;

        v_path := v_path || jsonb_build_object(
            'step', v_step,
            'mdo_id', v_chosen_mdo,
            'node_kind', v_chosen_kind,
            'title', v_chosen_title,
            'reason', v_chosen_reason,
            'choice_strategy', v_choice_strategy);

        INSERT INTO malu$retrieval_decision_audit
            (envelope_id, stage, allowed, reason, object_type, object_id)
        VALUES (p_envelope_id, 'tree_descent', true,
                format('chat descend step=%s %s', v_step, v_chosen_reason),
                'memory_detail_object', v_chosen_mdo);

        PERFORM record_derivation(
            'retrieval_summary', v_chosen_mdo,
            NULL, NULL, NULL, NULL, NULL, NULL,
            jsonb_build_object(
                'envelope_id', p_envelope_id,
                'chat_tree_id', p_chat_tree_id,
                'step', v_step,
                'cue_text', v_cue_text,
                'choice_strategy', v_choice_strategy,
                'score', v_chosen_score));

        v_current_mdo     := v_chosen_mdo;
        v_current_kind    := v_chosen_kind;
        v_current_title   := v_chosen_title;
        v_current_summary := v_chosen_summary;
    END LOOP;

    UPDATE malu$retrieval_envelope
       SET tree_descent_used = true,
           tree_descent_path = v_path
     WHERE envelope_id = p_envelope_id;

    RETURN QUERY
    SELECT m.mdo_id,
           COALESCE(m.topic_name, m.title),
           m.summary,
           v_step
      FROM malu$memory_detail_object m
     WHERE m.mdo_id = v_current_mdo;
END;
$body$;

REVOKE EXECUTE ON FUNCTION chat_tree_descent_retrieve(bigint, bigint, jsonb) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION chat_tree_descent_retrieve(bigint, bigint, jsonb) TO
    maludb_memory_admin, maludb_memory_executor, maludb_queue_worker;

-- =====================================================================
-- 2. retrieve_with_envelope_chat_tree — packaged entrypoint.
-- =====================================================================
CREATE FUNCTION retrieve_with_envelope_chat_tree(
    p_cue_text        text,
    p_chat_tree_id    bigint,
    p_descent_options jsonb DEFAULT '{}'::jsonb,
    p_limit           integer DEFAULT 1
) RETURNS TABLE (
    envelope_id     bigint,
    leaf_mdo_id     bigint,
    leaf_title      text,
    leaf_summary    text,
    depth_reached   integer)
LANGUAGE plpgsql VOLATILE
AS $body$
#variable_conflict use_column
DECLARE
    v_envelope_id bigint;
    v_intent      text;
    v_envelope    malu$retrieval_envelope_t;
BEGIN
    INSERT INTO malu$retrieval_envelope
        (account_id, cue_text, hints, partitions, temporal_mode,
         object_types, started_at)
    VALUES
        (current_account_id(), p_cue_text,
         jsonb_build_object('chat_tree_id', p_chat_tree_id),
         ARRAY[]::text[], 'current_valid',
         ARRAY['chat_index_topic','chat_index_message']::text[],
         now())
    RETURNING envelope_id INTO v_envelope_id;

    v_envelope := ROW(p_cue_text,
                      ARRAY['chat_index_topic','chat_index_message']::text[],
                      NULL::timestamptz, NULL::timestamptz,
                      NULL::numeric,
                      jsonb_build_object('chat_tree_id', p_chat_tree_id))::malu$retrieval_envelope_t;
    v_intent := classify_intent(v_envelope);

    INSERT INTO malu$retrieval_decision_audit
        (envelope_id, stage, allowed, reason)
    VALUES (v_envelope_id, 'planning', true,
            format('intent=%s', v_intent));

    RETURN QUERY
    SELECT v_envelope_id, t.leaf_mdo_id, t.leaf_title, t.leaf_summary, t.depth_reached
      FROM chat_tree_descent_retrieve(v_envelope_id, p_chat_tree_id, p_descent_options) t
     LIMIT GREATEST(p_limit, 1);

    UPDATE malu$retrieval_envelope
       SET finished_at = now(),
           final_count = 1
     WHERE envelope_id = v_envelope_id;

    PERFORM audit_event('retrieve_with_envelope_chat_tree',
        'malu$retrieval_envelope', v_envelope_id,
        jsonb_build_object('chat_tree_id', p_chat_tree_id,
                           'cue_text', p_cue_text,
                           'intent', v_intent));
END;
$body$;

REVOKE EXECUTE ON FUNCTION retrieve_with_envelope_chat_tree(text, bigint, jsonb, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION retrieve_with_envelope_chat_tree(text, bigint, jsonb, integer) TO
    maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- 3. MC2DB tool wrappers + registrations.
-- =====================================================================

CREATE FUNCTION advanced_chatindex_build(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE v_tree_id bigint;
BEGIN
    v_tree_id := source_package_promote_to_chat_index(
        (args ->> 'source_package_id')::bigint,
        NULLIF(args ->> 'model_alias_id', '')::bigint,
        NULLIF(args ->> 'prompt_template_id', '')::bigint,
        COALESCE((args ->> 'max_children')::integer, 10),
        COALESCE(args -> 'builder_options', '{}'::jsonb));

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('promoted source_package=%s -> chat_tree_id=%s',
                           args ->> 'source_package_id', v_tree_id))),
        'structuredContent', jsonb_build_object(
            'tree_id', v_tree_id,
            'source_package_id', (args ->> 'source_package_id')::bigint,
            'build_status', 'pending'),
        'isError', false));
END;
$body$;

CREATE FUNCTION advanced_chatindex_append(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_results jsonb := '[]'::jsonb;
    v_rec     record;
BEGIN
    FOR v_rec IN
        SELECT *
          FROM chat_index_append_messages(
            (args ->> 'tree_id')::bigint,
            COALESCE(args -> 'messages', '[]'::jsonb))
    LOOP
        v_results := v_results || jsonb_build_object(
            'message_index', v_rec.message_index,
            'mdo_id',        v_rec.mdo_id,
            'idempotent_hit', v_rec.idempotent_hit);
    END LOOP;

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('%s message(s) processed',
                           jsonb_array_length(v_results)))),
        'structuredContent', jsonb_build_object(
            'tree_id', (args ->> 'tree_id')::bigint,
            'results', v_results),
        'isError', false));
END;
$body$;

CREATE FUNCTION advanced_chatindex_ask(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE v_row record;
BEGIN
    SELECT *
      INTO v_row
      FROM retrieve_with_envelope_chat_tree(
        args ->> 'cue_text',
        (args ->> 'tree_id')::bigint,
        COALESCE(args -> 'descent_options', '{}'::jsonb),
        COALESCE((args ->> 'limit')::integer, 1));

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('leaf %s @ depth %s',
                           v_row.leaf_mdo_id, v_row.depth_reached))),
        'structuredContent', jsonb_build_object(
            'envelope_id',  v_row.envelope_id,
            'tree_id',      (args ->> 'tree_id')::bigint,
            'leaf_mdo_id',  v_row.leaf_mdo_id,
            'leaf_title',   v_row.leaf_title,
            'leaf_summary', v_row.leaf_summary,
            'depth_reached', v_row.depth_reached),
        'isError', false));
END;
$body$;

CREATE FUNCTION advanced_chatindex_list(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_limit  integer := COALESCE((args ->> 'limit')::integer, 50);
    v_status text    := args ->> 'build_status';
    v_trees  jsonb;
BEGIN
    SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY tree_id DESC),
                    '[]'::jsonb)
      INTO v_trees
      FROM (
        SELECT tree_id, source_package_id, build_status,
               current_node_mdo_id, max_children, sub_node_count,
               build_started_at, build_finished_at, superseded_by
          FROM malu$chat_index_tree
         WHERE v_status IS NULL OR build_status = v_status
         ORDER BY tree_id DESC
         LIMIT v_limit
      ) t;

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('%s chat tree(s)', jsonb_array_length(v_trees)))),
        'structuredContent', jsonb_build_object('trees', v_trees),
        'isError', false));
END;
$body$;

CREATE FUNCTION advanced_pageindex_tree_summary(args jsonb, context jsonb)
RETURNS void
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE
    v_tree_id bigint := (args ->> 'tree_id')::bigint;
    v_root    record;
    v_first   jsonb;
BEGIN
    SELECT mdo_id, title, summary, node_kind
      INTO v_root
      FROM malu$memory_detail_object
     WHERE tree_id = v_tree_id
       AND mdo_kind = 'page_index_node'
       AND parent_mdo_id IS NULL
     ORDER BY mdo_id LIMIT 1;
    IF v_root.mdo_id IS NULL THEN
        RAISE EXCEPTION 'maludb.pageindex.tree_summary: tree % has no root node',
            v_tree_id USING ERRCODE = 'no_data_found';
    END IF;

    SELECT COALESCE(jsonb_agg(row_to_json(t)::jsonb ORDER BY mdo_id),
                    '[]'::jsonb)
      INTO v_first
      FROM (
        SELECT mdo_id, title, summary, node_kind
          FROM malu$memory_detail_object
         WHERE parent_mdo_id = v_root.mdo_id
           AND mdo_kind = 'page_index_node'
         ORDER BY mdo_id
      ) t;

    CALL mc2db.put_object(jsonb_build_object(
        'content', jsonb_build_array(jsonb_build_object(
            'type', 'text',
            'text', format('%s top-level child node(s) under "%s"',
                           jsonb_array_length(v_first),
                           v_root.title))),
        'structuredContent', jsonb_build_object(
            'tree_id', v_tree_id,
            'root', jsonb_build_object(
                'mdo_id',    v_root.mdo_id,
                'title',     v_root.title,
                'summary',   v_root.summary,
                'node_kind', v_root.node_kind),
            'children', v_first),
        'isError', false));
END;
$body$;

GRANT EXECUTE ON FUNCTION
    advanced_chatindex_build(jsonb, jsonb),
    advanced_chatindex_append(jsonb, jsonb),
    advanced_chatindex_ask(jsonb, jsonb),
    advanced_chatindex_list(jsonb, jsonb),
    advanced_pageindex_tree_summary(jsonb, jsonb)
TO maludb_memory_admin, maludb_memory_executor;

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.chatindex.build',
    description => 'Promote a Source Package to a ChatIndex tree (queues the builder).',
    implementation_type => 'sql_function',
    risk_class => 'evidence_producing', read_only => false,
    input_schema  => '{"type":"object","required":["source_package_id"]}'::jsonb,
    output_schema => '{"type":"object","required":["tree_id"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_chatindex_build(jsonb, jsonb)'));

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.chatindex.append',
    description => 'Append one or more messages to a ChatIndex tree (handles topic decisions).',
    implementation_type => 'sql_function',
    risk_class => 'evidence_producing', read_only => false,
    input_schema  => '{"type":"object","required":["tree_id","messages"]}'::jsonb,
    output_schema => '{"type":"object","required":["results"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_chatindex_append(jsonb, jsonb)'));

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.chatindex.ask',
    description => 'Descend a ChatIndex tree to answer a query; returns the leaf terminus + envelope_id.',
    implementation_type => 'sql_function',
    input_schema  => '{"type":"object","required":["cue_text","tree_id"]}'::jsonb,
    output_schema => '{"type":"object","required":["leaf_mdo_id","depth_reached"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_chatindex_ask(jsonb, jsonb)'));

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.chatindex.list',
    description => 'List ChatIndex trees visible to the caller; optional build_status filter.',
    implementation_type => 'sql_function',
    input_schema  => '{"type":"object"}'::jsonb,
    output_schema => '{"type":"object","required":["trees"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_chatindex_list(jsonb, jsonb)'));

SELECT mc2db.register_tool(
    server_name => 'maludb.advanced', tool_name => 'maludb.pageindex.tree_summary',
    description => 'Return the root + first-level node titles/summaries for a PageIndex tree.',
    implementation_type => 'sql_function',
    input_schema  => '{"type":"object","required":["tree_id"]}'::jsonb,
    output_schema => '{"type":"object","required":["root","children"]}'::jsonb,
    impl_metadata => jsonb_build_object('function_signature',
        'maludb_core.advanced_pageindex_tree_summary(jsonb, jsonb)'));

-- ============================================================
-- Section: maludb_core--0.70.0--0.71.0.sql
-- ============================================================
-- =====================================================================
-- maludb_core 0.70.0 -> 0.71.0  (V4 alpha.6 — V4-REST-01)
--
-- Registers V4 PageIndex + ChatIndex endpoints in malu$rest_endpoint
-- via rest_register_endpoint. All eight endpoints from
-- version4-pageindex-plan.md §V4-REST-01:
--
--   POST /v4/pageindex/build
--   GET  /v4/pageindex/trees
--   GET  /v4/pageindex/trees/:tree_id
--   POST /v4/pageindex/ask
--   POST /v4/chatindex/build
--   POST /v4/chatindex/append
--   GET  /v4/chatindex/trees
--   POST /v4/chatindex/ask
--
-- All endpoints reuse the alpha.1..alpha.5 SQL functions as
-- handlers. The three needed list/get helpers
-- (pageindex_list_trees, pageindex_get_tree, chatindex_list_trees)
-- are added here as plain SETOF-returning functions so the same
-- handler can serve both REST and direct SQL callers without going
-- through mc2db.put_object.
--
-- Apply with:
--   ALTER EXTENSION maludb_core UPDATE TO '0.71.0';
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.71.0'::text $body$;

-- Migration-local helper (same pattern as V3-API-02 in
-- 0.61.0->0.62.0). Dropped at the end of the migration.
CREATE OR REPLACE FUNCTION _v3_api_arg(
    p_name text, p_type text, p_required boolean DEFAULT true,
    p_in   text DEFAULT 'body', p_default jsonb DEFAULT 'null'::jsonb)
    RETURNS jsonb
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$
    SELECT jsonb_build_object(
        'name',     p_name,
        'type',     p_type,
        'in',       p_in,
        'required', p_required,
        'default',  p_default)
$body$;

-- =====================================================================
-- 1. List / get helpers — plain SETOF functions for REST GETs.
-- =====================================================================

CREATE FUNCTION pageindex_list_trees(
    p_build_status text    DEFAULT NULL,
    p_limit        integer DEFAULT 50
) RETURNS TABLE (
    tree_id            bigint,
    source_package_id  bigint,
    parser_kind        text,
    build_status       text,
    build_started_at   timestamptz,
    build_finished_at  timestamptz,
    superseded_by      bigint)
LANGUAGE sql STABLE
AS $body$
    SELECT tree_id, source_package_id, parser_kind, build_status,
           build_started_at, build_finished_at, superseded_by
      FROM malu$page_index_tree
     WHERE p_build_status IS NULL OR build_status = p_build_status
     ORDER BY tree_id DESC
     LIMIT GREATEST(p_limit, 1);
$body$;

CREATE FUNCTION pageindex_get_tree(p_tree_id bigint)
RETURNS TABLE (
    tree_id            bigint,
    source_package_id  bigint,
    parser_kind        text,
    model_alias_id     bigint,
    prompt_template_id bigint,
    build_status       text,
    build_started_at   timestamptz,
    build_finished_at  timestamptz,
    failure_reason     text,
    superseded_by      bigint,
    valid_time_start   timestamptz,
    valid_time_end     timestamptz)
LANGUAGE sql STABLE
AS $body$
    SELECT tree_id, source_package_id, parser_kind, model_alias_id,
           prompt_template_id, build_status,
           build_started_at, build_finished_at, failure_reason,
           superseded_by, valid_time_start, valid_time_end
      FROM malu$page_index_tree
     WHERE tree_id = p_tree_id;
$body$;

CREATE FUNCTION chatindex_list_trees(
    p_build_status text    DEFAULT NULL,
    p_limit        integer DEFAULT 50
) RETURNS TABLE (
    tree_id              bigint,
    source_package_id    bigint,
    build_status         text,
    current_node_mdo_id  bigint,
    max_children         integer,
    sub_node_count       integer,
    build_started_at     timestamptz,
    build_finished_at    timestamptz,
    superseded_by        bigint)
LANGUAGE sql STABLE
AS $body$
    SELECT tree_id, source_package_id, build_status,
           current_node_mdo_id, max_children, sub_node_count,
           build_started_at, build_finished_at, superseded_by
      FROM malu$chat_index_tree
     WHERE p_build_status IS NULL OR build_status = p_build_status
     ORDER BY tree_id DESC
     LIMIT GREATEST(p_limit, 1);
$body$;

REVOKE EXECUTE ON FUNCTION pageindex_list_trees(text, integer) FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION pageindex_get_tree(bigint)         FROM PUBLIC;
REVOKE EXECUTE ON FUNCTION chatindex_list_trees(text, integer) FROM PUBLIC;
GRANT  EXECUTE ON FUNCTION pageindex_list_trees(text, integer) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT  EXECUTE ON FUNCTION pageindex_get_tree(bigint) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;
GRANT  EXECUTE ON FUNCTION chatindex_list_trees(text, integer) TO
    maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

