    'Promote a Source Package to a PageIndex tree (queues the builder).',
    ARRAY['pageindex.write']::text[], 'state_changing', '{}'::jsonb, true,
    30000, 1048576, 65536,
    jsonb_build_array(
        _v3_api_arg('p_source_package_id',  'bigint'),
        _v3_api_arg('p_parser_kind',        'text'),
