    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

-- Per-schema lookup of common document types ("Meeting Transcript",
-- "Change Request", ...). Advisory only: malu$document.document_type
-- has no FK to this table, so upload_document can write a brand-new
-- type string that is not yet seeded here. The lookup exists so the
-- UI has a stable list to populate its drop-down from.
CREATE TABLE malu$document_type (
    document_type_id  bigserial PRIMARY KEY,
    owner_schema      name NOT NULL DEFAULT current_schema(),
    document_type     text NOT NULL,
    description       text,
    display_order     integer,
    created_at        timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, document_type)
);
-- Case-insensitive uniqueness: "Transcript" and "transcript" share a
-- slot. Plain UNIQUE above stays as a belt-and-suspenders exact-case guard.
CREATE UNIQUE INDEX malu$document_type_owner_lower_idx
    ON malu$document_type(owner_schema, lower(document_type));
CREATE INDEX malu$document_type_owner_order_idx
    ON malu$document_type(owner_schema, display_order, document_type);

ALTER TABLE malu$document_type ENABLE ROW LEVEL SECURITY;
CREATE POLICY tenant_owner ON malu$document_type
    USING (owner_schema = current_schema())
    WITH CHECK (owner_schema = current_schema());

CREATE TABLE malu$raw_ingest (
    ingest_id     bigserial PRIMARY KEY,
    owner_schema  name NOT NULL DEFAULT current_schema(),
    source_type   text NOT NULL,
    source_name   text,
    payload_jsonb jsonb,
    content_text  text,
    content_bytes bytea,
    content_hash  text,
    state         text NOT NULL DEFAULT 'received'
        CHECK (state IN ('received','queued','processing','processed','partially_applied','applied','failed','ignored')),
    received_at   timestamptz NOT NULL DEFAULT now(),
    processed_at  timestamptz,
    last_error    text,
    context_jsonb jsonb NOT NULL DEFAULT '{}'::jsonb,
    CHECK (payload_jsonb IS NOT NULL OR content_text IS NOT NULL OR content_bytes IS NOT NULL),
    UNIQUE (owner_schema, ingest_id)
);
CREATE INDEX malu$raw_ingest_owner_state_idx ON malu$raw_ingest(owner_schema, state, received_at DESC);
CREATE INDEX malu$raw_ingest_hash_idx ON malu$raw_ingest(content_hash) WHERE content_hash IS NOT NULL;

