DROP TABLE maludb_core.malu$svpor_relationship_type CASCADE;

-- =====================================================================
-- maludb_core 0.79.0 -> 0.80.0
--
-- API enablement: bug fixes + unlink/delete/link helpers + project
-- archive + notes issue-state + skill/document body exposure.
--
--   A. Bug fixes
--      A1. Pin search_path on the 6 _payload_validate_* trigger fns so
--          memory/fact/claim/episode/source_package/memory_detail are
--          writable regardless of the caller's search_path.
--      A2. Grant the document inner helpers so quick_add_note /
--          upload_document work for tenant roles.
--   B. Unlink / delete helpers
--      maludb_subject_verb_unlink, maludb_svpor_relationship_delete,
--      maludb_pool_remove_named_member.
--   C. maludb_subject_verb_link(subject_id, verb_id) with baked-in
--      embedding defaults (namespace 'default', 1536, cosine).
--   D. Project archive: archived_at on subjects + project_archive /
--      project_unarchive.
--   E. Notes issue-state: issue_closed_at on malu$memory.
--   F. Expose skill markdown body + document body_text (read).
--
-- The schema-local facades (new functions + the widened views) are
-- (re)built by _enable_memory_schema_080_facade; existing schemas pick
-- them up by re-running enable_memory_schema().
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core.maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.80.0'::text $body$;

-- ===== A1. payload-validation triggers resolve maludb_core anywhere ===
ALTER FUNCTION maludb_core._payload_validate_memory()         SET search_path = pg_catalog, maludb_core, pg_temp;
ALTER FUNCTION maludb_core._payload_validate_episode()        SET search_path = pg_catalog, maludb_core, pg_temp;
ALTER FUNCTION maludb_core._payload_validate_mdo()            SET search_path = pg_catalog, maludb_core, pg_temp;
ALTER FUNCTION maludb_core._payload_validate_claim()          SET search_path = pg_catalog, maludb_core, pg_temp;
ALTER FUNCTION maludb_core._payload_validate_fact()           SET search_path = pg_catalog, maludb_core, pg_temp;
ALTER FUNCTION maludb_core._payload_validate_source_package() SET search_path = pg_catalog, maludb_core, pg_temp;

-- ===== A2. let tenant roles reach the document inner helpers ==========
GRANT EXECUTE ON FUNCTION maludb_core._upload_document_for_schema(name, text, text, text, jsonb, text, text[], text[], text[], text[], jsonb, text)
    TO maludb_memory_admin, maludb_memory_executor;
GRANT EXECUTE ON FUNCTION maludb_core._insert_document_svpor_hints_for_schema(name, bigint, jsonb)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== D/E/F. new base columns =======================================
-- D: project archive state on subjects.
ALTER TABLE maludb_core.malu$svpor_subject ADD COLUMN archived_at timestamptz;
-- E: notes issue-closed state on memories.
ALTER TABLE maludb_core.malu$memory         ADD COLUMN issue_closed_at timestamptz;
-- F: skill markdown/body content. malu$skill_package had no body column at
-- all (despite the request's premise), so add one; exposed via maludb_skill.
ALTER TABLE maludb_core.malu$skill_package  ADD COLUMN markdown text;

-- ===== C. subject<->verb link (baked embedding defaults) =============
CREATE FUNCTION maludb_core._link_subject_verb_for_schema(
    p_schema     name,
    p_subject_id bigint,
    p_verb_id    bigint
) RETURNS bigint
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_sname text;
    v_vname text;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    SELECT canonical_name INTO v_sname
      FROM maludb_core.malu$svpor_subject
     WHERE owner_schema = p_schema AND subject_id = p_subject_id;
    SELECT canonical_name INTO v_vname
      FROM maludb_core.malu$svpor_verb
     WHERE owner_schema = p_schema AND verb_id = p_verb_id;

    IF v_sname IS NULL OR v_vname IS NULL THEN
        RAISE EXCEPTION 'subject_id % or verb_id % not found in schema %',
            p_subject_id, p_verb_id, p_schema
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    RETURN maludb_core._register_vector_compartment_for_schema(
        p_schema, 'default', v_sname, v_vname, 1536, 'text-embedding-3-small', 'cosine');
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core._link_subject_verb_for_schema(name, bigint, bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._link_subject_verb_for_schema(name, bigint, bigint)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== B1. subject<->verb unlink =====================================
CREATE FUNCTION maludb_core._unlink_subject_verb_for_schema(
    p_schema     name,
    p_subject_id bigint,
    p_verb_id    bigint
) RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_sname text;
    v_vname text;
    v_count integer;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    SELECT canonical_name INTO v_sname
      FROM maludb_core.malu$svpor_subject
     WHERE owner_schema = p_schema AND subject_id = p_subject_id;
    SELECT canonical_name INTO v_vname
      FROM maludb_core.malu$svpor_verb
     WHERE owner_schema = p_schema AND verb_id = p_verb_id;

    IF v_sname IS NULL OR v_vname IS NULL THEN
        RAISE EXCEPTION 'subject_id % or verb_id % not found in schema %',
            p_subject_id, p_verb_id, p_schema
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    DELETE FROM maludb_core.malu$vector_compartment c
     USING maludb_core.malu$vector_subject s, maludb_core.malu$vector_verb v
     WHERE c.owner_schema = p_schema AND c.namespace = 'default'
       AND s.owner_schema = p_schema AND s.namespace = 'default'
       AND s.subject_name = v_sname AND c.subject_id = s.subject_id
       AND v.owner_schema = p_schema AND v.namespace = 'default'
       AND v.verb_name = v_vname AND c.verb_id = v.verb_id;
    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core._unlink_subject_verb_for_schema(name, bigint, bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._unlink_subject_verb_for_schema(name, bigint, bigint)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== B2. object-graph relationship delete ==========================
CREATE FUNCTION maludb_core.delete_svpor_relationship(
    p_source_kind       text,
    p_source_id         bigint,
    p_target_kind       text,
    p_target_id         bigint,
    p_relationship_type text DEFAULT NULL
) RETURNS integer
LANGUAGE plpgsql
SECURITY INVOKER
AS $body$
DECLARE
    v_schema name := current_schema();
    v_count  integer;
BEGIN
    DELETE FROM maludb_core.malu$relationship_edge e
     WHERE e.owner_schema = v_schema
       AND e.source_object_type = p_source_kind
       AND e.source_object_id   = p_source_id
       AND e.target_object_type = p_target_kind
       AND e.target_object_id   = p_target_id
       AND (p_relationship_type IS NULL OR e.relationship_type = p_relationship_type);
    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core.delete_svpor_relationship(text, bigint, text, bigint, text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.delete_svpor_relationship(text, bigint, text, bigint, text)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== B3. pool remove named member ==================================
CREATE FUNCTION maludb_core._pool_remove_named_member_for_schema(
    p_schema      name,
    p_pool_name   text,
    p_member_kind text,
    p_member_name text
) RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_pool_id     bigint;
    v_kind        text := pg_catalog.lower(pg_catalog.btrim(p_member_kind));
    v_name        text := pg_catalog.btrim(p_member_name);
    v_object_type text;
    v_object_id   bigint;
    v_count       integer;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    SELECT pool_id INTO v_pool_id
      FROM maludb_core.malu$active_memory_pool
     WHERE owner_schema = p_schema AND pool_name = p_pool_name;
    IF v_pool_id IS NULL THEN
        RAISE EXCEPTION 'pool_remove_named_member: pool % not found in schema %', p_pool_name, p_schema
            USING ERRCODE = 'no_data_found';
    END IF;

    IF v_kind = 'project' THEN
        SELECT subject_id INTO v_object_id FROM maludb_core.malu$svpor_subject
         WHERE owner_schema = p_schema AND canonical_name = v_name AND subject_type = 'project'
         ORDER BY subject_id LIMIT 1;
        v_object_type := 'subject';
    ELSIF v_kind = 'subject' THEN
        SELECT subject_id INTO v_object_id FROM maludb_core.malu$svpor_subject
         WHERE owner_schema = p_schema AND canonical_name = v_name
         ORDER BY subject_id LIMIT 1;
        v_object_type := 'subject';
    ELSIF v_kind = 'verb' THEN
        SELECT verb_id INTO v_object_id FROM maludb_core.malu$svpor_verb
         WHERE owner_schema = p_schema AND canonical_name = v_name
         ORDER BY verb_id LIMIT 1;
        v_object_type := 'verb';
    ELSIF v_kind = 'document' THEN
        SELECT document_id INTO v_object_id FROM maludb_core.malu$document
         WHERE owner_schema = p_schema AND title = v_name
         ORDER BY document_id LIMIT 1;
        v_object_type := 'document';
    ELSIF v_kind = 'skill' THEN
        SELECT skill_id INTO v_object_id FROM maludb_core.malu$skill_package
         WHERE owner_schema = p_schema AND skill_name = v_name
         ORDER BY updated_at DESC, skill_id DESC LIMIT 1;
        v_object_type := 'skill';
    ELSIF v_kind = 'memory' THEN
        SELECT memory_id INTO v_object_id FROM maludb_core.malu$memory
         WHERE owner_schema = p_schema AND title = v_name
         ORDER BY memory_id LIMIT 1;
        v_object_type := 'memory';
    ELSE
        RAISE EXCEPTION 'pool_remove_named_member: unsupported named member_kind %', p_member_kind
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    IF v_object_id IS NULL THEN
        RAISE EXCEPTION 'pool_remove_named_member: % named % not found in schema %', v_kind, v_name, p_schema
            USING ERRCODE = 'no_data_found';
    END IF;

    DELETE FROM maludb_core.malu$active_memory_pool_member
     WHERE owner_schema = p_schema
       AND pool_id = v_pool_id
       AND member_kind = v_kind
       AND member_object_type = v_object_type
       AND member_object_id = v_object_id;
    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core._pool_remove_named_member_for_schema(name, text, text, text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._pool_remove_named_member_for_schema(name, text, text, text)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== D. project archive / unarchive ================================
CREATE FUNCTION maludb_core.project_archive(p_project_id bigint) RETURNS boolean
LANGUAGE plpgsql
SECURITY INVOKER
AS $body$
DECLARE
    v_schema name := current_schema();
    v_count  integer;
BEGIN
    UPDATE maludb_core.malu$svpor_subject
       SET archived_at = now()
     WHERE owner_schema = v_schema AND subject_id = p_project_id
       AND subject_type = 'project' AND archived_at IS NULL;
    GET DIAGNOSTICS v_count = ROW_COUNT;

    IF v_count = 0 AND NOT EXISTS (
        SELECT 1 FROM maludb_core.malu$svpor_subject
         WHERE owner_schema = v_schema AND subject_id = p_project_id AND subject_type = 'project'
    ) THEN
        RAISE EXCEPTION 'project % not found in schema %', p_project_id, v_schema
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    RETURN v_count > 0;   -- true = archived now; false = already archived
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core.project_archive(bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.project_archive(bigint)
    TO maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION maludb_core.project_unarchive(p_project_id bigint) RETURNS boolean
LANGUAGE plpgsql
SECURITY INVOKER
AS $body$
DECLARE
    v_schema name := current_schema();
    v_count  integer;
BEGIN
    UPDATE maludb_core.malu$svpor_subject
       SET archived_at = NULL
     WHERE owner_schema = v_schema AND subject_id = p_project_id
       AND subject_type = 'project' AND archived_at IS NOT NULL;
    GET DIAGNOSTICS v_count = ROW_COUNT;

    IF v_count = 0 AND NOT EXISTS (
        SELECT 1 FROM maludb_core.malu$svpor_subject
         WHERE owner_schema = v_schema AND subject_id = p_project_id AND subject_type = 'project'
    ) THEN
        RAISE EXCEPTION 'project % not found in schema %', p_project_id, v_schema
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    RETURN v_count > 0;   -- true = unarchived now; false = not archived
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core.project_unarchive(bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.project_unarchive(bigint)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== schema-local facade: new helpers + widened views ==============
CREATE FUNCTION maludb_core._enable_memory_schema_080_facade(p_schema name) RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_count integer := 0;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    -- ---- widen existing views (already managed: re-create, no recount) ----
    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_subject AS
        SELECT subject_id, subject_type, canonical_name, aliases, description,
               created_at, classifier_md, archived_at
          FROM maludb_core.malu$svpor_subject
         WHERE owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_project AS
        SELECT subject_id, subject_type, canonical_name, aliases, description,
               created_at, classifier_md, archived_at
          FROM %I.maludb_subject
         WHERE subject_type = 'project'
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_person AS
        SELECT subject_id, subject_type, canonical_name, aliases, description,
               created_at, classifier_md, archived_at
          FROM %I.maludb_subject
         WHERE subject_type = 'person'
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_stakeholder AS
        SELECT subject_id, subject_type, canonical_name, aliases, description,
               created_at, classifier_md, archived_at
          FROM %I.maludb_subject
         WHERE subject_type = 'stakeholder'
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_memory AS
        SELECT memory_id, memory_kind, title, summary, payload_jsonb,
               occurred_at, occurred_until, recorded_at, sensitivity,
               lifecycle_state, consolidated_into_memory_id,
               created_at, updated_at, issue_closed_at
          FROM maludb_core.malu$memory
         WHERE owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_skill WITH (security_invoker = true) AS
        SELECT skill_id, skill_name, version, description, packaging_kind,
               applicability_jsonb, precondition_jsonb, enabled, created_at,
               updated_at, visibility, source_owner_schema, source_skill_id,
               forked_at, owner_schema, markdown
          FROM maludb_core.malu$skill_package
         WHERE owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_document WITH (security_invoker = true) AS
        SELECT d.document_id, d.source_package_id, d.title, d.source_type,
               d.media_type, d.primary_project_id, d.lifecycle_state,
               d.metadata_jsonb, d.created_at, d.updated_at,
               (SELECT sp.content_text
                  FROM maludb_core.malu$source_package sp
                 WHERE sp.owner_schema = d.owner_schema
                   AND sp.source_package_id = d.source_package_id
                   AND sp.source_type = d.source_type) AS body_text
          FROM maludb_core.malu$document d
         WHERE d.owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    -- ---- new helper functions (counted) ----
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_subject_verb_link', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_subject_verb_link(p_subject_id bigint, p_verb_id bigint)
        RETURNS bigint LANGUAGE sql SECURITY DEFINER
        SET search_path = pg_catalog, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core._link_subject_verb_for_schema(%L::name, p_subject_id, p_verb_id) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_subject_verb_link(bigint, bigint) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_subject_verb_link(bigint, bigint) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_subject_verb_link', 'function', 'Schema-local subject<->verb link (compartment) with default embedding config.');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_subject_verb_unlink', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_subject_verb_unlink(p_subject_id bigint, p_verb_id bigint)
        RETURNS integer LANGUAGE sql SECURITY DEFINER
        SET search_path = pg_catalog, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core._unlink_subject_verb_for_schema(%L::name, p_subject_id, p_verb_id) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_subject_verb_unlink(bigint, bigint) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_subject_verb_unlink(bigint, bigint) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_subject_verb_unlink', 'function', 'Schema-local subject<->verb unlink.');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_svpor_relationship_delete', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_svpor_relationship_delete(
            p_source_kind text, p_source_id bigint,
            p_target_kind text, p_target_id bigint,
            p_relationship_type text DEFAULT NULL
        ) RETURNS integer LANGUAGE sql SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.delete_svpor_relationship(
            p_source_kind, p_source_id, p_target_kind, p_target_id, p_relationship_type) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_svpor_relationship_delete(text, bigint, text, bigint, text) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_svpor_relationship_delete(text, bigint, text, bigint, text) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_svpor_relationship_delete', 'function', 'Schema-local object-graph relationship delete.');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_pool_remove_named_member', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_pool_remove_named_member(
            p_pool_name text, p_member_kind text, p_member_name text
        ) RETURNS integer LANGUAGE sql SECURITY DEFINER
        SET search_path = pg_catalog, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core._pool_remove_named_member_for_schema(%L::name, p_pool_name, p_member_kind, p_member_name) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_pool_remove_named_member(text, text, text) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_pool_remove_named_member(text, text, text) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_pool_remove_named_member', 'function', 'Schema-local pool named-member removal.');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_project_archive', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_project_archive(p_project_id bigint)
        RETURNS boolean LANGUAGE sql SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.project_archive(p_project_id) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_project_archive(bigint) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_project_archive(bigint) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_project_archive', 'function', 'Schema-local project archive.');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_project_unarchive', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_project_unarchive(p_project_id bigint)
        RETURNS boolean LANGUAGE sql SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.project_unarchive(p_project_id) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_project_unarchive(bigint) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_project_unarchive(bigint) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_project_unarchive', 'function', 'Schema-local project unarchive.');
    v_count := v_count + 1;

    RETURN v_count;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core._enable_memory_schema_080_facade(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._enable_memory_schema_080_facade(name)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== wire the new builder in (must run last) =======================
CREATE OR REPLACE FUNCTION maludb_core.enable_memory_schema(p_schema name DEFAULT current_schema())
RETURNS TABLE(schema_name name, enabled_version text, object_count integer)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_enabled_version text := maludb_core.maludb_core_version();
    v_count integer := 0;
BEGIN
    IF p_schema IS NULL THEN
        p_schema := current_schema();
    END IF;

    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    INSERT INTO maludb_core.malu$enabled_schema(schema_name, enabled_version, enabled_by)
    VALUES (p_schema, v_enabled_version, session_user)
    ON CONFLICT ON CONSTRAINT malu$enabled_schema_pkey DO UPDATE
       SET enabled_version   = EXCLUDED.enabled_version,
           last_refreshed_at = now();

    v_count := v_count + maludb_core._enable_memory_schema_subject_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_core_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ingest_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_pool_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ai_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_075_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_076_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_078_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_080_facade(p_schema);
    PERFORM maludb_core._grant_memory_schema_reader_access(p_schema);

    schema_name := p_schema;
    enabled_version := v_enabled_version;
    object_count := v_count;
    RETURN NEXT;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core.enable_memory_schema(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.enable_memory_schema(name)
    TO maludb_memory_admin, maludb_memory_executor, maludb_user, maludb_admin;

-- =====================================================================
-- maludb_core 0.80.0 -> 0.80.1
--
-- Fix: enable_memory_schema() is no longer idempotent after 0.80.0.
--
-- 0.80.0 widened maludb_subject / maludb_project / maludb_person /
-- maludb_stakeholder (archived_at), maludb_memory (issue_closed_at),
-- maludb_skill (markdown), and maludb_document (body_text) by re-creating
-- them in _enable_memory_schema_080_facade -- which runs AFTER the base
-- facade builders that still emit the narrower column lists. The first
-- enable works (adding a trailing column is allowed), but a second enable
-- makes the base builder try to shrink the already-widened view, which
-- CREATE OR REPLACE VIEW rejects ("cannot drop columns from view").
--
-- Fix: drop those views at the start of enable_memory_schema so the base
-- builders always recreate them cleanly and the 080 facade re-widens.
-- Dropping maludb_subject CASCADE also removes its dependent
-- maludb_project / maludb_person / maludb_stakeholder views, all of which
-- the subject facade recreates; the other three views have no dependents.
-- It all happens inside the single enable_memory_schema transaction.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core.maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.80.1'::text $body$;

CREATE OR REPLACE FUNCTION maludb_core.enable_memory_schema(p_schema name DEFAULT current_schema())
RETURNS TABLE(schema_name name, enabled_version text, object_count integer)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_enabled_version text := maludb_core.maludb_core_version();
    v_count integer := 0;
BEGIN
    IF p_schema IS NULL THEN
        p_schema := current_schema();
    END IF;

    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    -- Drop the views the 0.80 facade widens, so the base builders can
    -- recreate them without hitting "cannot drop columns from view" on
    -- re-enable. CASCADE on maludb_subject also drops the dependent
    -- maludb_project / maludb_person / maludb_stakeholder views.
    EXECUTE format('DROP VIEW IF EXISTS %I.maludb_subject CASCADE', p_schema);
    EXECUTE format('DROP VIEW IF EXISTS %I.maludb_memory CASCADE', p_schema);
    EXECUTE format('DROP VIEW IF EXISTS %I.maludb_skill CASCADE', p_schema);
    EXECUTE format('DROP VIEW IF EXISTS %I.maludb_document CASCADE', p_schema);

    INSERT INTO maludb_core.malu$enabled_schema(schema_name, enabled_version, enabled_by)
    VALUES (p_schema, v_enabled_version, session_user)
    ON CONFLICT ON CONSTRAINT malu$enabled_schema_pkey DO UPDATE
       SET enabled_version   = EXCLUDED.enabled_version,
           last_refreshed_at = now();

    v_count := v_count + maludb_core._enable_memory_schema_subject_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_core_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ingest_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_pool_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ai_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_075_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_076_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_078_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_080_facade(p_schema);
    PERFORM maludb_core._grant_memory_schema_reader_access(p_schema);

    schema_name := p_schema;
    enabled_version := v_enabled_version;
    object_count := v_count;
    RETURN NEXT;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core.enable_memory_schema(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.enable_memory_schema(name)
    TO maludb_memory_admin, maludb_memory_executor, maludb_user, maludb_admin;

-- =====================================================================
-- maludb_core 0.80.1 -> 0.80.2
--
-- Closes the last two API-project requests (db-requirements.md §1.2, §6):
--
--   §1.2  register_svpor_relationship is now idempotent and FK-validates
--         its endpoints. The create side previously inserted a fresh edge
--         every call and never checked that the subject/verb existed
--         (malu$relationship_edge has no real FK to the SVPOR tables), so
--         the API had to dedupe + existence-check itself. Now an identical
--         (source, target, relationship_type) edge in the same tenant is
--         returned as-is, and a dangling endpoint raises foreign_key_violation.
--
--   §6    New schema-local maludb_register_episode(...) facade: a thin,
--         search-path-safe wrapper over maludb_core.register_episode so the
--         REST endpoint can drop its `SET LOCAL search_path` dance. It is
--         SECURITY INVOKER with `SET search_path = <schema>, maludb_core,
--         pg_temp` -- NOT security definer -- so episodes stay tenant-owned
--         (current_schema() and RLS resolve to the caller's schema, exactly
--         as the direct register_episode call does today).
--
-- Also hardens 0.80.1's enable_memory_schema idempotency fix: 0.80.1 dropped
-- maludb_subject / maludb_memory / maludb_skill / maludb_document
-- unconditionally up front, which silently destroyed a tenant's own
-- same-named view and defeated the "refuse to replace an unmanaged view"
-- guard. enable_memory_schema now drops those four views only when they are
-- extension-managed (recorded in malu$enabled_schema_object), so re-enable
-- stays idempotent while an unmanaged collision is still refused.
--
-- Existing schemas pick up maludb_register_episode by re-running
-- maludb_core.enable_memory_schema(); the register_svpor_relationship fix is
-- in the shared core function and applies immediately.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core.maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.80.2'::text $body$;

-- ===== §1.2. idempotent, FK-validating SVPOR relationship create ======
CREATE OR REPLACE FUNCTION maludb_core.register_svpor_relationship(
    p_source_kind text,
    p_source_id bigint,
    p_target_kind text,
    p_target_id bigint,
    p_relationship_type text,
    p_label text DEFAULT NULL,
    p_edge_jsonb jsonb DEFAULT NULL,
    p_confidence numeric DEFAULT NULL
) RETURNS bigint
LANGUAGE plpgsql
SECURITY INVOKER
AS $body$
DECLARE
    v_source_kind text := lower(btrim(COALESCE(p_source_kind, '')));
    v_target_kind text := lower(btrim(COALESCE(p_target_kind, '')));
    v_schema      name := current_schema();
    v_edge_id     bigint;
BEGIN
    IF v_source_kind NOT IN ('subject','verb') OR v_target_kind NOT IN ('subject','verb') THEN
        RAISE EXCEPTION 'SVPOR relationships support only subject and verb endpoints'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    -- FK-validate both endpoints exist in this tenant's SVPOR graph. The
    -- polymorphic edge table carries no real FK to malu$svpor_subject /
    -- malu$svpor_verb, so a dangling id would otherwise be recorded as an
    -- orphan edge. RLS already scopes these tables to current_schema();
    -- the explicit owner_schema predicate keeps the intent obvious.
    IF (v_source_kind = 'subject'
            AND NOT EXISTS (SELECT 1 FROM maludb_core.malu$svpor_subject
                             WHERE owner_schema = v_schema AND subject_id = p_source_id))
       OR (v_source_kind = 'verb'
            AND NOT EXISTS (SELECT 1 FROM maludb_core.malu$svpor_verb
                             WHERE owner_schema = v_schema AND verb_id = p_source_id)) THEN
        RAISE EXCEPTION 'SVPOR source % % not found in schema %', v_source_kind, p_source_id, v_schema
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    IF (v_target_kind = 'subject'
            AND NOT EXISTS (SELECT 1 FROM maludb_core.malu$svpor_subject
                             WHERE owner_schema = v_schema AND subject_id = p_target_id))
       OR (v_target_kind = 'verb'
            AND NOT EXISTS (SELECT 1 FROM maludb_core.malu$svpor_verb
                             WHERE owner_schema = v_schema AND verb_id = p_target_id)) THEN
        RAISE EXCEPTION 'SVPOR target % % not found in schema %', v_target_kind, p_target_id, v_schema
            USING ERRCODE = 'foreign_key_violation';
    END IF;

    -- Idempotent: an identical (source, target, relationship_type) edge in
    -- this tenant is returned as-is rather than duplicated. label / edge_jsonb
    -- / confidence are not part of the identity -- a repeated link is the
    -- same link.
    SELECT e.edge_id INTO v_edge_id
      FROM maludb_core.malu$relationship_edge e
     WHERE e.owner_schema       = v_schema
       AND e.source_object_type = v_source_kind
       AND e.source_object_id   = p_source_id
       AND e.target_object_type = v_target_kind
       AND e.target_object_id   = p_target_id
       AND e.relationship_type  = p_relationship_type
     ORDER BY e.edge_id
     LIMIT 1;
    IF v_edge_id IS NOT NULL THEN
        RETURN v_edge_id;
    END IF;

    RETURN maludb_core.register_relationship_edge(
        v_source_kind,
        p_source_id,
        v_target_kind,
        p_target_id,
        p_relationship_type,
        p_label,
        COALESCE(p_edge_jsonb, '{}'::jsonb),
        p_confidence
    );
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core.register_svpor_relationship(text, bigint, text, bigint, text, text, jsonb, numeric) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.register_svpor_relationship(text, bigint, text, bigint, text, text, jsonb, numeric)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== §6. schema-local facade: search-path-safe episode writer ========
CREATE FUNCTION maludb_core._enable_memory_schema_0802_facade(p_schema name) RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_count integer := 0;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_register_episode', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_register_episode(
            p_episode_kind   text,
            p_title          text,
            p_summary        text DEFAULT NULL,
            p_payload_jsonb  jsonb DEFAULT '{}'::jsonb,
            p_occurred_at    timestamptz DEFAULT NULL,
            p_occurred_until timestamptz DEFAULT NULL,
            p_sensitivity    text DEFAULT 'internal'
        ) RETURNS bigint
        LANGUAGE sql
        SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$
            SELECT maludb_core.register_episode(
                p_episode_kind, p_title, p_summary, p_payload_jsonb,
                p_occurred_at, p_occurred_until, p_sensitivity
            )
        $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_register_episode(text, text, text, jsonb, timestamptz, timestamptz, text) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_register_episode(text, text, text, jsonb, timestamptz, timestamptz, text) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_register_episode', 'function', 'Schema-local search-path-safe episode writer.');
    v_count := v_count + 1;

    RETURN v_count;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core._enable_memory_schema_0802_facade(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._enable_memory_schema_0802_facade(name)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== wire the new builder in (must run last) =======================
-- Same body as 0.80.1 (keeps the up-front view drops that make re-enable
-- idempotent) plus the 0802 builder call.
CREATE OR REPLACE FUNCTION maludb_core.enable_memory_schema(p_schema name DEFAULT current_schema())
RETURNS TABLE(schema_name name, enabled_version text, object_count integer)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_enabled_version text := maludb_core.maludb_core_version();
    v_count integer := 0;
    v_view  name;
BEGIN
    IF p_schema IS NULL THEN
        p_schema := current_schema();
    END IF;

    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    -- Drop the views the 0.80 facade widens, so the base builders can
    -- recreate them without hitting "cannot drop columns from view" on
    -- re-enable -- but ONLY when they are extension-managed (recorded in
    -- malu$enabled_schema_object). A same-named view a tenant created
    -- themselves is left in place so the base builder's
    -- _memory_schema_assert_object_slot still refuses to replace it,
    -- instead of silently dropping it. (0.80.1 dropped these
    -- unconditionally, which defeated that guard.) CASCADE on
    -- maludb_subject also drops the dependent maludb_project /
    -- maludb_person / maludb_stakeholder views, which the subject facade
    -- recreates.
    FOREACH v_view IN ARRAY ARRAY['maludb_subject','maludb_memory','maludb_skill','maludb_document']::name[]
    LOOP
        IF EXISTS (
            SELECT 1 FROM maludb_core.malu$enabled_schema_object o
             WHERE o.schema_name = p_schema
               AND o.object_name = v_view
               AND o.object_kind = 'view'
        ) THEN
            EXECUTE format('DROP VIEW IF EXISTS %I.%I CASCADE', p_schema, v_view);
        END IF;
    END LOOP;

    INSERT INTO maludb_core.malu$enabled_schema(schema_name, enabled_version, enabled_by)
    VALUES (p_schema, v_enabled_version, session_user)
    ON CONFLICT ON CONSTRAINT malu$enabled_schema_pkey DO UPDATE
       SET enabled_version   = EXCLUDED.enabled_version,
           last_refreshed_at = now();

    v_count := v_count + maludb_core._enable_memory_schema_subject_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_core_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ingest_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_pool_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ai_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_075_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_076_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_078_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_080_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0802_facade(p_schema);
    PERFORM maludb_core._grant_memory_schema_reader_access(p_schema);

    schema_name := p_schema;
    enabled_version := v_enabled_version;
    object_count := v_count;
    RETURN NEXT;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core.enable_memory_schema(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.enable_memory_schema(name)
    TO maludb_memory_admin, maludb_memory_executor, maludb_user, maludb_admin;

-- =====================================================================
-- maludb_core 0.80.3 -> 0.80.3
--
-- Search-path-safe schema-local facades for editing an existing typed,
-- dated subject<->subject relationship:
--
--   maludb_subject_relationship_close(p_relationship_id, p_valid_to)
--       sets valid_to (e.g. now() for "expire now" or a chosen date);
--       returns true if changed
--   maludb_subject_relationship_delete(p_relationship_id)
--       removes the edge (for relationships entered by mistake); returns
--       the row count
--   maludb_subject_relationship_set_type(p_relationship_id, p_relationship_type)
--       edits relationship_type; returns true if changed
--
-- The writable maludb_subject_relationship view already supports the same
-- operations via plain UPDATE / DELETE; these facades are the parallel
-- search-path-safe call path mirroring maludb_register_episode and
-- maludb_svpor_relationship_create.
--
-- All three are SECURITY INVOKER (RLS + tenant ownership preserved) with
-- `SET search_path = <schema>, maludb_core, pg_temp`. They write directly
-- to maludb_core.malu$svpor_subject_relationship_edge (executor already
-- has CRUD + RLS scopes by owner_schema = current_schema()) rather than
-- wrapping a separate core helper -- the 0.79.0 consolidation deliberately
-- dropped close / delete / list / add_svpor_relationship_edge in favor of
-- the view, and resurrecting them would fight that decision.
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core.maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.81.0'::text $body$;

-- ===== schema-local facades ==========================================
CREATE FUNCTION maludb_core._enable_memory_schema_0803_facade(p_schema name) RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_count integer := 0;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    -- close (set valid_to; expire now or at a chosen date) -------------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_subject_relationship_close', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_subject_relationship_close(
            p_relationship_id bigint,
            p_valid_to        timestamptz DEFAULT now()
        ) RETURNS boolean
        LANGUAGE plpgsql
        SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$
        DECLARE
            v_schema name := current_schema();
        BEGIN
            IF p_relationship_id IS NULL OR p_valid_to IS NULL THEN
                RAISE EXCEPTION 'relationship_id and valid_to are required'
                    USING ERRCODE = 'invalid_parameter_value';
            END IF;
            UPDATE maludb_core.malu$svpor_subject_relationship_edge
               SET valid_to = p_valid_to
             WHERE owner_schema = v_schema
               AND edge_id = p_relationship_id
               AND valid_to IS DISTINCT FROM p_valid_to;
            RETURN FOUND;
        END;
        $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_subject_relationship_close(bigint, timestamptz) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_subject_relationship_close(bigint, timestamptz) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_subject_relationship_close', 'function', 'Schema-local subject<->subject relationship close (set valid_to).');
    v_count := v_count + 1;

    -- delete (relationship entered by mistake) -------------------------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_subject_relationship_delete', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_subject_relationship_delete(
            p_relationship_id bigint
        ) RETURNS integer
        LANGUAGE plpgsql
        SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$
        DECLARE
            v_schema name := current_schema();
            v_count  integer;
        BEGIN
            IF p_relationship_id IS NULL THEN
                RAISE EXCEPTION 'relationship_id is required'
                    USING ERRCODE = 'invalid_parameter_value';
            END IF;
            DELETE FROM maludb_core.malu$svpor_subject_relationship_edge
             WHERE owner_schema = v_schema
               AND edge_id = p_relationship_id;
            GET DIAGNOSTICS v_count = ROW_COUNT;
            RETURN v_count;
        END;
        $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_subject_relationship_delete(bigint) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_subject_relationship_delete(bigint) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_subject_relationship_delete', 'function', 'Schema-local subject<->subject relationship delete.');
    v_count := v_count + 1;

    -- set_type (edit relationship_type) --------------------------------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_subject_relationship_set_type', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_subject_relationship_set_type(
            p_relationship_id   bigint,
            p_relationship_type text
        ) RETURNS boolean
        LANGUAGE plpgsql
        SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$
        DECLARE
            v_schema name := current_schema();
        BEGIN
            IF p_relationship_id IS NULL OR p_relationship_type IS NULL OR btrim(p_relationship_type) = '' THEN
                RAISE EXCEPTION 'relationship_id and non-empty relationship_type are required'
                    USING ERRCODE = 'invalid_parameter_value';
            END IF;
            UPDATE maludb_core.malu$svpor_subject_relationship_edge
               SET relationship_type = p_relationship_type
             WHERE owner_schema = v_schema
               AND edge_id = p_relationship_id
               AND relationship_type IS DISTINCT FROM p_relationship_type;
            RETURN FOUND;
        END;
        $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_subject_relationship_set_type(bigint, text) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_subject_relationship_set_type(bigint, text) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_subject_relationship_set_type', 'function', 'Schema-local subject<->subject relationship_type edit.');
    v_count := v_count + 1;

    RETURN v_count;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core._enable_memory_schema_0803_facade(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._enable_memory_schema_0803_facade(name)
    TO maludb_memory_admin, maludb_memory_executor;

-- =====================================================================
-- maludb_core 0.81.0
--
-- Document type as a per-schema soft picker: a free-text document_type
-- column on malu$document (single primary value, drives the UI label)
-- plus a per-schema malu$document_type lookup that seeds the picker.
-- The lookup is advisory only; nothing prevents upload_document from
-- writing a brand-new type string that has not been seeded yet.
-- Secondary type tags can also accumulate via the new 'document_type'
-- tag_kind on malu$document_tag.
--
-- The 0810 facade re-issues the widened maludb_document view to expose
-- the new column at the end (CREATE OR REPLACE VIEW tolerates appended
-- columns) and replaces the 10-arg maludb_upload_document with an
-- 11-arg version that accepts p_document_type. Existing schemas pick
-- this up by re-running maludb_core.enable_memory_schema().
-- =====================================================================

CREATE FUNCTION maludb_core._enable_memory_schema_0810_facade(p_schema name) RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_count integer := 0;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    -- ---- maludb_document_type: writable per-schema lookup ----------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_document_type', 'view');
    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_document_type WITH (security_invoker = true) AS
        SELECT document_type_id,
               document_type,
               description,
               display_order,
               created_at
          FROM maludb_core.malu$document_type
         WHERE owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);
    EXECUTE format('GRANT SELECT, INSERT, UPDATE, DELETE ON %I.maludb_document_type TO maludb_memory_admin, maludb_memory_executor', p_schema);
    EXECUTE format('GRANT SELECT ON %I.maludb_document_type TO maludb_memory_auditor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_document_type', 'view', 'Schema-local document type lookup facade.');
    v_count := v_count + 1;

    -- ---- starter seed of common document types ---------------------
    -- ON CONFLICT DO NOTHING: idempotent on re-enable. Tenants are free
    -- to delete or rename these; we will not re-add anything they
    -- removed unless the lower(document_type) slot is empty.
    EXECUTE format($sql$
        INSERT INTO maludb_core.malu$document_type
            (owner_schema, document_type, description, display_order)
        VALUES
            (%L, 'Meeting Notes',     'Notes captured during a meeting.',                 10),
            (%L, 'Meeting Transcript','Verbatim transcript of a meeting or call.',        20),
            (%L, 'Email',             'Email message or thread.',                         30),
            (%L, 'Report',            'Analytical or status report.',                     40),
            (%L, 'White Paper',       'Long-form explanatory document.',                  50),
            (%L, 'Specification',     'Technical specification or design document.',      60),
            (%L, 'Change Request',    'Proposed change with rationale and scope.',        70),
            (%L, 'Decision Memo',     'Captured decision with options and rationale.',    80),
            (%L, 'Proposal',          'Proposal seeking approval or funding.',            90),
            (%L, 'Contract',          'Executed or draft contractual document.',         100)
        ON CONFLICT DO NOTHING
    $sql$,
        p_schema, p_schema, p_schema, p_schema, p_schema,
        p_schema, p_schema, p_schema, p_schema, p_schema);

    -- ---- maludb_document: re-widen with document_type --------------
    -- Same column list as the 0.80 widened view, with document_type
    -- appended at the end so CREATE OR REPLACE VIEW accepts it without
    -- a drop.
    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_document WITH (security_invoker = true) AS
        SELECT d.document_id, d.source_package_id, d.title, d.source_type,
               d.media_type, d.primary_project_id, d.lifecycle_state,
               d.metadata_jsonb, d.created_at, d.updated_at,
               (SELECT sp.content_text
                  FROM maludb_core.malu$source_package sp
                 WHERE sp.owner_schema = d.owner_schema
                   AND sp.source_package_id = d.source_package_id
                   AND sp.source_type = d.source_type) AS body_text,
               d.document_type
          FROM maludb_core.malu$document d
         WHERE d.owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);

    -- ---- maludb_upload_document: new 11-arg signature --------------
    -- Drop the 10-arg signature emitted by the ingest_facade so the new
    -- definition replaces it cleanly instead of living alongside as a
    -- second overload.
    EXECUTE format('DROP FUNCTION IF EXISTS %I.maludb_upload_document(text, text, text, jsonb, text, text[], text[], text[], text[], jsonb)', p_schema);
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_upload_document', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_upload_document(
            p_title          text,
            p_content_text   text,
            p_source_type    text   DEFAULT 'document',
            p_content_jsonb  jsonb  DEFAULT NULL,
            p_media_type     text   DEFAULT NULL,
            p_projects       text[] DEFAULT ARRAY[]::text[],
            p_subjects       text[] DEFAULT ARRAY[]::text[],
            p_verbs          text[] DEFAULT ARRAY[]::text[],
            p_events         text[] DEFAULT ARRAY[]::text[],
            p_metadata_jsonb jsonb  DEFAULT '{}'::jsonb,
            p_document_type  text   DEFAULT NULL
        ) RETURNS bigint
        LANGUAGE sql
        SECURITY DEFINER
        SET search_path = pg_catalog, maludb_core, pg_temp
        AS $facade$
            SELECT maludb_core._upload_document_for_schema(
                %L::name,
                p_title,
                p_content_text,
                p_source_type,
                p_content_jsonb,
                p_media_type,
                p_projects,
                p_subjects,
                p_verbs,
                p_events,
                p_metadata_jsonb,
                p_document_type
            )
        $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_upload_document(text, text, text, jsonb, text, text[], text[], text[], text[], jsonb, text) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_upload_document(text, text, text, jsonb, text, text[], text[], text[], text[], jsonb, text) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_upload_document', 'function', 'Schema-local document upload facade.');
    v_count := v_count + 1;

    RETURN v_count;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core._enable_memory_schema_0810_facade(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._enable_memory_schema_0810_facade(name)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== wire the new builder in (must run last) =======================
-- Same body as 0.80.3 plus the 0810 builder call.
CREATE OR REPLACE FUNCTION maludb_core.enable_memory_schema(p_schema name DEFAULT current_schema())
RETURNS TABLE(schema_name name, enabled_version text, object_count integer)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_enabled_version text := maludb_core.maludb_core_version();
    v_count integer := 0;
    v_view  name;
BEGIN
    IF p_schema IS NULL THEN
        p_schema := current_schema();
    END IF;

    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    FOREACH v_view IN ARRAY ARRAY['maludb_subject','maludb_memory','maludb_skill','maludb_document']::name[]
    LOOP
        IF EXISTS (
            SELECT 1 FROM maludb_core.malu$enabled_schema_object o
             WHERE o.schema_name = p_schema
               AND o.object_name = v_view
               AND o.object_kind = 'view'
        ) THEN
            EXECUTE format('DROP VIEW IF EXISTS %I.%I CASCADE', p_schema, v_view);
        END IF;
    END LOOP;

    INSERT INTO maludb_core.malu$enabled_schema(schema_name, enabled_version, enabled_by)
    VALUES (p_schema, v_enabled_version, session_user)
    ON CONFLICT ON CONSTRAINT malu$enabled_schema_pkey DO UPDATE
       SET enabled_version   = EXCLUDED.enabled_version,
           last_refreshed_at = now();

    v_count := v_count + maludb_core._enable_memory_schema_subject_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_core_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ingest_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_pool_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ai_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_075_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_076_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_078_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_080_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0802_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0803_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0810_facade(p_schema);
    PERFORM maludb_core._grant_memory_schema_reader_access(p_schema);

    schema_name := p_schema;
    enabled_version := v_enabled_version;
    object_count := v_count;
    RETURN NEXT;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core.enable_memory_schema(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.enable_memory_schema(name)
    TO maludb_memory_admin, maludb_memory_executor, maludb_user, maludb_admin;


-- ============================================================
-- Section: maludb_core--0.81.0--0.82.0.sql
-- ============================================================

-- =====================================================================
-- maludb_core 0.81.0 -> 0.82.0
--
-- Episode/event enrichment: link subjects, verbs, artifacts (documents),
-- and decisions to an episode, and make the whole thing agent-ready (an
-- LLM extractor can stage derived graph fragments as 'suggested' for
-- review, the same way provided data flows).
--
-- Investigation (verified against a live DB) established:
--   * malu$episode_object exists but had only a write facade
--     (maludb_register_episode) -- no read/list/update path.
--   * malu$relationship_edge is pairwise and uses a controlled
--     relationship_type vocabulary; register_svpor_relationship is
--     hard-restricted to subject<->verb endpoints, so it cannot link a
--     subject (or a document) to an episode.
--   * malu$claim / malu$fact carry SVPOR as denormalised text, not FKs,
--     and are source-oriented -- not a usable subject/verb/object bridge.
--
-- So this release adds a normalised, fully polymorphic SVO assertion
-- table plus the episode read/list/update surface and an event-type
-- picker.
--
--   1. malu$svpor_statement -- (subject_kind/subject_id) --verb_id-->
--      (object_kind/object_id), optional predicate, dated, with
--      confidence, optional source_package provenance, and a
--      provenance state (provided | suggested | accepted | rejected).
--      Both ends polymorphic over the SVPOR + governed-object graph,
--      including 'document' directly. The verb is always a
--      malu$svpor_verb, sidestepping the relationship_type vocabulary.
--      Idempotent and FK-validates both endpoints per kind.
--
--   2. malu$episode_type -- per-schema advisory picker for event types
--      (the document_type pattern from 0.81.0). episode_kind stays free
--      text; nothing is FK-enforced.
--
--   3. malu$episode_object.provenance -- so a derived event lands as
--      'suggested' for review, like derived statements/tags/hints.
--
-- Agent-readiness note: the derivation *process* (launching the LLM,
-- parsing) is NOT defined here -- it lives in the model gateway
-- (malu$model_request/response), the ingest pipeline
-- (malu$raw_ingest/malu$ingest_extraction), MC2DB tools, and lineage
-- (malu$derivation_ledger). This release only ensures the data model
-- carries the provenance/confidence/lineage needed for that process to
-- write reviewable output. malu$svpor_statement is registered as a
-- derived_object_type so its lineage can be recorded.
--
-- Existing schemas pick up the new objects by re-running
-- maludb_core.enable_memory_schema().
-- =====================================================================

CREATE OR REPLACE FUNCTION maludb_core.maludb_core_version() RETURNS text
    LANGUAGE SQL IMMUTABLE PARALLEL SAFE
    AS $body$ SELECT '0.82.0'::text $body$;

-- ===== 1. malu$episode_object: provenance ===========================
ALTER TABLE maludb_core.malu$episode_object
    ADD COLUMN IF NOT EXISTS provenance text NOT NULL DEFAULT 'provided'
        CHECK (provenance IN ('provided','suggested','accepted','rejected'));

-- ===== 2. malu$episode_type: per-schema advisory picker =============
CREATE TABLE IF NOT EXISTS maludb_core.malu$episode_type (
    episode_type_id  bigserial PRIMARY KEY,
    owner_schema     name NOT NULL DEFAULT current_schema(),
    episode_type     text NOT NULL,
    description      text,
    display_order    integer,
    created_at       timestamptz NOT NULL DEFAULT now(),
    UNIQUE (owner_schema, episode_type)
);
CREATE UNIQUE INDEX IF NOT EXISTS malu$episode_type_owner_lower_idx
    ON maludb_core.malu$episode_type(owner_schema, lower(episode_type));
CREATE INDEX IF NOT EXISTS malu$episode_type_owner_order_idx
    ON maludb_core.malu$episode_type(owner_schema, display_order, episode_type);

ALTER TABLE maludb_core.malu$episode_type ENABLE ROW LEVEL SECURITY;
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_catalog.pg_policy p
          JOIN pg_catalog.pg_class c ON c.oid = p.polrelid
          JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
         WHERE n.nspname = 'maludb_core'
           AND c.relname = 'malu$episode_type'
           AND p.polname = 'tenant_owner'
    ) THEN
        EXECUTE 'CREATE POLICY tenant_owner ON maludb_core.malu$episode_type
                 USING (owner_schema = current_schema())
                 WITH CHECK (owner_schema = current_schema())';
    END IF;
END$$;

GRANT SELECT, INSERT, UPDATE, DELETE ON maludb_core.malu$episode_type
    TO maludb_memory_admin, maludb_memory_executor;
GRANT SELECT ON maludb_core.malu$episode_type TO maludb_memory_auditor;
GRANT USAGE, SELECT ON SEQUENCE maludb_core.malu$episode_type_episode_type_id_seq
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== 3. malu$svpor_statement: polymorphic SVO assertion ===========
CREATE TABLE IF NOT EXISTS maludb_core.malu$svpor_statement (
    statement_id       bigserial PRIMARY KEY,
    owner_schema       name NOT NULL DEFAULT current_schema(),
    subject_kind       text NOT NULL,
    subject_id         bigint NOT NULL,
    verb_id            bigint NOT NULL
        REFERENCES maludb_core.malu$svpor_verb(verb_id) ON DELETE RESTRICT,
    object_kind        text NOT NULL,
    object_id          bigint NOT NULL,
    predicate_id       bigint
        REFERENCES maludb_core.malu$svpor_predicate(predicate_id) ON DELETE SET NULL,
    valid_from         timestamptz,
    valid_to           timestamptz,
    confidence         numeric(5,4) CHECK (confidence IS NULL OR confidence BETWEEN 0 AND 1),
    provenance         text NOT NULL DEFAULT 'provided'
        CHECK (provenance IN ('provided','suggested','accepted','rejected')),
    source_package_id  bigint
        REFERENCES maludb_core.malu$source_package(source_package_id) ON DELETE SET NULL,
    metadata_jsonb     jsonb NOT NULL DEFAULT '{}'::jsonb,
    created_at         timestamptz NOT NULL DEFAULT now(),
    CHECK (subject_kind IN
        ('subject','verb','document','episode_object','memory',
         'source_package','claim','fact','memory_detail_object')),
    CHECK (object_kind IN
        ('subject','verb','document','episode_object','memory',
         'source_package','claim','fact','memory_detail_object'))
);
-- Idempotency identity: a repeated (subject, verb, object) assertion in a
-- tenant is the same assertion. predicate/confidence/provenance/dates are
-- not part of the identity.
CREATE UNIQUE INDEX IF NOT EXISTS malu$svpor_statement_identity_idx
    ON maludb_core.malu$svpor_statement
       (owner_schema, subject_kind, subject_id, verb_id, object_kind, object_id);
CREATE INDEX IF NOT EXISTS malu$svpor_statement_subject_idx
    ON maludb_core.malu$svpor_statement(owner_schema, subject_kind, subject_id);
CREATE INDEX IF NOT EXISTS malu$svpor_statement_object_idx
    ON maludb_core.malu$svpor_statement(owner_schema, object_kind, object_id);
CREATE INDEX IF NOT EXISTS malu$svpor_statement_verb_idx
    ON maludb_core.malu$svpor_statement(owner_schema, verb_id);

ALTER TABLE maludb_core.malu$svpor_statement ENABLE ROW LEVEL SECURITY;
DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_catalog.pg_policy p
          JOIN pg_catalog.pg_class c ON c.oid = p.polrelid
          JOIN pg_catalog.pg_namespace n ON n.oid = c.relnamespace
         WHERE n.nspname = 'maludb_core'
           AND c.relname = 'malu$svpor_statement'
           AND p.polname = 'tenant_owner'
    ) THEN
        EXECUTE 'CREATE POLICY tenant_owner ON maludb_core.malu$svpor_statement
                 USING (owner_schema = current_schema())
                 WITH CHECK (owner_schema = current_schema())';
    END IF;
END$$;

GRANT SELECT, INSERT, UPDATE, DELETE ON maludb_core.malu$svpor_statement
    TO maludb_memory_admin, maludb_memory_executor;
GRANT SELECT ON maludb_core.malu$svpor_statement TO maludb_memory_auditor;
GRANT USAGE, SELECT ON SEQUENCE maludb_core.malu$svpor_statement_statement_id_seq
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== 4. derivation_ledger: register the new derived type ==========
ALTER TABLE maludb_core.malu$derivation_ledger
    DROP CONSTRAINT malu$derivation_ledger_derived_object_type_check;
ALTER TABLE maludb_core.malu$derivation_ledger
    ADD CONSTRAINT malu$derivation_ledger_derived_object_type_check
    CHECK (derived_object_type IN (
        'source_package','claim','fact','memory','episode_object',
        'memory_detail_object','relationship_edge','embedding',
        'page_index_tree','page_index_node','svpor_statement'));

-- ===== 5. core helpers: endpoint validation + writers ===============

-- Per-kind existence check for a polymorphic endpoint. RLS already scopes
-- the governed tables to current_schema(); the explicit owner_schema
-- predicate on tenant tables keeps intent obvious. Raises
-- foreign_key_violation when the endpoint does not exist.
-- No SET search_path: this is SECURITY INVOKER and its existence checks
-- depend on current_schema() resolving to the caller's tenant schema
-- (both for the explicit owner_schema predicate and for RLS). All table
-- references are maludb_core-qualified, so inheriting the caller's path is
-- safe. (Pinning pg_catalog here would make current_schema() = pg_catalog
-- and RLS would filter every row for a non-superuser tenant role.)
CREATE FUNCTION maludb_core._svpor_statement_assert_endpoint(
    p_schema name, p_kind text, p_id bigint
) RETURNS void
LANGUAGE plpgsql
SECURITY INVOKER
AS $body$
DECLARE
    v_ok boolean := false;
BEGIN
    CASE p_kind
        WHEN 'subject' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$svpor_subject
                          WHERE owner_schema = p_schema AND subject_id = p_id) INTO v_ok;
        WHEN 'verb' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$svpor_verb
                          WHERE owner_schema = p_schema AND verb_id = p_id) INTO v_ok;
        WHEN 'document' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$document
                          WHERE owner_schema = p_schema AND document_id = p_id) INTO v_ok;
        WHEN 'episode_object' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$episode_object
                          WHERE owner_schema = p_schema AND episode_id = p_id) INTO v_ok;
        WHEN 'memory' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$memory
                          WHERE owner_schema = p_schema AND memory_id = p_id) INTO v_ok;
        WHEN 'source_package' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$source_package
                          WHERE owner_schema = p_schema AND source_package_id = p_id) INTO v_ok;
        WHEN 'claim' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$claim
                          WHERE owner_schema = p_schema AND claim_id = p_id) INTO v_ok;
        WHEN 'fact' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$fact
                          WHERE owner_schema = p_schema AND fact_id = p_id) INTO v_ok;
        WHEN 'memory_detail_object' THEN
            SELECT EXISTS(SELECT 1 FROM maludb_core.malu$memory_detail_object
                          WHERE owner_schema = p_schema AND mdo_id = p_id) INTO v_ok;
        ELSE
            RAISE EXCEPTION 'svpor_statement: unsupported endpoint kind %', p_kind
                USING ERRCODE = 'invalid_parameter_value';
    END CASE;

    IF NOT v_ok THEN
        RAISE EXCEPTION 'svpor_statement endpoint % % not found in schema %', p_kind, p_id, p_schema
            USING ERRCODE = 'foreign_key_violation';
    END IF;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core._svpor_statement_assert_endpoint(name, text, bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._svpor_statement_assert_endpoint(name, text, bigint)
    TO maludb_memory_admin, maludb_memory_executor;

-- register_svpor_statement -- idempotent writer. Returns the statement id.
-- On a repeated (subject, verb, object) identity, the existing row is
-- returned and its provenance/confidence/predicate/dates are refreshed
-- when explicitly supplied (COALESCE keeps prior values otherwise).
CREATE FUNCTION maludb_core.register_svpor_statement(
    p_subject_kind     text,
    p_subject_id       bigint,
    p_verb_id          bigint,
    p_object_kind      text,
    p_object_id        bigint,
    p_predicate_id     bigint      DEFAULT NULL,
    p_valid_from       timestamptz DEFAULT NULL,
    p_valid_to         timestamptz DEFAULT NULL,
    p_confidence       numeric     DEFAULT NULL,
    p_provenance       text        DEFAULT 'provided',
    p_source_package_id bigint     DEFAULT NULL,
    p_metadata_jsonb   jsonb       DEFAULT '{}'::jsonb
) RETURNS bigint
LANGUAGE plpgsql
SECURITY INVOKER
AS $body$
DECLARE
    v_schema        name := current_schema();
    v_subject_kind  text := lower(btrim(COALESCE(p_subject_kind, '')));
    v_object_kind   text := lower(btrim(COALESCE(p_object_kind, '')));
    v_provenance    text := COALESCE(NULLIF(btrim(p_provenance), ''), 'provided');
    v_id            bigint;
BEGIN
    IF p_subject_id IS NULL OR p_verb_id IS NULL OR p_object_id IS NULL THEN
        RAISE EXCEPTION 'register_svpor_statement: subject_id, verb_id and object_id are required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    IF v_provenance NOT IN ('provided','suggested','accepted','rejected') THEN
        RAISE EXCEPTION 'register_svpor_statement: bad provenance %', v_provenance
            USING ERRCODE = 'invalid_parameter_value';
    END IF;

    -- Validate the verb and both polymorphic endpoints exist in this tenant.
    PERFORM maludb_core._svpor_statement_assert_endpoint(v_schema, 'verb', p_verb_id);
    PERFORM maludb_core._svpor_statement_assert_endpoint(v_schema, v_subject_kind, p_subject_id);
    PERFORM maludb_core._svpor_statement_assert_endpoint(v_schema, v_object_kind, p_object_id);

    INSERT INTO maludb_core.malu$svpor_statement
        (owner_schema, subject_kind, subject_id, verb_id, object_kind, object_id,
         predicate_id, valid_from, valid_to, confidence, provenance,
         source_package_id, metadata_jsonb)
    VALUES
        (v_schema, v_subject_kind, p_subject_id, p_verb_id, v_object_kind, p_object_id,
         p_predicate_id, p_valid_from, p_valid_to, p_confidence, v_provenance,
         p_source_package_id, COALESCE(p_metadata_jsonb, '{}'::jsonb))
    ON CONFLICT (owner_schema, subject_kind, subject_id, verb_id, object_kind, object_id)
    DO UPDATE SET
        predicate_id      = COALESCE(EXCLUDED.predicate_id,      malu$svpor_statement.predicate_id),
        valid_from        = COALESCE(EXCLUDED.valid_from,        malu$svpor_statement.valid_from),
        valid_to          = COALESCE(EXCLUDED.valid_to,          malu$svpor_statement.valid_to),
        confidence        = COALESCE(EXCLUDED.confidence,        malu$svpor_statement.confidence),
        provenance        = EXCLUDED.provenance,
        source_package_id = COALESCE(EXCLUDED.source_package_id, malu$svpor_statement.source_package_id),
        metadata_jsonb    = malu$svpor_statement.metadata_jsonb || EXCLUDED.metadata_jsonb
    RETURNING statement_id INTO v_id;

    RETURN v_id;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core.register_svpor_statement(
    text, bigint, bigint, text, bigint, bigint, timestamptz, timestamptz, numeric, text, bigint, jsonb) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.register_svpor_statement(
    text, bigint, bigint, text, bigint, bigint, timestamptz, timestamptz, numeric, text, bigint, jsonb)
    TO maludb_memory_admin, maludb_memory_executor;

-- close (set valid_to) / delete / set provenance
CREATE FUNCTION maludb_core.svpor_statement_close(
    p_statement_id bigint, p_valid_to timestamptz DEFAULT now()
) RETURNS boolean
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
BEGIN
    IF p_statement_id IS NULL OR p_valid_to IS NULL THEN
        RAISE EXCEPTION 'statement_id and valid_to are required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    UPDATE maludb_core.malu$svpor_statement
       SET valid_to = p_valid_to
     WHERE owner_schema = current_schema()
       AND statement_id = p_statement_id
       AND valid_to IS DISTINCT FROM p_valid_to;
    RETURN FOUND;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core.svpor_statement_close(bigint, timestamptz) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.svpor_statement_close(bigint, timestamptz)
    TO maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION maludb_core.svpor_statement_delete(p_statement_id bigint) RETURNS integer
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
DECLARE v_count integer;
BEGIN
    IF p_statement_id IS NULL THEN
        RAISE EXCEPTION 'statement_id is required' USING ERRCODE = 'invalid_parameter_value';
    END IF;
    DELETE FROM maludb_core.malu$svpor_statement
     WHERE owner_schema = current_schema()
       AND statement_id = p_statement_id;
    GET DIAGNOSTICS v_count = ROW_COUNT;
    RETURN v_count;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core.svpor_statement_delete(bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.svpor_statement_delete(bigint)
    TO maludb_memory_admin, maludb_memory_executor;

CREATE FUNCTION maludb_core.svpor_statement_set_provenance(
    p_statement_id bigint, p_provenance text
) RETURNS boolean
LANGUAGE plpgsql SECURITY INVOKER
AS $body$
BEGIN
    IF p_statement_id IS NULL
       OR p_provenance NOT IN ('provided','suggested','accepted','rejected') THEN
        RAISE EXCEPTION 'statement_id and a valid provenance are required'
            USING ERRCODE = 'invalid_parameter_value';
    END IF;
    UPDATE maludb_core.malu$svpor_statement
       SET provenance = p_provenance
     WHERE owner_schema = current_schema()
       AND statement_id = p_statement_id
       AND provenance IS DISTINCT FROM p_provenance;
    RETURN FOUND;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core.svpor_statement_set_provenance(bigint, text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.svpor_statement_set_provenance(bigint, text)
    TO maludb_memory_admin, maludb_memory_executor;

-- Display-name resolver for a polymorphic endpoint (best-effort label).
-- No SET search_path: see _svpor_statement_assert_endpoint above. The
-- label lookups scope by current_schema(), which must be the tenant.
CREATE FUNCTION maludb_core._svpor_endpoint_label(p_kind text, p_id bigint) RETURNS text
LANGUAGE plpgsql STABLE SECURITY INVOKER
AS $body$
DECLARE v_label text;
BEGIN
    CASE p_kind
        WHEN 'subject' THEN
            SELECT canonical_name INTO v_label FROM maludb_core.malu$svpor_subject
             WHERE owner_schema = current_schema() AND subject_id = p_id;
        WHEN 'verb' THEN
            SELECT canonical_name INTO v_label FROM maludb_core.malu$svpor_verb
             WHERE owner_schema = current_schema() AND verb_id = p_id;
        WHEN 'document' THEN
            SELECT title INTO v_label FROM maludb_core.malu$document
             WHERE owner_schema = current_schema() AND document_id = p_id;
        WHEN 'episode_object' THEN
            SELECT title INTO v_label FROM maludb_core.malu$episode_object
             WHERE owner_schema = current_schema() AND episode_id = p_id;
        WHEN 'memory' THEN
            SELECT title INTO v_label FROM maludb_core.malu$memory
             WHERE owner_schema = current_schema() AND memory_id = p_id;
        WHEN 'source_package' THEN
            SELECT source_type INTO v_label FROM maludb_core.malu$source_package
             WHERE owner_schema = current_schema() AND source_package_id = p_id;
        ELSE
            v_label := NULL;
    END CASE;
    RETURN v_label;
END;
$body$;
REVOKE ALL ON FUNCTION maludb_core._svpor_endpoint_label(text, bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._svpor_endpoint_label(text, bigint)
    TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- episode_get -- aggregate: the event plus everything related to it.
-- 'statements' covers attendees (subject person + verb), artifacts
-- (document + generated_by), and decisions (memory + made_during) -- any
-- row whose subject OR object is this episode. 'details' carries any
-- memory_detail_objects hung directly off the episode.
CREATE FUNCTION maludb_core.episode_get(p_episode_id bigint)
RETURNS jsonb
LANGUAGE sql STABLE SECURITY INVOKER
AS $body$
    SELECT jsonb_build_object(
        'episode', to_jsonb(e),
        'statements', COALESCE((
            SELECT jsonb_agg(jsonb_build_object(
                       'statement_id', s.statement_id,
                       'subject_kind', s.subject_kind,
                       'subject_id',   s.subject_id,
                       'subject_label', maludb_core._svpor_endpoint_label(s.subject_kind, s.subject_id),
                       'verb_id',      s.verb_id,
                       'verb',         maludb_core._svpor_endpoint_label('verb', s.verb_id),
                       'object_kind',  s.object_kind,
                       'object_id',    s.object_id,
                       'object_label', maludb_core._svpor_endpoint_label(s.object_kind, s.object_id),
                       'provenance',   s.provenance,
                       'confidence',   s.confidence,
                       'valid_from',   s.valid_from,
                       'valid_to',     s.valid_to)
                     ORDER BY s.statement_id)
              FROM maludb_core.malu$svpor_statement s
             WHERE s.owner_schema = e.owner_schema
               AND ((s.subject_kind = 'episode_object' AND s.subject_id = e.episode_id)
                 OR (s.object_kind  = 'episode_object' AND s.object_id  = e.episode_id))
        ), '[]'::jsonb),
        'details', COALESCE((
            SELECT jsonb_agg(to_jsonb(d) ORDER BY d.ordinal NULLS LAST, d.mdo_id)
              FROM maludb_core.malu$memory_detail_object d
             WHERE d.owner_schema = e.owner_schema
               AND d.episode_id = e.episode_id
        ), '[]'::jsonb)
    )
    FROM maludb_core.malu$episode_object e
    WHERE e.owner_schema = current_schema()
      AND e.episode_id = p_episode_id
$body$;
REVOKE ALL ON FUNCTION maludb_core.episode_get(bigint) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.episode_get(bigint)
    TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor;

-- ===== 6. 0.82.0 schema-local facade builder ========================
CREATE FUNCTION maludb_core._enable_memory_schema_0820_facade(p_schema name) RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_count integer := 0;
BEGIN
    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    -- ---- maludb_episode_type: writable per-schema picker -----------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_episode_type', 'view');
    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_episode_type WITH (security_invoker = true) AS
        SELECT episode_type_id, episode_type, description, display_order, created_at
          FROM maludb_core.malu$episode_type
         WHERE owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);
    EXECUTE format('GRANT SELECT, INSERT, UPDATE, DELETE ON %I.maludb_episode_type TO maludb_memory_admin, maludb_memory_executor', p_schema);
    EXECUTE format('GRANT SELECT ON %I.maludb_episode_type TO maludb_memory_auditor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_episode_type', 'view', 'Schema-local episode type picker facade.');
    v_count := v_count + 1;

    -- starter event types (idempotent; tenant edits survive re-enable)
    EXECUTE format($sql$
        INSERT INTO maludb_core.malu$episode_type
            (owner_schema, episode_type, description, display_order)
        VALUES
            (%L,'Meeting',       'General meeting.',                       10),
            (%L,'Daily Standup', 'Recurring team standup.',                20),
            (%L,'Review',        'Review or demo session.',                30),
            (%L,'Retrospective', 'Retrospective / lessons-learned.',       40),
            (%L,'1:1',           'One-on-one conversation.',               50),
            (%L,'Incident',      'Incident or outage event.',              60),
            (%L,'Planning',      'Planning or roadmap session.',           70)
        ON CONFLICT DO NOTHING
    $sql$, p_schema, p_schema, p_schema, p_schema, p_schema, p_schema, p_schema);

    -- ---- starter verbs for the meeting use-case --------------------
    EXECUTE format($sql$
        INSERT INTO maludb_core.malu$svpor_verb (owner_schema, canonical_name, aliases, description)
        VALUES
            (%L,'attended',     ARRAY['attended_by']::text[], 'Participant attended an event.'),
            (%L,'generated_by', ARRAY['produced_by']::text[], 'Artifact was generated by an event.'),
            (%L,'made_during',  ARRAY['decided_during']::text[], 'Decision/outcome made during an event.')
        ON CONFLICT (owner_schema, canonical_name) DO NOTHING
    $sql$, p_schema, p_schema, p_schema);

    -- ---- maludb_svpor_statement: writable view ---------------------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_svpor_statement', 'view');
    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_svpor_statement WITH (security_invoker = true) AS
        SELECT statement_id, subject_kind, subject_id, verb_id, object_kind, object_id,
               predicate_id, valid_from, valid_to, confidence, provenance,
               source_package_id, metadata_jsonb, created_at
          FROM maludb_core.malu$svpor_statement
         WHERE owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);
    EXECUTE format('GRANT SELECT, INSERT, UPDATE, DELETE ON %I.maludb_svpor_statement TO maludb_memory_admin, maludb_memory_executor', p_schema);
    EXECUTE format('GRANT SELECT ON %I.maludb_svpor_statement TO maludb_memory_auditor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_svpor_statement', 'view', 'Schema-local SVPOR statement facade.');
    v_count := v_count + 1;

    -- ---- maludb_svpor_statement_create / close / delete / set_provenance
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_svpor_statement_create', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_svpor_statement_create(
            p_subject_kind text, p_subject_id bigint, p_verb_id bigint,
            p_object_kind text, p_object_id bigint,
            p_predicate_id bigint DEFAULT NULL,
            p_valid_from timestamptz DEFAULT NULL, p_valid_to timestamptz DEFAULT NULL,
            p_confidence numeric DEFAULT NULL, p_provenance text DEFAULT 'provided',
            p_source_package_id bigint DEFAULT NULL, p_metadata_jsonb jsonb DEFAULT '{}'::jsonb
        ) RETURNS bigint LANGUAGE sql SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.register_svpor_statement(
            p_subject_kind, p_subject_id, p_verb_id, p_object_kind, p_object_id,
            p_predicate_id, p_valid_from, p_valid_to, p_confidence, p_provenance,
            p_source_package_id, p_metadata_jsonb) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_svpor_statement_create(text, bigint, bigint, text, bigint, bigint, timestamptz, timestamptz, numeric, text, bigint, jsonb) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_svpor_statement_create(text, bigint, bigint, text, bigint, bigint, timestamptz, timestamptz, numeric, text, bigint, jsonb) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_svpor_statement_create', 'function', 'Schema-local SVPOR statement writer.');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_svpor_statement_close', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_svpor_statement_close(p_statement_id bigint, p_valid_to timestamptz DEFAULT now())
        RETURNS boolean LANGUAGE sql SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.svpor_statement_close(p_statement_id, p_valid_to) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_svpor_statement_close(bigint, timestamptz) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_svpor_statement_close(bigint, timestamptz) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_svpor_statement_close', 'function', 'Schema-local SVPOR statement close (set valid_to).');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_svpor_statement_delete', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_svpor_statement_delete(p_statement_id bigint)
        RETURNS integer LANGUAGE sql SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.svpor_statement_delete(p_statement_id) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_svpor_statement_delete(bigint) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_svpor_statement_delete(bigint) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_svpor_statement_delete', 'function', 'Schema-local SVPOR statement delete.');
    v_count := v_count + 1;

    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_svpor_statement_set_provenance', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_svpor_statement_set_provenance(p_statement_id bigint, p_provenance text)
        RETURNS boolean LANGUAGE sql SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.svpor_statement_set_provenance(p_statement_id, p_provenance) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_svpor_statement_set_provenance(bigint, text) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_svpor_statement_set_provenance(bigint, text) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_svpor_statement_set_provenance', 'function', 'Schema-local SVPOR statement provenance edit.');
    v_count := v_count + 1;

    -- ---- maludb_episode: writable list/get/update view -------------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_episode', 'view');
    EXECUTE format($sql$
        CREATE OR REPLACE VIEW %I.maludb_episode WITH (security_invoker = true) AS
        SELECT episode_id, episode_kind, title, summary, payload_jsonb,
               occurred_at, occurred_until, recorded_at, sensitivity,
               lifecycle_state, provenance, created_at
          FROM maludb_core.malu$episode_object
         WHERE owner_schema = %L
        WITH LOCAL CHECK OPTION
    $sql$, p_schema, p_schema);
    EXECUTE format('GRANT SELECT, INSERT, UPDATE, DELETE ON %I.maludb_episode TO maludb_memory_admin, maludb_memory_executor', p_schema);
    EXECUTE format('GRANT SELECT ON %I.maludb_episode TO maludb_memory_auditor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_episode', 'view', 'Schema-local episode registry facade.');
    v_count := v_count + 1;

    -- ---- maludb_episode_get aggregate ------------------------------
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_episode_get', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_episode_get(p_episode_id bigint)
        RETURNS jsonb LANGUAGE sql STABLE SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$ SELECT maludb_core.episode_get(p_episode_id) $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_episode_get(bigint) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_episode_get(bigint) TO maludb_memory_admin, maludb_memory_executor, maludb_memory_auditor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_episode_get', 'function', 'Schema-local episode aggregate reader.');
    v_count := v_count + 1;

    -- ---- maludb_register_episode: extend with provenance (8-arg) ----
    -- Drop the 7-arg signature emitted by the 0802 facade so the new
    -- definition replaces it instead of living alongside as an overload.
    EXECUTE format('DROP FUNCTION IF EXISTS %I.maludb_register_episode(text, text, text, jsonb, timestamptz, timestamptz, text)', p_schema);
    PERFORM maludb_core._memory_schema_assert_object_slot(p_schema, 'maludb_register_episode', 'function');
    EXECUTE format($sql$
        CREATE OR REPLACE FUNCTION %I.maludb_register_episode(
            p_episode_kind   text,
            p_title          text,
            p_summary        text DEFAULT NULL,
            p_payload_jsonb  jsonb DEFAULT '{}'::jsonb,
            p_occurred_at    timestamptz DEFAULT NULL,
            p_occurred_until timestamptz DEFAULT NULL,
            p_sensitivity    text DEFAULT 'internal',
            p_provenance     text DEFAULT 'provided'
        ) RETURNS bigint
        LANGUAGE plpgsql
        SECURITY INVOKER
        SET search_path = %I, maludb_core, pg_temp
        AS $facade$
        DECLARE
            v_id bigint;
        BEGIN
            v_id := maludb_core.register_episode(
                p_episode_kind, p_title, p_summary, p_payload_jsonb,
                p_occurred_at, p_occurred_until, p_sensitivity);
            IF COALESCE(NULLIF(btrim(p_provenance), ''), 'provided') <> 'provided' THEN
                UPDATE maludb_core.malu$episode_object
                   SET provenance = p_provenance
                 WHERE owner_schema = current_schema()
                   AND episode_id = v_id;
            END IF;
            RETURN v_id;
        END;
        $facade$
    $sql$, p_schema, p_schema);
    EXECUTE format('REVOKE ALL ON FUNCTION %I.maludb_register_episode(text, text, text, jsonb, timestamptz, timestamptz, text, text) FROM PUBLIC', p_schema);
    EXECUTE format('GRANT EXECUTE ON FUNCTION %I.maludb_register_episode(text, text, text, jsonb, timestamptz, timestamptz, text, text) TO maludb_memory_admin, maludb_memory_executor', p_schema);
    PERFORM maludb_core._memory_schema_record_object(p_schema, 'maludb_register_episode', 'function', 'Schema-local search-path-safe episode writer (with provenance).');
    v_count := v_count + 1;

    RETURN v_count;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core._enable_memory_schema_0820_facade(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core._enable_memory_schema_0820_facade(name)
    TO maludb_memory_admin, maludb_memory_executor;

-- ===== 7. wire the 0820 facade into enable_memory_schema ============
CREATE OR REPLACE FUNCTION maludb_core.enable_memory_schema(p_schema name DEFAULT current_schema())
RETURNS TABLE(schema_name name, enabled_version text, object_count integer)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = pg_catalog, maludb_core, pg_temp
AS $body$
DECLARE
    v_enabled_version text := maludb_core.maludb_core_version();
    v_count integer := 0;
    v_view  name;
BEGIN
    IF p_schema IS NULL THEN
        p_schema := current_schema();
    END IF;

    PERFORM maludb_core._memory_schema_assert_manageable(p_schema);

    FOREACH v_view IN ARRAY ARRAY['maludb_subject','maludb_memory','maludb_skill','maludb_document']::name[]
    LOOP
        IF EXISTS (
            SELECT 1 FROM maludb_core.malu$enabled_schema_object o
             WHERE o.schema_name = p_schema
               AND o.object_name = v_view
               AND o.object_kind = 'view'
        ) THEN
            EXECUTE format('DROP VIEW IF EXISTS %I.%I CASCADE', p_schema, v_view);
        END IF;
    END LOOP;

    INSERT INTO maludb_core.malu$enabled_schema(schema_name, enabled_version, enabled_by)
    VALUES (p_schema, v_enabled_version, session_user)
    ON CONFLICT ON CONSTRAINT malu$enabled_schema_pkey DO UPDATE
       SET enabled_version   = EXCLUDED.enabled_version,
           last_refreshed_at = now();

    v_count := v_count + maludb_core._enable_memory_schema_subject_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_core_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ingest_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_pool_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_ai_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_075_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_076_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_078_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_080_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0802_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0803_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0810_facade(p_schema);
    v_count := v_count + maludb_core._enable_memory_schema_0820_facade(p_schema);
    PERFORM maludb_core._grant_memory_schema_reader_access(p_schema);

    schema_name := p_schema;
    enabled_version := v_enabled_version;
    object_count := v_count;
    RETURN NEXT;
END;
$body$;

REVOKE ALL ON FUNCTION maludb_core.enable_memory_schema(name) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION maludb_core.enable_memory_schema(name)
    TO maludb_memory_admin, maludb_memory_executor, maludb_user, maludb_admin;
